// `timescale 1ns/1ps

// ============================================================================
// soc_hs.v  —  RISC-V Research SoC Physical Wrapper (Pad Ring)
//
// Đây là module top-level dành cho tổng hợp (Synthesis) và mô phỏng (Simulation).
// Nó bọc lấy `soc_top` và khởi tạo các cell vật lý (IO Pads) như IOBUF, OBUFT
// để giao tiếp với các chân 2 chiều (inout) trên chip thật.
// ============================================================================


// ==============================================================================
// FILE: soc_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// soc_top.v  —  RISC-V Research SoC Top-Level  (Full Integration)
//
// Phiên bản đầy đủ — kết nối toàn bộ các module:
//   ✅ clk_reset_ctrl   — clock/reset an toàn (thay wire fabric_rst_n=ext_rst_n)
//   ✅ riscv_cpu_core   — CPU RV32IM + debug interface
//   ✅ icache_top        — ICache (M0)
//   ✅ dcache_top        — DCache (M1)
//   ✅ ascon_ip_top      — ASCON accelerator (S2, M2 DMA)
//   ✅ axi_width_conv    — 64→32 bit converter cho ASCON DMA
//   ✅ axi4_crossbar_5m12s — crossbar mở rộng (5M × 12S)
//   ✅ inst_mem_axi_slave  — IMEM (S0, SRAM — loaded by boot_ctrl)
//   ✅ data_mem_axi4_slave — DMEM (S1)
//   ✅ soc_ctrl_slave    — SoC Control (S3)
//   ✅ clint             — CLINT (S4)
//   ✅ uart_top          — UART (S5)
//   ✅ plic_top          — PLIC (S9)
//   ✅ jtag_debug_top    — JTAG DTM + DM (M4)
//   ✅ dma_ctrl          — DMA Controller (S11, M3)
//   ✅ boot_ctrl         — Boot Controller (loads IMEM, gates cpu_rst_n)
//   ✅ gpio_top          — GPIO 32-bit (S6)
//   ✅ timer_top         — Timer0/1 + WDT (S8)
//
// Topology Bus:
//   Masters: M0=ICache, M1=DCache, M2=ASCON-DMA, M3=DMA-Ctrl, M4=JTAG-DM
//   Slaves:  S0=IMEM, S1=DMEM, S2=ASCON, S3=SoC-Ctrl, S4=CLINT,
//            S5=UART, S6=GPIO, S7=SPI*, S8=Timer/WDT, S9=PLIC,
//            S10=OTP*, S11=DMA-Ctrl-Config
//   (* = stub/tie-off, chưa có module thực)
//
// IRQ routing:
//   uart_irq    → plic irq_src[1] (tx) / [2] (rx)  [hợp nhất tại plic input]
//   spi_irq     → plic irq_src[3]   (stub=0)
//   gpio_irq    → plic irq_src[4]   (từ gpio_top)
//   timer0_irq  → plic irq_src[5]   (từ timer_top)
//   timer1_irq  → plic irq_src[6]   (từ timer_top)
//   wdt_irq     → plic irq_src[7]   (từ timer_top.wdt_core)
//   ascon_irq   → plic irq_src[8]
//   dma_irq     → plic irq_src[9]
//   plic.meip   → cpu.external_irq
//
// Reset domains (từ clk_reset_ctrl):
//   fabric_rst_n  → crossbar, ICache, DCache, ASCON, SRAM, CLINT, SoC-Ctrl
//   cpu_rst_n     → cpu_rst = ~cpu_rst_n (active-high)
//   periph_rst_n  → UART, PLIC, DMA, JTAG
//
// IO pad:
//   clk, por_n, ext_rst_n,
//   uart_tx, uart_rx,
//   tck, tms, tdi, tdo, tdo_en
// ============================================================================

// ============================================================================
// Include all sub-modules
//
// FIX: Đường dẫn `include phụ thuộc cấu trúc thư mục dự án của bạn.
// Mặc định dùng đường dẫn tương đối từ thư mục gốc dự án.
// Nếu compile từ thư mục khác, điều chỉnh đường dẫn cho phù hợp.
//
// Lệnh compile mẫu (từ thư mục gốc dự án):
//   iverilog -g2005 -I. -o sim.out interconnect/axi4_crossbar_5m12s.v soc_top.v
// Hoặc dùng filelist:
//   iverilog -g2005 -f filelist.f -o sim.out
// ============================================================================

// ==============================================================================
// FILE: riscv_cpu_core_v2.v
// ==============================================================================

// `timescale 1ns/1ps


// ==============================================================================
// FILE: IFU.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// IFU.v — Instruction Fetch Unit
// ============================================================================
// Manages program counter and instruction fetching.
//
// Key design decisions:
//   - Instruction_Code is COMBINATIONAL from imem_rdata when ready & !stall
//   - PC_out exports PC register directly (combinational)
//   - instr_hold latches last valid instruction for ICache miss recovery
//   - PC updates only when: !stall AND imem_ready
// ============================================================================

module IFU (
    input wire        clock,
    input wire        reset,
    input wire        pc_src,           // 0: PC+4, 1: target_pc (branch/jump)
    input wire        stall,            // 1: hold PC (pipeline stall)
    input wire [31:0] target_pc,        // Branch/jump target address

    // Instruction Memory Interface
    output wire [31:0] imem_addr,       // Address to instruction memory
    output wire        imem_valid,      // Request valid (always 1)
    input  wire [31:0] imem_rdata,      // Instruction data from memory
    input  wire        imem_ready,      // Memory ready signal

    // Outputs to pipeline
    output wire [31:0] PC_out,          // Current PC
    output wire [31:0] Instruction_Code // Fetched instruction (combinational)
);

    // ========================================================================
    // Program Counter Register
    // ========================================================================
    reg [31:0] PC;

    wire [31:0] next_pc;
    assign next_pc = pc_src ? target_pc : (PC + 32'd4);

    // ========================================================================
    // Instruction Memory Interface
    // ========================================================================
    assign imem_addr  = PC;
    assign imem_valid = 1'b1;

    // ========================================================================
    // PC Update
    // ========================================================================
    always @(posedge clock or posedge reset) begin
        if (reset)
            PC <= 32'h00000000;
        else if (!stall && imem_ready)
            PC <= next_pc;
    end

    // ========================================================================
    // Instruction Hold Register — keeps last valid instruction on cache miss
    // ========================================================================
    reg [31:0] instr_hold;

    always @(posedge clock or posedge reset) begin
        if (reset)
            instr_hold <= 32'h00000013; // NOP
        else if (imem_ready && !stall)
            instr_hold <= imem_rdata;
    end

    // Combinational output: direct from memory when ready, else held value
    assign Instruction_Code = (imem_ready && !stall) ? imem_rdata : instr_hold;

    // PC output: directly from PC register
    assign PC_out = PC;

endmodule
// ==============================================================================
// FILE: reg_file.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// reg_file.v — RISC-V Register File (32 x 32-bit)
// ============================================================================
// Design for high-frequency synthesis:
//   - WRITE at NEGEDGE clock → data available at next POSEDGE read
//   - No internal forwarding MUX needed (was 3-level MUX chain on read path)
//   - x0 is hardwired to zero
//
// Timing improvement:
//   Before: read_data = MUX(x0_check, MUX(fwd_check, registers[addr]))
//           → 3-level MUX on 32-bit data, ~2-3ns added to ID stage path
//   After:  read_data = MUX(x0_check, registers[addr])
//           → 1-level MUX, write data settled at negedge (half cycle earlier)
// ============================================================================

module reg_file (
    input wire        clock,
    input wire        reset,

    // Read ports (asynchronous, combinational)
    input wire [4:0]  read_reg_num1,      // rs1
    input wire [4:0]  read_reg_num2,      // rs2
    output wire [31:0] read_data1,        // data from rs1
    output wire [31:0] read_data2,        // data from rs2

    // Write port (synchronous — negedge clock)
    input wire        regwrite,           // write enable
    input wire [4:0]  write_reg,          // rd
    input wire [31:0] write_data          // data to write to rd
);

    // 32 registers, each 32-bit
    reg [31:0] registers [31:0];

    integer i;

    // ========================================================================
    // WRITE at NEGEDGE clock
    // ========================================================================
    // WHY negedge: WB stage computes write_data by posedge. At negedge
    // (half cycle later), write_data is stable and written into the register
    // array. The NEXT posedge, any ID stage read sees the updated value
    // without needing a forwarding MUX bypass.
    //
    // This eliminates the internal forwarding path that was:
    //   (regwrite && write_reg == read_reg) ? write_data : registers[addr]
    // which added a 5-bit comparator + 32-bit 2:1 MUX to the read path.
    // ========================================================================
    always @(negedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < 32; i = i + 1)
                registers[i] <= 32'h00000000;
        end else begin
            if (regwrite && (write_reg != 5'b00000))
                registers[write_reg] <= write_data;
            registers[0] <= 32'h00000000;  // x0 always zero
        end
    end

    // ========================================================================
    // READ: Pure combinational (no forwarding MUX)
    // ========================================================================
    assign read_data1 = (read_reg_num1 == 5'b00000) ? 32'h00000000
                                                     : registers[read_reg_num1];

    assign read_data2 = (read_reg_num2 == 5'b00000) ? 32'h00000000
                                                     : registers[read_reg_num2];

endmodule
// ==============================================================================
// FILE: imm_gen.v
// ==============================================================================

// `timescale 1ns/1ps

module imm_gen (
    input wire [31:0] instr,        // Instruction 32-bit
    output reg [31:0] imm           // Immediate value (sign-extended)
);

    // ========================================================================
    // RISC-V Opcode Definition
    // ========================================================================
    localparam [6:0]
        OP_I_TYPE   = 7'b0010011,    // I-type: ADDI, ANDI, ORI, etc.
        OP_LOAD     = 7'b0000011,    // I-type: LW, LH, LB
        OP_JALR     = 7'b1100111,    // I-type: JALR
        OP_STORE    = 7'b0100011,    // S-type: SW, SH, SB
        OP_BRANCH   = 7'b1100011,    // B-type: BEQ, BNE, BLT, etc.
        OP_LUI      = 7'b0110111,    // U-type: LUI
        OP_AUIPC    = 7'b0010111,    // U-type: AUIPC
        OP_JAL      = 7'b1101111;    // J-type: JAL
    
    wire [6:0] opcode = instr[6:0];
    
    // ========================================================================
    // Immediate Generation Logic
    // ========================================================================
    always @(*) begin
        case (opcode)
            // ================================================================
            // I-TYPE: 12-bit immediate
            // Format: imm[11:0] = instr[31:20]
            // Sign-extend from bit 31
            // ================================================================
            OP_I_TYPE, OP_LOAD, OP_JALR: begin
                imm = {{20{instr[31]}}, instr[31:20]};
            end
            
            // ================================================================
            // S-TYPE: Store instructions (12-bit immediate)
            // Format: imm[11:5] = instr[31:25], imm[4:0] = instr[11:7]
            // Sign-extend from bit 31
            // ================================================================
            OP_STORE: begin
                imm = {{20{instr[31]}}, instr[31:25], instr[11:7]};
            end
            
            // ================================================================
            // B-TYPE: Branch instructions (13-bit immediate, always even)
            // CRITICAL FIX: Correct bit ordering
            // Format: imm[12]   = instr[31]      (sign bit)
            //         imm[11]   = instr[7]       (NOT instr[12]!)
            //         imm[10:5] = instr[30:25]
            //         imm[4:1]  = instr[11:8]
            //         imm[0]    = 0 (always even)
            // Sign-extend from bit 12 (which is instr[31])
            // ================================================================
            OP_BRANCH: begin
                imm = {{19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0};
            end
            
            // ================================================================
            // U-TYPE: Upper immediate (20-bit immediate)
            // Format: imm[31:12] = instr[31:12], imm[11:0] = 0
            // Used for LUI and AUIPC
            // ================================================================
            OP_LUI, OP_AUIPC: begin
                imm = {instr[31:12], 12'b0};
            end
            
            // ================================================================
            // J-TYPE: Jump (JAL) (21-bit immediate, always even)
            // Format: imm[20]    = instr[31]      (sign bit)
            //         imm[19:12] = instr[19:12]
            //         imm[11]    = instr[20]
            //         imm[10:1]  = instr[30:21]
            //         imm[0]     = 0 (always even)
            // Sign-extend from bit 20 (which is instr[31])
            // ================================================================
            OP_JAL: begin
                imm = {{11{instr[31]}}, instr[31], instr[19:12], instr[20], instr[30:21], 1'b0};
            end
            
            // ================================================================
            // R-TYPE and other opcodes: no immediate
            // ================================================================
            default: begin
                imm = 32'h00000000;
            end
        endcase
    end

endmodule

// ==============================================================================
// FILE: control.v
// ==============================================================================

// `timescale 1ns/1ps

module control (
    input wire [6:0] opcode,
    input wire [2:0] funct3,
    input wire [6:0] funct7,

    output reg [3:0] alu_control,
    output reg regwrite,
    output reg alusrc,
    output reg memread,
    output reg memwrite,
    output reg branch,
    output reg jump,
    output reg [1:0] byte_size,
    output reg fence
);

    localparam [6:0]
        OP_R_TYPE   = 7'b0110011,
        OP_I_TYPE   = 7'b0010011,
        OP_LOAD     = 7'b0000011,
        OP_STORE    = 7'b0100011,
        OP_BRANCH   = 7'b1100011,
        OP_JAL      = 7'b1101111,
        OP_JALR     = 7'b1100111,
        OP_LUI      = 7'b0110111,
        OP_AUIPC    = 7'b0010111,
        OP_FENCE    = 7'b0001111;

    localparam [3:0]
        ALU_ADD   = 4'b0000,
        ALU_SUB   = 4'b0001,
        ALU_AND   = 4'b0010,
        ALU_OR    = 4'b0011,
        ALU_XOR   = 4'b0100,
        ALU_SLL   = 4'b0101,
        ALU_SRL   = 4'b0110,
        ALU_SRA   = 4'b0111,
        ALU_SLT   = 4'b1000,
        ALU_SLTU  = 4'b1001,
        ALU_MUL   = 4'b1010,
        ALU_MULH  = 4'b1011,
        ALU_DIV   = 4'b1100,
        ALU_DIVU  = 4'b1101,
        ALU_REM   = 4'b1110,
        ALU_REMU  = 4'b1111;

    localparam [2:0]
        F3_ADD_SUB  = 3'b000,
        F3_SLL      = 3'b001,
        F3_SLT      = 3'b010,
        F3_SLTU     = 3'b011,
        F3_XOR      = 3'b100,
        F3_SRL_SRA  = 3'b101,
        F3_OR       = 3'b110,
        F3_AND      = 3'b111,
        F3_BYTE     = 3'b000,
        F3_HALF     = 3'b001,
        F3_WORD     = 3'b010,
        F3_BYTE_U   = 3'b100,
        F3_HALF_U   = 3'b101,
        F3_MUL      = 3'b000,
        F3_MULH     = 3'b001,
        F3_DIV      = 3'b100,
        F3_DIVU     = 3'b101,
        F3_REM      = 3'b110,
        F3_REMU     = 3'b111;

    localparam [6:0]
        F7_SUB_SRA  = 7'b0100000,
        F7_MULDIV   = 7'b0000001;

    always @(*) begin
        regwrite    = 0;
        alusrc      = 0;
        memread     = 0;
        memwrite    = 0;
        branch      = 0;
        jump        = 0;
        fence       = 0;
        byte_size   = 2'b10;
        alu_control = ALU_ADD;

        case (opcode)
            OP_R_TYPE: begin
                regwrite = 1;
                alusrc   = 0;
                if (funct7 == F7_MULDIV) begin
                    case (funct3)
                        F3_MUL:   alu_control = ALU_MUL;
                        F3_MULH:  alu_control = ALU_MULH;
                        F3_DIV:   alu_control = ALU_DIV;
                        F3_DIVU:  alu_control = ALU_DIVU;
                        F3_REM:   alu_control = ALU_REM;
                        F3_REMU:  alu_control = ALU_REMU;
                        default:  alu_control = ALU_ADD;
                    endcase
                end else begin
                    case (funct3)
                        F3_ADD_SUB: begin
                            if (funct7 == F7_SUB_SRA) alu_control = ALU_SUB;
                            else                       alu_control = ALU_ADD;
                        end
                        F3_SLL:     alu_control = ALU_SLL;
                        F3_SLT:     alu_control = ALU_SLT;
                        F3_SLTU:    alu_control = ALU_SLTU;
                        F3_XOR:     alu_control = ALU_XOR;
                        F3_SRL_SRA: begin
                            if (funct7 == F7_SUB_SRA) alu_control = ALU_SRA;
                            else                       alu_control = ALU_SRL;
                        end
                        F3_OR:      alu_control = ALU_OR;
                        F3_AND:     alu_control = ALU_AND;
                        default:    alu_control = ALU_ADD;
                    endcase
                end
            end

            OP_I_TYPE: begin
                regwrite = 1;
                alusrc   = 1;
                case (funct3)
                    F3_ADD_SUB: alu_control = ALU_ADD;
                    F3_SLL:     alu_control = ALU_SLL;
                    F3_SLT:     alu_control = ALU_SLT;
                    F3_SLTU:    alu_control = ALU_SLTU;
                    F3_XOR:     alu_control = ALU_XOR;
                    F3_SRL_SRA: begin
                        if (funct7 == F7_SUB_SRA) alu_control = ALU_SRA;
                        else                       alu_control = ALU_SRL;
                    end
                    F3_OR:      alu_control = ALU_OR;
                    F3_AND:     alu_control = ALU_AND;
                    default:    alu_control = ALU_ADD;
                endcase
            end

            OP_LOAD: begin
                regwrite    = 1;
                alusrc      = 1;
                memread     = 1;
                alu_control = ALU_ADD;
                case (funct3)
                    F3_BYTE:   byte_size = 2'b00;
                    F3_HALF:   byte_size = 2'b01;
                    F3_WORD:   byte_size = 2'b10;
                    F3_BYTE_U: byte_size = 2'b00;
                    F3_HALF_U: byte_size = 2'b01;
                    default:   byte_size = 2'b10;
                endcase
            end

            OP_STORE: begin
                alusrc      = 1;
                memwrite    = 1;
                alu_control = ALU_ADD;
                case (funct3)
                    F3_BYTE: byte_size = 2'b00;
                    F3_HALF: byte_size = 2'b01;
                    F3_WORD: byte_size = 2'b10;
                    default: byte_size = 2'b10;
                endcase
            end

            OP_BRANCH: begin
                branch      = 1;
                alusrc      = 0;
                alu_control = ALU_SUB;
            end

            OP_JAL: begin
                regwrite    = 1;
                jump        = 1;
                alu_control = ALU_ADD;
            end

            OP_JALR: begin
                regwrite    = 1;
                jump        = 1;
                alusrc      = 1;
                alu_control = ALU_ADD;
            end

            OP_LUI: begin
                regwrite    = 1;
                alusrc      = 1;
                alu_control = ALU_ADD;
            end

            OP_AUIPC: begin
                regwrite    = 1;
                alusrc      = 1;
                alu_control = ALU_ADD;
            end

            OP_FENCE: begin
                fence = 1;
            end

            default: begin
                regwrite    = 0;
                alusrc      = 0;
                memread     = 0;
                memwrite    = 0;
                branch      = 0;
                jump        = 0;
                fence       = 0;
                alu_control = ALU_ADD;
            end
        endcase
    end

endmodule
// ==============================================================================
// FILE: alu.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// alu.v — RISC-V Arithmetic Logic Unit (RV32I)
// ============================================================================
// Performs arithmetic, logic, shift, and comparison operations.
// MUL/MULH are handled by riscv_multiplier (pipelined, separate unit).
//
// Timing Optimization Notes:
//   - Comparison flags (less_than, less_than_u) computed independently from
//     alu_result to avoid adding MUX delay to the flag output path
// ============================================================================

module alu (
    input  wire [31:0] in1,
    input  wire [31:0] in2,
    input  wire [3:0]  alu_control,

    output reg  [31:0] alu_result,
    output wire        zero_flag,
    output wire        less_than,
    output wire        less_than_u
);

    // ========================================================================
    // ALU Operation Codes
    // ========================================================================
    localparam [3:0]
        ALU_ADD   = 4'b0000,
        ALU_SUB   = 4'b0001,
        ALU_AND   = 4'b0010,
        ALU_OR    = 4'b0011,
        ALU_XOR   = 4'b0100,
        ALU_SLL   = 4'b0101,
        ALU_SRL   = 4'b0110,
        ALU_SRA   = 4'b0111,
        ALU_SLT   = 4'b1000,
        ALU_SLTU  = 4'b1001;

    // ========================================================================
    // Signed operands (reused for comparisons)
    // ========================================================================
    wire signed [31:0] in1_signed = $signed(in1);
    wire signed [31:0] in2_signed = $signed(in2);

    // ========================================================================
    // Main ALU Operation MUX
    // ========================================================================
    // Pre-compute add/sub as separate wires so synthesis sees them as
    // independent parallel adders and avoids sharing gate-level logic.
    wire [31:0] add_result = in1 + in2;
    wire [31:0] sub_result = in1 - in2;
    always @(*) begin
        case (alu_control)
            // --- RV32I: Arithmetic ---
            ALU_ADD:  alu_result = add_result;
            ALU_SUB:  alu_result = sub_result;

            // --- RV32I: Logic ---
            ALU_AND:  alu_result = in1 & in2;
            ALU_OR:   alu_result = in1 | in2;
            ALU_XOR:  alu_result = in1 ^ in2;

            // --- RV32I: Shifts ---
            ALU_SLL:  alu_result = in1 << in2[4:0];
            ALU_SRL:  alu_result = in1 >> in2[4:0];
            ALU_SRA:  alu_result = $signed(in1) >>> in2[4:0];

            // --- RV32I: Set Less Than ---
            ALU_SLT:  alu_result = (in1_signed < in2_signed) ? 32'd1 : 32'd0;
            ALU_SLTU: alu_result = (in1 < in2) ? 32'd1 : 32'd0;

            // MUL/MULH handled by riscv_multiplier — WB mux overrides this 0
            default:  alu_result = 32'd0;
        endcase
    end

    // ========================================================================
    // Comparison Flags — independent of alu_result (shorter timing path)
    // ========================================================================
    // zero_flag computed directly from operands (32-bit XOR + NOR tree, ~1.3 ns)
    // rather than from alu_result (~4-5 ns adder path).
    // Correct because branch_logic only uses zero_flag for BEQ/BNE, where
    // alu_control is always ALU_SUB, so (in1 - in2 == 0) ≡ (in1 == in2).
    assign zero_flag   = (in1 == in2);
    assign less_than   = (in1_signed < in2_signed);
    assign less_than_u = (in1 < in2);

endmodule

// ==============================================================================
// FILE: riscv_multiplier.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// riscv_multiplier.v — 3-stage Pipelined Multiplier for RV32M (Fix 10A)
// ============================================================================
// Pipeline stages:
//   E1   : Sign-extend operands, latch (posedge N)
//   E1.5 : Decompose 33×33 into 4× 17×17 partial products, latch (posedge N+1)
//   E2   : CSA tree + final adder — sum partial products, latch (posedge N+2)
//
// Timing: result valid 3 cycles after mul_valid_i pulse (2-stage was 2 cycles).
// mul_ex_stall in hazard_detection adds 1 extra EX cycle so E1.5 can compute
// before E2 captures; net MUL latency from programmer perspective = same.
//
// hold_i / mul_hold_e15_i = stall_any && !mul_ex_stall — freezes all stages
// except during the multiplier's own stall cycle (E1 and E1.5 must advance).
//
// (* keep = 1 *) on sign bits reduces fanout from 133 to manageable levels.
// ============================================================================

module riscv_multiplier (
    input           clk_i,
    input           rst_i,

    // Dispatch: high for exactly 1 cycle when MUL instruction enters EX
    input           mul_valid_i,

    // Operation select: 00=MUL, 01=MULH, 10=MULHSU, 11=MULHU
    input  [1:0]    mul_op_i,

    input  [31:0]   operand_a_i,
    input  [31:0]   operand_b_i,

    // Freeze all stages (= stall_any && !mul_ex_stall)
    input           hold_i,

    // Freeze E1.5 stage only (same signal as hold_i from CPU top)
    input           mul_hold_e15_i,

    output [31:0]   writeback_value_o
);

    // ========================================================================
    // E1: Sign-extend operands and latch
    // ========================================================================
    reg  [32:0] operand_a_e1_q;
    reg  [32:0] operand_b_e1_q;
    reg         mulhi_sel_e1_q;

    reg  [32:0] operand_a_r;
    reg  [32:0] operand_b_r;

    always @* begin
        case (mul_op_i)
            2'b01,          // MULH:   signed A × signed B
            2'b10:          // MULHSU: signed A × unsigned B
                operand_a_r = {operand_a_i[31], operand_a_i};
            default:        // MUL / MULHU: unsigned A
                operand_a_r = {1'b0, operand_a_i};
        endcase
    end

    always @* begin
        case (mul_op_i)
            2'b01:          // MULH: signed B
                operand_b_r = {operand_b_i[31], operand_b_i};
            default:        // MUL / MULHSU / MULHU: unsigned B
                operand_b_r = {1'b0, operand_b_i};
        endcase
    end

    always @(posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
            operand_a_e1_q <= 33'b0;
            operand_b_e1_q <= 33'b0;
            mulhi_sel_e1_q <= 1'b0;
        end else if (!hold_i) begin
            if (mul_valid_i) begin
                operand_a_e1_q <= operand_a_r;
                operand_b_e1_q <= operand_b_r;
                mulhi_sel_e1_q <= (mul_op_i != 2'b00);
            end else begin
                operand_a_e1_q <= 33'b0;
                operand_b_e1_q <= 33'b0;
                mulhi_sel_e1_q <= 1'b0;
            end
        end
    end

    // ========================================================================
    // E1.5: Decompose 33×33 into four 17×17 partial products (~10-12 gate levels)
    // (* keep=1 *) on sign bits prevents fanout >50 at synthesis.
    // ========================================================================
wire sign_a = operand_a_e1_q[32];
wire sign_b = operand_b_e1_q[32];

    // Split 33-bit signed operands into 17-bit halves.
    // a_hi carries the sign bit so signed arithmetic propagates correctly.
    wire [16:0] a_lo = operand_a_e1_q[16:0];
    wire [16:0] a_hi = {sign_a, operand_a_e1_q[32:17]};  // sign-extended upper half
    wire [16:0] b_lo = operand_b_e1_q[16:0];
    wire [16:0] b_hi = {sign_b, operand_b_e1_q[32:17]};

    // Each 17×17 signed product fits in 34 bits
    wire signed [33:0] pp_ll_w = $signed(a_lo) * $signed(b_lo);
    wire signed [33:0] pp_lh_w = $signed(a_lo) * $signed(b_hi);
    wire signed [33:0] pp_hl_w = $signed(a_hi) * $signed(b_lo);
    wire signed [29:0] pp_hh_w = ($signed(a_hi) * $signed(b_hi));  // bits[33:30] exceed 64-bit result range

    reg signed [33:0] pp_ll_e15_q, pp_lh_e15_q, pp_hl_e15_q;
    reg        [29:0] pp_hh_e15_q;
    reg               mulhi_sel_e15_q;

    always @(posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
            pp_ll_e15_q     <= 34'b0;
            pp_lh_e15_q     <= 34'b0;
            pp_hl_e15_q     <= 34'b0;
            pp_hh_e15_q     <= 30'b0;
            mulhi_sel_e15_q <= 1'b0;
        end else if (!mul_hold_e15_i) begin
            pp_ll_e15_q     <= pp_ll_w;
            pp_lh_e15_q     <= pp_lh_w;
            pp_hl_e15_q     <= pp_hl_w;
            pp_hh_e15_q     <= pp_hh_w;
            mulhi_sel_e15_q <= mulhi_sel_e1_q;
        end
    end

    // ========================================================================
    // E1.5→E2: Sum four partial products with positional shifts (~12-14 gate levels)
    // Equivalent to: (a_hi<<17 + a_lo) * (b_hi<<17 + b_lo)
    //   = pp_hh<<34 + pp_hl<<17 + pp_lh<<17 + pp_ll
    // Sign-extend each 34-bit product to exactly 64 bits before summing.
    // pp_hh<<34 only contributes to bits [63:34], so only pp_hh[29:0] are kept.
    // ========================================================================
    wire [63:0] mult_result_w =
          {{30{pp_ll_e15_q[33]}}, pp_ll_e15_q}        // [LINT-FIX] 30+34 = 64b
        + {{13{pp_lh_e15_q[33]}}, pp_lh_e15_q, 17'b0} // [LINT-FIX] 13+34+17 = 64b
        + {{13{pp_hl_e15_q[33]}}, pp_hl_e15_q, 17'b0} // [LINT-FIX] 13+34+17 = 64b
        + {pp_hh_e15_q, 34'b0};                       // 30+34 = 64b

    wire [31:0] result_r = mulhi_sel_e15_q ? mult_result_w[63:32]
                                            : mult_result_w[31:0];

    // ========================================================================
    // E2: Output register
    // ========================================================================
    reg [31:0] result_e2_q;

    always @(posedge clk_i or posedge rst_i) begin
        if (rst_i)
            result_e2_q <= 32'b0;
        else if (!hold_i)
            result_e2_q <= result_r;
    end

    assign writeback_value_o = result_e2_q;

endmodule

// ==============================================================================
// FILE: branch_logic.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// branch_logic.v — Branch Condition Evaluator
// ============================================================================
// Evaluates branch conditions based on ALU comparison flags.
// Pure combinational — no timing-critical paths.
//
// funct3 encoding (RISC-V B-type):
//   000 = BEQ   (branch if equal)
//   001 = BNE   (branch if not equal)
//   100 = BLT   (branch if less than, signed)
//   101 = BGE   (branch if greater or equal, signed)
//   110 = BLTU  (branch if less than, unsigned)
//   111 = BGEU  (branch if greater or equal, unsigned)
// ============================================================================

module branch_logic (
    input wire        branch,        // Branch instruction (from control)
    input wire [2:0]  funct3,        // Function field (branch type)
    input wire        zero_flag,     // Zero flag from ALU
    input wire        less_than,     // Signed less than from ALU
    input wire        less_than_u,   // Unsigned less than from ALU
    output reg        taken          // Branch taken signal
);

    always @(*) begin
        if (branch) begin
            case (funct3)
                3'b000:  taken = zero_flag;           // BEQ
                3'b001:  taken = ~zero_flag;          // BNE
                3'b100:  taken = less_than;           // BLT
                3'b101:  taken = ~less_than;          // BGE
                3'b110:  taken = less_than_u;         // BLTU
                3'b111:  taken = ~less_than_u;        // BGEU
                default: taken = 1'b0;
            endcase
        end else begin
            taken = 1'b0;
        end
    end

endmodule
// ==============================================================================
// FILE: forwarding_unit.v
// ==============================================================================

// `timescale 1ns/1ps

module forwarding_unit (
    // Source registers in EX stage
    input [4:0] rs1_ex,
    input [4:0] rs2_ex,
    
    // Destination registers in MEM and WB stages
    input [4:0] rd_mem,
    input [4:0] rd_wb,
    
    // Write enable signals
    input regwrite_mem,
    input regwrite_wb,
    
    // Forwarding control outputs
    output reg [1:0] forward_a,  // For rs1
    output reg [1:0] forward_b   // For rs2
);

    // Forwarding encoding:
    // 2'b00: No forwarding (use value from register file)
    // 2'b01: Forward from WB stage
    // 2'b10: Forward from MEM stage

    always @(*) begin
        // Default: no forwarding
        forward_a = 2'b00;
        forward_b = 2'b00;
        
        // ============================================
        // Forwarding for rs1 (operand A)
        // ============================================
        
        // Priority 1: Forward from MEM stage (most recent)
        if (regwrite_mem && (rd_mem != 5'b00000) && (rd_mem == rs1_ex)) begin
            forward_a = 2'b10;
        end
        // Priority 2: Forward from WB stage (older instruction)
        else if (regwrite_wb && (rd_wb != 5'b00000) && (rd_wb == rs1_ex)) begin
            forward_a = 2'b01;
        end
        // Otherwise: no forwarding (use register file value)
        else begin
            forward_a = 2'b00;
        end
        
        // ============================================
        // Forwarding for rs2 (operand B)
        // ============================================
        
        // Priority 1: Forward from MEM stage (most recent)
        if (regwrite_mem && (rd_mem != 5'b00000) && (rd_mem == rs2_ex)) begin
            forward_b = 2'b10;
        end
        // Priority 2: Forward from WB stage (older instruction)
        else if (regwrite_wb && (rd_wb != 5'b00000) && (rd_wb == rs2_ex)) begin
            forward_b = 2'b01;
        end
        // Otherwise: no forwarding (use register file value)
        else begin
            forward_b = 2'b00;
        end
    end

endmodule
// ==============================================================================
// FILE: hazard_detection.v
// ==============================================================================

// `timescale 1ns/1ps

module hazard_detection (
    input wire        clk,
    input wire        rst,

    input wire        memread_id_ex,
    input wire [4:0]  rd_id_ex,
    input wire [4:0]  rs1_id,
    input wire [4:0]  rs2_id,
    input wire        rs1_used_id,
    input wire        rs2_used_id,

    input wire        branch_taken,
    input wire        imem_ready,
    input wire [31:0] lsu_scoreboard,
    input wire        mem_stage_pending,
    input wire        memread_mem_stage,
    input wire [4:0]  rd_mem_stage,

    input wire        fence_id,
    input wire        lsu_idle,

    // MUL in EX: result ready 2 cycles later (same as load-use pattern)
    input wire        mul_in_ex,

    // Static backward branch prediction signals (Fix 9)
    input wire        predict_taken_ex,
    input wire        predict_taken_id,
    input wire        mispredict_ex,

    output wire       stall,
    output wire       stall_if,
    output wire       flush_if_id,
    output wire       flush_id_ex,
    output wire       fence_stall,
    output wire       lsu_dep_stall,
    output wire       mul_ex_stall
);

    wire load_use_hazard;
    assign load_use_hazard = memread_id_ex &&
                             (rd_id_ex != 5'b0) &&
                             ((rs1_used_id && (rd_id_ex == rs1_id)) ||
                              (rs2_used_id && (rd_id_ex == rs2_id)));

    wire lsu_dependency_stall;
    assign lsu_dependency_stall = (rs1_used_id && (rs1_id != 5'b0) && lsu_scoreboard[rs1_id]) ||
                                  (rs2_used_id && (rs2_id != 5'b0) && lsu_scoreboard[rs2_id]);

    // Close the 1-cycle gap between EX load-use stall and LSU scoreboard set.
    wire mem_load_issue_hazard;
    assign mem_load_issue_hazard = mem_stage_pending &&
                                   memread_mem_stage &&
                                   (rd_mem_stage != 5'b0) &&
                                   ((rs1_used_id && (rd_mem_stage == rs1_id)) ||
                                    (rs2_used_id && (rd_mem_stage == rs2_id)));
    assign lsu_dep_stall = lsu_dependency_stall || mem_load_issue_hazard;

    wire imem_stall;
    assign imem_stall = !imem_ready;

    assign fence_stall = fence_id && (!lsu_idle || mem_stage_pending);

    // MUL result stall: stall 1 cycle if instruction after MUL reads MUL destination
    wire mul_result_stall;
    assign mul_result_stall = mul_in_ex &&
                              (rd_id_ex != 5'b0) &&
                              ((rs1_used_id && (rs1_id != 5'b0) && (rs1_id == rd_id_ex)) ||
                               (rs2_used_id && (rs2_id != 5'b0) && (rs2_id == rd_id_ex)));

    // mul_ex_stall: hold pipeline 1 extra cycle when MUL first enters EX (Fix 10B)
    // Allows E1.5 partial-product stage to compute before E2 captures result.
    reg mul_ex_stall_done_r;
    always @(posedge clk or posedge rst) begin
        if (rst)             mul_ex_stall_done_r <= 1'b0;
        else if (!mul_in_ex) mul_ex_stall_done_r <= 1'b0;
        else                 mul_ex_stall_done_r <= 1'b1;
    end
    assign mul_ex_stall = mul_in_ex && !mul_ex_stall_done_r;

    assign stall    = load_use_hazard || lsu_dep_stall || fence_stall || mul_result_stall || mul_ex_stall;
    assign stall_if = imem_stall;

    // Fix 9B: prediction-aware flush
    // Correctly-predicted taken branch: no IF/ID flush (prediction already redirected IFU)
    // Mispredicted (predicted taken but actually not): flush IF+ID, redirect to fall-through
    // New backward branch predicted taken in ID: flush IF/ID, redirect IFU to target
    assign flush_if_id = (branch_taken && !predict_taken_ex) || mispredict_ex || predict_taken_id;
    assign flush_id_ex = load_use_hazard || (branch_taken && !predict_taken_ex) || mispredict_ex || fence_stall || mul_result_stall;

endmodule

// ==============================================================================
// FILE: PIPELINE_REG_IF_ID.v
// ==============================================================================

// `timescale 1ns/1ps

module PIPELINE_REG_IF_ID (
    input clock,
    input reset,
    input flush,
    input stall,
    input [31:0] instr_in,
    input [31:0] pc_in,
    output reg [31:0] instr_out,
    output reg [31:0] pc_out
);

    // NOP instruction (ADDI x0, x0, 0)
    localparam NOP = 32'h00000013;

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            // Reset: khởi tạo với NOP
            instr_out <= NOP;
            pc_out <= 32'h00000000;
        end
        else if (flush) begin
            // Flush: chèn NOP vào pipeline (xóa instruction hiện tại)
            instr_out <= NOP;
            pc_out <= 32'h00000000;
        end
        else if (!stall) begin
            // Normal operation: cập nhật khi không bị stall
            instr_out <= instr_in;
            pc_out <= pc_in;
        end
        // Nếu stall=1: giữ nguyên giá trị (không có else)
    end

endmodule
// ==============================================================================
// FILE: PIPELINE_REG_ID_EX.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// PIPELINE_REG_ID_EX.v — ID/EX Pipeline Register (Refactored)
// ============================================================================
// Supports:
//   - flush: insert NOP bubble (clear all control + data)
//   - stall: hold current values
//   - fwd_capture: when stalled, capture forwarded operand values to prevent
//     stale data after forwarding window closes (FIX-FWD-STALL)
//
// Port naming: _in suffix = from ID stage, _out suffix = to EX stage
// ============================================================================

module PIPELINE_REG_ID_EX (
    input wire        clock,
    input wire        reset,
    input wire        flush,
    input wire        stall,

    // --- Forwarding capture during stall (FIX-FWD-STALL) ---
    input wire [1:0]  fwd_a_sel,          // current forward_a selection
    input wire [1:0]  fwd_b_sel,          // current forward_b selection
    input wire [31:0] fwd_a_data,         // forwarded operand A value
    input wire [31:0] fwd_b_data,         // forwarded operand B (pre-mux) value

    // --- Control signals ---
    input wire        regwrite_in,
    input wire        alusrc_in,
    input wire        memread_in,
    input wire        memwrite_in,
    input wire        branch_in,
    input wire        predict_taken_in,
    input wire        jump_in,

    // --- Data ---
    input wire [31:0] read_data1_in,
    input wire [31:0] read_data2_in,
    input wire [31:0] imm_in,
    input wire [31:0] pc_in,
    input wire [31:0] branch_target_in,

    // --- Register addresses ---
    input wire [4:0]  rs1_in,
    input wire [4:0]  rs2_in,
    input wire [4:0]  rd_in,

    // --- Function codes & opcode ---
    input wire [2:0]  funct3_in,
    input wire [3:0]  alu_control_in,
    input wire [1:0]  byte_size_in,
    input wire [6:0]  opcode_in,

    // --- Control outputs ---
    output reg        regwrite_out,
    output reg        alusrc_out,
    output reg        memread_out,
    output reg        memwrite_out,
    output reg        branch_out,
    output reg        predict_taken_out,
    output reg        jump_out,

    // --- Data outputs ---
    output reg [31:0] read_data1_out,
    output reg [31:0] read_data2_out,
    output reg [31:0] imm_out,
    output reg [31:0] pc_out,
    output reg [31:0] branch_target_out,

    // --- Register address outputs ---
    output reg [4:0]  rs1_out,
    output reg [4:0]  rs2_out,
    output reg [4:0]  rd_out,

    // --- Function code & opcode outputs ---
    output reg [2:0]  funct3_out,
    output reg [3:0]  alu_control_out,
    output reg [1:0]  byte_size_out,
    output reg [6:0]  opcode_out
);

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            regwrite_out    <= 1'b0;
            alusrc_out      <= 1'b0;
            memread_out     <= 1'b0;
            memwrite_out    <= 1'b0;
            branch_out      <= 1'b0;
            predict_taken_out <= 1'b0;
            jump_out        <= 1'b0;
            read_data1_out  <= 32'h0;
            read_data2_out  <= 32'h0;
            imm_out         <= 32'h0;
            pc_out          <= 32'h0;
            branch_target_out <= 32'h0;
            rs1_out         <= 5'b0;
            rs2_out         <= 5'b0;
            rd_out          <= 5'b0;
            funct3_out      <= 3'b0;
            alu_control_out <= 4'b0;
            byte_size_out   <= 2'b0;
            opcode_out      <= 7'b0;
        end else if (flush) begin
            regwrite_out    <= 1'b0;
            alusrc_out      <= 1'b0;
            memread_out     <= 1'b0;
            memwrite_out    <= 1'b0;
            branch_out      <= 1'b0;
            predict_taken_out <= 1'b0;
            jump_out        <= 1'b0;
            read_data1_out  <= 32'h0;
            read_data2_out  <= 32'h0;
            imm_out         <= 32'h0;
            pc_out          <= 32'h0;
            branch_target_out <= 32'h0;
            rs1_out         <= 5'b0;
            rs2_out         <= 5'b0;
            rd_out          <= 5'b0;
            funct3_out      <= 3'b0;
            alu_control_out <= 4'b0;
            byte_size_out   <= 2'b0;
            opcode_out      <= 7'b0;
        end else if (!stall) begin
            // Normal latch from ID stage
            regwrite_out    <= regwrite_in;
            alusrc_out      <= alusrc_in;
            memread_out     <= memread_in;
            memwrite_out    <= memwrite_in;
            branch_out      <= branch_in;
            predict_taken_out <= predict_taken_in;
            jump_out        <= jump_in;
            read_data1_out  <= read_data1_in;
            read_data2_out  <= read_data2_in;
            imm_out         <= imm_in;
            pc_out          <= pc_in;
            branch_target_out <= branch_target_in;
            rs1_out         <= rs1_in;
            rs2_out         <= rs2_in;
            rd_out          <= rd_in;
            funct3_out      <= funct3_in;
            alu_control_out <= alu_control_in;
            byte_size_out   <= byte_size_in;
            opcode_out      <= opcode_in;
        end else begin
            // [FIX-FWD-STALL] During stall, capture forwarded values
            // to prevent stale data when forwarding window expires.
            // Only update operand registers that are currently being forwarded.
            if (fwd_a_sel != 2'b00)
                read_data1_out <= fwd_a_data;
            if (fwd_b_sel != 2'b00)
                read_data2_out <= fwd_b_data;
        end
    end

endmodule
// ==============================================================================
// FILE: PIPELINE_REG_EX_MEM.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// PIPELINE_REG_EX_MEM.v — EX/MEM Pipeline Register
// ============================================================================
// Supports:
//   - stall_ex_mem: freeze when LSU dependency stall
//   - pass-once control: while upstream is stalled, each distinct EX instruction
//     is allowed to advance into MEM exactly once; replayed copies are bubbled
//     to prevent duplicate side effects
//
// Design note: data path always latches when !stall_ex_mem.
// Control signals are selectively cleared (bubble) based on stall conditions.
// ============================================================================

module PIPELINE_REG_EX_MEM (
    input wire        clock,
    input wire        reset,

    // Stall controls
    input wire        stall_ex_mem,     // freeze entire register (LSU dependency)
    input wire        stall_any,        // upstream stall (imem miss, load-use, debug)
    input wire        fence_stall,      // kept for interface compatibility

    // --- Control signals ---
    input wire        regwrite_in,
    input wire        memread_in,
    input wire        memwrite_in,
    input wire        jump_in,

    // --- Data ---
    input wire [31:0] alu_result_in,
    input wire [31:0] write_data_in,    // rs2 forwarded value for store
    input wire [31:0] pc_plus_4_in,

    // --- Register address ---
    input wire [4:0]  rd_in,
    input wire [1:0]  byte_size_in,
    input wire [2:0]  funct3_in,

    // --- MUL flag ---
    input wire        is_mul_in,

    // --- Control outputs ---
    output reg        regwrite_out,
    output reg        memread_out,
    output reg        memwrite_out,
    output reg        jump_out,

    // --- Data outputs ---
    output reg [31:0] alu_result_out,
    output reg [31:0] write_data_out,
    output reg [31:0] pc_plus_4_out,

    // --- Register address output ---
    output reg [4:0]  rd_out,
    output reg [1:0]  byte_size_out,
    output reg [2:0]  funct3_out,

    // --- MUL flag output ---
    output reg        is_mul_out
);

    reg [78:0] stalled_sig_r;
    reg        stalled_sig_valid_r;
    wire [78:0] ex_sig = {
        regwrite_in, memread_in, memwrite_in, jump_in, is_mul_in,
        rd_in, byte_size_in, funct3_in, alu_result_in, pc_plus_4_in
    };
    wire same_stalled_sig = stalled_sig_valid_r && (ex_sig == stalled_sig_r);

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            regwrite_out  <= 1'b0;
            memread_out   <= 1'b0;
            memwrite_out  <= 1'b0;
            jump_out      <= 1'b0;
            is_mul_out    <= 1'b0;
            alu_result_out <= 32'h0;
            write_data_out <= 32'h0;
            pc_plus_4_out  <= 32'h0;
            rd_out        <= 5'b0;
            byte_size_out <= 2'b0;
            funct3_out    <= 3'b0;
            stalled_sig_r <= 79'b0;
            stalled_sig_valid_r <= 1'b0;
        end else if (!stall_ex_mem) begin
            // Data path: always latch
            alu_result_out <= alu_result_in;
            write_data_out <= write_data_in;
            pc_plus_4_out  <= pc_plus_4_in;
            rd_out         <= rd_in;
            byte_size_out  <= byte_size_in;
            funct3_out     <= funct3_in;

            // Control path: while upstream is stalled, let each distinct EX
            // instruction advance exactly once, then bubble duplicate replays.
            if (stall_any && same_stalled_sig) begin
                regwrite_out <= 1'b0;
                memread_out  <= 1'b0;
                memwrite_out <= 1'b0;
                jump_out     <= 1'b0;
                is_mul_out   <= 1'b0;
            end else begin
                regwrite_out <= regwrite_in;
                memread_out  <= memread_in;
                memwrite_out <= memwrite_in;
                jump_out     <= jump_in;
                is_mul_out   <= is_mul_in;
            end

            if (stall_any) begin
                stalled_sig_r <= ex_sig;
                stalled_sig_valid_r <= 1'b1;
            end else begin
                stalled_sig_valid_r <= 1'b0;
            end
        end
    end

endmodule

// ==============================================================================
// FILE: PIPELINE_REG_MEM_WB.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// PIPELINE_REG_MEM_WB.v — MEM/WB Pipeline Register
// ============================================================================
// Two input sources:
//   1. LSU result (load data) — priority, latches when lsu_result_valid=1
//   2. Normal EX→MEM pass-through (ALU result, jump return address)
//
// Design note: LSU results take priority because loads are non-deterministic
// latency. When lsu_result_valid fires, it immediately overwrites the
// register regardless of other stall conditions.
// ============================================================================

module PIPELINE_REG_MEM_WB (
    input wire        clock,
    input wire        reset,

    // Stall/guard controls
    input wire        stall_ex_mem,      // freeze guard (sync with EX/MEM)
    input wire        lsu_committed,     // LSU result was committed last cycle

    // --- LSU result path (priority) ---
    input wire        lsu_result_valid,
    input wire [31:0] lsu_result_data,
    input wire [4:0]  lsu_result_rd,

    // --- Normal MEM stage path ---
    input wire        regwrite_in,
    input wire        memread_in,        // for masking regwrite on pending loads
    input wire        jump_in,
    input wire [31:0] alu_result_in,
    input wire [31:0] pc_plus_4_in,
    input wire [4:0]  rd_in,

    // --- MUL result path ---
    input wire        is_mul_in,

    // --- Outputs to WB ---
    output reg        regwrite_out,
    output reg        memtoreg_out,
    output reg        jump_out,
    output reg [31:0] alu_result_out,
    output reg [31:0] mem_data_out,
    output reg [31:0] pc_plus_4_out,
    output reg [4:0]  rd_out,
    output reg        is_mul_out
);

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            regwrite_out  <= 1'b0;
            memtoreg_out  <= 1'b0;
            jump_out      <= 1'b0;
            is_mul_out    <= 1'b0;
            alu_result_out <= 32'h0;
            mem_data_out   <= 32'h0;
            pc_plus_4_out  <= 32'h0;
            rd_out         <= 5'b0;
        end else begin
            if (lsu_result_valid) begin
                // LSU result takes priority — load completed
                mem_data_out   <= lsu_result_data;
                rd_out         <= lsu_result_rd;
                regwrite_out   <= 1'b1;
                memtoreg_out   <= 1'b1;
                jump_out       <= 1'b0;
                is_mul_out     <= 1'b0;
                alu_result_out <= alu_result_in;
                pc_plus_4_out  <= pc_plus_4_in;
            end else if (!stall_ex_mem && !lsu_committed) begin
                // Normal pass-through from MEM stage
                alu_result_out <= alu_result_in;
                pc_plus_4_out  <= pc_plus_4_in;
                regwrite_out   <= regwrite_in & ~memread_in;
                memtoreg_out   <= 1'b0;
                jump_out       <= jump_in;
                rd_out         <= rd_in;
                is_mul_out     <= is_mul_in;
                mem_data_out   <= 32'h0; // [LINT-FIX] clear when no LSU result (memtoreg_out=0 so WB ignores this)
            end
        end
    end

endmodule

// ==============================================================================
// FILE: LSU.v
// ==============================================================================

// `timescale 1ns/1ps

module LSU (
    input wire clk,
    input wire rst,

    input  wire        req_valid,
    output wire        req_ready,
    input  wire [31:0] req_addr,
    input  wire [31:0] req_wdata,
    input  wire [3:0]  req_wstrb,
    input  wire        req_is_load,
    input  wire [4:0]  req_rd,
    input  wire [2:0]  req_funct3,

    input  wire        fence,

    output reg         result_valid,
    output reg  [31:0] result_data,
    output reg  [4:0]  result_rd,
    input  wire        result_ack,

    output wire [31:0] scoreboard,
    output wire        lsu_idle,

    output reg         dcache_req,
    output reg         dcache_we,
    output reg  [31:0] dcache_addr,
    output reg  [31:0] dcache_wdata,
    output reg  [3:0]  dcache_wstrb,
    input  wire [31:0] dcache_rdata,
    input  wire        dcache_ready
);

    localparam SB_DEPTH = 4;
    localparam SB_BITS  = 2;

    reg [31:0] sb_addr  [0:SB_DEPTH-1];
    reg [31:0] sb_wdata [0:SB_DEPTH-1];
    reg [3:0]  sb_wstrb [0:SB_DEPTH-1];
    reg        sb_valid [0:SB_DEPTH-1];

    reg [SB_BITS-1:0] sb_wr_ptr;
    reg [SB_BITS-1:0] sb_rd_ptr;
    reg [SB_BITS:0]   sb_count;

    wire sb_full  = (sb_count == SB_DEPTH);
    wire sb_empty = (sb_count == 0);

    localparam LQ_DEPTH = 4;
    localparam LQ_BITS  = 2;

    reg [31:0] lq_addr    [0:LQ_DEPTH-1];
    reg [4:0]  lq_rd      [0:LQ_DEPTH-1];
    reg [2:0]  lq_funct3  [0:LQ_DEPTH-1];
    reg        lq_fwd     [0:LQ_DEPTH-1];
    reg [31:0] lq_fwd_data[0:LQ_DEPTH-1];

    reg [LQ_BITS-1:0] lq_wr_ptr;
    reg [LQ_BITS-1:0] lq_rd_ptr;
    reg [LQ_BITS:0]   lq_count;

    wire lq_full  = (lq_count == LQ_DEPTH);
    wire lq_empty = (lq_count == 0);

    reg [31:0] scoreboard_reg;
    assign scoreboard = scoreboard_reg;

    // lsu_idle: không có in-flight transaction nào
    // Dùng bởi hazard_detection để biết khi nào FENCE có thể commit
    assign lsu_idle = sb_empty && lq_empty &&
                      (load_state == LOAD_IDLE) &&
                      (drain_state == DRAIN_IDLE) &&
                      !result_valid;

    // `fence` đã được core gate theo trạng thái quiescent của LSU.
    // Ở đây chỉ cần chặn request mới trong cycle thực thi FENCE.
    assign req_ready = fence ? 1'b0 :
                       (req_is_load ? !lq_full : !sb_full);

    wire        fwd_hit;
    wire [31:0] fwd_data;
    reg         fwd_hit_r;
    reg  [31:0] fwd_data_r;
    reg  [3:0]  fwd_strb_r;    // [FIX-FWD] track which byte lanes are covered

    // =========================================================================
    // [FIX-FWD] Store-to-Load Forwarding — byte-lane merge
    //
    // TRƯỚC: fwd_data_r = sb_wdata[fi] (nguyên word) → nếu store buffer chứa
    //        sb (wstrb=0010), forward trả 0x0000XX00 cho cả word → byte 0,2,3
    //        bị zero thay vì giữ giá trị cũ từ cache.
    //
    // SAU:   Merge từng byte lane từ tất cả store buffer entries cùng word addr.
    //        Entry sau (index cao hơn nếu cùng addr) ghi đè entry trước — đúng
    //        thứ tự program order vì sb_wr_ptr tăng dần.
    //
    //        fwd_strb_r track byte nào đã được cover. Nếu < 4'b1111 (partial),
    //        KHÔNG forward — phải đợi store drain rồi đọc cache để lấy đủ data.
    //        Lý do: LSU không có đường đọc cache song song để merge.
    //
    // TRADE-OFF: Partial forward bị disable → sb store phải drain trước khi
    //   load cùng word addr hoàn thành. Tăng latency ~vài cycle nhưng đúng.
    //   Full partial merge cần đọc cache + merge = thay đổi kiến trúc lớn.
    // =========================================================================
    integer fi;
    always @(req_addr,
             sb_valid[0], sb_valid[1], sb_valid[2], sb_valid[3],
             sb_addr[0],  sb_addr[1],  sb_addr[2],  sb_addr[3],
             sb_wstrb[0], sb_wstrb[1], sb_wstrb[2], sb_wstrb[3],
             sb_wdata[0], sb_wdata[1], sb_wdata[2], sb_wdata[3]) begin
        fwd_hit_r  = 1'b0;
        fwd_data_r = 32'h0;
        fwd_strb_r = 4'b0000;
        for (fi = 0; fi < SB_DEPTH; fi = fi + 1) begin
            if (sb_valid[fi] && (sb_addr[fi][31:2] == req_addr[31:2])) begin
                fwd_hit_r = 1'b1;
                // Merge từng byte: entry mới (index cao) ghi đè entry cũ
                if (sb_wstrb[fi][0]) begin fwd_data_r[7:0]   = sb_wdata[fi][7:0];   fwd_strb_r[0] = 1'b1; end
                if (sb_wstrb[fi][1]) begin fwd_data_r[15:8]  = sb_wdata[fi][15:8];  fwd_strb_r[1] = 1'b1; end
                if (sb_wstrb[fi][2]) begin fwd_data_r[23:16] = sb_wdata[fi][23:16]; fwd_strb_r[2] = 1'b1; end
                if (sb_wstrb[fi][3]) begin fwd_data_r[31:24] = sb_wdata[fi][31:24]; fwd_strb_r[3] = 1'b1; end
            end
        end
    end
    // [FIX-FWD] Chỉ forward khi toàn bộ 4 byte lanes đều có trong store buffer.
    // Partial match → fwd_hit=0 → load đợi store drain, rồi đọc cache (đúng data).
    assign fwd_hit  = fwd_hit_r && (fwd_strb_r == 4'b1111);
    assign fwd_data = fwd_data_r;

    wire do_store = req_valid && req_ready && !req_is_load;
    wire do_load  = req_valid && req_ready &&  req_is_load;

    localparam [1:0]
        LOAD_IDLE   = 2'b00,
        LOAD_DCACHE = 2'b01,
        LOAD_RESULT = 2'b10;

    localparam
        DRAIN_IDLE = 1'b0,
        DRAIN_REQ  = 1'b1;

    reg [1:0] load_state;
    reg       drain_state;

    wire load_using_dcache = (load_state == LOAD_DCACHE);

    reg [31:0] cur_load_addr;
    reg [4:0]  cur_load_rd;
    reg [2:0]  cur_load_funct3;

    wire load_fsm_ready    = (load_state == LOAD_IDLE) && !result_valid;
    // [FIX-LSU-CONFLICT] Forwarded loads dequeue freely; non-forwarded loads
    // must wait for SB to drain so store-drain and dcache-load don't share
    // dcache_ready in the same cycle (caused duplicate NC_WRITE on UART TX).
    wire do_load_dequeue   = !lq_empty && load_fsm_ready && !fence
                          && (lq_fwd[lq_rd_ptr] || sb_empty);

    wire do_drain_pop = (drain_state == DRAIN_REQ)
                      && dcache_ready
                      && !load_using_dcache;

    function [31:0] apply_funct3;
        input [31:0] raw;
        input [2:0]  f3;
        case (f3)
            3'b000:  apply_funct3 = {{24{raw[7]}},  raw[7:0]};
            3'b001:  apply_funct3 = {{16{raw[15]}}, raw[15:0]};
            3'b010:  apply_funct3 = raw;
            3'b100:  apply_funct3 = {24'h0, raw[7:0]};
            3'b101:  apply_funct3 = {16'h0, raw[15:0]};
            default: apply_funct3 = raw;
        endcase
    endfunction

    integer si;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sb_wr_ptr      <= 0;
            sb_rd_ptr      <= 0;
            sb_count       <= 0;
            lq_wr_ptr      <= 0;
            lq_rd_ptr      <= 0;
            lq_count       <= 0;
            scoreboard_reg <= 32'h0;
            cur_load_addr   <= 32'h0;
            cur_load_rd     <= 5'h0;
            cur_load_funct3 <= 3'h0;
            for (si = 0; si < SB_DEPTH; si = si + 1)
                sb_valid[si] <= 1'b0;
        end else begin
            if (do_store) begin
                sb_addr  [sb_wr_ptr] <= req_addr;
                sb_wdata [sb_wr_ptr] <= req_wdata;
                sb_wstrb [sb_wr_ptr] <= req_wstrb;
                sb_valid [sb_wr_ptr] <= 1'b1;
                sb_wr_ptr <= sb_wr_ptr + 1'b1;
            end

            if (do_drain_pop) begin
                sb_valid[sb_rd_ptr] <= 1'b0;
                sb_rd_ptr <= sb_rd_ptr + 1'b1;
            end

            case ({do_store, do_drain_pop})
                2'b10:   sb_count <= sb_count + 1'b1;
                2'b01:   sb_count <= sb_count - 1'b1;
                default: ;
            endcase

            if (do_load) begin
                lq_addr    [lq_wr_ptr] <= req_addr;
                lq_rd      [lq_wr_ptr] <= req_rd;
                lq_funct3  [lq_wr_ptr] <= req_funct3;
                lq_fwd     [lq_wr_ptr] <= fwd_hit;
                lq_fwd_data[lq_wr_ptr] <= fwd_hit ? fwd_data : 32'h0;
                lq_wr_ptr  <= lq_wr_ptr + 1'b1;
                if (req_rd != 5'b0)
                    scoreboard_reg[req_rd] <= 1'b1;
            end

            if (do_load_dequeue) begin
                cur_load_addr   <= lq_addr  [lq_rd_ptr];
                cur_load_rd     <= lq_rd    [lq_rd_ptr];
                cur_load_funct3 <= lq_funct3[lq_rd_ptr];
                lq_rd_ptr <= lq_rd_ptr + 1'b1;
            end

            case ({do_load, do_load_dequeue})
                2'b10:   lq_count <= lq_count + 1'b1;
                2'b01:   lq_count <= lq_count - 1'b1;
                default: ;
            endcase

            if (result_valid && result_ack) begin
                if (result_rd != 5'b0)
                    scoreboard_reg[result_rd] <= 1'b0;
            end
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            load_state   <= LOAD_IDLE;
            result_valid <= 1'b0;
            result_data  <= 32'h0;
            result_rd    <= 5'h0;
        end else begin
            case (load_state)
                LOAD_IDLE: begin
                    if (do_load_dequeue) begin
                        if (lq_fwd[lq_rd_ptr]) begin
                            result_valid <= 1'b1;
                            result_rd    <= lq_rd[lq_rd_ptr];
                            result_data  <= apply_funct3(
                                               lq_fwd_data[lq_rd_ptr],
                                               lq_funct3  [lq_rd_ptr]);
                            load_state   <= LOAD_RESULT;
                        end else begin
                            load_state <= LOAD_DCACHE;
                        end
                    end
                end

                LOAD_DCACHE: begin
                    if (dcache_ready) begin
                        result_valid <= 1'b1;
                        result_rd    <= cur_load_rd;
                        result_data  <= apply_funct3(dcache_rdata, cur_load_funct3);
                        load_state   <= LOAD_RESULT;
                    end
                end

                LOAD_RESULT: begin
                    if (result_ack) begin
                        result_valid <= 1'b0;
                        load_state   <= LOAD_IDLE;
                    end
                end

                default: load_state <= LOAD_IDLE;
            endcase
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            drain_state <= DRAIN_IDLE;
        end else begin
            case (drain_state)
                DRAIN_IDLE: begin
                    if (!sb_empty && !load_using_dcache)
                        drain_state <= DRAIN_REQ;
                end

                DRAIN_REQ: begin
                    if (load_using_dcache) begin
                        drain_state <= DRAIN_IDLE;
                    end else if (dcache_ready) begin
                        drain_state <= DRAIN_IDLE;
                    end
                end

                default: drain_state <= DRAIN_IDLE;
            endcase
        end
    end

    wire [31:0] drain_addr  = sb_addr [sb_rd_ptr];
    wire [31:0] drain_wdata = sb_wdata[sb_rd_ptr];
    wire [3:0]  drain_wstrb = sb_wstrb[sb_rd_ptr];

    always @(*) begin
        dcache_req   = 1'b0;
        dcache_we    = 1'b0;
        dcache_addr  = 32'h0;
        dcache_wdata = 32'h0;
        dcache_wstrb = 4'h0;

        if (load_using_dcache) begin
            dcache_req  = 1'b1;
            dcache_we   = 1'b0;
            dcache_addr = cur_load_addr;
        end else if (drain_state == DRAIN_REQ) begin
            dcache_req   = 1'b1;
            dcache_we    = 1'b1;
            dcache_addr  = drain_addr;
            dcache_wdata = drain_wdata;
            dcache_wstrb = drain_wstrb;
        end
    end

endmodule
module riscv_cpu_core (
    input wire clk,
    input wire rst,


    output wire [31:0] imem_addr,
    output wire        imem_valid,
    input  wire [31:0] imem_rdata,
    input  wire        imem_ready,

    output wire [31:0] dcache_addr,
    output wire [31:0] dcache_wdata,
    output wire [3:0]  dcache_wstrb,
    output wire        dcache_req,
    output wire        dcache_we,
    input  wire [31:0] dcache_rdata,
    input  wire        dcache_ready,
    output wire [1:0]  dcache_fence_type,

    input  wire external_irq,
    input  wire timer_irq,
    input  wire sw_irq,

    // =========================================================================
    // JTAG Debug Interface  (kết nối với jtag_debug_top → riscv_dm)
    //
    // WHY cần 4 tín hiệu này:
    //   haltreq   : JTAG DM yêu cầu CPU dừng để debugger đọc/ghi registers.
    //               CPU phải drain pipeline và LSU store buffer trước khi báo halted.
    //   resumereq : DM yêu cầu CPU tiếp tục chạy bình thường.
    //   halted    : CPU báo cho DM biết đã vào D-mode (pipeline đóng băng hoàn toàn).
    //               DM chỉ được phép truy cập register file khi halted=1.
    //   running   : CPU báo đang chạy bình thường (halted=0 chưa đủ vì còn HALTING).
    //
    // WHY KHÔNG dùng rst để halt:
    //   rst xóa toàn bộ trạng thái CPU (PC, registers) → không thể resume.
    //   Debug mode chỉ đóng băng, không xóa — debugger có thể đọc PC, regs,
    //   rồi set breakpoint và resume từ đúng chỗ đã dừng.
    //
    // Kết nối trong soc_top.v:
    //   .debug_haltreq   (jtag_haltreq),    // từ u_jtag.haltreq
    //   .debug_resumereq (jtag_resumereq),   // từ u_jtag.resumereq
    //   .debug_halted    (jtag_halted),      // → u_jtag.halted
    //   .debug_running   (jtag_running)      // → u_jtag.running
    // =========================================================================
    input  wire debug_haltreq,    // DM → CPU: yêu cầu vào D-mode
    input  wire debug_resumereq,  // DM → CPU: yêu cầu thoát D-mode
    output wire debug_halted,     // CPU → DM: đang trong D-mode, pipeline frozen
    output wire debug_running,    // CPU → DM: đang chạy bình thường
    output wire cpu_wfi_o,        // CPU → SoC: đang chờ interrupt
    output wire perf_stall_o,     // CPU → SoC: pipeline stalled (stall_any)
    output wire perf_instr_ret_o  // CPU → SoC: instruction retired (regwrite_wb approx)
);

    localparam [6:0]
        OP_R_TYPE = 7'b0110011,
        OP_I_TYPE = 7'b0010011,
        OP_LOAD   = 7'b0000011,
        OP_STORE  = 7'b0100011,
        OP_BRANCH = 7'b1100011,
        OP_JALR   = 7'b1100111;

    // =========================================================================
    // IRQ aggregation — 2-FF CDC synchronizer chain
    // Prevents metastability when IRQ lines come from a different clock domain.
    // Adds 2-cycle latency to IRQ recognition (acceptable for interrupt handling).
    // =========================================================================
    reg ext_irq_s1, ext_irq_s2;
    reg tmr_irq_s1, tmr_irq_s2;
    reg sw_irq_s1,  sw_irq_s2;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            ext_irq_s1 <= 1'b0; ext_irq_s2 <= 1'b0;
            tmr_irq_s1 <= 1'b0; tmr_irq_s2 <= 1'b0;
            sw_irq_s1  <= 1'b0; sw_irq_s2  <= 1'b0;
        end else begin
            ext_irq_s1 <= external_irq; ext_irq_s2 <= ext_irq_s1;
            tmr_irq_s1 <= timer_irq;    tmr_irq_s2 <= tmr_irq_s1;
            sw_irq_s1  <= sw_irq;       sw_irq_s2  <= sw_irq_s1;
        end
    end

    wire irq_pending = ext_irq_s2 | tmr_irq_s2 | sw_irq_s2;

    reg irq_pending_lat;
    reg [1:0] irq_flush_cnt_r;
    always @(posedge clk or posedge rst) begin
        if (rst)
            irq_pending_lat <= 1'b0;
        else if (irq_flush_done)
            irq_pending_lat <= 1'b0;
        else if (irq_pending)
            irq_pending_lat <= 1'b1;
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            irq_flush_cnt_r <= 2'b00;
        end else if ((irq_flush_cnt_r == 2'b00) && irq_pending_lat) begin
            irq_flush_cnt_r <= 2'b11;
        end else if (irq_flush_cnt_r != 2'b00) begin
            irq_flush_cnt_r <= {1'b0, irq_flush_cnt_r[1]};
        end
    end
    wire irq_flush_done = (irq_flush_cnt_r == 2'b01);
    wire irq_flush = (irq_flush_cnt_r != 2'b00);

    // =========================================================================
    // DEBUG MODE FSM
    //
    // 2-FF CDC synchronizers for debug_haltreq / debug_resumereq coming from
    // the JTAG clock domain. Without synchronization, metastability in the FSM
    // can cause undefined state transitions.
    reg dbg_halt_s1,   dbg_halt_s2;
    reg dbg_resume_s1, dbg_resume_s2;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dbg_halt_s1   <= 1'b0; dbg_halt_s2   <= 1'b0;
            dbg_resume_s1 <= 1'b0; dbg_resume_s2 <= 1'b0;
        end else begin
            dbg_halt_s1   <= debug_haltreq;   dbg_halt_s2   <= dbg_halt_s1;
            dbg_resume_s1 <= debug_resumereq; dbg_resume_s2 <= dbg_resume_s1;
        end
    end

    // 3 trạng thái:
    //   DBG_RUNNING : CPU chạy bình thường
    //   DBG_HALTING : CPU nhận haltreq, đang chờ pipeline + LSU drain
    //   DBG_HALTED  : Pipeline đóng băng hoàn toàn, DM có thể đọc/ghi regs
    //
    // Điều kiện chuyển RUNNING → HALTING:
    //   debug_haltreq=1 AND lsu_sb_empty=1 AND dc_req=0
    //   WHY: Không halt giữa chừng khi LSU đang có in-flight transaction
    //   trên AXI bus — DMA của ASCON hoặc DCache evict có thể đang dùng
    //   bus → cắt ngang gây DECERR hoặc data corruption trên DMEM.
    //
    // Điều kiện chuyển HALTING → HALTED:
    //   Sau 1 cycle delay để pipeline stages drain (NOP propagate qua EX→MEM→WB).
    //   WHY 1 cycle đủ: HALTING đã đảm bảo LSU idle, pipeline stall = 1
    //   nên không có instruction mới vào. 1 cycle cho phép stall_any propagate.
    //
    // Điều kiện chuyển HALTED → RUNNING:
    //   debug_resumereq=1 (pulse từ DM sau khi debugger ghi xong)
    //
    // debug_mode=1 khi DBG_HALTED: inject vào stall_any để freeze pipeline
    // =========================================================================
    localparam DBG_RUNNING = 2'b00;
    localparam DBG_HALTING = 2'b01;
    localparam DBG_HALTED  = 2'b10;

    reg [1:0] dbg_state;
    reg       debug_mode;   // 1 khi đang trong D-mode

    // WHY cần lsu_sb_empty và dc_req từ bên ngoài FSM:
    //   lsu_sb_empty: Store Buffer rỗng → không còn pending write nào trên bus
    //   dc_req: DCache không có request đang chờ DCache ready
    //   Cả hai phải đồng thời thỏa trước khi halt an toàn.
    wire lsu_sb_empty_w = soc_lsu_sb_empty;   // wire từ LSU (xem bên dưới)

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dbg_state  <= DBG_RUNNING;
            debug_mode <= 1'b0;
        end else begin
            case (dbg_state)
                DBG_RUNNING: begin
                    // Chờ bus idle trước khi bước vào HALTING
                    if (dbg_halt_s2 && lsu_sb_empty_w && !dcache_req) begin
                        dbg_state <= DBG_HALTING;
                    end
                end
                DBG_HALTING: begin
                    // 1-cycle drain: stall đã được assert từ cycle trước
                    // (debug_mode chưa set nhưng haltreq làm flush_id_ex_final đúng)
                    // Sang HALTED và bật debug_mode để freeze pipeline hoàn toàn
                    dbg_state  <= DBG_HALTED;
                    debug_mode <= 1'b1;
                end
                DBG_HALTED: begin
                    // WHY check !dbg_halt_s2: DM có thể giữ haltreq=1 nhiều
                    // cycle. Chỉ resume khi resumereq pulse xuất hiện.
                    if (dbg_resume_s2) begin
                        dbg_state  <= DBG_RUNNING;
                        debug_mode <= 1'b0;
                    end
                end
                default: begin
                    dbg_state  <= DBG_RUNNING;
                    debug_mode <= 1'b0;
                end
            endcase
        end
    end

    // Output signals cho jtag_debug_top
    assign debug_halted  = (dbg_state == DBG_HALTED);
    assign debug_running = (dbg_state == DBG_RUNNING);

    reg cpu_wfi_r;

    // =========================================================================
    // Pipeline stage wires
    // =========================================================================
    wire [31:0] pc_if;
    wire [31:0] instr_if;
    wire [31:0] pc_id;
    wire [31:0] instr_id;

    wire [6:0] opcode_id = instr_id[6:0];
    wire [4:0] rd_id     = instr_id[11:7];
    wire [2:0] funct3_id = instr_id[14:12];
    wire [4:0] rs1_id    = instr_id[19:15];
    wire [4:0] rs2_id    = instr_id[24:20];
    wire [6:0] funct7_id = instr_id[31:25];

    wire [3:0] alu_control_id;
    wire regwrite_id, alusrc_id, memread_id, memwrite_id;
    wire branch_id, jump_id, fence_id;
    wire [1:0] byte_size_id;
    wire rs1_used_id;
    wire rs2_used_id;

    // =========================================================================
    // [FENCE-TYPE] Decode pred/succ bits từ FENCE instruction
    // =========================================================================
    wire fence_pred_w    = instr_id[24];  // W — memory write
    wire fence_pred_r    = instr_id[25];  // R — memory read
    wire fence_pred_i    = instr_id[27];  // I — input device
    wire       fence_is_fencei = funct3_id[0];

    wire fence_active = fence_id && !fence_stall;
    assign dcache_fence_type[0] = fence_active && (fence_is_fencei | fence_pred_w | fence_pred_i);
    assign dcache_fence_type[1] = fence_active && (fence_is_fencei | fence_pred_r | fence_pred_i);

    wire [31:0] read_data1_id, read_data2_id, imm_id;

    // Decode true source usage early so hazard detection does not treat
    // immediate bits as rs2 dependencies on I-type instructions.
    assign rs1_used_id = (opcode_id == OP_R_TYPE) ||
                         (opcode_id == OP_I_TYPE) ||
                         (opcode_id == OP_LOAD)   ||
                         (opcode_id == OP_STORE)  ||
                         (opcode_id == OP_BRANCH) ||
                         (opcode_id == OP_JALR);

    assign rs2_used_id = (opcode_id == OP_R_TYPE) ||
                         (opcode_id == OP_STORE)  ||
                         (opcode_id == OP_BRANCH);

    wire regwrite_ex, alusrc_ex, memread_ex, memwrite_ex;
    wire branch_ex, jump_ex;
    wire [31:0] read_data1_ex, read_data2_ex, imm_ex, pc_ex;
    wire [4:0]  rs1_ex, rs2_ex, rd_ex;
    wire [2:0]  funct3_ex;
    wire [3:0]  alu_control_ex;
    wire [1:0]  byte_size_ex;
    wire [6:0]  opcode_ex;

    wire [31:0] alu_in1, alu_in2, alu_in2_pre_mux, alu_in1_forwarded;
    wire [31:0] alu_result_ex;
    wire zero_flag_ex, less_than_ex, less_than_u_ex;
    wire branch_taken_ex;
    wire [31:0] target_pc_ex;
    wire [31:0] branch_target_ex;
    wire pc_src_ex;
    wire [31:0] pc_plus_4_ex;

    wire regwrite_mem, memread_mem, memwrite_mem;
    wire [31:0] alu_result_mem, write_data_mem, pc_plus_4_mem;
    wire [4:0]  rd_mem;
    wire [1:0]  byte_size_mem;
    wire [2:0]  funct3_mem;
    wire jump_mem;

    wire        lsu_req_valid, lsu_req_ready;
    wire [3:0]  lsu_req_wstrb;
    wire        lsu_result_valid;
    wire [31:0] lsu_result_data;
    wire [4:0]  lsu_result_rd;
    wire        lsu_result_ack;
    wire [31:0] lsu_scoreboard;
    wire        lsu_idle;

    wire regwrite_wb, memtoreg_wb, jump_wb;
    wire [31:0] alu_result_wb, mem_data_wb, pc_plus_4_wb;
    wire [4:0]  rd_wb;
    wire [31:0] write_back_data_wb;

    // MUL pipeline tracking
    wire        is_mul_mem, is_mul_wb;
    wire [31:0] mul_result_direct;  // writeback_value_o from multiplier (2-cycle delay)

    wire [1:0] forward_a, forward_b;
    wire stall, stall_if, stall_any;
    wire fence_stall;
    wire lsu_dep_stall;
    wire mul_ex_stall_wire;
    wire flush_if_id, flush_id_ex;

    // stall_any includes debug_mode and WFI idle state to freeze the pipeline.
    assign stall_any = stall | stall_if | debug_mode | cpu_wfi_r;

    localparam [6:0] OP_SYSTEM = 7'b1110011;
    wire is_wfi_id = (opcode_id == OP_SYSTEM) &&
                     (funct3_id == 3'b000) &&
                     (rs1_id == 5'b00000) &&
                     (rd_id == 5'b00000) &&
                     (instr_id[31:20] == 12'h105);
    wire wfi_wake = irq_pending | irq_pending_lat | dbg_halt_s2 | debug_mode;
    wire wfi_enter = is_wfi_id && !cpu_wfi_r && !wfi_wake && !stall_any;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            cpu_wfi_r <= 1'b0;
        end else if (wfi_wake) begin
            cpu_wfi_r <= 1'b0;
        end else if (wfi_enter) begin
            cpu_wfi_r <= 1'b1;
        end
    end

    assign cpu_wfi_o        = cpu_wfi_r;
assign perf_stall_o     = stall_any;
assign perf_instr_ret_o = regwrite_wb && !stall_any;

    // 2-bit BHT predictor: 256 entries, indexed by PC[9:2].
    wire predict_taken_ex;
    wire predict_taken_id;
    wire mispredict_ex;
    reg [1:0] bht_r [0:255];
    integer bht_i;
    wire [7:0] bht_idx_id = pc_id[9:2];
    wire [7:0] bht_idx_ex = pc_ex[9:2];
    wire [1:0] bht_state_id = bht_r[bht_idx_id];
    wire bht_taken_id = bht_state_id[1];

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            for (bht_i = 0; bht_i < 256; bht_i = bht_i + 1)
                bht_r[bht_i] <= 2'b01;
        end else if (branch_ex) begin
            case ({branch_taken_ex, bht_r[bht_idx_ex]})
                3'b0_00: bht_r[bht_idx_ex] <= 2'b00;
                3'b0_01: bht_r[bht_idx_ex] <= 2'b00;
                3'b0_10: bht_r[bht_idx_ex] <= 2'b01;
                3'b0_11: bht_r[bht_idx_ex] <= 2'b10;
                3'b1_00: bht_r[bht_idx_ex] <= 2'b01;
                3'b1_01: bht_r[bht_idx_ex] <= 2'b10;
                3'b1_10: bht_r[bht_idx_ex] <= 2'b11;
                3'b1_11: bht_r[bht_idx_ex] <= 2'b11;
                default: bht_r[bht_idx_ex] <= 2'b01;
            endcase
        end
    end

    // Guard with !stall_any to prevent re-predicting the same stalled branch.
    assign predict_taken_id = branch_id && bht_taken_id && !stall_any;
    assign mispredict_ex    = predict_taken_ex && !branch_taken_ex && branch_ex;

    // IFU redirect priority: mispredict recovery > actual branch/jump > WFI consume > prediction
    wire [31:0] wfi_resume_pc = pc_id + 32'd4;
    wire        ifu_pc_src    = mispredict_ex || pc_src_ex || wfi_enter || predict_taken_id;
    wire [31:0] ifu_target_pc = mispredict_ex  ? pc_plus_4_ex  :
                                pc_src_ex      ? target_pc_ex  :
                                wfi_enter      ? wfi_resume_pc :
                                                 branch_target_id;

    // Fix 10C: Multiplier stall — don't freeze multiplier during its own extra cycle
    wire mul_hold = stall_any && !mul_ex_stall_wire;

    // stall_ex_mem: only LSU dependency stall freezes EX/MEM
    // (fence_stall must NOT freeze — pre-fence store must reach MEM)
    wire stall_ex_mem = lsu_dep_stall;

    wire flush_if_id_final = flush_if_id | irq_flush | wfi_enter;
    wire flush_id_ex_final = flush_id_ex | irq_flush | wfi_enter;

    // =========================================================================
    // STAGE 1: IF
    // =========================================================================
    IFU instruction_fetch (
        .clock            (clk),
        .reset            (rst),
        .pc_src           (ifu_pc_src),
        .stall            (stall_any),      // debug_mode → stall_any → IFU dừng fetch
        .target_pc        (ifu_target_pc),
        .imem_addr        (imem_addr),
        .imem_valid       (imem_valid),
        .imem_rdata       (imem_rdata),
        .imem_ready       (imem_ready),
        .PC_out           (pc_if),
        .Instruction_Code (instr_if)
    );

    PIPELINE_REG_IF_ID if_id_reg (
        .clock    (clk),
        .reset    (rst),
        .flush    (flush_if_id_final),
        .stall    (stall_any),
        .instr_in (instr_if),
        .pc_in    (pc_if),
        .instr_out(instr_id),
        .pc_out   (pc_id)
    );

    // =========================================================================
    // STAGE 2: ID
    // =========================================================================
    control control_unit (
        .opcode     (opcode_id),
        .funct3     (funct3_id),
        .funct7     (funct7_id),
        .alu_control(alu_control_id),
        .regwrite   (regwrite_id),
        .alusrc     (alusrc_id),
        .memread    (memread_id),
        .memwrite   (memwrite_id),
        .branch     (branch_id),
        .jump       (jump_id),
        .byte_size  (byte_size_id),
        .fence      (fence_id)
    );

    reg_file register_file (
        .clock        (clk),
        .reset        (rst),
        .read_reg_num1(rs1_id),
        .read_reg_num2(rs2_id),
        .read_data1   (read_data1_id),
        .read_data2   (read_data2_id),
        .regwrite     (regwrite_wb),
        .write_reg    (rd_wb),
        .write_data   (write_back_data_wb)
    );

    imm_gen immediate_generator (
        .instr(instr_id),
        .imm  (imm_id)
    );

    // =========================================================================
    // ID/EX PIPELINE REGISTER (standalone module)
    // =========================================================================
    // Pre-compute branch target in ID stage to remove adder from EX critical path.
    // pc_id and imm_id are both available here; result passes through ID/EX register.
    wire [31:0] branch_target_id = pc_id + imm_id;

    PIPELINE_REG_ID_EX id_ex_reg (
        .clock           (clk),
        .reset           (rst),
        .flush           (flush_id_ex_final),
        .stall           (stall_any),
        // Forwarding capture (FIX-FWD-STALL)
        .fwd_a_sel       (forward_a),
        .fwd_b_sel       (forward_b),
        .fwd_a_data      (alu_in1_forwarded),
        .fwd_b_data      (alu_in2_pre_mux),
        // Control inputs
        .regwrite_in     (regwrite_id),
        .alusrc_in       (alusrc_id),
        .memread_in      (memread_id),
        .memwrite_in     (memwrite_id),
        .branch_in       (branch_id),
        .predict_taken_in(predict_taken_id),
        .jump_in         (jump_id),
        // Data inputs
        .read_data1_in   (read_data1_id),
        .read_data2_in   (read_data2_id),
        .imm_in          (imm_id),
        .pc_in           (pc_id),
        .branch_target_in(branch_target_id),
        // Register addresses
        .rs1_in          (rs1_id),
        .rs2_in          (rs2_id),
        .rd_in           (rd_id),
        // Function codes
        .funct3_in       (funct3_id),
        .alu_control_in  (alu_control_id),
        .byte_size_in    (byte_size_id),
        .opcode_in       (opcode_id),
        // Control outputs
        .regwrite_out    (regwrite_ex),
        .alusrc_out      (alusrc_ex),
        .memread_out     (memread_ex),
        .memwrite_out    (memwrite_ex),
        .branch_out      (branch_ex),
        .predict_taken_out(predict_taken_ex),
        .jump_out        (jump_ex),
        // Data outputs
        .read_data1_out  (read_data1_ex),
        .read_data2_out  (read_data2_ex),
        .imm_out         (imm_ex),
        .pc_out          (pc_ex),
        .branch_target_out(branch_target_ex),
        // Register address outputs
        .rs1_out         (rs1_ex),
        .rs2_out         (rs2_ex),
        .rd_out          (rd_ex),
        // Function code outputs
        .funct3_out      (funct3_ex),
        .alu_control_out (alu_control_ex),
        .byte_size_out   (byte_size_ex),
        .opcode_out      (opcode_ex)
    );

    // =========================================================================
    // STAGE 3: EX
    // =========================================================================
    forwarding_unit fwd_unit (
        .rs1_ex      (rs1_ex),       .rs2_ex      (rs2_ex),
        .rd_mem      (rd_mem),       .rd_wb       (rd_wb),
        .regwrite_mem(regwrite_mem), .regwrite_wb (regwrite_wb),
        .forward_a   (forward_a),    .forward_b   (forward_b)
    );

    // Flat AND-OR mux: expand WB source inline to eliminate cascaded mux levels.
    // OLD: alu_in1_forwarded (3-way) → alu_in1 (3-way) = 4 extra gate levels on critical path.
    // NEW: single 8-way OR of AND terms, all selectors mutually exclusive.
    wire fwd_a_mem  = (forward_a == 2'b10);
    wire fwd_a_wb   = (forward_a == 2'b01);
    wire fwd_a_none = (forward_a == 2'b00);
    wire fwd_b_mem  = (forward_b == 2'b10);
    wire fwd_b_wb   = (forward_b == 2'b01);
    wire fwd_b_none = (forward_b == 2'b00);

    // Kept for multiplier operands, store data, and ID/EX forwarding-capture port
    assign alu_in1_forwarded = ({32{fwd_a_mem}}  & alu_result_mem)    |
                               ({32{fwd_a_wb}}   & write_back_data_wb) |
                               ({32{fwd_a_none}} & read_data1_ex);
    assign alu_in2_pre_mux   = ({32{fwd_b_mem}}  & alu_result_mem)    |
                               ({32{fwd_b_wb}}   & write_back_data_wb) |
                               ({32{fwd_b_none}} & read_data2_ex);

    wire is_lui_ex      = (opcode_ex == 7'b0110111);
    wire is_auipc_ex    = (opcode_ex == 7'b0010111);
    wire not_lui_auipc  = !is_lui_ex && !is_auipc_ex;

    // WB source selectors (shared between alu_in1 and alu_in2 paths)
    wire wb_sel_jump = jump_wb;
    wire wb_sel_mul  = is_mul_wb;
    wire wb_sel_load = memtoreg_wb;
    wire wb_sel_alu  = !jump_wb && !is_mul_wb && !memtoreg_wb;

    // alu_in1: 8 mutually exclusive cases (LUI / AUIPC / MEM-fwd / WB×4 / RF)
    wire alu1_lui      = is_lui_ex;
    wire alu1_auipc    = is_auipc_ex;
    wire alu1_fwdmem   = not_lui_auipc && fwd_a_mem;
    wire alu1_wb_jump  = not_lui_auipc && fwd_a_wb && wb_sel_jump;
    wire alu1_wb_mul   = not_lui_auipc && fwd_a_wb && wb_sel_mul;
    wire alu1_wb_load  = not_lui_auipc && fwd_a_wb && wb_sel_load;
    wire alu1_wb_alu   = not_lui_auipc && fwd_a_wb && wb_sel_alu;
    wire alu1_rf       = not_lui_auipc && !fwd_a_mem && !fwd_a_wb;

    assign alu_in1 = ({32{alu1_lui}}     & 32'h0)            |
                     ({32{alu1_auipc}}   & pc_ex)             |
                     ({32{alu1_fwdmem}}  & alu_result_mem)    |
                     ({32{alu1_wb_jump}} & pc_plus_4_wb)      |
                     ({32{alu1_wb_mul}}  & mul_result_direct) |
                     ({32{alu1_wb_load}} & mem_data_wb)       |
                     ({32{alu1_wb_alu}}  & alu_result_wb)     |
                     ({32{alu1_rf}}      & read_data1_ex);

    // alu_in2: 7 mutually exclusive cases (IMM / MEM-fwd / WB×4 / RF)
    wire alu2_imm      = alusrc_ex;
    wire alu2_fwdmem   = !alusrc_ex && fwd_b_mem;
    wire alu2_wb_jump  = !alusrc_ex && fwd_b_wb && wb_sel_jump;
    wire alu2_wb_mul   = !alusrc_ex && fwd_b_wb && wb_sel_mul;
    wire alu2_wb_load  = !alusrc_ex && fwd_b_wb && wb_sel_load;
    wire alu2_wb_alu   = !alusrc_ex && fwd_b_wb && wb_sel_alu;
    wire alu2_rf       = !alusrc_ex && !fwd_b_mem && !fwd_b_wb;

    assign alu_in2 = ({32{alu2_imm}}     & imm_ex)            |
                     ({32{alu2_fwdmem}}  & alu_result_mem)    |
                     ({32{alu2_wb_jump}} & pc_plus_4_wb)      |
                     ({32{alu2_wb_mul}}  & mul_result_direct) |
                     ({32{alu2_wb_load}} & mem_data_wb)       |
                     ({32{alu2_wb_alu}}  & alu_result_wb)     |
                     ({32{alu2_rf}}      & read_data2_ex);

    alu arithmetic_logic_unit (
        .in1        (alu_in1),     .in2        (alu_in2),
        .alu_control(alu_control_ex),
        .alu_result (alu_result_ex),
        .zero_flag  (zero_flag_ex),
        .less_than  (less_than_ex), .less_than_u(less_than_u_ex)
    );

    branch_logic branch_unit (
        .branch     (branch_ex),    .funct3     (funct3_ex),
        .zero_flag  (zero_flag_ex), .less_than  (less_than_ex),
        .less_than_u(less_than_u_ex), .taken    (branch_taken_ex)
    );

    // =========================================================================
    // 2-stage Pipelined Multiplier (tách khỏi ALU critical path)
    // =========================================================================
    // is_mul_ex: MUL/MULH instruction at EX stage
    // mul_op_ex: 00=MUL, 01=MULH (signed×signed high)
    // mul_valid_ex: dispatch pulse — high for 1 cycle when MUL enters EX
    localparam [3:0] ALU_MUL_CODE  = 4'b1010;
    localparam [3:0] ALU_MULH_CODE = 4'b1011;

    wire        is_mul_ex  = (alu_control_ex == ALU_MUL_CODE) | (alu_control_ex == ALU_MULH_CODE);
    wire [1:0]  mul_op_ex  = (alu_control_ex == ALU_MULH_CODE) ? 2'b01 : 2'b00;
    // mul_valid_ex uses mul_hold (not stall_any) so E1 fires on cycle N even
    // though mul_ex_stall=1 makes stall_any=1 on that cycle.
    wire        mul_valid_ex = is_mul_ex & !mul_hold & !flush_id_ex_final;

    riscv_multiplier multiplier_unit (
        .clk_i            (clk),
        .rst_i            (rst),
        .mul_valid_i      (mul_valid_ex),
        .mul_op_i         (mul_op_ex),
        .operand_a_i      (alu_in1_forwarded),  // forwarded rs1 (pre-LUI/AUIPC mux)
        .operand_b_i      (alu_in2_pre_mux),    // forwarded rs2 (pre-alusrc mux)
        .hold_i           (mul_hold),
        .mul_hold_e15_i   (mul_hold),
        .writeback_value_o(mul_result_direct)   // valid at WB stage (3 cycles after EX)
    );

    assign pc_plus_4_ex = pc_ex + 32'd4;

    wire [31:0] jalr_target;
    assign jalr_target  = (alu_in1 + imm_ex) & 32'hFFFFFFFE;
    // branch_target_ex = pc_id + imm_id, pre-computed in ID stage to remove
    // this adder from the EX stage critical path.
    assign target_pc_ex = (opcode_ex == 7'b1100111) ? jalr_target : branch_target_ex;
    assign pc_src_ex    = (branch_ex & branch_taken_ex) | jump_ex;

    // =========================================================================
    // EX/MEM PIPELINE REGISTER (standalone module)
    // =========================================================================
    PIPELINE_REG_EX_MEM ex_mem_reg (
        .clock          (clk),
        .reset          (rst),
        .stall_ex_mem   (stall_ex_mem),
        .stall_any      (stall_any),
        .fence_stall    (fence_stall),
        // Control inputs
        .regwrite_in    (regwrite_ex),
        .memread_in     (memread_ex),
        .memwrite_in    (memwrite_ex),
        .jump_in        (jump_ex),
        // Data inputs
        .alu_result_in  (alu_result_ex),
        .write_data_in  (alu_in2_pre_mux),
        .pc_plus_4_in   (pc_plus_4_ex),
        .rd_in          (rd_ex),
        .byte_size_in   (byte_size_ex),
        .funct3_in      (funct3_ex),
        .is_mul_in      (is_mul_ex),
        // Control outputs
        .regwrite_out   (regwrite_mem),
        .memread_out    (memread_mem),
        .memwrite_out   (memwrite_mem),
        .jump_out       (jump_mem),
        // Data outputs
        .alu_result_out (alu_result_mem),
        .write_data_out (write_data_mem),
        .pc_plus_4_out  (pc_plus_4_mem),
        .rd_out         (rd_mem),
        .byte_size_out  (byte_size_mem),
        .funct3_out     (funct3_mem),
        .is_mul_out     (is_mul_mem)
    );

    // =========================================================================
    // STAGE 4: MEM — via LSU
    // =========================================================================
    // [FIX-BYTELANE] Store byte strobe
    reg [3:0] wstrb_comb;
    always @(*) begin
        case (byte_size_mem)
            2'b00:   wstrb_comb = 4'b0001 << alu_result_mem[1:0];
            2'b01:   wstrb_comb = 4'b0011 << {alu_result_mem[1], 1'b0};
            2'b10:   wstrb_comb = 4'b1111;
            default: wstrb_comb = 4'b0000;
        endcase
    end
    assign lsu_req_wstrb = wstrb_comb;

    // [FIX-BYTELANE] Store data shift
    reg [31:0] wdata_shifted;
    always @(*) begin
        case (byte_size_mem)
            2'b00:   wdata_shifted = {24'b0, write_data_mem[7:0]} << (alu_result_mem[1:0] * 8);
            2'b01:   wdata_shifted = {16'b0, write_data_mem[15:0]} << (alu_result_mem[1] ? 16 : 0);
            2'b10:   wdata_shifted = write_data_mem;
            default: wdata_shifted = write_data_mem;
        endcase
    end

    // [FIX-DOUBLE-ISSUE] Track which MEM-stage request has already been
    // accepted by LSU. Signature includes PC+4 so consecutive identical
    // loads/stores still issue independently.
    reg        lsu_req_sent;
    reg [74:0] lsu_req_sig_r;
    wire       lsu_req_valid_raw = memread_mem | memwrite_mem;
    wire [74:0] lsu_req_sig = {memread_mem, memwrite_mem, rd_mem, lsu_req_wstrb, alu_result_mem, pc_plus_4_mem};
    wire       lsu_req_new  = (lsu_req_sig != lsu_req_sig_r);
    wire       lsu_req_fire;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            lsu_req_sent  <= 1'b0;
            lsu_req_sig_r <= 75'b0;
        end else begin
            if (lsu_req_fire) begin
                lsu_req_sent  <= 1'b1;
                lsu_req_sig_r <= lsu_req_sig;
            end else if (!lsu_req_valid_raw) begin
                lsu_req_sent <= 1'b0;
            end else if (lsu_req_new) begin
                lsu_req_sent  <= 1'b0;
                lsu_req_sig_r <= lsu_req_sig;
            end
        end
    end
    assign lsu_req_valid = lsu_req_valid_raw & (!lsu_req_sent || lsu_req_new);
    assign lsu_req_fire  = lsu_req_valid && lsu_req_ready;

    wire soc_lsu_sb_empty;

    LSU lsu_unit (
        .clk         (clk),           .rst         (rst),
        .req_valid   (lsu_req_valid),  .req_ready   (lsu_req_ready),
        .req_addr    (alu_result_mem), .req_wdata   (wdata_shifted),
        .req_wstrb   (lsu_req_wstrb),  .req_is_load (memread_mem),
        .req_rd      (rd_mem),         .req_funct3  (funct3_mem),
        // fence reaches LSU only after hazard logic has observed quiescent LSU.
        // This keeps FENCE from blocking pre-existing load/store drain activity.
        .fence       (|dcache_fence_type),
        .result_valid(lsu_result_valid), .result_data(lsu_result_data),
        .result_rd   (lsu_result_rd),  .result_ack  (lsu_result_ack),
        .scoreboard  (lsu_scoreboard), .lsu_idle    (lsu_idle),
        .dcache_req  (dcache_req),     .dcache_we   (dcache_we),
        .dcache_addr (dcache_addr),    .dcache_wdata(dcache_wdata),
        .dcache_wstrb(dcache_wstrb),   .dcache_rdata(dcache_rdata),
        .dcache_ready(dcache_ready)
    );

    assign soc_lsu_sb_empty = lsu_idle;

    // =========================================================================
    // MEM/WB REGISTER (standalone module)
    // =========================================================================
    reg lsu_committed_r;
    wire wb_passthrough_valid = !stall_ex_mem && !lsu_committed_r && !memread_mem && regwrite_mem;
    wire lsu_result_commit = lsu_result_valid && !wb_passthrough_valid;
    always @(posedge clk or posedge rst) begin
        if (rst)
            lsu_committed_r <= 1'b0;
        else
            lsu_committed_r <= lsu_result_commit;
    end

    // Hold LSU result until MEM/WB is free so loads do not clobber ALU/MUL WB.
    assign lsu_result_ack = lsu_result_commit;

    PIPELINE_REG_MEM_WB mem_wb_reg (
        .clock            (clk),
        .reset            (rst),
        .stall_ex_mem     (stall_ex_mem),
        .lsu_committed    (lsu_committed_r),
        // LSU result path (priority)
        .lsu_result_valid (lsu_result_commit),
        .lsu_result_data  (lsu_result_data),
        .lsu_result_rd    (lsu_result_rd),
        // Normal MEM stage path
        .regwrite_in      (regwrite_mem),
        .memread_in       (memread_mem),
        .jump_in          (jump_mem),
        .alu_result_in    (alu_result_mem),
        .pc_plus_4_in     (pc_plus_4_mem),
        .rd_in            (rd_mem),
        .is_mul_in        (is_mul_mem),
        // Outputs to WB
        .regwrite_out     (regwrite_wb),
        .memtoreg_out     (memtoreg_wb),
        .jump_out         (jump_wb),
        .alu_result_out   (alu_result_wb),
        .mem_data_out     (mem_data_wb),
        .pc_plus_4_out    (pc_plus_4_wb),
        .rd_out           (rd_wb),
        .is_mul_out       (is_mul_wb)
    );

    // =========================================================================
    // STAGE 5: WB
    // =========================================================================
    // AND-OR MUX: 4 cases mutually exclusive (jump/mul/load/alu can't overlap).
    // is_alu_wb is the complement so selectors are exhaustive (Fix 11).
    wire is_alu_wb = !jump_wb && !is_mul_wb && !memtoreg_wb;
    assign write_back_data_wb = ({32{jump_wb}}     & pc_plus_4_wb)     |
                                ({32{is_mul_wb}}   & mul_result_direct) |
                                ({32{memtoreg_wb}} & mem_data_wb)       |
                                ({32{is_alu_wb}}   & alu_result_wb);

    // =========================================================================
    // HAZARD DETECTION UNIT
    // =========================================================================
    hazard_detection hazard_unit (
        .clk            (clk),
        .rst            (rst),
        .memread_id_ex  (memread_ex),
        .rd_id_ex       (rd_ex),
        .rs1_id         (rs1_id),
        .rs2_id         (rs2_id),
        .rs1_used_id    (rs1_used_id),
        .rs2_used_id    (rs2_used_id),
        .branch_taken   (pc_src_ex),
        .imem_ready     (imem_ready),
        .lsu_scoreboard (lsu_scoreboard),
        .mem_stage_pending(lsu_req_valid),
        .memread_mem_stage(memread_mem),
        .rd_mem_stage   (rd_mem),
        .fence_id       (fence_id),
        .lsu_idle       (lsu_idle),
        .mul_in_ex      (is_mul_ex),
        .predict_taken_ex(predict_taken_ex),
        .predict_taken_id(predict_taken_id),
        .mispredict_ex  (mispredict_ex),
        .stall          (stall),
        .stall_if       (stall_if),
        .flush_if_id    (flush_if_id),
        .flush_id_ex    (flush_id_ex),
        .fence_stall    (fence_stall),
        .lsu_dep_stall  (lsu_dep_stall),
        .mul_ex_stall   (mul_ex_stall_wire)
    );

endmodule

