// FILE: icache_top.v
// ==============================================================================


// ============================================================================
// icache_top — thêm AXI4 ID signals để kết nối vào axi4_crossbar (M0)
// ============================================================================

// ==============================================================================
// FILE: icache_tag_array.v
// ==============================================================================

// ============================================================================
// icache_tag_array — 32 lines, index 5 bit, tag 22 bit
// ============================================================================
module icache_tag_array (
    input wire clk,
    input wire rst_n,

    input wire [4:0]   lookup_index,
    input wire [21:0]  lookup_tag,
    output wire        hit,

    input wire         update_valid,
    input wire [4:0]   update_index,
    input wire [21:0]  update_tag,

    input wire         flush_all
);
    reg        valid_array [0:31];
    reg [21:0] tag_array   [0:31];

    assign hit = valid_array[lookup_index] &&
                 (tag_array[lookup_index] == lookup_tag);

    integer i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 32; i = i + 1) begin
                valid_array[i] <= 1'b0;
                tag_array[i]   <= 22'h0;
            end
        end else begin
            if (flush_all) begin
                for (i = 0; i < 32; i = i + 1)
                    valid_array[i] <= 1'b0;
            end else if (update_valid) begin
                valid_array[update_index] <= 1'b1;
                tag_array[update_index]   <= update_tag;
            end
        end
    end
endmodule

// ==============================================================================
// FILE: icache_data_array.v
// ==============================================================================

// ============================================================================
// icache_data_array — 32 lines × 8 words = 256 entries (giữ nguyên depth)
// Thay đổi: offset 2 bit → 3 bit, index 6 bit → 5 bit
// ============================================================================
module icache_data_array (
    input wire clk,
    input wire rst_n,

    // Read
    input wire [4:0]   read_index,    // 5 bit (32 lines)
    input wire [2:0]   read_offset,   // 3 bit (8 words)
    output wire [31:0] read_data,

    // Write (refill)
    input wire         write_enable,
    input wire [4:0]   write_index,   // 5 bit
    input wire [2:0]   write_offset,  // 3 bit
    input wire [31:0]  write_data
);
    // 32 lines × 8 words = 256 entries — depth không đổi
    reg [31:0] data_array [0:255];

    // Read: {index[4:0], offset[2:0]} = 8 bit address
    wire [7:0] read_addr  = {read_index,  read_offset};
    wire [7:0] write_addr = {write_index, write_offset};

    assign read_data = data_array[read_addr];

    always @(posedge clk) begin
        if (write_enable)
            data_array[write_addr] <= write_data;
    end

    integer i;
    initial begin
        for (i = 0; i < 256; i = i + 1)
            data_array[i] = 32'h00000013; // NOP
    end
endmodule

// ==============================================================================
// FILE: icache_axi_interface.v
// ==============================================================================

// ============================================================================
// icache_axi_interface — ARLEN=7 (8 beats = 8 words = 1 cache line)
// Thêm AXI4 ID signals để kết nối vào axi4_crossbar
// ============================================================================
module icache_axi_interface #(
    parameter ID_WIDTH = 4
)(
    input wire clk,
    input wire rst_n,

    input wire [31:0]  refill_addr,
    input wire         refill_start,
    output reg         refill_busy,
    output reg         refill_done,

    output reg [31:0]  refill_data,
    output reg [2:0]   refill_word,       // 3 bit: 0-7
    output reg         refill_data_valid,

    output wire [ID_WIDTH-1:0] M_AXI_ARID,
    output wire [31:0]         M_AXI_ARADDR,
    output wire [7:0]          M_AXI_ARLEN,
    output wire [2:0]          M_AXI_ARSIZE,
    output wire [1:0]          M_AXI_ARBURST,
    output wire [2:0]          M_AXI_ARPROT,
    output wire                M_AXI_ARVALID,
    input  wire                M_AXI_ARREADY,

    input  wire [ID_WIDTH-1:0] M_AXI_RID,
    input  wire [31:0]         M_AXI_RDATA,
    input  wire [1:0]          M_AXI_RRESP,
    input  wire                M_AXI_RLAST,
    input  wire                M_AXI_RVALID,
    output wire                M_AXI_RREADY
);
    // ICache luôn dùng ARID = 0 (master 0, ID cố định)
    assign M_AXI_ARID    = {ID_WIDTH{1'b0}};
    assign M_AXI_ARLEN   = 8'd7;
    assign M_AXI_ARSIZE  = 3'b010; // 4 bytes
    assign M_AXI_ARBURST = 2'b01;  // INCR
    assign M_AXI_ARPROT  = 3'b000;

    localparam IDLE = 1'b0;
    localparam R    = 1'b1;

    reg       state;
    reg [2:0] word_counter;

    assign M_AXI_RREADY  = (state == R);
    assign M_AXI_ARVALID = (state == IDLE) && refill_start;
    assign M_AXI_ARADDR  = refill_addr;

    wire ar_handshake = M_AXI_ARVALID && M_AXI_ARREADY;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state             <= IDLE;
            refill_busy       <= 1'b0;
            refill_done       <= 1'b0;
            refill_data_valid <= 1'b0;
            refill_data       <= 32'h0;
            refill_word       <= 3'h0;
            word_counter      <= 3'h0;
        end else begin
            refill_done       <= 1'b0;
            refill_data_valid <= 1'b0;

            case (state)
                IDLE: begin
                    word_counter <= 3'h0;
                    if (ar_handshake) begin
                        refill_busy <= 1'b1;
                        state       <= R;
                    end
                end

                R: begin
                    if (M_AXI_RVALID && M_AXI_RREADY) begin
                        refill_data       <= M_AXI_RDATA;
                        refill_word       <= word_counter;
                        refill_data_valid <= 1'b1;
                        word_counter      <= word_counter + 1;

                        if (M_AXI_RLAST) begin
                            refill_done <= 1'b1;
                            refill_busy <= 1'b0;
                            state       <= IDLE;
                        end
                    end
                end

                default: state <= IDLE;
            endcase
        end
    end
endmodule

