// ============================================================================
// icache_controller — 8 words/line, index 5 bit, offset 3 bit
// ============================================================================
module icache_controller (
    input wire clk,
    input wire rst_n,

    input wire [31:0]  cpu_addr,
    input wire         cpu_req,
    output wire [31:0] cpu_rdata,
    output wire        cpu_ready,
    input wire         flush,

    output wire [4:0]  tag_lookup_index,   // 5 bit
    output wire [21:0] tag_lookup_tag,
    input wire         tag_hit,
    output reg         tag_update_valid,
    output reg [4:0]   tag_update_index,   // 5 bit
    output reg [21:0]  tag_update_tag,
    output reg         tag_flush_all,

    output wire [4:0]  data_read_index,    // 5 bit
    output wire [2:0]  data_read_offset,   // 3 bit
    input wire [31:0]  data_read_data,
    output reg         data_write_enable,
    output reg [4:0]   data_write_index,   // 5 bit
    output reg [2:0]   data_write_offset,  // 3 bit
    output reg [31:0]  data_write_data,

    output wire [31:0] refill_addr,
    output wire        refill_start,
    input wire         refill_busy,
    input wire         refill_done,
    input wire [31:0]  refill_data,
    input wire [2:0]   refill_word,        // 3 bit
    input wire         refill_data_valid,

    output reg [31:0]  stat_hits,
    output reg [31:0]  stat_misses
);

    // =========================================================================
    // IMEM address limit — pf_ptr wraps here to prevent DECERR on AXI crossbar
    // Default: 8 KB (matches inst_mem.v MEM_DEPTH=1024 words)
    // =========================================================================
    parameter IMEM_LIMIT = 32'h00002000;

    // =========================================================================
    // Address decomposition — LINE_SIZE=32 bytes
    // [31:10] tag=22bit  [9:5] index=5bit  [4:2] offset=3bit  [1:0]=00
    // =========================================================================
    wire [21:0] cpu_tag    = cpu_addr[31:10];
    wire [4:0]  cpu_index  = cpu_addr[9:5];
    wire [2:0]  cpu_offset = cpu_addr[4:2];
    wire [31:0] cpu_line_addr = {cpu_addr[31:5], 5'b00000};  // align 32 bytes

    // Wrapped next pf_ptr values — prevent prefetcher from crossing IMEM boundary
    wire [31:0] pf_ptr_next    = (pf_ptr + 32'd32 >= IMEM_LIMIT) ? 32'h0 : pf_ptr + 32'd32;
    wire [31:0] cpu_line_next  = (cpu_line_addr + 32'd32 >= IMEM_LIMIT) ? 32'h0 : cpu_line_addr + 32'd32;

    // =========================================================================
    // Shadow valid/tag — 32 lines
    // =========================================================================
    reg        ctrl_valid [0:31];
    reg [21:0] ctrl_tag   [0:31];

    // FIX: ctrl_hit_committed = line đang được commit ngay cycle này
    // Khi refill_done=1, ctrl_valid[pf_index] chưa kịp update (registered lag),
    // nhưng ta biết line đó đã xong → tính là hit ngay để tránh cpu_miss=1 sai.
    wire line_just_done = refill_done &&
                          (pf_index == cpu_index) &&
                          (pf_tag   == cpu_tag);

    // FIX-ALIAS: Prefetcher đang ghi một line KHÁC vào cùng set với CPU.
    // Trong cửa sổ này, ctrl_tag chưa update nhưng data_array đang bị overwrite
    // word-by-word với dữ liệu sai (NOP từ vùng ngoài chương trình).
    // → Buộc cpu_miss=1 để CPU đợi prefetch xong rồi mới demand-fill đúng line.
    wire prefetch_aliasing = pf_active &&
                             (pf_index == cpu_index) &&
                             (pf_tag   != cpu_tag);

    wire ctrl_hit = ((ctrl_valid[cpu_index] || line_just_done) &&
                     (ctrl_tag[cpu_index] == cpu_tag || line_just_done)) &&
                    !prefetch_aliasing;

    assign tag_lookup_index = cpu_index;
    assign tag_lookup_tag   = cpu_tag;
    assign data_read_index  = cpu_index;
    assign data_read_offset = cpu_offset;

    // =========================================================================
    // Prefetch engine
    // =========================================================================
    reg [31:0] pf_ptr;      // line-aligned, bước 32 bytes
    reg [4:0]  pf_index;
    reg [21:0] pf_tag;
    reg        pf_active;

    wire [4:0]  pf_ptr_index = pf_ptr[9:5];
    wire [21:0] pf_ptr_tag   = pf_ptr[31:10];

    // FIX: pf_ptr_cached tính cả line vừa được commit
    wire pf_line_just_done = refill_done &&
                             (pf_index == pf_ptr_index) &&
                             (pf_tag   == pf_ptr_tag);
    wire pf_ptr_cached = (ctrl_valid[pf_ptr_index] || pf_line_just_done) &&
                         (ctrl_tag[pf_ptr_index] == pf_ptr_tag || pf_line_just_done);

    wire cpu_miss = cpu_req && !ctrl_hit;

    wire loading_cpu_line = pf_active &&
                            (pf_index == cpu_index) &&
                            (pf_tag   == cpu_tag);

    assign refill_addr  = cpu_miss ? cpu_line_addr : pf_ptr;
    // FIX: bypass pf_active stale khi refill_done=1
    assign refill_start = !refill_busy &&
                          (!pf_active || refill_done) &&
                          (cpu_miss || !pf_ptr_cached);

    // =========================================================================
    // CPU stall capture
    // =========================================================================
    reg [31:0] stall_data;
    reg        stall_data_rdy;

    // =========================================================================
    // CPU output
    // =========================================================================
    reg        cpu_ready_int;
    reg [31:0] cpu_rdata_int;

    always @(*) begin
        cpu_ready_int = 1'b0;
        cpu_rdata_int = 32'h0;
        if (cpu_req) begin
            if (ctrl_hit) begin
                cpu_ready_int = 1'b1;
                cpu_rdata_int = data_read_data;
            end else if (loading_cpu_line && stall_data_rdy && refill_done) begin
                cpu_ready_int = 1'b1;
                cpu_rdata_int = stall_data;
            end
        end
    end

    assign cpu_ready = cpu_ready_int;
    assign cpu_rdata = cpu_rdata_int;

    // =========================================================================
    // Sequential
    // =========================================================================
    integer i;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            pf_ptr            <= 32'h0;
            pf_index          <= 5'h0;
            pf_tag            <= 22'h0;
            pf_active         <= 1'b0;
            stall_data        <= 32'h0;
            stall_data_rdy    <= 1'b0;
            tag_update_valid  <= 1'b0;
            tag_update_index  <= 5'h0;
            tag_update_tag    <= 22'h0;
            tag_flush_all     <= 1'b0;
            data_write_enable <= 1'b0;
            data_write_index  <= 5'h0;
            data_write_offset <= 3'h0;
            data_write_data   <= 32'h0;
            stat_hits         <= 32'h0;
            stat_misses       <= 32'h0;
            for (i = 0; i < 32; i = i + 1) begin
                ctrl_valid[i] <= 1'b0;
                ctrl_tag[i]   <= 22'h0;
            end

        end else begin
            tag_update_valid  <= 1'b0;
            tag_flush_all     <= 1'b0;
            data_write_enable <= 1'b0;

            if (flush) begin
                tag_flush_all  <= 1'b1;
                pf_active      <= 1'b0;
                pf_ptr         <= cpu_line_addr;
                stall_data_rdy <= 1'b0;
                for (i = 0; i < 32; i = i + 1)
                    ctrl_valid[i] <= 1'b0;

            end else begin

                // Phase 1: khởi động load
                // FIX: điều kiện khớp với assign refill_start
                if (!refill_busy && (!pf_active || refill_done)) begin
                    if (cpu_miss) begin
                        pf_index       <= cpu_index;
                        pf_tag         <= cpu_tag;
                        pf_active      <= 1'b1;
                        stall_data_rdy <= 1'b0;
                        stat_misses    <= stat_misses + 1;
                        pf_ptr         <= cpu_line_next; // FIX-WRAP: wrap at IMEM_LIMIT
                    end else if (pf_ptr_cached) begin
                        pf_ptr <= pf_ptr_next;
                    end else if (cpu_req && pf_ptr_index == cpu_index) begin
                        // FIX-THRASH: prefetch line này sẽ evict set đang dùng bởi CPU
                        // → chỉ advance pf_ptr, không fetch → tránh thrashing vô hạn
                        pf_ptr <= pf_ptr_next;
                    end else begin
                        pf_index  <= pf_ptr_index;
                        pf_tag    <= pf_ptr_tag;
                        pf_active <= 1'b1;
                        pf_ptr    <= pf_ptr_next;
                    end
                end

                // Phase 2: nhận data
                if (refill_data_valid) begin
                    data_write_enable <= 1'b1;
                    data_write_index  <= pf_index;
                    data_write_offset <= refill_word;
                    data_write_data   <= refill_data;

                    if (loading_cpu_line && !stall_data_rdy &&
                        refill_word == cpu_offset) begin
                        stall_data     <= refill_data;
                        stall_data_rdy <= 1'b1;
                    end
                end

                // Phase 3: xong 1 line
                if (refill_done) begin
                    tag_update_valid     <= 1'b1;
                    tag_update_index     <= pf_index;
                    tag_update_tag       <= pf_tag;
                    ctrl_valid[pf_index] <= 1'b1;
                    ctrl_tag[pf_index]   <= pf_tag;
                    pf_active            <= 1'b0;
                    stall_data_rdy       <= 1'b0;
                end

                if (cpu_req && ctrl_hit)
                    stat_hits <= stat_hits + 1;
            end
        end
    end
endmodule

module icache_top #(
    parameter CACHE_SIZE = 1024,
    parameter LINE_SIZE  = 32,
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input wire clk,
    input wire rst_n,

    // CPU interface
    input  wire [ADDR_WIDTH-1:0] cpu_addr,
    input  wire                  cpu_req,
    output wire [DATA_WIDTH-1:0] cpu_rdata,
    output wire                  cpu_ready,
    input  wire                  flush,

    // AXI4 Read Address Channel
    output wire [ID_WIDTH-1:0]   mem_arid,
    output wire [ADDR_WIDTH-1:0] mem_araddr,
    output wire [7:0]            mem_arlen,
    output wire [2:0]            mem_arsize,
    output wire [1:0]            mem_arburst,
    output wire [2:0]            mem_arprot,
    output wire                  mem_arvalid,
    input  wire                  mem_arready,

    // AXI4 Read Data Channel
    input  wire [ID_WIDTH-1:0]   mem_rid,
    input  wire [DATA_WIDTH-1:0] mem_rdata,
    input  wire [1:0]            mem_rresp,
    input  wire                  mem_rlast,
    input  wire                  mem_rvalid,
    output wire                  mem_rready,

    // AXI4 Write Address Channel (ICache không ghi — tie off, crossbar trả DECERR)
    output wire [ID_WIDTH-1:0]   mem_awid,
    output wire [ADDR_WIDTH-1:0] mem_awaddr,
    output wire [7:0]            mem_awlen,
    output wire [2:0]            mem_awsize,
    output wire [1:0]            mem_awburst,
    output wire [2:0]            mem_awprot,
    output wire                  mem_awvalid,
    input  wire                  mem_awready,

    // AXI4 Write Data Channel
    output wire [DATA_WIDTH-1:0] mem_wdata,
    output wire [3:0]            mem_wstrb,
    output wire                  mem_wlast,
    output wire                  mem_wvalid,
    input  wire                  mem_wready,

    // AXI4 Write Response Channel
    input  wire [ID_WIDTH-1:0]   mem_bid,
    input  wire [1:0]            mem_bresp,
    input  wire                  mem_bvalid,
    output wire                  mem_bready,

    // Statistics
    output wire [31:0] stat_hits,
    output wire [31:0] stat_misses
);

    // ICache không bao giờ ghi — tie off toàn bộ write channels
    assign mem_awid    = {ID_WIDTH{1'b0}};
    assign mem_awaddr  = 32'h0;
    assign mem_awlen   = 8'h0;
    assign mem_awsize  = 3'b000;
    assign mem_awburst = 2'b00;
    assign mem_awprot  = 3'b000;
    assign mem_awvalid = 1'b0;
    assign mem_wdata   = 32'h0;
    assign mem_wstrb   = 4'h0;
    assign mem_wlast   = 1'b0;
    assign mem_wvalid  = 1'b0;
    assign mem_bready  = 1'b0;

    // Internal signals
    wire [4:0]  tag_lookup_index;
    wire [21:0] tag_lookup_tag;
    wire        tag_hit;
    wire        tag_update_valid;
    wire [4:0]  tag_update_index;
    wire [21:0] tag_update_tag;
    wire        tag_flush_all;

    wire [4:0]  data_read_index;
    wire [2:0]  data_read_offset;
    wire [31:0] data_read_data;
    wire        data_write_enable;
    wire [4:0]  data_write_index;
    wire [2:0]  data_write_offset;
    wire [31:0] data_write_data;

    wire [31:0] refill_addr;
    wire        refill_start;
    wire        refill_busy;
    wire        refill_done;
    wire [31:0] refill_data;
    wire [2:0]  refill_word;
    wire        refill_data_valid;

    icache_tag_array tag_array_inst (
        .clk(clk), .rst_n(rst_n),
        .lookup_index(tag_lookup_index),
        .lookup_tag(tag_lookup_tag),
        .hit(tag_hit),
        .update_valid(tag_update_valid),
        .update_index(tag_update_index),
        .update_tag(tag_update_tag),
        .flush_all(tag_flush_all)
    );

    icache_data_array data_array_inst (
        .clk(clk), .rst_n(rst_n),
        .read_index(data_read_index),
        .read_offset(data_read_offset),
        .read_data(data_read_data),
        .write_enable(data_write_enable),
        .write_index(data_write_index),
        .write_offset(data_write_offset),
        .write_data(data_write_data)
    );

    icache_axi_interface #(.ID_WIDTH(ID_WIDTH)) axi_interface_inst (
        .clk(clk), .rst_n(rst_n),
        .refill_addr(refill_addr),
        .refill_start(refill_start),
        .refill_busy(refill_busy),
        .refill_done(refill_done),
        .refill_data(refill_data),
        .refill_word(refill_word),
        .refill_data_valid(refill_data_valid),
        .M_AXI_ARID(mem_arid),
        .M_AXI_ARADDR(mem_araddr),
        .M_AXI_ARLEN(mem_arlen),
        .M_AXI_ARSIZE(mem_arsize),
        .M_AXI_ARBURST(mem_arburst),
        .M_AXI_ARPROT(mem_arprot),
        .M_AXI_ARVALID(mem_arvalid),
        .M_AXI_ARREADY(mem_arready),
        .M_AXI_RID(mem_rid),
        .M_AXI_RDATA(mem_rdata),
        .M_AXI_RRESP(mem_rresp),
        .M_AXI_RLAST(mem_rlast),
        .M_AXI_RVALID(mem_rvalid),
        .M_AXI_RREADY(mem_rready)
    );

    icache_controller controller_inst (
        .clk(clk), .rst_n(rst_n),
        .cpu_addr(cpu_addr),
        .cpu_req(cpu_req),
        .cpu_rdata(cpu_rdata),
        .cpu_ready(cpu_ready),
        .flush(flush),
        .tag_lookup_index(tag_lookup_index),
        .tag_lookup_tag(tag_lookup_tag),
        .tag_hit(tag_hit),
        .tag_update_valid(tag_update_valid),
        .tag_update_index(tag_update_index),
        .tag_update_tag(tag_update_tag),
        .tag_flush_all(tag_flush_all),
        .data_read_index(data_read_index),
        .data_read_offset(data_read_offset),
        .data_read_data(data_read_data),
        .data_write_enable(data_write_enable),
        .data_write_index(data_write_index),
        .data_write_offset(data_write_offset),
        .data_write_data(data_write_data),
        .refill_addr(refill_addr),
        .refill_start(refill_start),
        .refill_busy(refill_busy),
        .refill_done(refill_done),
        .refill_data(refill_data),
        .refill_word(refill_word),
        .refill_data_valid(refill_data_valid),
        .stat_hits(stat_hits),
        .stat_misses(stat_misses)
    );

endmodule

// ==============================================================================
// FILE: dcache_top.v
// ==============================================================================

// ============================================================================
// Module: dcache_top  —  Write-Back + Write-Allocate version
// Thêm AXI4 ID signals để kết nối vào axi4_crossbar (M1)
// ============================================================================

// ==============================================================================
// FILE: dcache_tag_array.v
// ==============================================================================

// ============================================================================
// Module: dcache_tag_array — Direct-Mapped, 64 sets, 22-bit tag
// ============================================================================
//
// [FENCE-TYPE] Tách biệt flush và invalidate:
//
//   flush_all      = 1 : chỉ clear dirty bits, GIỮ NGUYÊN valid bits
//                        → cache lines vẫn readable (stack an toàn)
//                        → triggered bởi fence w,w (fence_type[0]=1)
//
//   invalidate_all = 1 : clear cả valid bits lẫn dirty bits
//                        → toàn bộ cache bị invalidate
//                        → triggered bởi fence iorw / fence.i (fence_type[1]=1)
//
// Cả hai có thể assert cùng lúc (fence iorw):
//   flush_all=1 + invalidate_all=1 → writeback dirty + invalidate all
//
// Lưu ý: flush_all chỉ clear dirty bit, KHÔNG writeback dữ liệu ra DMEM.
// Việc writeback được thực hiện bởi dcache_controller thông qua evict path
// trước khi assert flush_all. Trong thiết kế này (write-back, write-allocate),
// fence w,w yêu cầu writeback trước khi DMA đọc — controller phải xử lý
// eviction loop trước khi signal flush_all (TODO: cần fence FSM trong controller
// nếu muốn đúng hoàn toàn). Hiện tại flush_all chỉ clear dirty để tránh
// false eviction sau fence.
//
// ============================================================================

module dcache_tag_array #(
    parameter NUM_SETS  = 64,   // 6-bit index → 64 sets
    parameter TAG_WIDTH = 22    // addr[31:10]
)(
    input  wire                  clk,
    input  wire                  rst_n,

    // Lookup (combinational read — results valid next cycle)
    input  wire [5:0]            lookup_index,
    input  wire [TAG_WIDTH-1:0]  lookup_tag,
    output wire                  hit,
    output wire                  dirty_out,
    output wire [TAG_WIDTH-1:0]  evict_tag_out,

    // Update (fill new line after refill)
    input  wire                  update_valid,
    input  wire [5:0]            update_index,
    input  wire [TAG_WIDTH-1:0]  update_tag,

    // Dirty management
    input  wire                  dirty_set,
    input  wire                  dirty_clear,
    input  wire [5:0]            dirty_index,

    // [FENCE-TYPE] Flush vs Invalidate — tách biệt
    // flush_all=1      : clear dirty bits ONLY  (fence w,w)
    // invalidate_all=1 : clear valid + dirty     (fence iorw / fence.i)
    input  wire                  flush_all,
    input  wire                  invalidate_all
);

    // =========================================================================
    // Storage arrays
    // =========================================================================
    reg [TAG_WIDTH-1:0] tags  [0:NUM_SETS-1];
    reg                 valid [0:NUM_SETS-1];
    reg                 dirty [0:NUM_SETS-1];

    integer i;

    // =========================================================================
    // Synchronous write
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Power-on reset: invalidate everything
            for (i = 0; i < NUM_SETS; i = i + 1) begin
                valid[i] <= 1'b0;
                dirty[i] <= 1'b0;
                tags[i]  <= {TAG_WIDTH{1'b0}};
            end
        end else begin
            // ─── Priority (highest → lowest) ───────────────────────────────
            // 1. invalidate_all : clear valid + dirty tất cả sets (fence iorw)
            // 2. flush_all      : clear dirty ONLY (fence w,w) — valid an toàn
            // 3. update_valid   : install new tag sau refill
            // 4. dirty_set      : mark line dirty sau write
            // 5. dirty_clear    : clear dirty sau eviction
            // Các op này không conflict trong thực tế vì controller serializes
            // fence trước khi resume normal operation.
            // ─────────────────────────────────────────────────────────────────

            if (invalidate_all) begin
                // fence iorw / fence.i → invalidate toàn bộ
                for (i = 0; i < NUM_SETS; i = i + 1) begin
                    valid[i] <= 1'b0;
                    dirty[i] <= 1'b0;
                end
            end else if (flush_all) begin
                // fence w,w → chỉ clear dirty, GIỮ NGUYÊN valid
                // Stack frame vẫn readable, không cần refill lại
                for (i = 0; i < NUM_SETS; i = i + 1) begin
                    dirty[i] <= 1'b0;
                end
            end else begin
                // Normal operation
                if (update_valid) begin
                    tags [update_index] <= update_tag;
                    valid[update_index] <= 1'b1;
                    dirty[update_index] <= 1'b0; // new refill = clean
                end

                if (dirty_set) begin
                    dirty[dirty_index] <= 1'b1;
                end

                if (dirty_clear) begin
                    dirty[dirty_index] <= 1'b0;
                end
            end
        end
    end

    // =========================================================================
    // Synchronous read (1-cycle latency — matches dcache_controller FIX-BUG-LOOKUP)
    // =========================================================================
    reg                 hit_r;
    reg                 dirty_r;
    reg [TAG_WIDTH-1:0] evict_tag_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            hit_r       <= 1'b0;
            dirty_r     <= 1'b0;
            evict_tag_r <= {TAG_WIDTH{1'b0}};
        end else begin
            hit_r       <= valid[lookup_index] && (tags[lookup_index] == lookup_tag);
            dirty_r     <= dirty[lookup_index];
            evict_tag_r <= tags[lookup_index];
        end
    end

    assign hit          = hit_r;
    assign dirty_out    = dirty_r;
    assign evict_tag_out = evict_tag_r;

endmodule

// ==============================================================================
// FILE: dcache_data_array.v
// ==============================================================================

// ============================================================================
// Module: dcache_data_array  —  Write-Back version
// ============================================================================
// Không thay đổi so với bản trước — logic đã đúng.
// read_all_index/read_word_{0..3}: đọc toàn bộ 4 words của 1 cache line
// trong cùng một cycle cho eviction burst.
// Write-first forwarding cho cả single-word và all-words read.
// ============================================================================

module dcache_data_array (
    input wire clk,
    input wire rst_n,

    // ── Single-word read (CPU load) ───────────────────────────────────────────
    input wire [5:0]   read_index,
    input wire [1:0]   read_offset,
    output wire [31:0] read_data,

    // ── All-words read (eviction) ─────────────────────────────────────────────
    input wire [5:0]   read_all_index,
    output wire [31:0] read_word_0,
    output wire [31:0] read_word_1,
    output wire [31:0] read_word_2,
    output wire [31:0] read_word_3,

    // ── Write (store hit, refill, write-allocate) ─────────────────────────────
    input wire         write_enable,
    input wire [5:0]   write_index,
    input wire [1:0]   write_offset,
    input wire [31:0]  write_data,
    input wire [3:0]   write_strb
);

    // ========================================================================
    // Storage: 64 lines × 4 words = 256 × 32-bit
    // Flat addr: {index[5:0], offset[1:0]}
    // ========================================================================
    reg [31:0] data_array [0:255];

    integer i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 256; i = i + 1)
                data_array[i] <= 32'h0;
        end
    end

    // ========================================================================
    // Write Logic (Sequential, byte-enable)
    // ========================================================================
    wire [7:0] write_addr_flat = {write_index, write_offset};

    always @(posedge clk) begin
        if (write_enable) begin
            if (write_strb[0]) data_array[write_addr_flat][7:0]   <= write_data[7:0];
            if (write_strb[1]) data_array[write_addr_flat][15:8]  <= write_data[15:8];
            if (write_strb[2]) data_array[write_addr_flat][23:16] <= write_data[23:16];
            if (write_strb[3]) data_array[write_addr_flat][31:24] <= write_data[31:24];
        end
    end

    // ========================================================================
    // Single-word Read (Combinational, write-first forwarding)
    // ========================================================================
    wire [7:0]  read_addr_flat = {read_index, read_offset};
    wire        addr_collision = write_enable && (write_addr_flat == read_addr_flat);
    wire [31:0] raw_read       = data_array[read_addr_flat];

    assign read_data[7:0]   = (addr_collision && write_strb[0]) ? write_data[7:0]   : raw_read[7:0];
    assign read_data[15:8]  = (addr_collision && write_strb[1]) ? write_data[15:8]  : raw_read[15:8];
    assign read_data[23:16] = (addr_collision && write_strb[2]) ? write_data[23:16] : raw_read[23:16];
    assign read_data[31:24] = (addr_collision && write_strb[3]) ? write_data[31:24] : raw_read[31:24];

    // ========================================================================
    // All-words Read (Combinational — eviction)
    // Write-first forwarding cho từng word
    // ========================================================================
    wire [7:0] ra0 = {read_all_index, 2'd0};
    wire [7:0] ra1 = {read_all_index, 2'd1};
    wire [7:0] ra2 = {read_all_index, 2'd2};
    wire [7:0] ra3 = {read_all_index, 2'd3};

    wire col0 = write_enable && (write_addr_flat == ra0);
    wire col1 = write_enable && (write_addr_flat == ra1);
    wire col2 = write_enable && (write_addr_flat == ra2);
    wire col3 = write_enable && (write_addr_flat == ra3);

    assign read_word_0[7:0]   = (col0 && write_strb[0]) ? write_data[7:0]   : data_array[ra0][7:0];
    assign read_word_0[15:8]  = (col0 && write_strb[1]) ? write_data[15:8]  : data_array[ra0][15:8];
    assign read_word_0[23:16] = (col0 && write_strb[2]) ? write_data[23:16] : data_array[ra0][23:16];
    assign read_word_0[31:24] = (col0 && write_strb[3]) ? write_data[31:24] : data_array[ra0][31:24];

    assign read_word_1[7:0]   = (col1 && write_strb[0]) ? write_data[7:0]   : data_array[ra1][7:0];
    assign read_word_1[15:8]  = (col1 && write_strb[1]) ? write_data[15:8]  : data_array[ra1][15:8];
    assign read_word_1[23:16] = (col1 && write_strb[2]) ? write_data[23:16] : data_array[ra1][23:16];
    assign read_word_1[31:24] = (col1 && write_strb[3]) ? write_data[31:24] : data_array[ra1][31:24];

    assign read_word_2[7:0]   = (col2 && write_strb[0]) ? write_data[7:0]   : data_array[ra2][7:0];
    assign read_word_2[15:8]  = (col2 && write_strb[1]) ? write_data[15:8]  : data_array[ra2][15:8];
    assign read_word_2[23:16] = (col2 && write_strb[2]) ? write_data[23:16] : data_array[ra2][23:16];
    assign read_word_2[31:24] = (col2 && write_strb[3]) ? write_data[31:24] : data_array[ra2][31:24];

    assign read_word_3[7:0]   = (col3 && write_strb[0]) ? write_data[7:0]   : data_array[ra3][7:0];
    assign read_word_3[15:8]  = (col3 && write_strb[1]) ? write_data[15:8]  : data_array[ra3][15:8];
    assign read_word_3[23:16] = (col3 && write_strb[2]) ? write_data[23:16] : data_array[ra3][23:16];
    assign read_word_3[31:24] = (col3 && write_strb[3]) ? write_data[31:24] : data_array[ra3][31:24];

endmodule

// ==============================================================================
// FILE: dcache_axi_interface.v
// ==============================================================================

// ============================================================================
// Module: dcache_axi_interface  —  Write-Back version
// Thêm AXI4 ID signals để kết nối vào axi4_crossbar (M1)
//
// FIX-BUG2: refill_addr bị latch sai cycle trong RD_IDLE
//   Controller set refill_addr và refill_start bằng nonblocking (<=) nên
//   giá trị chỉ có hiệu lực ở cuối cycle đó. RD_IDLE chạy cùng posedge
//   sẽ thấy giá trị CŨ.
//   FIX: Thêm state RD_LATCH — 1-cycle buffer, đọc refill_addr ở cycle sau.
//
// FIX-BUG-TIMING: refill_data_valid, refill_done, refill_data, refill_word
//   Nếu là reg (nonblocking <=), chúng có hiệu lực 1 cycle SAU beat.
//   Controller nhận trễ → DRAIN xong muộn → TC01/TC10/TC11 fail/timeout.
//
//   FIX: Đổi tất cả thành COMBINATIONAL (wire):
//     refill_data_valid = (rd_state==RD_R) && RVALID && RREADY
//     refill_done       = refill_data_valid && RLAST
//     refill_data       = refill_data_valid ? M_AXI_RDATA     : refill_data_r
//     refill_word       = refill_data_valid ? rd_word_counter : refill_word_r
//
//   refill_data_r / refill_word_r là internal reg để giữ giá trị ổn định
//   khi valid=0. rd_word_counter tăng SAU khi beat được nhận → giá trị
//   live trong cycle hiện tại luôn = index đúng của beat đang đến.
// ============================================================================
module dcache_axi_interface #(
    parameter ID_WIDTH = 4
)(
    input wire clk,
    input wire rst_n,

    // ========================================================================
    // Read Refill Interface
    // ========================================================================
    input wire [31:0]  refill_addr,
    input wire         refill_start,
    input wire         refill_nc,       // [NC-BYPASS] 1 = single-beat (ARLEN=0)
    output reg         refill_busy,
    output wire        refill_done,        // combinational: valid && RLAST
    output wire [31:0] refill_data,        // combinational MUX
    output wire [1:0]  refill_word,        // combinational MUX
    output wire        refill_data_valid,  // combinational: RD_R && RVALID && RREADY

    // ========================================================================
    // Eviction Interface
    // ========================================================================
    input wire [31:0]  evict_addr,
    input wire [31:0]  evict_data_0,
    input wire [31:0]  evict_data_1,
    input wire [31:0]  evict_data_2,
    input wire [31:0]  evict_data_3,
    input wire         evict_start,
    input wire         evict_nc,        // [NC-BYPASS] 1 = single-beat (AWLEN=0)
    input wire [3:0]   evict_wstrb_nc,  // [NC-BYPASS] byte strobe cho NC write
    output reg         evict_busy,
    output reg         evict_done,

    // ========================================================================
    // AXI4 Read Channel
    // ========================================================================
    output wire [ID_WIDTH-1:0] M_AXI_ARID,
    output reg  [31:0]         M_AXI_ARADDR,
    output wire [7:0]          M_AXI_ARLEN,
    output wire [2:0]          M_AXI_ARSIZE,
    output wire [1:0]          M_AXI_ARBURST,
    output wire [2:0]          M_AXI_ARPROT,
    output reg                 M_AXI_ARVALID,
    input  wire                M_AXI_ARREADY,

    input  wire [ID_WIDTH-1:0] M_AXI_RID,
    input  wire [31:0]         M_AXI_RDATA,
    input  wire [1:0]          M_AXI_RRESP,
    input  wire                M_AXI_RLAST,
    input  wire                M_AXI_RVALID,
    output reg                 M_AXI_RREADY,

    // ========================================================================
    // AXI4 Write Channel
    // ========================================================================
    output wire [ID_WIDTH-1:0] M_AXI_AWID,
    output reg  [31:0]         M_AXI_AWADDR,
    output wire [7:0]          M_AXI_AWLEN,
    output wire [2:0]          M_AXI_AWSIZE,
    output wire [1:0]          M_AXI_AWBURST,
    output wire [2:0]          M_AXI_AWPROT,
    output reg                 M_AXI_AWVALID,
    input  wire                M_AXI_AWREADY,

    output reg  [31:0]         M_AXI_WDATA,
    output reg  [3:0]          M_AXI_WSTRB,
    output reg                 M_AXI_WLAST,
    output reg                 M_AXI_WVALID,
    input  wire                M_AXI_WREADY,

    input  wire [ID_WIDTH-1:0] M_AXI_BID,
    input  wire [1:0]          M_AXI_BRESP,
    input  wire                M_AXI_BVALID,
    output reg                 M_AXI_BREADY
);

    // ========================================================================
    // AXI constant signals
    // ========================================================================
    assign M_AXI_ARID    = {ID_WIDTH{1'b0}};
    assign M_AXI_AWID    = {ID_WIDTH{1'b0}};

    // [NC-BYPASS] ARLEN/AWLEN: bình thường = 3 (4-beat cache refill/evict)
    // Khi NC bypass được kích hoạt: = 0 (1-beat single transaction)
    // nc_beat_mode được set bởi controller thông qua refill_nc / evict_nc flags.
    // Giải pháp đơn giản: controller set refill_addr[0]=1 để báo NC mode
    // → NHƯNG điều này sẽ làm địa chỉ sai.
    //
    // Giải pháp đúng: thêm port nc_read / nc_write vào axi_interface.
    // Controller set các port này khi kick NC transaction.
    assign M_AXI_ARLEN   = rd_burst_len;
    assign M_AXI_ARSIZE  = 3'b010;
    assign M_AXI_ARBURST = 2'b01;
    assign M_AXI_ARPROT  = 3'b000;
    assign M_AXI_AWLEN   = ev_burst_len;
    assign M_AXI_AWSIZE  = 3'b010;
    assign M_AXI_AWBURST = 2'b01;
    assign M_AXI_AWPROT  = 3'b000;

    // ========================================================================
    // [NC-BYPASS] Burst length registers
    // Normal cache: ARLEN=3 (4-beat), NC bypass: ARLEN=0 (1-beat)
    // ========================================================================
    reg [7:0] rd_burst_len;
    reg [7:0] ev_burst_len;
    reg       rd_nc_mode;    // latch NC mode khi bắt đầu transaction
    reg       ev_nc_mode;

    // ========================================================================
    // Read Refill FSM
    // ========================================================================
    localparam [2:0]
        RD_IDLE  = 3'b000,
        RD_LATCH = 3'b001,
        RD_AR    = 3'b010,
        RD_R     = 3'b011;

    reg [2:0] rd_state;
    reg [1:0] rd_word_counter;

    // Internal latched regs (hold last beat value, used when valid=0)
    reg [31:0] refill_data_r;
    reg [1:0]  refill_word_r;

    // ── Combinational output assignments ─────────────────────────────────────
    // Assert in the SAME cycle as the AXI beat — no pipeline delay.
    assign refill_data_valid = (rd_state == RD_R) && M_AXI_RVALID && M_AXI_RREADY;
    assign refill_done       = refill_data_valid && M_AXI_RLAST;

    // When a beat is arriving: expose LIVE values directly from AXI bus.
    // When idle: expose last latched values (stable, unused by controller).
    assign refill_data = refill_data_valid ? M_AXI_RDATA     : refill_data_r;
    assign refill_word = refill_data_valid ? rd_word_counter : refill_word_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state        <= RD_IDLE;
            refill_busy     <= 1'b0;
            refill_data_r   <= 32'h0;
            refill_word_r   <= 2'b00;
            rd_word_counter <= 2'b00;
            M_AXI_ARADDR    <= 32'h0;
            M_AXI_ARVALID   <= 1'b0;
            M_AXI_RREADY    <= 1'b0;
            rd_burst_len    <= 8'd3;
            rd_nc_mode      <= 1'b0;
        end else begin
            case (rd_state)

                // ── RD_IDLE ──────────────────────────────────────────────────
                RD_IDLE: begin
                    refill_busy     <= 1'b0;
                    M_AXI_ARVALID   <= 1'b0;
                    M_AXI_RREADY    <= 1'b0;
                    rd_word_counter <= 2'b00;

                    if (refill_start) begin
                        refill_busy  <= 1'b1;
                        rd_burst_len <= refill_nc ? 8'd0 : 8'd3;
                        rd_nc_mode   <= refill_nc;
                        rd_state     <= RD_LATCH;
                    end
                end

                // ── RD_LATCH: 1-cycle buffer, refill_addr đã stable ──────────
                RD_LATCH: begin
                    M_AXI_ARADDR  <= refill_addr;
                    M_AXI_ARVALID <= 1'b1;
                    rd_state      <= RD_AR;
                end

                // ── RD_AR: chờ ARREADY ───────────────────────────────────────
                RD_AR: begin
                    if (M_AXI_ARREADY) begin
                        M_AXI_ARVALID <= 1'b0;
                        M_AXI_RREADY  <= 1'b1;
                        rd_state      <= RD_R;
                    end
                end

                // ── RD_R: nhận burst (4 beats bình thường, 1 beat NC mode) ──
                // refill_data_valid/done/data/word là COMBO → controller thấy
                // ngay trong cycle RVALID. Chỉ cần latch vào _r để giữ giá trị
                // ổn định sau khi RVALID về 0.
                // rd_word_counter tăng AFTER latch → combo output đọc giá trị
                // TRƯỚC khi tăng = đúng index của beat đang đến.
                RD_R: begin
                    if (M_AXI_RVALID && M_AXI_RREADY) begin
                        refill_data_r <= M_AXI_RDATA;
                        refill_word_r <= rd_word_counter;

                        if (M_AXI_RLAST) begin
                            M_AXI_RREADY    <= 1'b0;
                            refill_busy     <= 1'b0;
                            rd_word_counter <= 2'b00;
                            rd_nc_mode      <= 1'b0;
                            rd_state        <= RD_IDLE;
                        end else begin
                            // NC mode không nên có non-LAST beats, nhưng nếu
                            // slave gửi thêm thì bỏ qua (defensive)
                            rd_word_counter <= rd_word_counter + 1'b1;
                        end
                    end
                end

                default: rd_state <= RD_IDLE;
            endcase
        end
    end

    // ========================================================================
    // Eviction Write State Machine
    // ========================================================================
    localparam [1:0]
        EV_IDLE = 2'b00,
        EV_AW   = 2'b01,
        EV_W    = 2'b10,
        EV_B    = 2'b11;

    reg [1:0]  ev_state;
    reg [1:0]  ev_beat;
    reg        ev_aw_done;
    reg [31:0] ev_d0, ev_d1, ev_d2, ev_d3;

    function [31:0] ev_word;
        input [1:0] beat;
        begin
            case (beat)
                2'd0: ev_word = ev_d0;
                2'd1: ev_word = ev_d1;
                2'd2: ev_word = ev_d2;
                2'd3: ev_word = ev_d3;
            endcase
        end
    endfunction

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ev_state      <= EV_IDLE;
            evict_busy    <= 1'b0;
            evict_done    <= 1'b0;
            ev_beat       <= 2'b00;
            ev_aw_done    <= 1'b0;
            M_AXI_AWADDR  <= 32'h0;
            M_AXI_AWVALID <= 1'b0;
            M_AXI_WDATA   <= 32'h0;
            M_AXI_WSTRB   <= 4'hf;
            M_AXI_WLAST   <= 1'b0;
            M_AXI_WVALID  <= 1'b0;
            M_AXI_BREADY  <= 1'b0;
            ev_d0 <= 32'h0; ev_d1 <= 32'h0;
            ev_d2 <= 32'h0; ev_d3 <= 32'h0;
            ev_burst_len  <= 8'd3;
            ev_nc_mode    <= 1'b0;
        end else begin
            evict_done <= 1'b0;

            case (ev_state)

                // ── EV_IDLE: latch request, assert AW only ────────────────────
                // KHÔNG assert WVALID ở đây. Nếu AWREADY=1 ngay lập tức,
                // beat 0 sẽ bị consumed trong EV_AW trước khi ev_beat được đếm.
                EV_IDLE: begin
                    evict_busy    <= 1'b0;
                    M_AXI_AWVALID <= 1'b0;
                    M_AXI_WVALID  <= 1'b0;
                    M_AXI_WLAST   <= 1'b0;
                    M_AXI_BREADY  <= 1'b0;
                    ev_beat       <= 2'b00;
                    ev_aw_done    <= 1'b0;

                    if (evict_start) begin
                        M_AXI_AWADDR  <= evict_addr;
                        ev_d0         <= evict_data_0;
                        ev_d1         <= evict_data_1;
                        ev_d2         <= evict_data_2;
                        ev_d3         <= evict_data_3;
                        ev_burst_len  <= evict_nc ? 8'd0 : 8'd3;
                        ev_nc_mode    <= evict_nc;
                        M_AXI_AWVALID <= 1'b1;
                        evict_busy    <= 1'b1;
                        ev_state      <= EV_AW;
                    end
                end

                // ── EV_AW: chờ AWREADY, rồi bắt đầu write data ──────────────
                EV_AW: begin
                    if (M_AXI_AWVALID && M_AXI_AWREADY) begin
                        M_AXI_AWVALID <= 1'b0;
                        // Bắt đầu burst: gửi beat 0
                        M_AXI_WVALID  <= 1'b1;
                        M_AXI_WDATA   <= ev_d0;
                        M_AXI_WSTRB   <= ev_nc_mode ? evict_wstrb_nc : 4'hf;
                        M_AXI_WLAST   <= ev_nc_mode ? 1'b1 : 1'b0;
                        ev_beat       <= 2'b00;
                        ev_state      <= EV_W;
                    end
                end

                // ── EV_W: gửi toàn bộ write data burst (beat 0..3) ───────────
                EV_W: begin
                    if (M_AXI_WVALID && M_AXI_WREADY) begin
                        if (ev_nc_mode || ev_beat == 2'd3) begin
                            // Beat cuối accepted → kết thúc
                            M_AXI_WVALID <= 1'b0;
                            M_AXI_WLAST  <= 1'b0;
                            M_AXI_BREADY <= 1'b1;
                            ev_state     <= EV_B;
                        end else begin
                            // Gửi beat tiếp theo
                            ev_beat     <= ev_beat + 1'b1;
                            M_AXI_WDATA <= ev_word(ev_beat + 1'b1);
                            // WLAST=1 khi đang ở beat 2 (beat kế = 3 = last)
                            M_AXI_WLAST <= (ev_beat == 2'd2) ? 1'b1 : 1'b0;
                        end
                    end
                end

                // ── EV_B: chờ write response ──────────────────────────────────
                EV_B: begin
                    if (M_AXI_BVALID && M_AXI_BREADY) begin
                        M_AXI_BREADY <= 1'b0;
                        evict_done   <= 1'b1;
                        evict_busy   <= 1'b0;
                        ev_state     <= EV_IDLE;
                    end
                end

                default: ev_state <= EV_IDLE;
            endcase
        end
    end

endmodule

// ==============================================================================
// FILE: dcache_controller.v
// ==============================================================================

// ============================================================================
// Module: dcache_controller  —  Write-Back + Write-Allocate
// FIXED VERSION
// ============================================================================
// BUG FIXES:
//
// [FIX-1] evict_start multi-driver race
//   Root cause: flush FSM và sequential output block đều drive evict_start.
//   Output block default evict_start<=0 mỗi cycle → ghi đè pulse từ flush FSM
//   trong FLUSH_TAG_WAIT → evict không bao giờ start từ flush path.
//   Fix: tách thành flush_evict_start (flush FSM) và main_evict_start (main FSM).
//   evict_start = flush_evict_start | main_evict_start (combinational OR).
//
// [FIX-2] tag_dirty_clear multi-driver
//   Root cause: FLUSH_EVICT trong output block và DCACHE_STATE_EVICT trong
//   main FSM output block đều drive tag_dirty_clear → Verilog last-assign wins.
//   Fix: tách thành flush_dirty_clear và main_dirty_clear, OR lại.
//
// [FIX-3] TC15: fence_type=2'b10 (invalidate only) không trigger flush_busy
//   Root cause: FLUSH_IDLE chỉ check fence_flush (bit[0]). Invalidate-only
//   (bit[1]=1, bit[0]=0) không start flush FSM → flush_busy không lên → TB timeout.
//   Fix: FLUSH_IDLE start khi fence_any (|fence_type). Nếu không cần flush
//   (fence_inval only), skip thẳng đến FLUSH_DONE.
//
// [FIX-4] evict_nc flag không clear sau NC write
//   Root cause: evict_nc set khi NC write, nhưng flush evict path cũng dùng
//   evict_start → evict_nc có thể còn set stale từ lần trước.
//   Fix: evict_nc chỉ set khi main FSM NC path, clear ở default.
//
// [ORIGINAL FIXES PRESERVED]
//   [FIX-BUG-IDLE-HIT] idle_tag_hit_valid guard
//   [FIX-FLUSH-BITMAP] dirty_bitmap priority encoder
//   [FIX-FLUSH-TAG-WAIT] 1-cycle tag latency
//   [FIX-TC3] deferred pending write
// ============================================================================

`define FLUSH_IDLE     3'd0
`define FLUSH_SETTLE   3'd1
`define FLUSH_TAG_WAIT 3'd5
`define FLUSH_SCAN     3'd2
`define FLUSH_EVICT    3'd3
`define FLUSH_DONE     3'd4

module dcache_controller (
    input wire clk,
    input wire rst_n,

    input wire [31:0]  cpu_addr,
    input wire [31:0]  cpu_wdata,
    input wire [3:0]   cpu_wstrb,
    input wire         cpu_req,
    input wire         cpu_we,
    output wire [31:0] cpu_rdata,
    output wire        cpu_ready,
    input wire [1:0]   fence_type,

    output wire [31:0] current_addr,
    output wire [31:0] current_data,
    output wire        current_valid,

    output wire [5:0]  tag_lookup_index,
    output wire [21:0] tag_lookup_tag,
    input wire         tag_hit,
    input wire         tag_dirty_out,
    input wire [21:0]  tag_evict_tag_out,
    output reg         tag_update_valid,
    output reg [5:0]   tag_update_index,
    output reg [21:0]  tag_update_tag,
    output reg         tag_flush_all,
    output reg         tag_invalidate_all,
    output wire        tag_dirty_set,
    output wire        tag_dirty_clear,
    output reg [5:0]   tag_dirty_index,

    output wire [5:0]  data_read_index,
    output wire [1:0]  data_read_offset,
    input wire [31:0]  data_read_data,
    output reg         data_write_enable,
    output reg [5:0]   data_write_index,
    output reg [1:0]   data_write_offset,
    output reg [31:0]  data_write_data,
    output reg [3:0]   data_write_strb,

    output wire [5:0]  data_read_all_index,
    input wire [31:0]  data_read_word_0,
    input wire [31:0]  data_read_word_1,
    input wire [31:0]  data_read_word_2,
    input wire [31:0]  data_read_word_3,

    output reg [31:0]  refill_addr,
    output reg         refill_start,
    output reg         refill_nc,
    input wire         refill_busy,
    input wire         refill_done,
    input wire [31:0]  refill_data,
    input wire [1:0]   refill_word,
    input wire         refill_data_valid,

    output reg [31:0]  evict_addr,
    output reg [31:0]  evict_data_0,
    output reg [31:0]  evict_data_1,
    output reg [31:0]  evict_data_2,
    output reg [31:0]  evict_data_3,
    output wire        evict_start,     // [FIX-1] now wire (OR of two sources)
    output reg         evict_nc,
    output reg [3:0]   evict_wstrb_nc,
    input wire         evict_busy,
    input wire         evict_done,

    output reg [31:0]  stat_hits,
    output reg [31:0]  stat_misses,
    output reg [31:0]  stat_writes
);

    localparam [2:0]
        DCACHE_STATE_IDLE         = 3'b000,
        DCACHE_STATE_LOOKUP       = 3'b001,
        DCACHE_STATE_REFILL       = 3'b010,
        DCACHE_STATE_EVICT        = 3'b011,
        DCACHE_STATE_WAIT         = 3'b100,
        DCACHE_STATE_REFILL_DRAIN = 3'b101,
        DCACHE_STATE_NC_READ      = 3'b110,
        DCACHE_STATE_NC_WRITE     = 3'b111;

    wire fence_flush = fence_type[0];
    wire fence_inval = fence_type[1];
    wire fence_any   = |fence_type;

    // =========================================================================
    // [FIX-1] Separate evict_start sources — OR them together
    // =========================================================================
    reg flush_evict_start;  // from flush FSM
    reg main_evict_start;   // from main FSM sequential output
    assign evict_start = flush_evict_start | main_evict_start;

    // [FIX-NC-DOUBLE] 1-cycle guard: NC_WRITE/NC_READ return to IDLE while
    // cpu_req still holds old instruction (CPU pipeline stall release has
    // 1-cycle latency). This flag blocks re-issue for exactly 1 cycle.
    reg nc_just_completed;

    // =========================================================================
    // [FIX-2] Separate tag_dirty_clear / tag_dirty_set sources
    // =========================================================================
    reg flush_dirty_clear;
    reg main_dirty_clear;
    reg main_dirty_set;
    assign tag_dirty_clear = flush_dirty_clear | main_dirty_clear;
    assign tag_dirty_set   = main_dirty_set;

    // =========================================================================
    // [FIX-FLUSH-BITMAP] Shadow dirty bitmap
    // =========================================================================
    reg [63:0] dirty_bitmap;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dirty_bitmap <= 64'h0;
        end else begin
            if (tag_flush_all || tag_invalidate_all) begin
                dirty_bitmap <= 64'h0;
            end else begin
                if (main_dirty_set)
                    dirty_bitmap[tag_dirty_index] <= 1'b1;
                if (tag_dirty_clear)
                    dirty_bitmap[tag_dirty_index] <= 1'b0;
            end
        end
    end

    // Priority encoder
    reg [5:0]  flush_next_dirty_index;
    reg        flush_has_dirty;

    integer pe_i;
    always @(*) begin
        flush_next_dirty_index = 6'd0;
        flush_has_dirty        = 1'b0;
        for (pe_i = 63; pe_i >= 0; pe_i = pe_i - 1) begin
            if (dirty_bitmap[pe_i]) begin
                flush_next_dirty_index = pe_i[5:0];
                flush_has_dirty        = 1'b1;
            end
        end
    end

    // =========================================================================
    // Flush FSM
    // =========================================================================
    reg [2:0] flush_state;
    reg [5:0] flush_index;
    reg       flush_need_inval;
    reg       flush_busy;

    reg [31:0] cur_addr;
    reg [31:0] cur_wdata;
    reg [3:0]  cur_wstrb;
    reg        cur_we;

    assign current_addr  = cur_addr;
    assign current_data  = cur_wdata;
    assign current_valid = (state != DCACHE_STATE_IDLE);

    reg [2:0] state, next_state;

    wire addr_is_nc = (cpu_addr[31:29] != 3'b000);

    wire        idle_hit_check = (state == DCACHE_STATE_IDLE)
                                 && cpu_req && !fence_any && !flush_busy;

    wire [31:0] lookup_addr   = idle_hit_check ? cpu_addr : cur_addr;
    wire [21:0] lookup_tag_w  = lookup_addr[31:10];
    wire [5:0]  lookup_index  = lookup_addr[9:4];
    wire [1:0]  lookup_offset = lookup_addr[3:2];

    wire [21:0] cur_tag    = cur_addr[31:10];
    wire [5:0]  cur_index  = cur_addr[9:4];
    wire [1:0]  cur_offset = cur_addr[3:2];

    assign tag_lookup_index = flush_busy ? flush_index : lookup_index;
    assign tag_lookup_tag   = flush_busy ? 22'h0       : lookup_tag_w;

    assign data_read_index     = flush_busy ? flush_index : lookup_index;
    assign data_read_offset    = lookup_offset;
    assign data_read_all_index = flush_busy ? flush_index : cur_index;

    // =========================================================================
    // [FIX-BUG-IDLE-HIT] Guard tag_hit trong IDLE
    // =========================================================================
    reg [5:0]  prev_lookup_index;
    reg [21:0] prev_lookup_tag;
    reg        prev_was_idle_hit_check;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            prev_lookup_index       <= 6'h0;
            prev_lookup_tag         <= 22'h0;
            prev_was_idle_hit_check <= 1'b0;
        end else begin
            prev_lookup_index       <= tag_lookup_index;
            prev_lookup_tag         <= lookup_tag_w;
            prev_was_idle_hit_check <= idle_hit_check;
        end
    end

    wire idle_tag_hit_valid = prev_was_idle_hit_check
                              && (lookup_index == prev_lookup_index)
                              && (lookup_tag_w == prev_lookup_tag)
                              && !flush_busy;

    wire idle_hit = tag_hit && idle_tag_hit_valid;

    // =========================================================================
    // tag_lookup_stable cho LOOKUP state
    // =========================================================================
    reg tag_lookup_stable;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            tag_lookup_stable <= 1'b0;
        else if (state == DCACHE_STATE_IDLE)
            tag_lookup_stable <= 1'b0;
        else if (state == DCACHE_STATE_LOOKUP)
            tag_lookup_stable <= 1'b1;
        else
            tag_lookup_stable <= 1'b0;
    end

    reg [5:0]  refill_index_r;
    reg [21:0] refill_tag_r;
    reg [1:0]  requested_offset;
    reg [31:0] requested_data;
    reg        requested_data_ready;
    reg [5:0]  evict_index_r;
    reg        pending_write;
    reg        do_deferred_write;
    reg [1:0]  deferred_offset;
    reg [31:0] deferred_wdata;
    reg [3:0]  deferred_wstrb;
    reg [5:0]  deferred_index;

    // =========================================================================
    // Main FSM — sequential state
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            state <= DCACHE_STATE_IDLE;
        else
            state <= next_state;
    end

    // =========================================================================
    // Main FSM — combinational next-state
    // =========================================================================
    always @(*) begin
        next_state = state;
        case (state)

            DCACHE_STATE_IDLE: begin
                if (!flush_busy && cpu_req && !fence_any && !nc_just_completed) begin
                    if (addr_is_nc)
                        next_state = cpu_we ? DCACHE_STATE_NC_WRITE
                                            : DCACHE_STATE_NC_READ;
                    else if (idle_hit)
                        next_state = DCACHE_STATE_IDLE;
                    else
                        next_state = DCACHE_STATE_LOOKUP;
                end
            end

            DCACHE_STATE_LOOKUP: begin
                if (tag_lookup_stable) begin
                    if (tag_hit)
                        next_state = DCACHE_STATE_IDLE;
                    else if (tag_dirty_out)
                        next_state = DCACHE_STATE_EVICT;
                    else
                        next_state = DCACHE_STATE_REFILL;
                end
            end

            DCACHE_STATE_EVICT: begin
                if (evict_done) next_state = DCACHE_STATE_WAIT;
            end

            DCACHE_STATE_WAIT: begin
                next_state = DCACHE_STATE_REFILL;
            end

            DCACHE_STATE_REFILL: begin
                if (!cur_we && refill_data_valid && (refill_word == requested_offset)) begin
                    if (refill_done) next_state = DCACHE_STATE_IDLE;
                    else             next_state = DCACHE_STATE_REFILL_DRAIN;
                end else if (cur_we && refill_done) begin
                    next_state = DCACHE_STATE_IDLE;
                end else if (!cur_we && refill_done && requested_data_ready) begin
                    next_state = DCACHE_STATE_IDLE;
                end
            end

            DCACHE_STATE_REFILL_DRAIN: begin
                if (refill_done) next_state = DCACHE_STATE_IDLE;
            end

            DCACHE_STATE_NC_READ: begin
                if (refill_done) next_state = DCACHE_STATE_IDLE;
            end

            DCACHE_STATE_NC_WRITE: begin
                if (evict_done) next_state = DCACHE_STATE_IDLE;
            end

            default: next_state = DCACHE_STATE_IDLE;
        endcase
    end

    // =========================================================================
    // CPU output — combinational
    // =========================================================================
    reg        cpu_ready_int;
    reg [31:0] cpu_rdata_int;

    always @(*) begin
        cpu_ready_int = 1'b0;
        cpu_rdata_int = 32'h0;

        if (!flush_busy) begin
            case (state)
                DCACHE_STATE_IDLE: begin
                    if (cpu_req && idle_hit && !fence_any) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = cpu_we ? 32'h0 : data_read_data;
                    end
                end

                DCACHE_STATE_LOOKUP: begin
                    if (tag_lookup_stable && tag_hit) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = cur_we ? 32'h0 : data_read_data;
                    end
                end

                DCACHE_STATE_REFILL: begin
                    if (!cur_we && refill_data_valid && (refill_word == requested_offset)) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = refill_data;
                    end else if (cur_we && refill_done) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = 32'h0;
                    end else if (!cur_we && refill_done && requested_data_ready) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = requested_data;
                    end
                end

                DCACHE_STATE_REFILL_DRAIN: ;

                DCACHE_STATE_NC_READ: begin
                    if (refill_done) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = refill_data;
                    end
                end

                DCACHE_STATE_NC_WRITE: begin
                    if (evict_done) begin
                        cpu_ready_int = 1'b1;
                        cpu_rdata_int = 32'h0;
                    end
                end

                default: ;
            endcase
        end
    end

    assign cpu_ready = cpu_ready_int;
    assign cpu_rdata = cpu_rdata_int;

    // =========================================================================
    // Flush FSM — sequential
    // [FIX-3] Start on fence_any (not just fence_flush)
    //   If fence_inval only (no flush needed), skip to FLUSH_DONE directly.
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            flush_state        <= `FLUSH_IDLE;
            flush_index        <= 6'h0;
            flush_need_inval   <= 1'b0;
            flush_busy         <= 1'b0;
            flush_evict_start  <= 1'b0;  // [FIX-1]
        end else begin
            flush_evict_start <= 1'b0;  // default: deassert each cycle

            case (flush_state)

                `FLUSH_IDLE: begin
                    // [FIX-3] trigger on any fence (flush or invalidate)
                    if (fence_any) begin
                        flush_need_inval <= fence_inval;
                        flush_busy       <= 1'b1;
                        // If invalidate-only (no dirty writeback needed), skip scan
                        if (!fence_flush)
                            flush_state <= `FLUSH_DONE;
                        else
                            flush_state <= `FLUSH_SCAN;
                    end
                end

                `FLUSH_SCAN: begin
                    if (!flush_has_dirty) begin
                        flush_state <= `FLUSH_DONE;
                    end else begin
                        flush_index <= flush_next_dirty_index;
                        flush_state <= `FLUSH_SETTLE;
                    end
                end

                `FLUSH_SETTLE: begin
                    evict_index_r <= flush_index;
                    // data_array is combinational: latch data NOW
                    evict_data_0 <= data_read_word_0;
                    evict_data_1 <= data_read_word_1;
                    evict_data_2 <= data_read_word_2;
                    evict_data_3 <= data_read_word_3;
                    flush_state  <= `FLUSH_TAG_WAIT;
                end

                // [FIX-FLUSH-TAG-WAIT] tag_array registered output now valid
                // [FIX-1] pulse flush_evict_start here (not main evict_start)
                `FLUSH_TAG_WAIT: begin
                    evict_addr        <= {tag_evict_tag_out, flush_index, 4'b0000};
                    flush_evict_start <= 1'b1;   // [FIX-1] dedicated signal
                    flush_state       <= `FLUSH_EVICT;
                end

                `FLUSH_EVICT: begin
                    // flush_evict_start already cleared by default above
                    if (evict_done) begin
                        dirty_bitmap[evict_index_r] <= 1'b0;
                        flush_state <= `FLUSH_SCAN;
                    end
                end

                `FLUSH_DONE: begin
                    flush_busy  <= 1'b0;
                    flush_state <= `FLUSH_IDLE;
                end

                default: flush_state <= `FLUSH_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Sequential Output Logic — Main FSM
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cur_addr             <= 32'h0;
            cur_wdata            <= 32'h0;
            cur_wstrb            <= 4'h0;
            cur_we               <= 1'b0;
            refill_addr          <= 32'h0;
            refill_start         <= 1'b0;
            refill_nc            <= 1'b0;
            refill_index_r       <= 6'h0;
            refill_tag_r         <= 22'h0;
            requested_offset     <= 2'b00;
            requested_data       <= 32'h0;
            requested_data_ready <= 1'b0;
            evict_addr           <= 32'h0;
            evict_data_0         <= 32'h0;
            evict_data_1         <= 32'h0;
            evict_data_2         <= 32'h0;
            evict_data_3         <= 32'h0;
            main_evict_start     <= 1'b0;  // [FIX-1]
            nc_just_completed    <= 1'b0;  // [FIX-NC-DOUBLE]
            evict_index_r        <= 6'h0;
            evict_nc             <= 1'b0;
            evict_wstrb_nc       <= 4'h0;
            pending_write        <= 1'b0;
            do_deferred_write    <= 1'b0;
            deferred_offset      <= 2'b00;
            deferred_wdata       <= 32'h0;
            deferred_wstrb       <= 4'h0;
            deferred_index       <= 6'h0;
            tag_update_valid     <= 1'b0;
            tag_update_index     <= 6'h0;
            tag_update_tag       <= 22'h0;
            tag_flush_all        <= 1'b0;
            tag_invalidate_all   <= 1'b0;
            main_dirty_set       <= 1'b0;   // [FIX-2]
            main_dirty_clear     <= 1'b0;   // [FIX-2]
            flush_dirty_clear    <= 1'b0;   // [FIX-2]
            tag_dirty_index      <= 6'h0;
            data_write_enable    <= 1'b0;
            data_write_index     <= 6'h0;
            data_write_offset    <= 2'b00;
            data_write_data      <= 32'h0;
            data_write_strb      <= 4'h0;
            stat_hits            <= 32'h0;
            stat_misses          <= 32'h0;
            stat_writes          <= 32'h0;
        end else begin
            // Pulse defaults
            refill_start       <= 1'b0;
            refill_nc          <= 1'b0;
            main_evict_start   <= 1'b0;   // [FIX-1]
            evict_nc           <= 1'b0;
            nc_just_completed  <= 1'b0;   // [FIX-NC-DOUBLE]
            tag_update_valid   <= 1'b0;
            tag_flush_all      <= 1'b0;
            tag_invalidate_all <= 1'b0;
            main_dirty_set     <= 1'b0;   // [FIX-2]
            main_dirty_clear   <= 1'b0;   // [FIX-2]
            flush_dirty_clear  <= 1'b0;   // [FIX-2]
            data_write_enable  <= 1'b0;
            do_deferred_write  <= 1'b0;

            // ── Flush FSM outputs ─────────────────────────────────────────────
            case (flush_state)

                `FLUSH_EVICT: begin
                    // [FIX-2] Use flush_dirty_clear instead of tag_dirty_clear
                    if (evict_done) begin
                        flush_dirty_clear <= 1'b1;
                        tag_dirty_index   <= evict_index_r;
                    end
                end

                `FLUSH_DONE: begin
                    tag_flush_all <= flush_need_inval ? 1'b0 : fence_flush;
                    // [FIX-3] Always assert invalidate_all if needed
                    if (flush_need_inval)
                        tag_invalidate_all <= 1'b1;
                    else if (fence_flush)
                        tag_flush_all <= 1'b1;
                end

                default: ;
            endcase

            // ── Main FSM outputs ──────────────────────────────────────────────
            if (!flush_busy) begin
                case (state)

                    DCACHE_STATE_IDLE: begin
                        requested_data_ready <= 1'b0;
                        pending_write        <= 1'b0;

                        // [FIX-TC3] deferred pending write
                        if (do_deferred_write) begin
                            data_write_enable <= 1'b1;
                            data_write_index  <= deferred_index;
                            data_write_offset <= deferred_offset;
                            data_write_data   <= deferred_wdata;
                            data_write_strb   <= deferred_wstrb;
                            do_deferred_write <= 1'b0;
                        end

                        if (cpu_req && !fence_any && !nc_just_completed) begin  // [FIX-NC-DOUBLE]
                            cur_addr  <= cpu_addr;
                            cur_wdata <= cpu_wdata;
                            cur_wstrb <= cpu_wstrb;
                            cur_we    <= cpu_we;

                            if (addr_is_nc) begin
                                if (cpu_we) begin
                                    evict_addr       <= cpu_addr;
                                    evict_data_0     <= cpu_wdata;
                                    evict_data_1     <= 32'h0;
                                    evict_data_2     <= 32'h0;
                                    evict_data_3     <= 32'h0;
                                    evict_nc         <= 1'b1;
                                    evict_wstrb_nc   <= cpu_wstrb;
                                    main_evict_start <= 1'b1;  // [FIX-1]
                                    stat_writes      <= stat_writes + 1;
                                end else begin
                                    refill_addr  <= cpu_addr;
                                    refill_nc    <= 1'b1;
                                    refill_start <= 1'b1;
                                end
                            end else if (idle_hit) begin
                                if (cpu_we) begin
                                    stat_writes       <= stat_writes + 1;
                                    stat_hits         <= stat_hits + 1;
                                    data_write_enable <= 1'b1;
                                    data_write_index  <= lookup_index;
                                    data_write_offset <= lookup_offset;
                                    data_write_data   <= cpu_wdata;
                                    data_write_strb   <= cpu_wstrb;
                                    main_dirty_set    <= 1'b1;  // [FIX-2]
                                    tag_dirty_index   <= lookup_index;
                                end else begin
                                    stat_hits <= stat_hits + 1;
                                end
                            end
                        end
                    end

                    DCACHE_STATE_LOOKUP: begin
                        if (tag_lookup_stable) begin
                            if (tag_hit) begin
                                if (cur_we) begin
                                    stat_writes       <= stat_writes + 1;
                                    stat_hits         <= stat_hits + 1;
                                    data_write_enable <= 1'b1;
                                    data_write_index  <= cur_index;
                                    data_write_offset <= cur_offset;
                                    data_write_data   <= cur_wdata;
                                    data_write_strb   <= cur_wstrb;
                                    main_dirty_set    <= 1'b1;  // [FIX-2]
                                    tag_dirty_index   <= cur_index;
                                end else begin
                                    stat_hits <= stat_hits + 1;
                                end
                            end else begin
                                stat_misses <= stat_misses + 1;
                                if (cur_we) stat_writes <= stat_writes + 1;

                                refill_index_r   <= cur_index;
                                refill_tag_r     <= cur_tag;
                                requested_offset <= cur_offset;
                                pending_write    <= cur_we;

                                if (tag_dirty_out) begin
                                    evict_addr       <= {tag_evict_tag_out, cur_index, 4'b0000};
                                    evict_data_0     <= data_read_word_0;
                                    evict_data_1     <= data_read_word_1;
                                    evict_data_2     <= data_read_word_2;
                                    evict_data_3     <= data_read_word_3;
                                    evict_index_r    <= cur_index;
                                    main_evict_start <= 1'b1;  // [FIX-1]
                                end else begin
                                    refill_addr  <= {cur_addr[31:4], 4'b0000};
                                    refill_start <= 1'b1;
                                end
                            end
                        end
                    end

                    DCACHE_STATE_EVICT: begin
                        if (evict_done) begin
                            main_dirty_clear <= 1'b1;  // [FIX-2]
                            tag_dirty_index  <= evict_index_r;
                        end
                    end

                    DCACHE_STATE_WAIT: begin
                        refill_addr  <= {cur_addr[31:4], 4'b0000};
                        refill_start <= 1'b1;
                    end

                    DCACHE_STATE_REFILL: begin
                        if (refill_data_valid) begin
                            data_write_enable <= 1'b1;
                            data_write_index  <= refill_index_r;
                            data_write_offset <= refill_word;
                            data_write_data   <= refill_data;
                            data_write_strb   <= 4'b1111;

                            if (refill_word == requested_offset && !requested_data_ready) begin
                                requested_data       <= refill_data;
                                requested_data_ready <= 1'b1;
                            end
                        end

                        if (refill_done) begin
                            tag_update_valid <= 1'b1;
                            tag_update_index <= refill_index_r;
                            tag_update_tag   <= refill_tag_r;

                            if (pending_write) begin
                                if (refill_data_valid) begin
                                    do_deferred_write <= 1'b1;
                                    deferred_index    <= refill_index_r;
                                    deferred_offset   <= requested_offset;
                                    deferred_wdata    <= cur_wdata;
                                    deferred_wstrb    <= cur_wstrb;
                                end else begin
                                    data_write_enable <= 1'b1;
                                    data_write_index  <= refill_index_r;
                                    data_write_offset <= requested_offset;
                                    data_write_data   <= cur_wdata;
                                    data_write_strb   <= cur_wstrb;
                                end
                                main_dirty_set  <= 1'b1;  // [FIX-2]
                                tag_dirty_index <= refill_index_r;
                                pending_write   <= 1'b0;
                            end
                        end
                    end

                    DCACHE_STATE_REFILL_DRAIN: begin
                        if (refill_data_valid) begin
                            data_write_enable <= 1'b1;
                            data_write_index  <= refill_index_r;
                            data_write_offset <= refill_word;
                            data_write_data   <= refill_data;
                            data_write_strb   <= 4'b1111;
                        end

                        if (refill_done) begin
                            tag_update_valid <= 1'b1;
                            tag_update_index <= refill_index_r;
                            tag_update_tag   <= refill_tag_r;
                        end
                    end

                    DCACHE_STATE_NC_READ: begin
                        // [FIX-NC-DOUBLE] signal completion so IDLE skips 1 cycle
                        if (refill_done) nc_just_completed <= 1'b1;
                    end
                    DCACHE_STATE_NC_WRITE: begin
                        // [FIX-NC-DOUBLE] signal completion so IDLE skips 1 cycle
                        if (evict_done) nc_just_completed <= 1'b1;
                    end

                    default: ;
                endcase
            end
        end
    end

endmodule


module dcache_top #(
    parameter CACHE_SIZE = 8192,
    parameter LINE_SIZE  = 16,
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input wire clk,
    input wire rst_n,

    // ========================================================================
    // CPU Interface
    // ========================================================================
    input  wire [ADDR_WIDTH-1:0] cpu_addr,
    input  wire [DATA_WIDTH-1:0] cpu_wdata,
    input  wire [3:0]            cpu_wstrb,
    input  wire                  cpu_req,
    input  wire                  cpu_we,
    output wire [DATA_WIDTH-1:0] cpu_rdata,
    output wire                  cpu_ready,
    // fence_type[0]=flush-dirty  fence_type[1]=invalidate-read
    input  wire [1:0]            fence_type,

    // Debug
    output wire [ADDR_WIDTH-1:0] current_addr,
    output wire [DATA_WIDTH-1:0] current_data,
    output wire                  current_valid,

    // ========================================================================
    // AXI4 Read Address Channel
    // ========================================================================
    output wire [ID_WIDTH-1:0]   mem_arid,
    output wire [ADDR_WIDTH-1:0] mem_araddr,
    output wire [7:0]            mem_arlen,
    output wire [2:0]            mem_arsize,
    output wire [1:0]            mem_arburst,
    output wire [2:0]            mem_arprot,
    output wire                  mem_arvalid,
    input  wire                  mem_arready,

    // AXI4 Read Data Channel
    input  wire [ID_WIDTH-1:0]   mem_rid,
    input  wire [DATA_WIDTH-1:0] mem_rdata,
    input  wire [1:0]            mem_rresp,
    input  wire                  mem_rlast,
    input  wire                  mem_rvalid,
    output wire                  mem_rready,

    // ========================================================================
    // AXI4 Write Address Channel
    // ========================================================================
    output wire [ID_WIDTH-1:0]   mem_awid,
    output wire [ADDR_WIDTH-1:0] mem_awaddr,
    output wire [7:0]            mem_awlen,
    output wire [2:0]            mem_awsize,
    output wire [1:0]            mem_awburst,
    output wire [2:0]            mem_awprot,
    output wire                  mem_awvalid,
    input  wire                  mem_awready,

    // AXI4 Write Data Channel
    output wire [DATA_WIDTH-1:0] mem_wdata,
    output wire [3:0]            mem_wstrb,
    output wire                  mem_wlast,
    output wire                  mem_wvalid,
    input  wire                  mem_wready,

    // AXI4 Write Response Channel
    input  wire [ID_WIDTH-1:0]   mem_bid,
    input  wire [1:0]            mem_bresp,
    input  wire                  mem_bvalid,
    output wire                  mem_bready,

    // ========================================================================
    // Statistics
    // ========================================================================
    output wire [31:0] stat_hits,
    output wire [31:0] stat_misses,
    output wire [31:0] stat_writes
);

    // ========================================================================
    // Internal Signals — Tag Array
    // ========================================================================
    wire [5:0]  tag_lookup_index;
    wire [21:0] tag_lookup_tag;
    wire        tag_hit;
    wire        tag_dirty_out;
    wire [21:0] tag_evict_tag_out;
    wire        tag_update_valid;
    wire [5:0]  tag_update_index;
    wire [21:0] tag_update_tag;
    wire        tag_flush_all;      // flush dirty lines (write-back) — fence w,w hoặc fence iorw
    wire        tag_invalidate_all; // xóa valid bits (invalidate)    — fence iorw hoặc fence.i
    wire        tag_dirty_set;
    wire        tag_dirty_clear;
    wire [5:0]  tag_dirty_index;

    // ========================================================================
    // Internal Signals — Data Array
    // ========================================================================
    wire [5:0]  data_read_index;
    wire [1:0]  data_read_offset;
    wire [31:0] data_read_data;
    wire [5:0]  data_read_all_index;
    wire [31:0] data_read_word_0;
    wire [31:0] data_read_word_1;
    wire [31:0] data_read_word_2;
    wire [31:0] data_read_word_3;
    wire        data_write_enable;
    wire [5:0]  data_write_index;
    wire [1:0]  data_write_offset;
    wire [31:0] data_write_data;
    wire [3:0]  data_write_strb;

    // ========================================================================
    // Internal Signals — AXI Refill / Eviction
    // ========================================================================
    wire [31:0] refill_addr;
    wire        refill_start;
    wire        refill_nc;       // [NC-BYPASS]
    wire        refill_busy;
    wire        refill_done;
    wire [31:0] refill_data;
    wire [1:0]  refill_word;
    wire        refill_data_valid;

    wire [31:0] evict_addr;
    wire [31:0] evict_data_0;
    wire [31:0] evict_data_1;
    wire [31:0] evict_data_2;
    wire [31:0] evict_data_3;
    wire        evict_start;
    wire        evict_nc;        // [NC-BYPASS]
    wire [3:0]  evict_wstrb_nc;  // [NC-BYPASS]
    wire        evict_busy;
    wire        evict_done;

    // ========================================================================
    // Sub-Modules
    // ========================================================================

    dcache_tag_array tag_array_inst (
        .clk            (clk),
        .rst_n          (rst_n),
        .lookup_index   (tag_lookup_index),
        .lookup_tag     (tag_lookup_tag),
        .hit            (tag_hit),
        .dirty_out      (tag_dirty_out),
        .evict_tag_out  (tag_evict_tag_out),
        .update_valid   (tag_update_valid),
        .update_index   (tag_update_index),
        .update_tag     (tag_update_tag),
        .dirty_set      (tag_dirty_set),
        .dirty_clear    (tag_dirty_clear),
        .dirty_index    (tag_dirty_index),
        .flush_all      (tag_flush_all),
        .invalidate_all (tag_invalidate_all)
    );

    dcache_data_array data_array_inst (
        .clk             (clk),
        .rst_n           (rst_n),
        .read_index      (data_read_index),
        .read_offset     (data_read_offset),
        .read_data       (data_read_data),
        .read_all_index  (data_read_all_index),
        .read_word_0     (data_read_word_0),
        .read_word_1     (data_read_word_1),
        .read_word_2     (data_read_word_2),
        .read_word_3     (data_read_word_3),
        .write_enable    (data_write_enable),
        .write_index     (data_write_index),
        .write_offset    (data_write_offset),
        .write_data      (data_write_data),
        .write_strb      (data_write_strb)
    );

    dcache_axi_interface #(.ID_WIDTH(ID_WIDTH)) axi_interface_inst (
        .clk               (clk),
        .rst_n             (rst_n),

        .refill_addr       (refill_addr),
        .refill_start      (refill_start),
        .refill_nc         (refill_nc),
        .refill_busy       (refill_busy),
        .refill_done       (refill_done),
        .refill_data       (refill_data),
        .refill_word       (refill_word),
        .refill_data_valid (refill_data_valid),

        .evict_addr        (evict_addr),
        .evict_data_0      (evict_data_0),
        .evict_data_1      (evict_data_1),
        .evict_data_2      (evict_data_2),
        .evict_data_3      (evict_data_3),
        .evict_start       (evict_start),
        .evict_nc          (evict_nc),
        .evict_wstrb_nc    (evict_wstrb_nc),
        .evict_busy        (evict_busy),
        .evict_done        (evict_done),

        .M_AXI_ARID        (mem_arid),
        .M_AXI_ARADDR      (mem_araddr),
        .M_AXI_ARLEN       (mem_arlen),
        .M_AXI_ARSIZE      (mem_arsize),
        .M_AXI_ARBURST     (mem_arburst),
        .M_AXI_ARPROT      (mem_arprot),
        .M_AXI_ARVALID     (mem_arvalid),
        .M_AXI_ARREADY     (mem_arready),
        .M_AXI_RID         (mem_rid),
        .M_AXI_RDATA       (mem_rdata),
        .M_AXI_RRESP       (mem_rresp),
        .M_AXI_RLAST       (mem_rlast),
        .M_AXI_RVALID      (mem_rvalid),
        .M_AXI_RREADY      (mem_rready),

        .M_AXI_AWID        (mem_awid),
        .M_AXI_AWADDR      (mem_awaddr),
        .M_AXI_AWLEN       (mem_awlen),
        .M_AXI_AWSIZE      (mem_awsize),
        .M_AXI_AWBURST     (mem_awburst),
        .M_AXI_AWPROT      (mem_awprot),
        .M_AXI_AWVALID     (mem_awvalid),
        .M_AXI_AWREADY     (mem_awready),
        .M_AXI_WDATA       (mem_wdata),
        .M_AXI_WSTRB       (mem_wstrb),
        .M_AXI_WLAST       (mem_wlast),
        .M_AXI_WVALID      (mem_wvalid),
        .M_AXI_WREADY      (mem_wready),
        .M_AXI_BID         (mem_bid),
        .M_AXI_BRESP       (mem_bresp),
        .M_AXI_BVALID      (mem_bvalid),
        .M_AXI_BREADY      (mem_bready)
    );

    dcache_controller controller_inst (
        .clk                (clk),
        .rst_n              (rst_n),

        .cpu_addr           (cpu_addr),
        .cpu_wdata          (cpu_wdata),
        .cpu_wstrb          (cpu_wstrb),
        .cpu_req            (cpu_req),
        .cpu_we             (cpu_we),
        .cpu_rdata          (cpu_rdata),
        .cpu_ready          (cpu_ready),
        .fence_type         (fence_type),

        .current_addr       (current_addr),
        .current_data       (current_data),
        .current_valid      (current_valid),

        .tag_lookup_index   (tag_lookup_index),
        .tag_lookup_tag     (tag_lookup_tag),
        .tag_hit            (tag_hit),
        .tag_dirty_out      (tag_dirty_out),
        .tag_evict_tag_out  (tag_evict_tag_out),
        .tag_update_valid   (tag_update_valid),
        .tag_update_index   (tag_update_index),
        .tag_update_tag     (tag_update_tag),
        .tag_flush_all      (tag_flush_all),
        .tag_invalidate_all (tag_invalidate_all),
        .tag_dirty_set      (tag_dirty_set),
        .tag_dirty_clear    (tag_dirty_clear),
        .tag_dirty_index    (tag_dirty_index),

        .data_read_index    (data_read_index),
        .data_read_offset   (data_read_offset),
        .data_read_data     (data_read_data),
        .data_write_enable  (data_write_enable),
        .data_write_index   (data_write_index),
        .data_write_offset  (data_write_offset),
        .data_write_data    (data_write_data),
        .data_write_strb    (data_write_strb),

        .data_read_all_index(data_read_all_index),
        .data_read_word_0   (data_read_word_0),
        .data_read_word_1   (data_read_word_1),
        .data_read_word_2   (data_read_word_2),
        .data_read_word_3   (data_read_word_3),

        .refill_addr        (refill_addr),
        .refill_start       (refill_start),
        .refill_nc          (refill_nc),
        .refill_busy        (refill_busy),
        .refill_done        (refill_done),
        .refill_data        (refill_data),
        .refill_word        (refill_word),
        .refill_data_valid  (refill_data_valid),

        .evict_addr         (evict_addr),
        .evict_data_0       (evict_data_0),
        .evict_data_1       (evict_data_1),
        .evict_data_2       (evict_data_2),
        .evict_data_3       (evict_data_3),
        .evict_start        (evict_start),
        .evict_nc           (evict_nc),
        .evict_wstrb_nc     (evict_wstrb_nc),
        .evict_busy         (evict_busy),
        .evict_done         (evict_done),

        .stat_hits          (stat_hits),
        .stat_misses        (stat_misses),
        .stat_writes        (stat_writes)
    );

endmodule

// ==============================================================================
// FILE: inst_mem_axi_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// inst_mem_axi_slave.v - AXI4 Full Slave (v5 - fixes)
// ============================================================================
// FIXES:
//
// [FIX-CRIT-3] AWREADY delay 1 cycle:
//   Gốc: S_AXI_AWREADY <= 1'b1 khi detect AWVALID (sequential → delay 1 cycle)
//   → Master fire-and-forget sẽ miss handshake.
//   Fix: S_AXI_AWREADY = combinational, HIGH khi wr_state == WR_IDLE.
//   Tương tự cách S_AXI_ARREADY đã làm (combinational assign).
//   SLVERR response vẫn đúng: AWREADY lên ngay, data được drain, BRESP=SLVERR.
//
// [FIX-WR-DATA-DRAIN] Khi AWREADY combinational, WREADY phải sẵn sàng ngay
//   cycle WR_DATA (không cần pre-assert trong WR_IDLE nữa).
//   Đơn giản hóa: WREADY = 1'b1 trong WR_DATA state.
//
// Các tính năng khác giữ nguyên từ v4.
// ============================================================================


// ==============================================================================
// FILE: inst_mem.v
// ==============================================================================

// `timescale 1ns/1ps

module inst_mem #(
    parameter MEM_SIZE      = 8192,
    parameter ADDR_WIDTH    = 32,
    parameter DATA_WIDTH    = 32,
    parameter MEM_INIT_FILE = ""
)(
    input wire clk,
    input wire rst_n,

    // Direct read — 1-cycle latency (registered BRAM output)
    input  wire [ADDR_WIDTH-1:0] PC,
    output wire [DATA_WIDTH-1:0] Instruction_Code,

    // Burst Read Interface
    input  wire [ADDR_WIDTH-1:0] burst_addr,
    input  wire [7:0]            burst_len,
    input  wire                  burst_req,
    output wire [DATA_WIDTH-1:0] burst_data,
    output reg                   burst_valid,
    output reg                   burst_last,
    input  wire                  burst_ready,

    // Write port (boot sideband + AXI write path)
    input  wire                    wr_en,
    input  wire [ADDR_WIDTH-1:0]   wr_addr,
    input  wire [DATA_WIDTH-1:0]   wr_data,
    input  wire [DATA_WIDTH/8-1:0] wr_strb
);

    localparam MEM_DEPTH = MEM_SIZE / (DATA_WIDTH/8);
    localparam ADDR_LSB  = $clog2(DATA_WIDTH/8);
    localparam ADDR_BITS = $clog2(MEM_DEPTH);

    // (* ram_style = "block" *)   // uncomment để force BRAM trên Vivado
    reg [DATA_WIDTH-1:0] memory [0:MEM_DEPTH-1];

    // =========================================================================
    // Write port — synchronous byte-enable
    // =========================================================================
    wire [ADDR_BITS-1:0] wr_word_addr = wr_addr[ADDR_BITS+ADDR_LSB-1 : ADDR_LSB];

    integer b;
    always @(posedge clk) begin
        if (wr_en)
            for (b = 0; b < DATA_WIDTH/8; b = b + 1)
                if (wr_strb[b])
                    memory[wr_word_addr][b*8 +: 8] <= wr_data[b*8 +: 8];
    end

    // =========================================================================
    // Burst FSM
    // =========================================================================
    localparam BURST_IDLE   = 1'b0;
    localparam BURST_ACTIVE = 1'b1;

    reg        burst_state;
    reg [ADDR_WIDTH-1:0] current_addr;
    reg [7:0]  beat_count;
    reg [7:0]  total_beats;

    wire [ADDR_WIDTH-1:0] next_addr    = current_addr + (DATA_WIDTH/8);
    wire                  next_is_last = (beat_count + 8'd1 == total_beats);

    // =========================================================================
    // BRAM read — single registered port, 1-cycle latency
    //
    // Address presented at posedge T → data available at T+1.
    // Timing aligns naturally with burst_valid (both set via registered assign):
    //   T   : burst_req=1  → BRAM samples burst_addr, FSM sets burst_valid<=1
    //   T+1 : burst_valid=1, bram_dout = memory[burst_addr]  ✓
    //
    // When advancing (beat N accepted at T_N): present next_addr to BRAM at T_N
    // so data for beat N+1 is ready at T_N+1 when burst_valid still=1.
    // =========================================================================

    // advance=1 at posedge T_N → we need next beat's address at T_N for BRAM
    wire advance = (burst_state == BURST_ACTIVE) && burst_valid && burst_ready && !burst_last;

    wire [ADDR_WIDTH-1:0] bram_addr_sel;
    assign bram_addr_sel = (burst_state == BURST_IDLE && burst_req) ? burst_addr :
                           advance                                   ? next_addr  :
                           (burst_state == BURST_ACTIVE)             ? current_addr :
                                                                       PC;

    wire [ADDR_BITS-1:0] bram_word_addr = bram_addr_sel[ADDR_BITS+ADDR_LSB-1 : ADDR_LSB];

    reg [DATA_WIDTH-1:0] bram_dout;
    always @(posedge clk)
        bram_dout <= memory[bram_word_addr];

    assign burst_data       = bram_dout;
    assign Instruction_Code = bram_dout;   // 1-cycle latency (vestigial port — ICache sits in front)

    // =========================================================================
    // FSM state update
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            burst_state  <= BURST_IDLE;
            burst_valid  <= 1'b0;
            burst_last   <= 1'b0;
            current_addr <= {ADDR_WIDTH{1'b0}};
            beat_count   <= 8'd0;
            total_beats  <= 8'd0;
        end else begin
            case (burst_state)

                BURST_IDLE: begin
                    if (burst_req) begin
                        current_addr <= burst_addr;
                        beat_count   <= 8'd0;
                        total_beats  <= burst_len;
                        burst_state  <= BURST_ACTIVE;
                        burst_valid  <= 1'b1;
                        burst_last   <= (burst_len == 8'd0);
                    end else begin
                        burst_valid  <= 1'b0;
                        burst_last   <= 1'b0;
                    end
                end

                BURST_ACTIVE: begin
                    if (burst_ready && burst_valid) begin
                        if (burst_last) begin
                            burst_state <= BURST_IDLE;
                            burst_valid <= 1'b0;
                            burst_last  <= 1'b0;
                        end else begin
                            beat_count   <= beat_count + 8'd1;
                            current_addr <= next_addr;
                            burst_valid  <= 1'b1;
                            burst_last   <= next_is_last;
                        end
                    end
                end

                default: burst_state <= BURST_IDLE;

            endcase
        end
    end

    // =========================================================================
    // Memory init — NOP fill (boot_ctrl loads actual program at runtime)
    // =========================================================================
    integer i;
    initial begin
        for (i = 0; i < MEM_DEPTH; i = i + 1)
            memory[i] = 32'h00000013;
    end

endmodule

module inst_mem_axi_slave #(
    parameter ADDR_WIDTH    = 32,
    parameter DATA_WIDTH    = 32,
    parameter ID_WIDTH      = 4,
    parameter MEM_SIZE      = 4096,
    parameter MEM_INIT_FILE = ""   // unused — boot_ctrl loads at runtime
)(
    input wire clk,
    input wire rst_n,

    // ── Boot sideband write port (from boot_ctrl, bypasses crossbar) ─────────
    input  wire                    boot_we,
    input  wire [ADDR_WIDTH-1:0]   boot_addr,
    input  wire [DATA_WIDTH-1:0]   boot_wdata,

    // Write channels (now writable — used by JTAG debugger via AXI)
    input  wire [ID_WIDTH-1:0]     S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]   S_AXI_AWADDR,
    input  wire [7:0]              S_AXI_AWLEN,
    input  wire [2:0]              S_AXI_AWSIZE,
    input  wire [1:0]              S_AXI_AWBURST,
    input  wire [2:0]              S_AXI_AWPROT,
    input  wire                    S_AXI_AWVALID,
    output wire                    S_AXI_AWREADY,  // [FIX-CRIT-3] combinational

    input  wire [DATA_WIDTH-1:0]   S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                    S_AXI_WLAST,
    input  wire                    S_AXI_WVALID,
    output wire                    S_AXI_WREADY,   // [FIX] combinational trong WR_DATA

    output reg  [ID_WIDTH-1:0]     S_AXI_BID,
    output reg  [1:0]              S_AXI_BRESP,
    output reg                     S_AXI_BVALID,
    input  wire                    S_AXI_BREADY,

    // Read channels
    input  wire [ID_WIDTH-1:0]     S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]   S_AXI_ARADDR,
    input  wire [7:0]              S_AXI_ARLEN,
    input  wire [2:0]              S_AXI_ARSIZE,
    input  wire [1:0]              S_AXI_ARBURST,
    input  wire [2:0]              S_AXI_ARPROT,
    input  wire                    S_AXI_ARVALID,
    output wire                    S_AXI_ARREADY,  // combinational (giữ nguyên)

    output wire [ID_WIDTH-1:0]     S_AXI_RID,
    output wire [DATA_WIDTH-1:0]   S_AXI_RDATA,
    output wire [1:0]              S_AXI_RRESP,
    output wire                    S_AXI_RLAST,
    output wire                    S_AXI_RVALID,
    input  wire                    S_AXI_RREADY
);

    localparam [1:0] RESP_OKAY   = 2'b00;
    localparam [1:0] RESP_SLVERR = 2'b10;

    // =========================================================================
    // Read State Machine
    // =========================================================================
    localparam RD_IDLE  = 1'b0;
    localparam RD_BURST = 1'b1;
    reg rd_state;

    assign S_AXI_ARREADY = (rd_state == RD_IDLE);
    wire ar_handshake    = S_AXI_ARVALID && S_AXI_ARREADY;
    wire burst_req       = ar_handshake;

    reg [ADDR_WIDTH-1:0] read_addr;
    reg [7:0]            burst_len_r;
    reg [ID_WIDTH-1:0]   rid_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            read_addr   <= {ADDR_WIDTH{1'b0}};
            burst_len_r <= 8'd0;
            rid_r       <= {ID_WIDTH{1'b0}};
        end else if (ar_handshake) begin
            read_addr   <= S_AXI_ARADDR;
            burst_len_r <= S_AXI_ARLEN;
            rid_r       <= S_AXI_ARID;
        end
    end

    assign S_AXI_RID = ar_handshake ? S_AXI_ARID : rid_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            rd_state <= RD_IDLE;
        else case (rd_state)
            RD_IDLE:  if (ar_handshake)                                  rd_state <= RD_BURST;
            RD_BURST: if (S_AXI_RVALID && S_AXI_RREADY && S_AXI_RLAST) rd_state <= RD_IDLE;
            default:  rd_state <= RD_IDLE;
        endcase
    end

    wire [ADDR_WIDTH-1:0] burst_addr = ar_handshake ? S_AXI_ARADDR : read_addr;
    wire [7:0]            burst_len  = ar_handshake ? S_AXI_ARLEN  : burst_len_r;

    wire [DATA_WIDTH-1:0] burst_data;
    wire                  burst_valid;
    wire                  burst_last;
    wire [DATA_WIDTH-1:0] simple_inst;

    // ── Write mux: boot sideband has priority, then AXI write ────────────────
    // boot_we is only active during boot (before cpu_rst_n releases).
    // AXI writes (JTAG debugger) only happen after boot_done, so no conflict.
    wire                    imem_wr_en;
    wire [ADDR_WIDTH-1:0]   imem_wr_addr;
    wire [DATA_WIDTH-1:0]   imem_wr_data;
    wire [DATA_WIDTH/8-1:0] imem_wr_strb;

    wire axi_wr_pulse;   // one-cycle write pulse from AXI write channel

    assign imem_wr_en   = boot_we | axi_wr_pulse;
    assign imem_wr_addr = boot_we ? boot_addr  : axi_wr_data_addr_r;
    assign imem_wr_data = boot_we ? boot_wdata : axi_wr_data_r;
    assign imem_wr_strb = boot_we ? {DATA_WIDTH/8{1'b1}} : axi_wr_strb_r;

    inst_mem #(
        .MEM_SIZE   (MEM_SIZE),
        .ADDR_WIDTH (ADDR_WIDTH),
        .DATA_WIDTH (DATA_WIDTH)
    ) imem (
        .clk              (clk),
        .rst_n            (rst_n),
        .PC               (burst_addr),
        .Instruction_Code (simple_inst),
        .burst_addr       (burst_addr),
        .burst_len        (burst_len),
        .burst_req        (burst_req),
        .burst_data       (burst_data),
        .burst_valid      (burst_valid),
        .burst_last       (burst_last),
        .burst_ready      (S_AXI_RREADY),
        .wr_en            (imem_wr_en),
        .wr_addr          (imem_wr_addr),
        .wr_data          (imem_wr_data),
        .wr_strb          (imem_wr_strb)
    );

    assign S_AXI_RDATA  = burst_data;
    assign S_AXI_RRESP  = RESP_OKAY;
    assign S_AXI_RLAST  = burst_last;
    assign S_AXI_RVALID = burst_valid;

    // =========================================================================
    // Write channels — writable SRAM (used by JTAG debugger to load programs)
    // [FIX-CRIT-3] Combinational AWREADY/WREADY
    // =========================================================================
    localparam [1:0] WR_IDLE = 2'b00,
                     WR_DATA = 2'b01,
                     WR_RESP = 2'b10;
    reg [1:0]               wr_state;
    reg [ID_WIDTH-1:0]      bid_r;
    reg [ADDR_WIDTH-1:0]    axi_wr_addr_r;
    reg [ADDR_WIDTH-1:0]    axi_wr_data_addr_r;  // [FIX-WR-ADDR] capture addr before increment
    reg [DATA_WIDTH-1:0]    axi_wr_data_r;
    reg [DATA_WIDTH/8-1:0]  axi_wr_strb_r;
    reg                     axi_wr_pulse_r;

    assign axi_wr_pulse = axi_wr_pulse_r;

    // [FIX-CRIT-3] AWREADY combinational: HIGH when WR_IDLE
    assign S_AXI_AWREADY = (wr_state == WR_IDLE);

    // [FIX] WREADY combinational: HIGH when WR_DATA
    assign S_AXI_WREADY  = (wr_state == WR_DATA);

    wire aw_handshake = S_AXI_AWVALID && S_AXI_AWREADY;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state        <= WR_IDLE;
            S_AXI_BID       <= {ID_WIDTH{1'b0}};
            S_AXI_BRESP     <= RESP_OKAY;
            S_AXI_BVALID    <= 1'b0;
            bid_r           <= {ID_WIDTH{1'b0}};
            axi_wr_addr_r      <= {ADDR_WIDTH{1'b0}};
            axi_wr_data_addr_r <= {ADDR_WIDTH{1'b0}};
            axi_wr_data_r      <= {DATA_WIDTH{1'b0}};
            axi_wr_strb_r      <= {DATA_WIDTH/8{1'b0}};
            axi_wr_pulse_r  <= 1'b0;
        end else begin
            axi_wr_pulse_r <= 1'b0;   // default: no write this cycle

            case (wr_state)
                WR_IDLE: begin
                    if (aw_handshake) begin
                        bid_r         <= S_AXI_AWID;
                        axi_wr_addr_r <= S_AXI_AWADDR;
                        wr_state      <= WR_DATA;
                    end
                end
                WR_DATA: begin
                    if (S_AXI_WVALID) begin
                        // Capture data and latch write address BEFORE advancing it
                        axi_wr_data_r      <= S_AXI_WDATA;
                        axi_wr_strb_r      <= S_AXI_WSTRB;
                        axi_wr_data_addr_r <= axi_wr_addr_r;  // [FIX-WR-ADDR] pre-increment capture
                        axi_wr_pulse_r     <= 1'b1;

                        if (S_AXI_WLAST) begin
                            S_AXI_BID    <= bid_r;
                            S_AXI_BRESP  <= RESP_OKAY;
                            S_AXI_BVALID <= 1'b1;
                            wr_state     <= WR_RESP;
                        end else begin
                            // Advance address for burst writes
                            axi_wr_addr_r <= axi_wr_addr_r + (DATA_WIDTH/8);
                        end
                    end
                end
                WR_RESP: begin
                    if (S_AXI_BREADY) begin
                        S_AXI_BVALID <= 1'b0;
                        wr_state     <= WR_IDLE;
                    end
                end
                default: wr_state <= WR_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Debug
    // =========================================================================
    `ifdef SIMULATION
    always @(posedge clk) begin
        if (ar_handshake)
            $display("[IMEM] Burst start: addr=0x%h len=%0d id=0x%h @ %0t",
                     S_AXI_ARADDR, S_AXI_ARLEN+1, S_AXI_ARID, $time);
        if (S_AXI_RVALID && S_AXI_RREADY)
            $display("[IMEM] Beat: data=0x%h last=%b rid=0x%h @ %0t",
                     S_AXI_RDATA, S_AXI_RLAST, S_AXI_RID, $time);
        if (aw_handshake)
            $display("[IMEM] AXI Write: addr=0x%h @ %0t", S_AXI_AWADDR, $time);
        if (boot_we)
            $display("[IMEM] Boot write: addr=0x%h data=0x%h @ %0t",
                     boot_addr, boot_wdata, $time);
    end
    `endif

endmodule
// ==============================================================================
// FILE: data_mem_axi_slave.v
// ==============================================================================

// `timescale 1ns/1ps


// ==============================================================================
// FILE: data_mem_burst.v
// ==============================================================================

// `timescale 1ns/1ps

module data_mem_burst #(
    parameter MEM_SIZE   = 8192,
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter BASE_ADDR  = 32'h10000000
)(
    input wire clk,
    input wire rst_n,

    // Burst Read Interface
    input  wire [ADDR_WIDTH-1:0] burst_rd_addr,
    input  wire [7:0]            burst_rd_len,
    input  wire                  burst_rd_req,
    output wire [DATA_WIDTH-1:0] burst_rd_data,
    output reg                   burst_rd_valid,
    output reg                   burst_rd_last,
    input  wire                  burst_rd_ready,

    // Burst Write Interface
    input  wire [ADDR_WIDTH-1:0] burst_wr_addr,
    input  wire [DATA_WIDTH-1:0] burst_wr_data,
    input  wire [3:0]            burst_wr_strb,
    input  wire                  burst_wr_valid,
    output wire                  burst_wr_ready,
    input  wire                  burst_wr_last
);
    localparam ADDR_LSB  = $clog2(DATA_WIDTH/8);
    localparam MEM_DEPTH = MEM_SIZE / (DATA_WIDTH/8);
    localparam ADDR_BITS = $clog2(MEM_DEPTH);

    // (* ram_style = "block" *)   // uncomment để force BRAM trên Vivado
    reg [DATA_WIDTH-1:0] memory [0:MEM_DEPTH-1];

    // =========================================================================
    // Burst Write — synchronous byte-enable write port
    //
    // burst_wr_addr (beat 0) comes from slave's write_addr register.
    // Subsequent beats: internal wr_current_addr tracks advancement.
    // BASE_ADDR assumed aligned to MEM_SIZE → lower ADDR_BITS+ADDR_LSB bits
    // give the local word index directly.
    // =========================================================================
    reg [ADDR_WIDTH-1:0] wr_current_addr;
    reg                  wr_first_beat;

    wire [ADDR_WIDTH-1:0] wr_eff_addr  = wr_first_beat ? burst_wr_addr : wr_current_addr;
    wire [ADDR_BITS-1:0]  wr_word_idx  = wr_eff_addr[ADDR_BITS+ADDR_LSB-1 : ADDR_LSB];

    assign burst_wr_ready = 1'b1;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_current_addr <= {ADDR_WIDTH{1'b0}};
            wr_first_beat   <= 1'b1;
        end else if (burst_wr_valid) begin
            if (!burst_wr_last) begin
                wr_current_addr <= wr_eff_addr + (DATA_WIDTH/8);
                wr_first_beat   <= 1'b0;
            end else begin
                wr_first_beat   <= 1'b1;
            end
        end
    end

    always @(posedge clk) begin
        if (burst_wr_valid) begin
            if (burst_wr_strb[0]) memory[wr_word_idx][7:0]   <= burst_wr_data[7:0];
            if (burst_wr_strb[1]) memory[wr_word_idx][15:8]  <= burst_wr_data[15:8];
            if (burst_wr_strb[2]) memory[wr_word_idx][23:16] <= burst_wr_data[23:16];
            if (burst_wr_strb[3]) memory[wr_word_idx][31:24] <= burst_wr_data[31:24];
        end
    end

    // =========================================================================
    // Burst Read — BRAM-compatible 1-cycle latency
    //
    // Address mux → BRAM samples at posedge T → burst_rd_data valid at T+1.
    // burst_rd_valid also set at T+1 → RVALID and RDATA aligned. ✓
    //
    // advance=1: present next beat address to BRAM at T so data ready at T+1.
    // hold (burst_rd_ready=0): present current_addr → BRAM re-reads same word.
    // =========================================================================
    localparam RD_IDLE   = 1'b0;
    localparam RD_ACTIVE = 1'b1;

    reg        rd_state;
    reg [ADDR_WIDTH-1:0] rd_current_addr;
    reg [7:0]  rd_beat_count;
    reg [7:0]  rd_total_beats;

    wire [ADDR_WIDTH-1:0] rd_next_addr  = rd_current_addr + (DATA_WIDTH/8);
    wire                  advance_rd    = (rd_state == RD_ACTIVE) && burst_rd_valid
                                          && burst_rd_ready && !burst_rd_last;

    wire [ADDR_WIDTH-1:0] bram_rd_sel;
    assign bram_rd_sel = (rd_state == RD_IDLE && burst_rd_req) ? burst_rd_addr  :
                         advance_rd                             ? rd_next_addr   :
                         (rd_state == RD_ACTIVE)               ? rd_current_addr :
                                                                  {ADDR_WIDTH{1'b0}};

    wire [ADDR_BITS-1:0] bram_rd_word = bram_rd_sel[ADDR_BITS+ADDR_LSB-1 : ADDR_LSB];

    reg [DATA_WIDTH-1:0] bram_rd_ff;
    always @(posedge clk)
        bram_rd_ff <= memory[bram_rd_word];

    assign burst_rd_data = bram_rd_ff;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state        <= RD_IDLE;
            burst_rd_valid  <= 1'b0;
            burst_rd_last   <= 1'b0;
            rd_current_addr <= {ADDR_WIDTH{1'b0}};
            rd_beat_count   <= 8'd0;
            rd_total_beats  <= 8'd0;
        end else begin
            case (rd_state)

                RD_IDLE: begin
                    if (burst_rd_req) begin
                        rd_current_addr <= burst_rd_addr;
                        rd_beat_count   <= 8'd0;
                        rd_total_beats  <= burst_rd_len;
                        rd_state        <= RD_ACTIVE;
                        burst_rd_valid  <= 1'b1;
                        burst_rd_last   <= (burst_rd_len == 8'd0);
                    end else begin
                        burst_rd_valid  <= 1'b0;
                        burst_rd_last   <= 1'b0;
                    end
                end

                RD_ACTIVE: begin
                    if (burst_rd_ready && burst_rd_valid) begin
                        if (burst_rd_last) begin
                            rd_state       <= RD_IDLE;
                            burst_rd_valid <= 1'b0;
                            burst_rd_last  <= 1'b0;
                        end else begin
                            rd_beat_count   <= rd_beat_count + 8'd1;
                            rd_current_addr <= rd_next_addr;
                            burst_rd_valid  <= 1'b1;
                            burst_rd_last   <= (rd_beat_count + 8'd1 == rd_total_beats);
                        end
                    end
                end

                default: rd_state <= RD_IDLE;

            endcase
        end
    end

    integer i;
    initial begin
        for (i = 0; i < MEM_DEPTH; i = i + 1)
            memory[i] = {DATA_WIDTH{1'b0}};
    end

endmodule

module data_mem_axi4_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter MEM_SIZE   = 8192
)(
    input wire clk,
    input wire rst_n,

    // Write Address Channel
    input  wire [ID_WIDTH-1:0]     S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]   S_AXI_AWADDR,
    input  wire [7:0]              S_AXI_AWLEN,
    input  wire [2:0]              S_AXI_AWSIZE,
    input  wire [1:0]              S_AXI_AWBURST,
    input  wire [2:0]              S_AXI_AWPROT,
    input  wire                    S_AXI_AWVALID,
    output wire                    S_AXI_AWREADY,

    // Write Data Channel
    input  wire [DATA_WIDTH-1:0]   S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                    S_AXI_WLAST,
    input  wire                    S_AXI_WVALID,
    output wire                    S_AXI_WREADY,   // combinational: wr_state == WR_BURST

    // Write Response Channel
    output reg  [ID_WIDTH-1:0]     S_AXI_BID,
    output reg  [1:0]              S_AXI_BRESP,
    output reg                     S_AXI_BVALID,
    input  wire                    S_AXI_BREADY,

    // Read Address Channel
    input  wire [ID_WIDTH-1:0]     S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]   S_AXI_ARADDR,
    input  wire [7:0]              S_AXI_ARLEN,
    input  wire [2:0]              S_AXI_ARSIZE,
    input  wire [1:0]              S_AXI_ARBURST,
    input  wire [2:0]              S_AXI_ARPROT,
    input  wire                    S_AXI_ARVALID,
    output wire                    S_AXI_ARREADY,

    // Read Data Channel
    output wire [ID_WIDTH-1:0]     S_AXI_RID,
    output wire [DATA_WIDTH-1:0]   S_AXI_RDATA,
    output wire [1:0]              S_AXI_RRESP,
    output wire                    S_AXI_RLAST,
    output wire                    S_AXI_RVALID,
    input  wire                    S_AXI_RREADY
);
    localparam [1:0] RESP_OKAY = 2'b00;

    // =========================================================================
    // Read State Machine
    // =========================================================================
    localparam [1:0] RD_IDLE  = 2'b00,
                     RD_BURST = 2'b01;
    reg [1:0] rd_state, rd_next;

    assign S_AXI_ARREADY = (rd_state == RD_IDLE);
    wire   ar_handshake  = S_AXI_ARVALID && S_AXI_ARREADY;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) rd_state <= RD_IDLE;
        else        rd_state <= rd_next;
    end

    always @(*) begin
        rd_next = rd_state;
        case (rd_state)
            RD_IDLE:  if (ar_handshake)                                   rd_next = RD_BURST;
            RD_BURST: if (S_AXI_RVALID && S_AXI_RREADY && S_AXI_RLAST)  rd_next = RD_IDLE;
            default:  rd_next = RD_IDLE;
        endcase
    end

    reg [ADDR_WIDTH-1:0] read_addr;
    reg [ID_WIDTH-1:0]   rd_id_latch;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            read_addr    <= {ADDR_WIDTH{1'b0}};
            rd_id_latch  <= {ID_WIDTH{1'b0}};
        end else if (ar_handshake) begin
            read_addr   <= S_AXI_ARADDR;
            rd_id_latch <= S_AXI_ARID;
        end
    end

    // burst_rd_req: combinational pulse → 1-cycle latency from AR handshake to RVALID
    wire burst_rd_req;
    assign burst_rd_req = ar_handshake;

    // burst_rd_addr: use S_AXI_ARADDR directly during handshake, registered otherwise
    wire [ADDR_WIDTH-1:0] burst_rd_addr;
    assign burst_rd_addr = ar_handshake ? S_AXI_ARADDR : read_addr;

    // =========================================================================
    // Write State Machine
    // =========================================================================
    localparam [2:0] WR_IDLE  = 3'b000,
                     WR_BURST = 3'b001,
                     WR_RESP  = 3'b010;
    reg [2:0] wr_state, wr_next;

    assign S_AXI_AWREADY = (wr_state == WR_IDLE);
    assign S_AXI_WREADY  = (wr_state == WR_BURST);  // combinational, no 1-cycle delay
    wire   aw_handshake  = S_AXI_AWVALID && S_AXI_AWREADY;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) wr_state <= WR_IDLE;
        else        wr_state <= wr_next;
    end

    always @(*) begin
        wr_next = wr_state;
        case (wr_state)
            WR_IDLE:  if (aw_handshake)                       wr_next = WR_BURST;
            WR_BURST: if (S_AXI_WVALID && S_AXI_WLAST)       wr_next = WR_RESP;
            WR_RESP:  if (S_AXI_BREADY && S_AXI_BVALID)      wr_next = WR_IDLE;
            default:  wr_next = WR_IDLE;
        endcase
    end

    reg [ADDR_WIDTH-1:0] write_addr;
    reg [ID_WIDTH-1:0]   wr_id_latch;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            write_addr  <= {ADDR_WIDTH{1'b0}};
            wr_id_latch <= {ID_WIDTH{1'b0}};
        end else if (aw_handshake) begin
            write_addr  <= S_AXI_AWADDR;
            wr_id_latch <= S_AXI_AWID;
        end
    end

    // burst_wr_valid: only when WREADY=1 (wr_state==WR_BURST), preventing W before AW
    wire burst_wr_valid = (wr_state == WR_BURST) && S_AXI_WVALID;

    // burst_wr_addr: use write_addr (registered AWADDR). Beat 0 uses write_addr directly;
    // data_mem_burst internally advances wr_current_addr for beats 1+.
    wire [ADDR_WIDTH-1:0] burst_wr_addr = write_addr;

    // Write Response
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            S_AXI_BRESP  <= RESP_OKAY;
            S_AXI_BVALID <= 1'b0;
            S_AXI_BID    <= {ID_WIDTH{1'b0}};
        end else begin
            case (wr_state)
                WR_BURST: begin
                    if (S_AXI_WVALID && S_AXI_WREADY && S_AXI_WLAST) begin
                        S_AXI_BRESP  <= RESP_OKAY;
                        S_AXI_BVALID <= 1'b1;
                        S_AXI_BID    <= wr_id_latch;
                    end
                end
                WR_RESP: begin
                    if (S_AXI_BREADY && S_AXI_BVALID)
                        S_AXI_BVALID <= 1'b0;
                end
                default: S_AXI_BVALID <= 1'b0;
            endcase
        end
    end

    // =========================================================================
    // Read outputs
    // =========================================================================
    wire [DATA_WIDTH-1:0] burst_rd_data;
    wire                  burst_rd_valid;
    wire                  burst_rd_last;

    assign S_AXI_RID    = rd_id_latch;
    assign S_AXI_RDATA  = burst_rd_data;
    assign S_AXI_RRESP  = RESP_OKAY;
    assign S_AXI_RLAST  = burst_rd_last;
    assign S_AXI_RVALID = burst_rd_valid;

    // =========================================================================
    // Data Memory Instance
    // =========================================================================
    data_mem_burst #(
        .MEM_SIZE  (MEM_SIZE),
        .ADDR_WIDTH(ADDR_WIDTH),
        .DATA_WIDTH(DATA_WIDTH)
    ) dmem (
        .clk            (clk),
        .rst_n          (rst_n),
        .burst_rd_addr  (burst_rd_addr),
        .burst_rd_len   (S_AXI_ARLEN),
        .burst_rd_req   (burst_rd_req),
        .burst_rd_data  (burst_rd_data),
        .burst_rd_valid (burst_rd_valid),
        .burst_rd_last  (burst_rd_last),
        .burst_rd_ready (S_AXI_RREADY),
        .burst_wr_addr  (burst_wr_addr),
        .burst_wr_data  (S_AXI_WDATA),
        .burst_wr_strb  (S_AXI_WSTRB),
        .burst_wr_valid (burst_wr_valid),
        .burst_wr_ready (),   // always 1 inside data_mem_burst
        .burst_wr_last  (S_AXI_WLAST)
    );

endmodule

// ==============================================================================
// FILE: axi4_crossbar_5m12s.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// axi4_crossbar_5m12s.v  —  AXI4 Non-blocking Crossbar (5 Master × 12 Slave)
// All `define macros expanded to plain Verilog for readability & tool compat.
//
// Slave address map:
//   S0:  IMEM      0x0000_0000  mask 0xFFFF_E000  (8 KB)
//   S1:  DMEM      0x1000_0000  mask 0xFFFF_E000  (8 KB)
//   S2:  ASCON     0x2000_0000  mask 0xFFFF_F000  (4 KB)
//   S3:  SOC CTRL  0x3000_0000  mask 0xFFFF_F000  (4 KB)
//   S4:  CLINT     0x4000_0000  mask 0xFFFF_0000  (64 KB)
//   S5:  UART      0x5000_0000  mask 0xFFFF_F000  (4 KB)
//   S6:  GPIO      0x5001_0000  mask 0xFFFF_F000  (4 KB)
//   S7:  SPI       0x5002_0000  mask 0xFFFF_F000  (4 KB)
//   S8:  Timer/WDT 0x5003_0000  mask 0xFFFF_F000  (4 KB)
//   S9:  PLIC      0x5004_0000  mask 0xFFFF_F000  (4 KB)
//   S10: OTP Ctrl  0x6000_0000  mask 0xFFFF_F000  (4 KB)
//   S11: DMA Ctrl  0x6001_0000  mask 0xFFFF_F000  (4 KB)
//   ERR: index 12 = DECERR (unmapped address)
// ============================================================================


// ==============================================================================
// FILE: axi4_addr_decoder.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// axi4_addr_decoder.v
// [Fix 6] Mở rộng lên 12 slave: S9=PLIC, S10=OTP, S11=DMA_CTRL
//         slave_sel 4-bit (0-11=slave, 12=DECERR)
// ============================================================================

module axi4_addr_decoder #(
    parameter NUM_SLAVES  = 12,
    parameter ADDR_WIDTH  = 32,
    parameter [ADDR_WIDTH-1:0] S0_BASE  = 32'h0000_0000, parameter [ADDR_WIDTH-1:0] S0_MASK  = 32'hFFFF_E000,
    parameter [ADDR_WIDTH-1:0] S1_BASE  = 32'h1000_0000, parameter [ADDR_WIDTH-1:0] S1_MASK  = 32'hFFFF_E000,
    parameter [ADDR_WIDTH-1:0] S2_BASE  = 32'h2000_0000, parameter [ADDR_WIDTH-1:0] S2_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S3_BASE  = 32'h3000_0000, parameter [ADDR_WIDTH-1:0] S3_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S4_BASE  = 32'h4000_0000, parameter [ADDR_WIDTH-1:0] S4_MASK  = 32'hFFFF_0000,
    parameter [ADDR_WIDTH-1:0] S5_BASE  = 32'h5000_0000, parameter [ADDR_WIDTH-1:0] S5_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S6_BASE  = 32'h5001_0000, parameter [ADDR_WIDTH-1:0] S6_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S7_BASE  = 32'h5002_0000, parameter [ADDR_WIDTH-1:0] S7_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S8_BASE  = 32'h5003_0000, parameter [ADDR_WIDTH-1:0] S8_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S9_BASE  = 32'h5004_0000, parameter [ADDR_WIDTH-1:0] S9_MASK  = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S10_BASE = 32'h6000_0000, parameter [ADDR_WIDTH-1:0] S10_MASK = 32'hFFFF_F000,
    parameter [ADDR_WIDTH-1:0] S11_BASE = 32'h6001_0000, parameter [ADDR_WIDTH-1:0] S11_MASK = 32'hFFFF_F000
)(
    input  wire [ADDR_WIDTH-1:0] addr,
    output reg  [3:0]            slave_sel   // 0-11=slave, 12=DECERR
);

    always @(*) begin
        slave_sel = NUM_SLAVES[3:0]; // default DECERR
        if      ((addr & S11_MASK) == S11_BASE) slave_sel = 4'd11;
        else if ((addr & S10_MASK) == S10_BASE) slave_sel = 4'd10;
        else if ((addr & S9_MASK)  == S9_BASE)  slave_sel = 4'd9;
        else if ((addr & S8_MASK)  == S8_BASE)  slave_sel = 4'd8;
        else if ((addr & S7_MASK)  == S7_BASE)  slave_sel = 4'd7;
        else if ((addr & S6_MASK)  == S6_BASE)  slave_sel = 4'd6;
        else if ((addr & S5_MASK)  == S5_BASE)  slave_sel = 4'd5;
        else if ((addr & S4_MASK)  == S4_BASE)  slave_sel = 4'd4;
        else if ((addr & S3_MASK)  == S3_BASE)  slave_sel = 4'd3;
        else if ((addr & S2_MASK)  == S2_BASE)  slave_sel = 4'd2;
        else if ((addr & S1_MASK)  == S1_BASE)  slave_sel = 4'd1;
        else if ((addr & S0_MASK)  == S0_BASE)  slave_sel = 4'd0;
    end

endmodule
// ==============================================================================
// FILE: axi4_master_mux_5m.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// axi4_master_mux_5m.v
// Arbitration + mux cho MỘT slave port — hỗ trợ 5 Master.
//
// Masters:
//   M0 = ICache    (priority 0 — cao nhất)
//   M1 = DCache    (priority 1)
//   M2 = ASCON DMA (priority 2)
//   M3 = DMA Ctrl  (priority 3)
//   M4 = JTAG DM   (priority 4 — thấp nhất)
//
// Quy tắc arbitration (Fixed Priority, no burst cut):
//   - Grant cho master priority cao nhất đang request ở trạng thái IDLE.
//   - Không cắt burst: giữ grant cho đến khi RLAST (read) hoặc B-handshake (write).
//   - M4 (JTAG) chỉ được grant khi M0..M3 đều idle — đảm bảo debug không
//     ảnh hưởng đến real-time pipeline.
//
// ID tagging: 3 bit cao của ID = master index (000=M0 .. 100=M4)
//   → Yêu cầu ID_WIDTH >= 4 (3 tag bits + ≥1 user bit).
//   → Với ID_WIDTH=4: user bits = ID[0], tag = ID[3:1]  ← không dùng vì
//     cần 3 tag bits. Thực tế tag = ID[ID_WIDTH-1:ID_WIDTH-3].
// ============================================================================

module axi4_master_mux_5m #(
    parameter ID_WIDTH   = 4,
    parameter DATA_WIDTH = 32,
    parameter ADDR_WIDTH = 32,
    parameter STRB_WIDTH = DATA_WIDTH / 8
)(
    input wire clk,
    input wire rst_n,

    // ========================================================================
    // Master 0 — ICache
    // ========================================================================
    input  wire [ID_WIDTH-1:0]   m0_arid,
    input  wire [ADDR_WIDTH-1:0] m0_araddr,
    input  wire [7:0]            m0_arlen,
    input  wire [2:0]            m0_arsize,
    input  wire [1:0]            m0_arburst,
    input  wire [2:0]            m0_arprot,
    input  wire                  m0_arvalid,
    output wire                  m0_arready,

    output wire [ID_WIDTH-1:0]   m0_rid,
    output wire [DATA_WIDTH-1:0] m0_rdata,
    output wire [1:0]            m0_rresp,
    output wire                  m0_rlast,
    output wire                  m0_rvalid,
    input  wire                  m0_rready,

    input  wire [ID_WIDTH-1:0]   m0_awid,
    input  wire [ADDR_WIDTH-1:0] m0_awaddr,
    input  wire [7:0]            m0_awlen,
    input  wire [2:0]            m0_awsize,
    input  wire [1:0]            m0_awburst,
    input  wire [2:0]            m0_awprot,
    input  wire                  m0_awvalid,
    output wire                  m0_awready,

    input  wire [DATA_WIDTH-1:0] m0_wdata,
    input  wire [STRB_WIDTH-1:0] m0_wstrb,
    input  wire                  m0_wlast,
    input  wire                  m0_wvalid,
    output wire                  m0_wready,

    output wire [ID_WIDTH-1:0]   m0_bid,
    output wire [1:0]            m0_bresp,
    output wire                  m0_bvalid,
    input  wire                  m0_bready,

    // ========================================================================
    // Master 1 — DCache
    // ========================================================================
    input  wire [ID_WIDTH-1:0]   m1_arid,
    input  wire [ADDR_WIDTH-1:0] m1_araddr,
    input  wire [7:0]            m1_arlen,
    input  wire [2:0]            m1_arsize,
    input  wire [1:0]            m1_arburst,
    input  wire [2:0]            m1_arprot,
    input  wire                  m1_arvalid,
    output wire                  m1_arready,

    output wire [ID_WIDTH-1:0]   m1_rid,
    output wire [DATA_WIDTH-1:0] m1_rdata,
    output wire [1:0]            m1_rresp,
    output wire                  m1_rlast,
    output wire                  m1_rvalid,
    input  wire                  m1_rready,

    input  wire [ID_WIDTH-1:0]   m1_awid,
    input  wire [ADDR_WIDTH-1:0] m1_awaddr,
    input  wire [7:0]            m1_awlen,
    input  wire [2:0]            m1_awsize,
    input  wire [1:0]            m1_awburst,
    input  wire [2:0]            m1_awprot,
    input  wire                  m1_awvalid,
    output wire                  m1_awready,

    input  wire [DATA_WIDTH-1:0] m1_wdata,
    input  wire [STRB_WIDTH-1:0] m1_wstrb,
    input  wire                  m1_wlast,
    input  wire                  m1_wvalid,
    output wire                  m1_wready,

    output wire [ID_WIDTH-1:0]   m1_bid,
    output wire [1:0]            m1_bresp,
    output wire                  m1_bvalid,
    input  wire                  m1_bready,

    // ========================================================================
    // Master 2 — ASCON DMA (64-bit via width converter → 32-bit)
    // ========================================================================
    input  wire [ID_WIDTH-1:0]   m2_arid,
    input  wire [ADDR_WIDTH-1:0] m2_araddr,
    input  wire [7:0]            m2_arlen,
    input  wire [2:0]            m2_arsize,
    input  wire [1:0]            m2_arburst,
    input  wire [2:0]            m2_arprot,
    input  wire                  m2_arvalid,
    output wire                  m2_arready,

    output wire [ID_WIDTH-1:0]   m2_rid,
    output wire [DATA_WIDTH-1:0] m2_rdata,
    output wire [1:0]            m2_rresp,
    output wire                  m2_rlast,
    output wire                  m2_rvalid,
    input  wire                  m2_rready,

    input  wire [ID_WIDTH-1:0]   m2_awid,
    input  wire [ADDR_WIDTH-1:0] m2_awaddr,
    input  wire [7:0]            m2_awlen,
    input  wire [2:0]            m2_awsize,
    input  wire [1:0]            m2_awburst,
    input  wire [2:0]            m2_awprot,
    input  wire                  m2_awvalid,
    output wire                  m2_awready,

    input  wire [DATA_WIDTH-1:0] m2_wdata,
    input  wire [STRB_WIDTH-1:0] m2_wstrb,
    input  wire                  m2_wlast,
    input  wire                  m2_wvalid,
    output wire                  m2_wready,

    output wire [ID_WIDTH-1:0]   m2_bid,
    output wire [1:0]            m2_bresp,
    output wire                  m2_bvalid,
    input  wire                  m2_bready,

    // ========================================================================
    // Master 3 — DMA Controller (multi-channel general purpose)
    // ========================================================================
    input  wire [ID_WIDTH-1:0]   m3_arid,
    input  wire [ADDR_WIDTH-1:0] m3_araddr,
    input  wire [7:0]            m3_arlen,
    input  wire [2:0]            m3_arsize,
    input  wire [1:0]            m3_arburst,
    input  wire [2:0]            m3_arprot,
    input  wire                  m3_arvalid,
    output wire                  m3_arready,

    output wire [ID_WIDTH-1:0]   m3_rid,
    output wire [DATA_WIDTH-1:0] m3_rdata,
    output wire [1:0]            m3_rresp,
    output wire                  m3_rlast,
    output wire                  m3_rvalid,
    input  wire                  m3_rready,

    input  wire [ID_WIDTH-1:0]   m3_awid,
    input  wire [ADDR_WIDTH-1:0] m3_awaddr,
    input  wire [7:0]            m3_awlen,
    input  wire [2:0]            m3_awsize,
    input  wire [1:0]            m3_awburst,
    input  wire [2:0]            m3_awprot,
    input  wire                  m3_awvalid,
    output wire                  m3_awready,

    input  wire [DATA_WIDTH-1:0] m3_wdata,
    input  wire [STRB_WIDTH-1:0] m3_wstrb,
    input  wire                  m3_wlast,
    input  wire                  m3_wvalid,
    output wire                  m3_wready,

    output wire [ID_WIDTH-1:0]   m3_bid,
    output wire [1:0]            m3_bresp,
    output wire                  m3_bvalid,
    input  wire                  m3_bready,

    // ========================================================================
    // Master 4 — JTAG Debug Module (system bus access)
    // ========================================================================
    input  wire [ID_WIDTH-1:0]   m4_arid,
    input  wire [ADDR_WIDTH-1:0] m4_araddr,
    input  wire [7:0]            m4_arlen,
    input  wire [2:0]            m4_arsize,
    input  wire [1:0]            m4_arburst,
    input  wire [2:0]            m4_arprot,
    input  wire                  m4_arvalid,
    output wire                  m4_arready,

    output wire [ID_WIDTH-1:0]   m4_rid,
    output wire [DATA_WIDTH-1:0] m4_rdata,
    output wire [1:0]            m4_rresp,
    output wire                  m4_rlast,
    output wire                  m4_rvalid,
    input  wire                  m4_rready,

    input  wire [ID_WIDTH-1:0]   m4_awid,
    input  wire [ADDR_WIDTH-1:0] m4_awaddr,
    input  wire [7:0]            m4_awlen,
    input  wire [2:0]            m4_awsize,
    input  wire [1:0]            m4_awburst,
    input  wire [2:0]            m4_awprot,
    input  wire                  m4_awvalid,
    output wire                  m4_awready,

    input  wire [DATA_WIDTH-1:0] m4_wdata,
    input  wire [STRB_WIDTH-1:0] m4_wstrb,
    input  wire                  m4_wlast,
    input  wire                  m4_wvalid,
    output wire                  m4_wready,

    output wire [ID_WIDTH-1:0]   m4_bid,
    output wire [1:0]            m4_bresp,
    output wire                  m4_bvalid,
    input  wire                  m4_bready,

    // ========================================================================
    // Slave Port
    // ========================================================================
    output wire [ID_WIDTH-1:0]   s_arid,
    output wire [ADDR_WIDTH-1:0] s_araddr,
    output wire [7:0]            s_arlen,
    output wire [2:0]            s_arsize,
    output wire [1:0]            s_arburst,
    output wire [2:0]            s_arprot,
    output wire                  s_arvalid,
    input  wire                  s_arready,

    input  wire [ID_WIDTH-1:0]   s_rid,
    input  wire [DATA_WIDTH-1:0] s_rdata,
    input  wire [1:0]            s_rresp,
    input  wire                  s_rlast,
    input  wire                  s_rvalid,
    output wire                  s_rready,

    output wire [ID_WIDTH-1:0]   s_awid,
    output wire [ADDR_WIDTH-1:0] s_awaddr,
    output wire [7:0]            s_awlen,
    output wire [2:0]            s_awsize,
    output wire [1:0]            s_awburst,
    output wire [2:0]            s_awprot,
    output wire                  s_awvalid,
    input  wire                  s_awready,

    output wire [DATA_WIDTH-1:0] s_wdata,
    output wire [STRB_WIDTH-1:0] s_wstrb,
    output wire                  s_wlast,
    output wire                  s_wvalid,
    input  wire                  s_wready,

    input  wire [ID_WIDTH-1:0]   s_bid,
    input  wire [1:0]            s_bresp,
    input  wire                  s_bvalid,
    output wire                  s_bready
);

    // ========================================================================
    // ID Tag constants — 3 bits → supports 8 masters (5 used)
    // ========================================================================
    localparam [2:0] TAG_M0 = 3'b000;
    localparam [2:0] TAG_M1 = 3'b001;
    localparam [2:0] TAG_M2 = 3'b010;
    localparam [2:0] TAG_M3 = 3'b011;
    localparam [2:0] TAG_M4 = 3'b100;

    // ========================================================================
    // Read Arbitration FSM — Fixed Priority M0 > M1 > M2 > M3 > M4
    // No burst cut: hold grant until RLAST
    // ========================================================================
    localparam [2:0] RD_IDLE = 3'd0,
                     RD_M0   = 3'd1,
                     RD_M1   = 3'd2,
                     RD_M2   = 3'd3,
                     RD_M3   = 3'd4,
                     RD_M4   = 3'd5;

    reg [2:0] rd_arb;

    // Next-state combinational helper
    function [2:0] rd_next_winner;
        input m0v, m1v, m2v, m3v, m4v;
        begin
            if      (m0v) rd_next_winner = RD_M0;
            else if (m1v) rd_next_winner = RD_M1;
            else if (m2v) rd_next_winner = RD_M2;
            else if (m3v) rd_next_winner = RD_M3;
            else if (m4v) rd_next_winner = RD_M4;
            else          rd_next_winner = RD_IDLE;
        end
    endfunction

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_arb <= RD_IDLE;
        end else begin
            case (rd_arb)
                RD_IDLE: rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                   m2_arvalid, m3_arvalid, m4_arvalid);
                RD_M0: if (s_rvalid && m0_rready && s_rlast)
                           rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                    m2_arvalid, m3_arvalid, m4_arvalid);
                RD_M1: if (s_rvalid && m1_rready && s_rlast)
                           rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                    m2_arvalid, m3_arvalid, m4_arvalid);
                RD_M2: if (s_rvalid && m2_rready && s_rlast)
                           rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                    m2_arvalid, m3_arvalid, m4_arvalid);
                RD_M3: if (s_rvalid && m3_rready && s_rlast)
                           rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                    m2_arvalid, m3_arvalid, m4_arvalid);
                RD_M4: if (s_rvalid && m4_rready && s_rlast)
                           rd_arb <= rd_next_winner(m0_arvalid, m1_arvalid,
                                                    m2_arvalid, m3_arvalid, m4_arvalid);
                default: rd_arb <= RD_IDLE;
            endcase
        end
    end

    wire rd_grant_m0 = (rd_arb == RD_M0) ||
                       (rd_arb == RD_IDLE && m0_arvalid);
    wire rd_grant_m1 = (rd_arb == RD_M1) ||
                       (rd_arb == RD_IDLE && !m0_arvalid && m1_arvalid);
    wire rd_grant_m2 = (rd_arb == RD_M2) ||
                       (rd_arb == RD_IDLE && !m0_arvalid && !m1_arvalid && m2_arvalid);
    wire rd_grant_m3 = (rd_arb == RD_M3) ||
                       (rd_arb == RD_IDLE && !m0_arvalid && !m1_arvalid &&
                        !m2_arvalid && m3_arvalid);
    wire rd_grant_m4 = (rd_arb == RD_M4) ||
                       (rd_arb == RD_IDLE && !m0_arvalid && !m1_arvalid &&
                        !m2_arvalid && !m3_arvalid && m4_arvalid);

    // ========================================================================
    // Write Arbitration FSM — Fixed Priority M0 > M1 > M2 > M3 > M4
    // No burst cut: hold grant until B-handshake
    // ========================================================================
    localparam [2:0] WR_IDLE = 3'd0,
                     WR_M0   = 3'd1,
                     WR_M1   = 3'd2,
                     WR_M2   = 3'd3,
                     WR_M3   = 3'd4,
                     WR_M4   = 3'd5;

    reg [2:0] wr_arb;

    function [2:0] wr_next_winner;
        input m0v, m1v, m2v, m3v, m4v;
        begin
            if      (m0v) wr_next_winner = WR_M0;
            else if (m1v) wr_next_winner = WR_M1;
            else if (m2v) wr_next_winner = WR_M2;
            else if (m3v) wr_next_winner = WR_M3;
            else if (m4v) wr_next_winner = WR_M4;
            else          wr_next_winner = WR_IDLE;
        end
    endfunction

    // Helper: which master's bready to check
    wire cur_bready = (wr_arb == WR_M0) ? m0_bready :
                      (wr_arb == WR_M1) ? m1_bready :
                      (wr_arb == WR_M2) ? m2_bready :
                      (wr_arb == WR_M3) ? m3_bready : m4_bready;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_arb <= WR_IDLE;
        end else begin
            case (wr_arb)
                WR_IDLE: wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                   m2_awvalid, m3_awvalid, m4_awvalid);
                WR_M0: if (s_bvalid && m0_bready)
                           wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                    m2_awvalid, m3_awvalid, m4_awvalid);
                WR_M1: if (s_bvalid && m1_bready)
                           wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                    m2_awvalid, m3_awvalid, m4_awvalid);
                WR_M2: if (s_bvalid && m2_bready)
                           wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                    m2_awvalid, m3_awvalid, m4_awvalid);
                WR_M3: if (s_bvalid && m3_bready)
                           wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                    m2_awvalid, m3_awvalid, m4_awvalid);
                WR_M4: if (s_bvalid && m4_bready)
                           wr_arb <= wr_next_winner(m0_awvalid, m1_awvalid,
                                                    m2_awvalid, m3_awvalid, m4_awvalid);
                default: wr_arb <= WR_IDLE;
            endcase
        end
    end

    wire wr_grant_m0 = (wr_arb == WR_M0) ||
                       (wr_arb == WR_IDLE && m0_awvalid);
    wire wr_grant_m1 = (wr_arb == WR_M1) ||
                       (wr_arb == WR_IDLE && !m0_awvalid && m1_awvalid);
    wire wr_grant_m2 = (wr_arb == WR_M2) ||
                       (wr_arb == WR_IDLE && !m0_awvalid && !m1_awvalid && m2_awvalid);
    wire wr_grant_m3 = (wr_arb == WR_M3) ||
                       (wr_arb == WR_IDLE && !m0_awvalid && !m1_awvalid &&
                        !m2_awvalid && m3_awvalid);
    wire wr_grant_m4 = (wr_arb == WR_M4) ||
                       (wr_arb == WR_IDLE && !m0_awvalid && !m1_awvalid &&
                        !m2_awvalid && !m3_awvalid && m4_awvalid);

    // ========================================================================
    // AR Channel Mux → Slave
    // ========================================================================
    assign s_arvalid = rd_grant_m0 ? m0_arvalid :
                       rd_grant_m1 ? m1_arvalid :
                       rd_grant_m2 ? m2_arvalid :
                       rd_grant_m3 ? m3_arvalid :
                       rd_grant_m4 ? m4_arvalid : 1'b0;

    assign s_araddr  = rd_grant_m0 ? m0_araddr :
                       rd_grant_m1 ? m1_araddr :
                       rd_grant_m2 ? m2_araddr :
                       rd_grant_m3 ? m3_araddr : m4_araddr;

    assign s_arlen   = rd_grant_m0 ? m0_arlen :
                       rd_grant_m1 ? m1_arlen :
                       rd_grant_m2 ? m2_arlen :
                       rd_grant_m3 ? m3_arlen : m4_arlen;

    assign s_arsize  = rd_grant_m0 ? m0_arsize :
                       rd_grant_m1 ? m1_arsize :
                       rd_grant_m2 ? m2_arsize :
                       rd_grant_m3 ? m3_arsize : m4_arsize;

    assign s_arburst = rd_grant_m0 ? m0_arburst :
                       rd_grant_m1 ? m1_arburst :
                       rd_grant_m2 ? m2_arburst :
                       rd_grant_m3 ? m3_arburst : m4_arburst;

    assign s_arprot  = rd_grant_m0 ? m0_arprot :
                       rd_grant_m1 ? m1_arprot :
                       rd_grant_m2 ? m2_arprot :
                       rd_grant_m3 ? m3_arprot : m4_arprot;

    // ID tagging: top 3 bits = master index
    assign s_arid = rd_grant_m0 ? {TAG_M0, m0_arid[ID_WIDTH-4:0]} :
                    rd_grant_m1 ? {TAG_M1, m1_arid[ID_WIDTH-4:0]} :
                    rd_grant_m2 ? {TAG_M2, m2_arid[ID_WIDTH-4:0]} :
                    rd_grant_m3 ? {TAG_M3, m3_arid[ID_WIDTH-4:0]} :
                                  {TAG_M4, m4_arid[ID_WIDTH-4:0]};

    assign m0_arready = rd_grant_m0 ? s_arready : 1'b0;
    assign m1_arready = rd_grant_m1 ? s_arready : 1'b0;
    assign m2_arready = rd_grant_m2 ? s_arready : 1'b0;
    assign m3_arready = rd_grant_m3 ? s_arready : 1'b0;
    assign m4_arready = rd_grant_m4 ? s_arready : 1'b0;

    // ========================================================================
    // R Channel Demux ← Slave (top 3 bits of RID = master index)
    // ========================================================================
    wire [2:0] rd_resp_tag = s_rid[ID_WIDTH-1:ID_WIDTH-3];

    wire rd_resp_to_m0 = (rd_resp_tag == TAG_M0);
    wire rd_resp_to_m1 = (rd_resp_tag == TAG_M1);
    wire rd_resp_to_m2 = (rd_resp_tag == TAG_M2);
    wire rd_resp_to_m3 = (rd_resp_tag == TAG_M3);
    wire rd_resp_to_m4 = (rd_resp_tag == TAG_M4);

    // Strip tag bits when returning to master
    wire [ID_WIDTH-4:0] s_rid_user = s_rid[ID_WIDTH-4:0];
    assign m0_rid = {{3{1'b0}}, s_rid_user};
    assign m1_rid = {{3{1'b0}}, s_rid_user};
    assign m2_rid = {{3{1'b0}}, s_rid_user};
    assign m3_rid = {{3{1'b0}}, s_rid_user};
    assign m4_rid = {{3{1'b0}}, s_rid_user};

    assign m0_rdata  = s_rdata;
    assign m1_rdata  = s_rdata;
    assign m2_rdata  = s_rdata;
    assign m3_rdata  = s_rdata;
    assign m4_rdata  = s_rdata;

    assign m0_rresp  = s_rresp;
    assign m1_rresp  = s_rresp;
    assign m2_rresp  = s_rresp;
    assign m3_rresp  = s_rresp;
    assign m4_rresp  = s_rresp;

    assign m0_rlast  = s_rlast && rd_resp_to_m0;
    assign m1_rlast  = s_rlast && rd_resp_to_m1;
    assign m2_rlast  = s_rlast && rd_resp_to_m2;
    assign m3_rlast  = s_rlast && rd_resp_to_m3;
    assign m4_rlast  = s_rlast && rd_resp_to_m4;

    assign m0_rvalid = s_rvalid && rd_resp_to_m0;
    assign m1_rvalid = s_rvalid && rd_resp_to_m1;
    assign m2_rvalid = s_rvalid && rd_resp_to_m2;
    assign m3_rvalid = s_rvalid && rd_resp_to_m3;
    assign m4_rvalid = s_rvalid && rd_resp_to_m4;

    assign s_rready  = rd_resp_to_m0 ? m0_rready :
                       rd_resp_to_m1 ? m1_rready :
                       rd_resp_to_m2 ? m2_rready :
                       rd_resp_to_m3 ? m3_rready :
                       rd_resp_to_m4 ? m4_rready : 1'b0;

    // ========================================================================
    // AW Channel Mux → Slave
    // ========================================================================
    assign s_awvalid = wr_grant_m0 ? m0_awvalid :
                       wr_grant_m1 ? m1_awvalid :
                       wr_grant_m2 ? m2_awvalid :
                       wr_grant_m3 ? m3_awvalid :
                       wr_grant_m4 ? m4_awvalid : 1'b0;

    assign s_awaddr  = wr_grant_m0 ? m0_awaddr :
                       wr_grant_m1 ? m1_awaddr :
                       wr_grant_m2 ? m2_awaddr :
                       wr_grant_m3 ? m3_awaddr : m4_awaddr;

    assign s_awlen   = wr_grant_m0 ? m0_awlen :
                       wr_grant_m1 ? m1_awlen :
                       wr_grant_m2 ? m2_awlen :
                       wr_grant_m3 ? m3_awlen : m4_awlen;

    assign s_awsize  = wr_grant_m0 ? m0_awsize :
                       wr_grant_m1 ? m1_awsize :
                       wr_grant_m2 ? m2_awsize :
                       wr_grant_m3 ? m3_awsize : m4_awsize;

    assign s_awburst = wr_grant_m0 ? m0_awburst :
                       wr_grant_m1 ? m1_awburst :
                       wr_grant_m2 ? m2_awburst :
                       wr_grant_m3 ? m3_awburst : m4_awburst;

    assign s_awprot  = wr_grant_m0 ? m0_awprot :
                       wr_grant_m1 ? m1_awprot :
                       wr_grant_m2 ? m2_awprot :
                       wr_grant_m3 ? m3_awprot : m4_awprot;

    assign s_awid    = wr_grant_m0 ? {TAG_M0, m0_awid[ID_WIDTH-4:0]} :
                       wr_grant_m1 ? {TAG_M1, m1_awid[ID_WIDTH-4:0]} :
                       wr_grant_m2 ? {TAG_M2, m2_awid[ID_WIDTH-4:0]} :
                       wr_grant_m3 ? {TAG_M3, m3_awid[ID_WIDTH-4:0]} :
                                     {TAG_M4, m4_awid[ID_WIDTH-4:0]};

    assign m0_awready = wr_grant_m0 ? s_awready : 1'b0;
    assign m1_awready = wr_grant_m1 ? s_awready : 1'b0;
    assign m2_awready = wr_grant_m2 ? s_awready : 1'b0;
    assign m3_awready = wr_grant_m3 ? s_awready : 1'b0;
    assign m4_awready = wr_grant_m4 ? s_awready : 1'b0;

    // ========================================================================
    // W Channel Mux → Slave
    // ========================================================================
    assign s_wdata  = wr_grant_m0 ? m0_wdata :
                      wr_grant_m1 ? m1_wdata :
                      wr_grant_m2 ? m2_wdata :
                      wr_grant_m3 ? m3_wdata : m4_wdata;

    assign s_wstrb  = wr_grant_m0 ? m0_wstrb :
                      wr_grant_m1 ? m1_wstrb :
                      wr_grant_m2 ? m2_wstrb :
                      wr_grant_m3 ? m3_wstrb : m4_wstrb;

    assign s_wlast  = wr_grant_m0 ? m0_wlast :
                      wr_grant_m1 ? m1_wlast :
                      wr_grant_m2 ? m2_wlast :
                      wr_grant_m3 ? m3_wlast : m4_wlast;

    assign s_wvalid = wr_grant_m0 ? m0_wvalid :
                      wr_grant_m1 ? m1_wvalid :
                      wr_grant_m2 ? m2_wvalid :
                      wr_grant_m3 ? m3_wvalid :
                      wr_grant_m4 ? m4_wvalid : 1'b0;

    assign m0_wready = wr_grant_m0 ? s_wready : 1'b0;
    assign m1_wready = wr_grant_m1 ? s_wready : 1'b0;
    assign m2_wready = wr_grant_m2 ? s_wready : 1'b0;
    assign m3_wready = wr_grant_m3 ? s_wready : 1'b0;
    assign m4_wready = wr_grant_m4 ? s_wready : 1'b0;

    // ========================================================================
    // B Channel Demux ← Slave
    // ========================================================================
    wire [2:0] wr_resp_tag = s_bid[ID_WIDTH-1:ID_WIDTH-3];

    wire wr_resp_to_m0 = (wr_resp_tag == TAG_M0);
    wire wr_resp_to_m1 = (wr_resp_tag == TAG_M1);
    wire wr_resp_to_m2 = (wr_resp_tag == TAG_M2);
    wire wr_resp_to_m3 = (wr_resp_tag == TAG_M3);
    wire wr_resp_to_m4 = (wr_resp_tag == TAG_M4);

    wire [ID_WIDTH-4:0] s_bid_user = s_bid[ID_WIDTH-4:0];
    assign m0_bid = {{3{1'b0}}, s_bid_user};
    assign m1_bid = {{3{1'b0}}, s_bid_user};
    assign m2_bid = {{3{1'b0}}, s_bid_user};
    assign m3_bid = {{3{1'b0}}, s_bid_user};
    assign m4_bid = {{3{1'b0}}, s_bid_user};

    assign m0_bresp  = s_bresp;
    assign m1_bresp  = s_bresp;
    assign m2_bresp  = s_bresp;
    assign m3_bresp  = s_bresp;
    assign m4_bresp  = s_bresp;

    assign m0_bvalid = s_bvalid && wr_resp_to_m0;
    assign m1_bvalid = s_bvalid && wr_resp_to_m1;
    assign m2_bvalid = s_bvalid && wr_resp_to_m2;
    assign m3_bvalid = s_bvalid && wr_resp_to_m3;
    assign m4_bvalid = s_bvalid && wr_resp_to_m4;

    assign s_bready  = wr_resp_to_m0 ? m0_bready :
                       wr_resp_to_m1 ? m1_bready :
                       wr_resp_to_m2 ? m2_bready :
                       wr_resp_to_m3 ? m3_bready :
                       wr_resp_to_m4 ? m4_bready : 1'b0;

endmodule
// ==============================================================================
// FILE: axi4_decerr_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// axi4_decerr_slave.v
// Xử lý giao dịch tới địa chỉ không ánh xạ — trả về DECERR
//
// Read:  Nhận AR → phát R với RDATA=0xDEAD_BEEF, RRESP=DECERR, RLAST=1
// Write: Nhận AW → consume W (drain burst) → phát B với BRESP=DECERR
// ============================================================================

module axi4_decerr_slave #(
    parameter ID_WIDTH   = 4,
    parameter DATA_WIDTH = 32,
    parameter ADDR_WIDTH = 32
)(
    input wire clk,
    input wire rst_n,

    // AR channel
    input  wire [ID_WIDTH-1:0]   s_arid,
    input  wire [ADDR_WIDTH-1:0] s_araddr,
    input  wire [7:0]            s_arlen,
    input  wire                  s_arvalid,
    output reg                   s_arready,

    // R channel
    output reg  [ID_WIDTH-1:0]   s_rid,
    output reg  [DATA_WIDTH-1:0] s_rdata,
    output reg  [1:0]            s_rresp,
    output reg                   s_rlast,
    output reg                   s_rvalid,
    input  wire                  s_rready,

    // AW channel
    input  wire [ID_WIDTH-1:0]   s_awid,
    input  wire [ADDR_WIDTH-1:0] s_awaddr,
    input  wire [7:0]            s_awlen,
    input  wire                  s_awvalid,
    output reg                   s_awready,

    // W channel
    input  wire                  s_wlast,
    input  wire                  s_wvalid,
    output reg                   s_wready,

    // B channel
    output reg  [ID_WIDTH-1:0]   s_bid,
    output reg  [1:0]            s_bresp,
    output reg                   s_bvalid,
    input  wire                  s_bready
);

    // ========================================================================
    // Read FSM
    // ========================================================================
    localparam [1:0] RS_IDLE = 2'd0,
                     RS_RESP = 2'd1,
                     RS_WAIT = 2'd2;

    reg [1:0]          rs_state;
    reg [ID_WIDTH-1:0] r_pending_id;
    reg [7:0]          r_beat_cnt;
    reg [7:0]          r_len_latch;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rs_state     <= RS_IDLE;
            s_arready    <= 1'b1;
            s_rvalid     <= 1'b0;
            s_rdata      <= 32'hDEAD_BEEF;
            s_rresp      <= 2'b11;
            s_rlast      <= 1'b0;
            s_rid        <= {ID_WIDTH{1'b0}};
            r_beat_cnt   <= 8'h0;
            r_len_latch  <= 8'h0;
            r_pending_id <= {ID_WIDTH{1'b0}};
        end else begin
            case (rs_state)
                RS_IDLE: begin
                    s_arready <= 1'b1;
                    s_rvalid  <= 1'b0;
                    if (s_arvalid && s_arready) begin
                        r_pending_id <= s_arid;
                        r_len_latch  <= s_arlen;
                        r_beat_cnt   <= 8'h0;
                        s_arready    <= 1'b0;
                        rs_state     <= RS_RESP;
                    end
                end

                RS_RESP: begin
                    s_rid    <= r_pending_id;
                    s_rdata  <= 32'hDEAD_BEEF;
                    s_rresp  <= 2'b11; // DECERR
                    s_rlast  <= (r_beat_cnt == r_len_latch);
                    s_rvalid <= 1'b1;
                    rs_state <= RS_WAIT;
                end

                RS_WAIT: begin
                    if (s_rvalid && s_rready) begin
                        if (s_rlast) begin
                            s_rvalid  <= 1'b0;
                            s_rlast   <= 1'b0;
                            s_arready <= 1'b1;
                            rs_state  <= RS_IDLE;
                        end else begin
                            r_beat_cnt <= r_beat_cnt + 1'b1;
                            s_rlast    <= (r_beat_cnt + 1'b1 == r_len_latch);
                            rs_state   <= RS_RESP;
                        end
                    end
                end

                default: rs_state <= RS_IDLE;
            endcase
        end
    end

    // ========================================================================
    // Write FSM
    // ========================================================================
    localparam [1:0] WS_IDLE  = 2'd0,
                     WS_DRAIN = 2'd1,
                     WS_RESP  = 2'd2;

    reg [1:0]          ws_state;
    reg [ID_WIDTH-1:0] w_pending_id;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ws_state     <= WS_IDLE;
            s_awready    <= 1'b1;
            s_wready     <= 1'b0;
            s_bvalid     <= 1'b0;
            s_bresp      <= 2'b11;
            s_bid        <= {ID_WIDTH{1'b0}};
            w_pending_id <= {ID_WIDTH{1'b0}};
        end else begin
            case (ws_state)
                WS_IDLE: begin
                    s_awready <= 1'b1;
                    s_wready  <= 1'b0;
                    s_bvalid  <= 1'b0;
                    if (s_awvalid && s_awready) begin
                        w_pending_id <= s_awid;
                        s_awready    <= 1'b0;
                        s_wready     <= 1'b1;
                        ws_state     <= WS_DRAIN;
                    end
                end

                WS_DRAIN: begin
                    // Consume toàn bộ burst, bỏ dữ liệu
                    if (s_wvalid && s_wready && s_wlast) begin
                        s_wready <= 1'b0;
                        s_bid    <= w_pending_id;
                        s_bresp  <= 2'b11; // DECERR
                        s_bvalid <= 1'b1;
                        ws_state <= WS_RESP;
                    end
                end

                WS_RESP: begin
                    if (s_bvalid && s_bready) begin
                        s_bvalid  <= 1'b0;
                        s_awready <= 1'b1;
                        ws_state  <= WS_IDLE;
                    end
                end

                default: ws_state <= WS_IDLE;
            endcase
        end
    end

endmodule
