        .s_awvalid(m2_aw_to_err), .s_awready(m2_awready_s[12]),
        .s_wlast  (M2_AXI_WLAST),  .s_wvalid(M2_AXI_WVALID),
        .s_wready (m2_wready_s[12]),
        .s_bid    (m2_bid_s[12]),  .s_bresp (m2_bresp_s[12]),
        .s_bvalid (m2_bvalid_s[12]),.s_bready(M2_AXI_BREADY)
