// ============================================================================
// ==============================================================================
// FILE: ascon_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : ascon_ip_top  (v5 — bỏ AXI-Stream, fix INCR burst, fix DMA race)
//
// CHANGES vs v4:
//   FIX-BUG-TOP5 : Xóa hoàn toàn AXI-Stream mode và u_axis instantiation.
//                  Lý do: AXIS_WRAPPER không cần thiết cho SoC CPU+DMA.
//                  Bỏ s_axis_*/m_axis_* khỏi port list.
//
//   FIX-BUG-TOP6 : core_start_mux trong DMA mode trước đây chỉ dùng
//                  dma_core_start, không kiểm tra data_valid.
//                  Race condition: CORE start trước khi DMA FSM nạp ptext.
//                  Fix: core_start_mux = dma_core_start & dma_core_data_valid.
//
//   FIX-BUG-TOP7 : burst_len=8'd1 gây DMA phát 2-beat (128-bit total) qua
//                  width converter 64→32. Converter cắt không đúng boundary.
//                  Fix: burst_len=8'd0 → 1-beat 64-bit → converter cắt 2×32-bit.
//
//   FIX-BUG-TOP8 : o_tag/o_tag_valid/o_busy không có assign trong v4.
//                  Fix: wire trực tiếp từ core_tag_out_w, core_tag_valid_w,
//                  core_busy_w | dma_busy_w.
//
// Hai chế độ hoạt động (slave_dma_en từ register CTRL[2]):
//   [1] CPU-Direct mode (dma_en=0):
//       CPU viết KEY/NONCE/PT qua AXI4-Full slave → ascon_CORE (u_core_cpu)
//       Hỗ trợ INCR burst để nạp Key/Nonce 128-bit bằng memcpy (4 beat × 32-bit)
//
//   [2] DMA mode (dma_en=1):
//       DMA fetch PT từ DDR (1-beat 64-bit) → ascon_CORE → CT/TAG → DDR
//
// NOTE về compile filelist (KHÔNG dùng `include):
//   1. ascon_INITIALIZATION, ascon_STATE_REGISTER, ascon_DATAPATH,
//      ascon_PERMUTATION, ascon_TAG_GENERATOR, ascon_TAG_COMPARATOR,
//      ascon_CONTROLLER
//   2. ascon_CORE.v
//   3. ascon_axi_slave.v
//   4. ascon_dma + submodules
//   5. ascon_ip_top.v  ← file này, KHÔNG `include gì cả
// ============================================================================
// FIX-BUG-TOP1: Xóa tất cả `include — dùng compile filelist thay thế (xem NOTE ở header)

// ==============================================================================
// FILE: ascon_axi_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : ascon_axi_slave
// Version : 2.4  (FIX-MODE-OVERLAP: tách bit enc_dec khỏi bit variant)
//
// Changes vs v2.3:
//   FIX-MODE-OVERLAP : reg_mode[0] và core_enc_dec trước đây cùng dùng bit[0]
//                      khiến "chọn variant" và "chọn hướng" xung đột nhau.
//                      Fix: reg_mode[1] = direction (enc=0/dec=1),
//                           reg_mode[0] = variant   (128=0/128a=1).
//                      Bảng giá trị ghi ADDR_MODE:
//                        0x0 = ASCON-128  Encrypt
//                        0x1 = ASCON-128a Encrypt
//                        0x2 = ASCON-128  Decrypt
//                        0x3 = ASCON-128a Decrypt
//
// Changes vs v2.2:
//   FIX-INCR-BURST : WR_DATA không tăng wr_addr_lat qua các beat của burst.
//                    Khi CPU dùng memcpy để nạp Key[127:0] hoặc Nonce[127:0],
//                    GCC/CPU phát AXI INCR burst: AWLEN=3, 4 beat × 32-bit.
//                    v2.2 decode tất cả 4 beat vào địa chỉ đầu (KEY_0),
//                    KEY_1/KEY_2/KEY_3 không bao giờ được ghi → key sai.
//                    Fix:
//                      WR_IDLE: set WREADY=1 khi AW handshake (mở kênh W)
//                      WR_DATA: decode mỗi beat WVALID ngay lập tức,
//                               tăng wr_addr_lat += 4 nếu !WLAST,
//                               chuyển WR_RESP chỉ khi WLAST=1.
//
// Changes vs v2.1:
//   FIX-BUG-CTRL2 : core_start bị suppressed khi DMA_EN=1.
//   FIX-BUG-AWREADY : AWREADY=1 chuyển sang WR_DONE (sau BVALID=0).
//   FIX-WLAST       : Thêm wr_wlast_lat, decode khi WLAST=1.
//   FIX-BUG-CTRL    : Tách điều kiện core_start / dma_start.
//
// Changes vs v1.9:
//   FIX-BUG1 : Nâng cấp AXI4-Lite → AXI4-Full, burst read/write.
//   FIX-BUG2 : Thêm register ADDR_DATA_LEN (offset 0x03C).
// ============================================================================
module ascon_axi_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
) (
    input  wire                    clk,
    input  wire                    rst_n,

    // ── AXI4-Full Write Address Channel
    input  wire [ID_WIDTH-1:0]     S_AXI_AWID,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [ADDR_WIDTH-1:0]   S_AXI_AWADDR,   // [31:12] unused (12-bit offset only)
    /* verilator lint_on UNUSEDSIGNAL */
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [7:0]              S_AXI_AWLEN,    // AXI4-Full port, not decoded (single-reg)
    input  wire [2:0]              S_AXI_AWSIZE,
    input  wire [1:0]              S_AXI_AWBURST,
    input  wire [2:0]              S_AXI_AWPROT,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire                    S_AXI_AWVALID,
    output reg                     S_AXI_AWREADY,

    // ── AXI4-Full Write Data Channel
    input  wire [DATA_WIDTH-1:0]   S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                    S_AXI_WLAST,
    input  wire                    S_AXI_WVALID,
    output reg                     S_AXI_WREADY,

    // ── AXI4-Full Write Response Channel
    output reg  [ID_WIDTH-1:0]     S_AXI_BID,
    output reg  [1:0]              S_AXI_BRESP,
    output reg                     S_AXI_BVALID,
    input  wire                    S_AXI_BREADY,

    // ── AXI4-Full Read Address Channel
    input  wire [ID_WIDTH-1:0]     S_AXI_ARID,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [ADDR_WIDTH-1:0]   S_AXI_ARADDR,   // [31:12] unused (12-bit offset only)
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire [7:0]              S_AXI_ARLEN,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [2:0]              S_AXI_ARSIZE,   // AXI4-Full port, not decoded (fixed-reg read)
    input  wire [1:0]              S_AXI_ARBURST,
    input  wire [2:0]              S_AXI_ARPROT,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire                    S_AXI_ARVALID,
    output reg                     S_AXI_ARREADY,

    // ── AXI4-Full Read Data Channel
    output reg  [ID_WIDTH-1:0]     S_AXI_RID,
    output reg  [DATA_WIDTH-1:0]   S_AXI_RDATA,
    output reg  [1:0]              S_AXI_RRESP,
    output reg                     S_AXI_RLAST,
    output reg                     S_AXI_RVALID,
    input  wire                    S_AXI_RREADY,

    // ── Interface to ascon_CORE
    output wire [127:0]            core_key,
    output wire [127:0]            core_nonce,
    output wire [127:0]            core_data_in,
    output wire [6:0]              core_data_len,
    output wire                    core_enc_dec,
    output wire [1:0]              core_mode,
    output reg                     core_start,
    output reg                     core_soft_rst,

    input  wire                    core_busy,
    input  wire                    core_done,
    input  wire                    core_data_out_valid,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [127:0]            core_data_out,  // [63:0] zero in ASCON-128 mode
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire [127:0]            core_tag_out,
    input  wire                    core_tag_valid,

    // ── Interface to ascon_dma
    output wire [31:0]             dma_src_addr,
    output wire [31:0]             dma_dst_addr,
    output wire [31:0]             dma_length,
    output wire [7:0]              dma_burst_len,
    output wire                    dma_en,
    output reg                     dma_start,
    output reg                     dma_soft_rst,

    input  wire                    dma_busy,
    input  wire                    dma_done,
    input  wire                    dma_error,

    // ── Interrupt
    output wire                    irq
);

    // =========================================================================
    // Address offset localparams  (12-bit offset from base)
    // =========================================================================
    localparam [11:0]
        ADDR_CTRL      = 12'h020,
        ADDR_STATUS    = 12'h004,
        ADDR_MODE      = 12'h000,
        ADDR_IRQ_EN    = 12'h00C,
        ADDR_KEY_0     = 12'h010,
        ADDR_KEY_1     = 12'h014,
        ADDR_KEY_2     = 12'h018,
        ADDR_KEY_3     = 12'h01C,
        ADDR_NONCE_0   = 12'h024,
        ADDR_NONCE_1   = 12'h028,
        ADDR_NONCE_2   = 12'h02C,
        ADDR_NONCE_3   = 12'h030,
        ADDR_PTEXT_0   = 12'h034,
        ADDR_PTEXT_1   = 12'h038,
        ADDR_DATA_LEN  = 12'h03C,   // Changed
        ADDR_CTEXT_0   = 12'h040,
        ADDR_CTEXT_1   = 12'h044,
        ADDR_TAG_0     = 12'h048,
        ADDR_TAG_1     = 12'h04C,
        ADDR_TAG_2     = 12'h050,
        ADDR_TAG_3     = 12'h054,
        ADDR_DMA_SRC   = 12'h100,
        ADDR_DMA_DST   = 12'h104,
        ADDR_DMA_LEN   = 12'h108,
        ADDR_DMA_BURST = 12'h114;

    // =========================================================================
    // Write FSM states
    // =========================================================================
    localparam [1:0]
        WR_IDLE = 2'b00,
        WR_DATA = 2'b01,
        WR_RESP = 2'b10,
        WR_DONE = 2'b11;

    reg [1:0] wr_state;

    // =========================================================================
    // Read FSM states
    // =========================================================================
    localparam [1:0]
        RD_IDLE  = 2'b00,
        RD_VALID = 2'b01;

    reg [1:0] rd_state;

    // =========================================================================
    // Write channel pipeline registers
    // =========================================================================
    reg [11:0]         wr_addr_lat;
    reg [ID_WIDTH-1:0] wr_id_lat;
    reg [31:0]         wr_data_lat;
    reg [3:0]          wr_strb_lat;
    // wr_len_lat removed (unused)
    // wr_beat_cnt removed (unused)
    reg                wr_wlast_lat;  // [FIX-WLAST] latch WLAST khi pre-latch W

    // module-level decode wires (combinational, FIX-BLKSEQ: was blocking reg in seq block)
    wire [31:0] wr_exec_data;
    wire [3:0]  wr_exec_strb;
    // Combinational mux: select bus data (case B) or latched data (case A)
    assign wr_exec_data = (S_AXI_WVALID && S_AXI_WREADY) ? S_AXI_WDATA : wr_data_lat;
    assign wr_exec_strb = (S_AXI_WVALID && S_AXI_WREADY) ? S_AXI_WSTRB : wr_strb_lat;

    // =========================================================================
    // Read channel pipeline registers
    // =========================================================================
    /* verilator lint_off UNUSEDSIGNAL */
    reg [11:0]           rd_addr_lat;  // latched but read via rd_data_lat
    /* verilator lint_on UNUSEDSIGNAL */
    reg [ID_WIDTH-1:0]   rd_id_lat;
    reg [DATA_WIDTH-1:0] rd_data_lat;
    reg [7:0]            rd_len_lat;   // FIX-BUG1: burst length latch
    reg [7:0]            rd_beat_cnt;  // FIX-BUG1: beat counter

    // =========================================================================
    // Storage registers
    // =========================================================================
    // reg_mode[0] = variant  : 0=ASCON-128, 1=ASCON-128a
    // reg_mode[1] = direction: 0=Encrypt,   1=Decrypt
    reg [1:0]  reg_mode;
    reg [2:0]  reg_irq_en;
    reg        reg_dma_en;
    reg [6:0]  reg_data_len;   // FIX-BUG2: số byte thực của PT

    reg [31:0] reg_key_0,   reg_key_1,   reg_key_2,   reg_key_3;
    reg [31:0] reg_nonce_0, reg_nonce_1, reg_nonce_2, reg_nonce_3;
    reg [31:0] reg_ptext_0, reg_ptext_1;

    reg [31:0] reg_ctext_0, reg_ctext_1;
    reg [31:0] reg_tag_0,   reg_tag_1,   reg_tag_2,   reg_tag_3;

    reg [31:0] reg_dma_src, reg_dma_dst, reg_dma_len;
    reg [7:0]  reg_dma_burst_len;

    reg        status_done,  status_dma_done;
    reg        status_error, status_dma_error;

    // =========================================================================
    // Byte-enable helper
    // =========================================================================
    function [31:0] apply_strb;
        input [31:0] old_val, new_val;
        input [3:0]  strb;
        begin
            apply_strb[31:24] = strb[3] ? new_val[31:24] : old_val[31:24];
            apply_strb[23:16] = strb[2] ? new_val[23:16] : old_val[23:16];
            apply_strb[15: 8] = strb[1] ? new_val[15: 8] : old_val[15: 8];
            apply_strb[ 7: 0] = strb[0] ? new_val[ 7: 0] : old_val[ 7: 0];
        end
    endfunction

    // =========================================================================
    // Register read mux
    // =========================================================================
    wire [31:0] status_word = {
        26'h0,
        status_dma_error, // [5]
        status_error,     // [4]
        status_dma_done,  // [3]
        dma_busy,         // [2]
        status_done,      // [1]
        core_busy         // [0]
    };

    function [31:0] reg_read_mux;
        input [11:0] addr;
        begin
            case (addr)
                ADDR_CTRL:     reg_read_mux = {29'h0, reg_dma_en, 1'b0, 1'b0};
                ADDR_STATUS:   reg_read_mux = status_word;
                ADDR_MODE:     reg_read_mux = {30'h0, reg_mode};
                ADDR_IRQ_EN:   reg_read_mux = {29'h0, reg_irq_en};
                ADDR_DATA_LEN: reg_read_mux = {25'h0, reg_data_len};   // FIX-BUG2
                ADDR_KEY_0:    reg_read_mux = reg_key_0;
                ADDR_KEY_1:    reg_read_mux = reg_key_1;
                ADDR_KEY_2:    reg_read_mux = reg_key_2;
                ADDR_KEY_3:    reg_read_mux = reg_key_3;
                ADDR_NONCE_0:  reg_read_mux = reg_nonce_0;
                ADDR_NONCE_1:  reg_read_mux = reg_nonce_1;
                ADDR_NONCE_2:  reg_read_mux = reg_nonce_2;
                ADDR_NONCE_3:  reg_read_mux = reg_nonce_3;
                ADDR_PTEXT_0, ADDR_PTEXT_1: reg_read_mux = 32'h0;
                ADDR_CTEXT_0: reg_read_mux = reg_ctext_0;
                ADDR_CTEXT_1: reg_read_mux = reg_ctext_1;
                ADDR_TAG_0:   reg_read_mux = reg_tag_0;
                ADDR_TAG_1:   reg_read_mux = reg_tag_1;
                ADDR_TAG_2:   reg_read_mux = reg_tag_2;
                ADDR_TAG_3:   reg_read_mux = reg_tag_3;
                ADDR_DMA_SRC: reg_read_mux = reg_dma_src;
                ADDR_DMA_DST: reg_read_mux = reg_dma_dst;
                ADDR_DMA_LEN: reg_read_mux = reg_dma_len;
                ADDR_DMA_BURST: reg_read_mux = {24'h0, reg_dma_burst_len};
                default:      reg_read_mux = 32'h0;
            endcase
        end
    endfunction

    // =========================================================================
    // WRITE CHANNEL FSM  (FIX-BUG1: AXI4-Full burst support)
    //
    // Burst model: slave hỗ trợ INCR và FIXED burst.
    // Với register-mapped IP, tất cả beat trong burst đều ghi vào cùng
    // địa chỉ wr_addr_lat (simplified). Decode chỉ khi WLAST=1.
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state      <= WR_IDLE;
            S_AXI_AWREADY <= 1'b1;
            S_AXI_WREADY  <= 1'b1;
            S_AXI_BVALID  <= 1'b0;
            S_AXI_BRESP   <= 2'b00;
            S_AXI_BID     <= {ID_WIDTH{1'b0}};
            wr_addr_lat   <= 12'h0;
            wr_id_lat     <= {ID_WIDTH{1'b0}};
            wr_data_lat   <= 32'h0;
            wr_strb_lat   <= 4'h0;
            // wr_len_lat removed
            // wr_beat_cnt removed
            wr_wlast_lat  <= 1'b0;
            // Storage registers
            reg_mode      <= 2'h0;
            reg_irq_en    <= 3'h0;
            reg_dma_en    <= 1'b0;
            reg_data_len  <= 7'd8;   // default 8 bytes
            reg_key_0     <= 32'h0; reg_key_1   <= 32'h0;
            reg_key_2     <= 32'h0; reg_key_3   <= 32'h0;
            reg_nonce_0   <= 32'h0; reg_nonce_1 <= 32'h0;
            reg_nonce_2   <= 32'h0; reg_nonce_3 <= 32'h0;
            reg_ptext_0   <= 32'h0; reg_ptext_1 <= 32'h0;
            reg_dma_src   <= 32'h0;
            reg_dma_dst   <= 32'h0;
            reg_dma_len   <= 32'd8;
            reg_dma_burst_len <= 8'h0;
            core_start    <= 1'b0;
            core_soft_rst <= 1'b0;
            dma_start     <= 1'b0;
            dma_soft_rst  <= 1'b0;
        end else begin
            // Default: deassert 1-cycle control pulses every cycle
            core_start    <= 1'b0;
            core_soft_rst <= 1'b0;
            dma_start     <= 1'b0;
            dma_soft_rst  <= 1'b0;

            // [BUG3-FIX] Clear reg_dma_en on soft_rst (moved here from status block
            // to avoid multiple-driver conflict on reg_dma_en).
            if (core_soft_rst)
                reg_dma_en <= 1'b0;

            case (wr_state)

                // ── WR_IDLE ──────────────────────────────────────────────────
                // Accept AW. Pre-latch W nếu đến cùng cycle (AXI4 chuẩn).
                // WREADY=1 tại đây (từ reset hoặc sau WR_DONE).
                WR_IDLE: begin
                    // Pre-latch W nếu valid trước hoặc cùng lúc AW
                    if (S_AXI_WVALID && S_AXI_WREADY) begin
                        wr_data_lat  <= S_AXI_WDATA;
                        wr_strb_lat  <= S_AXI_WSTRB;
                        wr_wlast_lat <= S_AXI_WLAST;  // [FIX-WLAST]
                        S_AXI_WREADY <= 1'b0;   // đã latch W, không nhận thêm
                    end
                    if (S_AXI_AWVALID && S_AXI_AWREADY) begin
                        wr_addr_lat   <= S_AXI_AWADDR[11:0];
                        wr_id_lat     <= S_AXI_AWID;
                        S_AXI_AWREADY <= 1'b0;
                        S_AXI_WREADY  <= 1'b1;   // [FIX-INCR-BURST] mở sẵn WREADY để nhận burst
                        wr_state      <= WR_DATA;
                    end
                end

                // ── WR_DATA ──────────────────────────────────────────────────
                // [FIX-INCR-BURST] Hỗ trợ INCR burst từ CPU memcpy (nạp Key/Nonce).
                // Mỗi beat WVALID ghi vào wr_addr_lat, sau đó tăng địa chỉ +4 byte.
                // Chỉ chuyển sang WR_RESP khi WLAST=1 (beat cuối của burst).
                // Pre-latch path (WREADY=0, wr_wlast_lat=1): đường A như cũ.
                WR_DATA: begin
                    if (S_AXI_WVALID && S_AXI_WREADY) begin

                        // 1. Ghi dữ liệu vào Register tại địa chỉ hiện tại
                        case (wr_addr_lat)
                            ADDR_CTRL: begin
                                if (wr_exec_strb[0]) begin
                                    if (wr_exec_data[1]) begin
                                        core_soft_rst <= 1'b1;
                                        dma_soft_rst  <= 1'b1;
                                    end
                                    if (wr_exec_data[0]) begin
                                        // Sử dụng trực tiếp bit 2 của dữ liệu đang ghi để quyết định start core hay dma
                                        if (!core_busy && !wr_exec_data[2])
                                            core_start <= 1'b1;
                                        
                                        if (wr_exec_data[2] && !dma_busy)
                                            dma_start <= 1'b1;
                                    end
                                    reg_dma_en <= wr_exec_data[2];
                                end
                            end
                            ADDR_MODE:     if (wr_exec_strb[0]) reg_mode     <= wr_exec_data[1:0];
                            ADDR_IRQ_EN:   if (wr_exec_strb[0]) reg_irq_en   <= wr_exec_data[2:0];
                            ADDR_DATA_LEN: if (wr_exec_strb[0]) reg_data_len <= wr_exec_data[6:0];
                            ADDR_KEY_0:    reg_key_0   <= apply_strb(reg_key_0,   wr_exec_data, wr_exec_strb);
                            ADDR_KEY_1:    reg_key_1   <= apply_strb(reg_key_1,   wr_exec_data, wr_exec_strb);
                            ADDR_KEY_2:    reg_key_2   <= apply_strb(reg_key_2,   wr_exec_data, wr_exec_strb);
                            ADDR_KEY_3:    reg_key_3   <= apply_strb(reg_key_3,   wr_exec_data, wr_exec_strb);
                            ADDR_NONCE_0:  reg_nonce_0 <= apply_strb(reg_nonce_0, wr_exec_data, wr_exec_strb);
                            ADDR_NONCE_1:  reg_nonce_1 <= apply_strb(reg_nonce_1, wr_exec_data, wr_exec_strb);
                            ADDR_NONCE_2:  reg_nonce_2 <= apply_strb(reg_nonce_2, wr_exec_data, wr_exec_strb);
                            ADDR_NONCE_3:  reg_nonce_3 <= apply_strb(reg_nonce_3, wr_exec_data, wr_exec_strb);
                            ADDR_PTEXT_0:  reg_ptext_0 <= apply_strb(reg_ptext_0, wr_exec_data, wr_exec_strb);
                            ADDR_PTEXT_1:  reg_ptext_1 <= apply_strb(reg_ptext_1, wr_exec_data, wr_exec_strb);
                            ADDR_DMA_SRC:  reg_dma_src <= apply_strb(reg_dma_src, wr_exec_data, wr_exec_strb);
                            ADDR_DMA_DST:  reg_dma_dst <= apply_strb(reg_dma_dst, wr_exec_data, wr_exec_strb);
                            ADDR_DMA_LEN:  reg_dma_len <= apply_strb(reg_dma_len, wr_exec_data, wr_exec_strb);
                            ADDR_DMA_BURST: begin
                                if (wr_exec_strb[0]) reg_dma_burst_len <= wr_exec_data[7:0];
                            end
                            default: ;
                        endcase

                        // 2. Xử lý AXI Burst
                        if (S_AXI_WLAST) begin
                            // Beat cuối: phát response
                            S_AXI_BID    <= wr_id_lat;
                            S_AXI_BRESP  <= 2'b00;
                            S_AXI_BVALID <= 1'b1;
                            S_AXI_WREADY <= 1'b0;
                            wr_state     <= WR_RESP;
                        end else begin
                            // Còn beat tiếp: tăng địa chỉ +4 (32-bit bus = 4 byte/beat)
                            // WHY: CPU memcpy phát INCR burst liên tiếp để nạp Key[127:0]
                            //      (4 word × 4 byte = 16 byte). Không tăng địa chỉ →
                            //      tất cả 4 beat đều ghi vào KEY_0, bỏ mất KEY_1/2/3.
                            wr_addr_lat  <= wr_addr_lat + 12'h4;
                            S_AXI_WREADY <= 1'b1;
                            wr_state     <= WR_DATA;
                        end

                    end else if (!S_AXI_WREADY && wr_wlast_lat) begin
                        // Pre-latch path (case A): W đã latch tại WR_IDLE với WLAST=1
                        S_AXI_BID    <= wr_id_lat;
                        S_AXI_BRESP  <= 2'b00;
                        S_AXI_BVALID <= 1'b1;
                        wr_state     <= WR_RESP;
                    end
                end

                // ── WR_RESP ───────────────────────────────────────────────────
                // [FIX-BUG-AWREADY] KHÔNG set AWREADY tại đây.
                // Nếu AWREADY=1 trong khi BVALID=1 còn chưa clear (WR_DONE cycle),
                // master có thể handshake AW nhưng WR_DONE không latch → transaction LOST.
                // AWREADY=1 được chuyển sang WR_DONE sau khi BVALID đã clear.
                WR_RESP: begin
                    if (S_AXI_BREADY) begin
                        S_AXI_WREADY  <= 1'b1;
                        wr_state      <= WR_DONE;
                    end
                end

                // ── WR_DONE ───────────────────────────────────────────────────
                // [FIX-BUG-AWREADY] BVALID clear TRƯỚC khi AWREADY=1.
                // Đảm bảo master không thể handshake AW mới trong cycle này
                // vì AWREADY chỉ vừa được set → master sẽ thấy AWREADY=1 ở cycle SAU.
                WR_DONE: begin
                    S_AXI_BVALID  <= 1'b0;
                    S_AXI_AWREADY <= 1'b1;   // [FIX] set sau khi BVALID=0
                    wr_state      <= WR_IDLE;
                end

                default: begin
                    wr_state      <= WR_IDLE;
                    S_AXI_AWREADY <= 1'b1;
                    S_AXI_WREADY  <= 1'b1;
                end
            endcase
        end
    end

    // =========================================================================
    // Status sticky bits + ctext/tag capture
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            status_done      <= 1'b0; status_dma_done  <= 1'b0;
            status_error     <= 1'b0; status_dma_error <= 1'b0;
            reg_ctext_0 <= 32'h0; reg_ctext_1 <= 32'h0;
            reg_tag_0   <= 32'h0; reg_tag_1   <= 32'h0;
            reg_tag_2   <= 32'h0; reg_tag_3   <= 32'h0;
        end else begin
            if (core_soft_rst) begin
                // Reset có ưu tiên cao nhất, xóa tất cả các bit sticky
                status_done      <= 1'b0;
                status_dma_done  <= 1'b0;
                status_error     <= 1'b0;
                status_dma_error <= 1'b0;
            end else begin
                // Latch dữ liệu CT/Tag
                if (core_data_out_valid) begin
                    reg_ctext_0 <= core_data_out[127:96];
                    reg_ctext_1 <= core_data_out[95:64];
                end
                if (core_tag_valid) begin
                    reg_tag_0 <= core_tag_out[127:96];
                    reg_tag_1 <= core_tag_out[95:64];
                    reg_tag_2 <= core_tag_out[63:32];
                    reg_tag_3 <= core_tag_out[31:0];
                end
                
                // Latch trạng thái (Sticky Bits) - Chỉ set, không tự động clear
                if (core_done)  status_done      <= 1'b1;
                if (dma_done)   status_dma_done  <= 1'b1;
                if (dma_error)  status_dma_error <= 1'b1;
            end
        end
    end

    // =========================================================================
    // READ CHANNEL FSM  (FIX-BUG1: AXI4-Full burst support)
    //
    // Burst model: phát (ARLEN+1) beat, tất cả cùng dữ liệu từ rd_data_lat
    // (register-read pattern — địa chỉ không increment cho register-mapped IP).
    // RLAST = 1 tại beat cuối.
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state      <= RD_IDLE;
            S_AXI_ARREADY <= 1'b1;
            S_AXI_RVALID  <= 1'b0;
            S_AXI_RLAST   <= 1'b0;
            S_AXI_RDATA   <= {DATA_WIDTH{1'b0}};
            S_AXI_RRESP   <= 2'b00;
            S_AXI_RID     <= {ID_WIDTH{1'b0}};
            rd_addr_lat   <= 12'h0;
            rd_id_lat     <= {ID_WIDTH{1'b0}};
            rd_data_lat   <= {DATA_WIDTH{1'b0}};
            rd_len_lat    <= 8'h0;
            rd_beat_cnt   <= 8'h0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    if (S_AXI_ARVALID && S_AXI_ARREADY) begin
                        rd_addr_lat   <= S_AXI_ARADDR[11:0];
                        rd_id_lat     <= S_AXI_ARID;
                        rd_data_lat   <= reg_read_mux(S_AXI_ARADDR[11:0]);
                        rd_len_lat    <= S_AXI_ARLEN;   // FIX-BUG1
                        rd_beat_cnt   <= 8'h0;
                        S_AXI_ARREADY <= 1'b0;
                        rd_state      <= RD_VALID;
                    end
                end

                RD_VALID: begin
                    if (!S_AXI_RVALID) begin
                        S_AXI_RVALID <= 1'b1;
                        S_AXI_RDATA  <= rd_data_lat;
                        S_AXI_RRESP  <= 2'b00;
                        S_AXI_RID    <= rd_id_lat;
                        // FIX-BUG1: set RLAST=1 when this is the last beat
                        S_AXI_RLAST  <= (rd_beat_cnt == rd_len_lat) ? 1'b1 : 1'b0;
                    end else if (S_AXI_RREADY) begin
                        if (rd_beat_cnt == rd_len_lat) begin
                            // Last beat acknowledged
                            S_AXI_RVALID  <= 1'b0;
                            S_AXI_RLAST   <= 1'b0;
                            S_AXI_ARREADY <= 1'b1;
                            rd_state      <= RD_IDLE;
                        end else begin
                            // More beats to send
                            rd_beat_cnt  <= rd_beat_cnt + 8'h1;
                            S_AXI_RDATA  <= rd_data_lat;  // same register data
                            S_AXI_RLAST  <= (rd_beat_cnt + 8'h1 == rd_len_lat) ? 1'b1 : 1'b0;
                        end
                    end
                end

                default: begin
                    rd_state      <= RD_IDLE;
                    S_AXI_ARREADY <= 1'b1;
                    S_AXI_RLAST   <= 1'b0;
                end
            endcase
        end
    end

    // =========================================================================
    // Output wires to ascon_CORE
    // =========================================================================
    assign core_key      = {reg_key_0,   reg_key_1,   reg_key_2,   reg_key_3};
    assign core_nonce    = {reg_nonce_0, reg_nonce_1, reg_nonce_2, reg_nonce_3};
    assign core_data_in  = {reg_ptext_0, reg_ptext_1, 64'h0};
    assign core_data_len = reg_data_len;   // FIX-BUG2: từ register, không hardcode
    // FIX-MODE-OVERLAP: tách 2 chức năng ra 2 bit riêng biệt
    //   reg_mode[0] → core_mode[0]: chọn ASCON variant (128=0 / 128a=1)
    //   reg_mode[1] → core_enc_dec: chọn hướng         (Encrypt=0 / Decrypt=1)
    assign core_enc_dec  = reg_mode[1];   // bit[1] = direction
    assign core_mode     = reg_mode;      // bit[0] = variant (dùng bởi CORE nội bộ)

    // =========================================================================
    // Output wires to ascon_dma
    // =========================================================================
    assign dma_src_addr = reg_dma_src;
    assign dma_dst_addr = reg_dma_dst;
    assign dma_length   = reg_dma_len;
    assign dma_burst_len= reg_dma_burst_len;
    assign dma_en       = reg_dma_en;

    // =========================================================================
    // Interrupt
    // =========================================================================
    assign irq = (status_done      & reg_irq_en[0]) |
                 (status_dma_done  & reg_irq_en[1]) |
                 (status_error     & reg_irq_en[2]) |
                 (status_dma_error & reg_irq_en[2]);

endmodule
// ==============================================================================
// FILE: ascon_CORE.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================
// Module: ascon_CORE  (v12 — fix mode_int: bỏ đảo bit, dùng mode trực tiếp)
//
// FIX vs v11:
//   BUG: mode_int = {mode[1], ~mode[0]} đảo bit0 khiến:
//        TB mode=00 (ASCON-128) → mode_int=01 → CONTROLLER chạy ASCON-128a params
//        → calls_pa=3 thay vì 2, calls_pb=2 thay vì 1 → FSM stuck ở S_POST_INIT
//
//   FIX: mode_int = mode (không đảo).
//        Convention thống nhất toàn hệ thống:
//          mode=2'b00 → ASCON-128  (G=6, pa=2calls, pb=1call)
//          mode=2'b01 → ASCON-128a (G=4, pa=3calls, pb=2calls)
//        CONTROLLER decode: mode[0]=0 → 128, mode[0]=1 → 128a
//
// Mode routing (sau fix):
//   u_init  ← mode      (chọn IV_128 hoặc IV_128a)
//   u_ctrl  ← mode_int  (= mode, chọn G/calls_pa/calls_pb)
//   u_dp    ← mode_int  (= mode, chọn rate 64 hoặc 128-bit)
//   u_perm  ← mode_int  (= mode, consistent)
// ============================================================

// ==============================================================================
// FILE: ascon_INITIALIZATION.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================
// Module: ascon_INITIALIZATION  (v2 — fix IV_128A)
//
// FIX vs v1:
//   IV_128A: placeholder → giá trị đúng theo NIST Ascon-AEAD128a spec
//     SW ascon.py builds IV bytes: [version=1, 0, (b<<4)|a=0x8c,
//                                    taglen=128 as LE16 → 0x80,0x00,
//                                    rate=32=0x20, 0, 0]
//     = 01 00 8c 80 00 20 00 00  (8 bytes)
//     SW loads as LE 64-bit int: int.from_bytes(...,'little')
//                               = 0x00002000808c0001
//
// State layout (320 bits):
//   [319:256] = x0 = IV
//   [255:192] = x1 = bswap(key_in[127:64])
//   [191:128] = x2 = bswap(key_in[63:0])
//   [127: 64] = x3 = bswap(nonce_in[127:64])
//   [ 63:  0] = x4 = bswap(nonce_in[63:0])
// ============================================================
module ascon_INITIALIZATION (
    input  wire         clk,
    input  wire         rst_n,

    input  wire         load_key,
    input  wire         load_nonce,
    input  wire [1:0]   mode,
    input  wire         init_start,

    input  wire [127:0] key_in,
    input  wire [127:0] nonce_in,

    output reg  [319:0] init_state_out,
    output reg          init_valid
);

    // NIST Ascon-AEAD128:  IV bytes 01 00 8c 80 00 10 00 00 → LE64 = 0x00001000808c0001
    // NIST Ascon-AEAD128a: IV bytes 01 00 8c 80 00 20 00 00 → LE64 = 0x00002000808c0001
    //   (rate=32=0x20, b=12,a=8 → (b<<4)|a = 0x8c, taglen=128 → 0x80 LE16)
    localparam [63:0] IV_128  = 64'h00001000808c0001; // NIST Ascon-AEAD128
    localparam [63:0] IV_128A = 64'h00002000808c0001; // FIX: NIST Ascon-AEAD128a (rate=32 bytes)
    localparam [63:0] IV_HASH = 64'h00400c0000000100; // Ascon-Hash

    function [63:0] bswap64;
        input [63:0] x;
        begin
            bswap64 = { x[ 7: 0], x[15: 8], x[23:16], x[31:24],
                        x[39:32], x[47:40], x[55:48], x[63:56] };
        end
    endfunction

    reg [127:0] key_reg;
    reg [127:0] nonce_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) key_reg <= 128'b0;
        else if (load_key) key_reg <= key_in;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) nonce_reg <= 128'b0;
        else if (load_nonce) nonce_reg <= nonce_in;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            init_state_out <= 320'b0;
            init_valid     <= 1'b0;
        end else if (init_start) begin
            init_valid <= 1'b1;
            case (mode)
                2'b00: init_state_out <= {
                    IV_128,
                    bswap64(key_reg[127:64]),
                    bswap64(key_reg[63:0]),
                    bswap64(nonce_reg[127:64]),
                    bswap64(nonce_reg[63:0])
                };
                2'b01: init_state_out <= {
                    IV_128A,                     // FIX: dùng giá trị đúng
                    bswap64(key_reg[127:64]),
                    bswap64(key_reg[63:0]),
                    bswap64(nonce_reg[127:64]),
                    bswap64(nonce_reg[63:0])
                };
                2'b10: init_state_out <= {
                    IV_HASH,
                    bswap64(key_reg[127:64]),
                    bswap64(key_reg[63:0]),
                    bswap64(nonce_reg[127:64]),
                    bswap64(nonce_reg[63:0])
                };
                default: init_state_out <= {
                    IV_128,
                    bswap64(key_reg[127:64]),
                    bswap64(key_reg[63:0]),
                    bswap64(nonce_reg[127:64]),
                    bswap64(nonce_reg[63:0])
                };
            endcase
        end else begin
            init_valid <= 1'b0;
        end
    end

endmodule
// ==============================================================================
// FILE: ascon_STATE_REGISTER.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module: ascon_STATE_REGISTER  (OPT v5 — fix: latch state_in thay vì init_state)
//
// FIX vs v4:
//   BUG: always block latch `init_state` thay vì `state_in`
//        → dp_state và perm_state không bao giờ được lưu vào state_out
//        → toàn bộ AD/PT/Final phase đều sai
//   FIX: đổi `init_state` → `state_in` trong always block
//        CORE chịu trách nhiệm mux state_next_final → state_in
// ============================================================================
module ascon_STATE_REGISTER (
    input  wire         clk,
    input  wire         rst_n,

    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [1:0]   src_sel,    // legacy port, not used (mux done in CORE)
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire         load,

    input  wire [319:0] state_in,   // already muxed in CORE (state_next_final)

    // Legacy ports — kept for interface compatibility
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [319:0] init_state,
    input  wire [319:0] dp_state,
    input  wire [319:0] perm_state,
    /* verilator lint_on UNUSEDSIGNAL */

    output reg  [319:0] state_out
);
    // FIX: dùng state_in (= state_next_final từ CORE) thay vì init_state
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) state_out <= 320'b0;
        else if (load) state_out <= state_in;  // FIX: was `init_state`
    end

endmodule
// ==============================================================================
// FILE: ascon_datapath.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================
// Module: ascon_DATAPATH  (v2 — GCD dual-rate fix)
//
// FIX vs v1:
//   FIX-1: Rate theo đúng spec ASCON:
//     ASCON-128  (mode=00): rate = 64-bit  → chỉ XOR vào x0
//                           x1 không thay đổi (zero-pad phần upper)
//     ASCON-128a (mode=01): rate = 128-bit → XOR vào cả x0 và x1
//     Cả 2 mode đều dùng chung datapath 128-bit với 1-bit mode MUX
//     (đây chính là G_DUAL_RATE unified datapath theo spec)
//
//   FIX-2: G_DUAL_RATE parameter điều khiển:
//     G_DUAL_RATE=1 (default): unified 128-bit datapath như mô tả trên
//     G_DUAL_RATE=0: chỉ hỗ trợ ASCON-128 đơn (64-bit rate cứng)
//
//   FIX-3: Output data_out chỉ xuất rate portion:
//     ASCON-128:  data_out[127:64] = ciphertext/plaintext 64-bit
//                 data_out[63:0]   = 64'h0 (padding)
//     ASCON-128a: data_out[127:0]  = ciphertext/plaintext 128-bit
//
// Retained from v1:
//   Padding (0x01, extra_pad_block_needed)
//   Decrypt state update (mask/padx formula)
//   Byte-swap (BE→LE)
//   NIST Ascon-AEAD128 correctness
// ============================================================
module ascon_DATAPATH #(
    parameter G_DUAL_RATE = 1    // 1=unified 128-bit datapath, 0=128-only 64-bit
) (
    input  wire         clk,
    input  wire         rst_n,

    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [1:0]   mode,  // mode[1] unused; mode[0] selects 128 vs 128a rate
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire         enc_dec,
    input  wire         pad_enable,
    input  wire [1:0]   block_sel,

    input  wire [127:0] ad_in,
    input  wire [127:0] data_in,
    input  wire [6:0]   data_len,
    input  wire [319:0] state_in,

    output reg  [319:0] state_xored,
    output reg  [127:0] data_out,
    output reg          data_out_valid,
    output wire         extra_pad_block_needed
);

    // ------------------------------------------------------------------
    // Rate bytes:
    //   ASCON-128  (mode=00): rate = 8  bytes (64-bit)
    //   ASCON-128a (mode=01): rate = 16 bytes (128-bit)
    // FIX-1: rate_bytes phụ thuộc mode khi G_DUAL_RATE=1
    // ------------------------------------------------------------------
    wire [6:0] rate_bytes;
    generate
        if (G_DUAL_RATE == 1) begin : gen_dual_rate
            // mode[0]=0 → ASCON-128 (rate=8 bytes), mode[0]=1 → ASCON-128a (rate=16 bytes)
            assign rate_bytes = (mode[0] == 1'b0) ? 7'd8 : 7'd16;
        end else begin : gen_single_rate
            assign rate_bytes = 7'd8;  // ASCON-128 only
        end
    endgenerate

    // extra_pad_block_needed: block đầy, cần thêm block pad riêng
    assign extra_pad_block_needed = pad_enable && (data_len == rate_bytes);

    // Select correct input source
    wire [127:0] raw_input = (block_sel == 2'b00) ? ad_in : data_in;

    // ------------------------------------------------------------------
    // Byte-swap: reverse byte order within a 64-bit word
    // ------------------------------------------------------------------
    function [63:0] bswap64;
        input [63:0] x;
        begin
            bswap64 = { x[ 7: 0], x[15: 8], x[23:16], x[31:24],
                        x[39:32], x[47:40], x[55:48], x[63:56] };
        end
    endfunction

    // ------------------------------------------------------------------
    // Padding:
    //   len < rate : copy bytes[0..len-1], byte[len]=0x01, zero rest
    //   len == rate: extra_pad_block_needed asserted, block này raw
    // ------------------------------------------------------------------
    function [127:0] apply_padding;
        input [127:0] blk;
        input [6:0]   len;
        input [6:0]   rate;
        integer i;
        reg [127:0] out;
        begin
            out = 128'b0;
            for (i = 0; i < 16; i = i + 1) begin
                if (i < {{25{1'b0}}, len})          // FIX-WIDTHEXPAND: cast len to 32-bit
                    out[127 - i*8 -: 8] = blk[127 - i*8 -: 8];
                else if (i == {{25{1'b0}}, len} && len < rate) // FIX-WIDTHEXPAND: cast len to 32-bit
                    out[127 - i*8 -: 8] = 8'h01;
            end
            apply_padding = out;
        end
    endfunction

    // ------------------------------------------------------------------
    // Decrypt helper: mask và padx cho last block
    // ------------------------------------------------------------------
    function [127:0] build_dec_mask;
        input [6:0] len;
        integer i;
        reg [127:0] m;
        begin
            m = 128'b0;
            for (i = 0; i < 16; i = i + 1)
                if (i >= {{25{1'b0}}, len}) m[127 - i*8 -: 8] = 8'hFF; // FIX-WIDTHEXPAND
            build_dec_mask = m;
        end
    endfunction

    function [127:0] build_dec_padx;
        input [6:0] len;
        // integer i removed (unused, FIX-UNUSEDSIGNAL)
        reg [127:0] p;
        begin
            p = 128'b0;
            if (len < 7'd16) p[127 - {{25{1'b0}}, len}*8 -: 8] = 8'h01; // FIX-WIDTHEXPAND
            build_dec_padx = p;
        end
    endfunction

    // ---- state words ----
    wire [63:0] x0 = state_in[319:256];
    wire [63:0] x1 = state_in[255:192];

    // ---- padded data ----
    reg [127:0] padded_data;
    always @(*) begin
        if (pad_enable)
            padded_data = apply_padding(raw_input, data_len, rate_bytes);
        else
            padded_data = raw_input;
    end

    wire [63:0] pd_hi_bswap = bswap64(padded_data[127:64]);
    wire [63:0] pd_lo_bswap = bswap64(padded_data[ 63: 0]);

    // ---- CT zero-padded → LE integers ----
    wire [127:0] ct_zero_padded = raw_input;
    wire [63:0] ci_hi = bswap64(ct_zero_padded[127:64]);
    wire [63:0] ci_lo = bswap64(ct_zero_padded[ 63: 0]);

    // ---- Decrypt mask/padx ----
    wire [127:0] dec_mask_be = build_dec_mask(data_len);
    wire [127:0] dec_padx_be = build_dec_padx(data_len);
    wire [63:0]  mask_hi     = bswap64(dec_mask_be[127:64]);
    wire [63:0]  mask_lo     = bswap64(dec_mask_be[ 63: 0]);
    wire [63:0]  padx_hi     = bswap64(dec_padx_be[127:64]);
    wire [63:0]  padx_lo     = bswap64(dec_padx_be[ 63: 0]);

    wire [63:0] dec_new_x0 = (x0 & mask_hi) ^ ci_hi ^ padx_hi;
    wire [63:0] dec_new_x1 = (x1 & mask_lo) ^ ci_lo ^ padx_lo;

    // ------------------------------------------------------------------
    // Main combinational logic
    // FIX-1: phân biệt rate=64-bit (128) vs rate=128-bit (128a)
    // ------------------------------------------------------------------
    reg [127:0] data_out_comb;
    reg         data_out_valid_comb;
    reg [319:0] state_temp;

    // Determine active rate:
    //   is_128a=1 → 128-bit rate (x0 và x1)
    //   is_128a=0 → 64-bit rate  (chỉ x0, x1 giữ nguyên)
    // mode[0]=0 → ASCON-128 (64-bit rate), mode[0]=1 → ASCON-128a (128-bit rate)
    wire is_128a = (G_DUAL_RATE == 1) && (mode[0] == 1'b1);

    always @(*) begin
        state_temp          = state_in;
        data_out_comb       = 128'b0;
        data_out_valid_comb = 1'b0;
        state_xored         = state_in;

        // ---------------------------------------------------------------
        // FIX-1: unified dual-rate datapath
        //   is_128a=0 (ASCON-128, 64-bit rate):
        //     - Chỉ x0 tham gia XOR
        //     - x1 giữ nguyên trong state
        //     - data_out[127:64] = result 64-bit, data_out[63:0]=0
        //   is_128a=1 (ASCON-128a, 128-bit rate):
        //     - Cả x0 và x1 tham gia XOR
        //     - data_out[127:0] = result 128-bit
        // ---------------------------------------------------------------

        if (block_sel == 2'b00) begin
            // ---- AD block: always encrypt-style XOR absorb ----
            if (!is_128a) begin
                // ASCON-128: rate=64-bit, chỉ x0
                state_temp[319:256] = x0 ^ pd_hi_bswap;
                state_temp[255:192] = x1;           // x1 unchanged
            end else begin
                // ASCON-128a: rate=128-bit, x0 và x1
                state_temp[319:256] = x0 ^ pd_hi_bswap;
                state_temp[255:192] = x1 ^ pd_lo_bswap;
            end
            data_out_valid_comb = 1'b0;  // AD không output data

        end else begin
            // ---- Data block (PT/CT) ----
            if (!is_128a) begin
                // ASCON-128: rate=64-bit
                if (enc_dec == 1'b0) begin
                    // ENCRYPT
                    data_out_comb[127:64] = bswap64(x0 ^ pd_hi_bswap);
                    data_out_comb[ 63: 0] = 64'h0;      // upper lane output=0
                    state_temp[319:256]   = x0 ^ pd_hi_bswap;
                    state_temp[255:192]   = x1;          // x1 unchanged
                end else begin
                    // DECRYPT
                    data_out_comb[127:64] = bswap64(x0 ^ ci_hi);
                    data_out_comb[ 63: 0] = 64'h0;
                    state_temp[319:256]   = dec_new_x0;
                    state_temp[255:192]   = x1;          // x1 unchanged
                end
            end else begin
                // ASCON-128a: rate=128-bit
                if (enc_dec == 1'b0) begin
                    // ENCRYPT
                    data_out_comb[127:64] = bswap64(x0 ^ pd_hi_bswap);
                    data_out_comb[ 63: 0] = bswap64(x1 ^ pd_lo_bswap);
                    state_temp[319:256]   = x0 ^ pd_hi_bswap;
                    state_temp[255:192]   = x1 ^ pd_lo_bswap;
                end else begin
                    // DECRYPT
                    data_out_comb[127:64] = bswap64(x0 ^ ci_hi);
                    data_out_comb[ 63: 0] = bswap64(x1 ^ ci_lo);
                    state_temp[319:256]   = dec_new_x0;
                    state_temp[255:192]   = dec_new_x1;
                end
            end
            data_out_valid_comb = 1'b1;
        end

        state_xored = state_temp;
    end

    // ---- Registered output ----
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out       <= 128'b0;
            data_out_valid <= 1'b0;
        end else begin
            data_out_valid <= data_out_valid_comb;
            if (data_out_valid_comb)
                data_out <= data_out_comb;
        end
    end

endmodule
// ==============================================================================
// FILE: ascon_PERMUTATION.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module: ascon_PERMUTATION  (v9 — Unrolled Pipeline Architecture)
//
// THIẾT KẾ MỚI: Fully Unrolled + Optionally Pipelined
// ============================================================================
//
// KIẾN TRÚC:
//
//   G_SBOX_PIPELINE=0 (PARALLEL_ROUNDS > 1, no inter-round regs):
//     → Combinational chain của G rounds, 1 cycle/call
//     → Crit path = G × (CA + SL + LD) deep
//     → Throughput tối đa, latency tối thiểu
//
//   G_SBOX_PIPELINE=1 (PIPELINE_STAGES > 1):
//     → Mỗi round là 1 pipeline stage với register
//     → Latency = G cycles, nhưng Fmax tăng cao hơn nhiều
//     → Cho phép ghi "pipelined architecture" hợp lệ trong bài báo
//     → 1 new block vào pipeline mỗi cycle = throughput lý tưởng
//
// THAM SỐ:
//   G_SBOX_PIPELINE = 0: combinational unroll (all rounds in 1 cycle)
//   G_SBOX_PIPELINE = 1: pipelined unroll (1 round/cycle, round-register)
//
//   G_ROUNDS_MAX = số rounds tối đa được unroll (12 cho pa)
//   G_COMB_RND   = số rounds được gom vào 1 stage khi pipeline
//                  (= 1: mỗi round 1 stage; = 2: 2 rounds/stage...)
//
// INTERFACE THAY ĐỔI SO VỚI v8:
//   - Thêm output: latency_cycles (để CONTROLLER biết cần đợi bao nhiêu cycle)
//   - done vẫn còn để tương thích với CONTROLLER cũ
//   - Khi G_SBOX_PIPELINE=0: done assert sau 1 cycle (như cũ)
//   - Khi G_SBOX_PIPELINE=1: done assert sau `rounds` cycles
//
// FSM ĐƠN GIẢN HÓA:
//   - Không còn lỗi pha vì mỗi stage là independent register
//   - Pipeline flush tự động khi start_perm
//
// ============================================================================


// ==============================================================================
// FILE: ascon_ROUND_COMB.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module: ASCON_ROUND_COMB
//
// Một round ASCON hoàn toàn combinational:
//   CA → SL (combinational) → LD
//
// Dùng trong unrolled pipeline: mỗi instance là 1 round,
// pipeline register chèn GIỮA các instance.
// ============================================================================

module ASCON_ROUND_COMB (
    input  wire [319:0] state_in,
    input  wire [3:0]   round_const,   // absolute round index
    output wire [319:0] state_out
);

    // ---- Unpack ----
    wire [63:0] x0 = state_in[319:256];
    wire [63:0] x1 = state_in[255:192];
    wire [63:0] x2 = state_in[191:128];
    wire [63:0] x3 = state_in[127: 64];
    wire [63:0] x4 = state_in[ 63:  0];

    // ---- Constant Addition ----
    wire [7:0]  rc  = 8'hF0 - ({4'h0, round_const} * 8'h0F);
    wire [63:0] x2c = x2 ^ {56'h0, rc};

    // ---- Substitution Layer (combinational, bit-sliced) ----
    wire [63:0] s0, s1, s2, s3, s4;

    genvar i;
    generate
        for (i = 0; i < 64; i = i + 1) begin : sl
            wire [4:0] sb_in  = {x4[i], x3[i], x2c[i], x1[i], x0[i]};
            wire [4:0] sb_out;

            // Correct ASCON 5-bit S-box with affine transformations
            wire x0_in = sb_in[0];
            wire x1_in = sb_in[1];
            wire x2_in = sb_in[2];
            wire x3_in = sb_in[3];
            wire x4_in = sb_in[4];

            // 1. First Affine Transformation
            wire v0 = x0_in ^ x4_in;
            wire v1 = x1_in;
            wire v2 = x2_in ^ x1_in;
            wire v3 = x3_in;
            wire v4 = x4_in ^ x3_in;

            // 2. Chi (Non-linear Layer)
            wire t0 = (~v0) & v1;
            wire t1 = (~v1) & v2;
            wire t2 = (~v2) & v3;
            wire t3 = (~v3) & v4;
            wire t4 = (~v4) & v0;

            wire u0 = v0 ^ t1;
            wire u1 = v1 ^ t2;
            wire u2 = v2 ^ t3;
            wire u3 = v3 ^ t4;
            wire u4 = v4 ^ t0;

            // 3. Second Affine Transformation
            assign sb_out[0] = u0 ^ u4;
            assign sb_out[1] = u1 ^ u0;
            assign sb_out[2] = ~u2;
            assign sb_out[3] = u3 ^ u2;
            assign sb_out[4] = u4;

            assign s0[i] = sb_out[0];
            assign s1[i] = sb_out[1];
            assign s2[i] = sb_out[2];
            assign s3[i] = sb_out[3];
            assign s4[i] = sb_out[4];
        end
    endgenerate

    // ---- Linear Diffusion ----
    function [63:0] ROR;
        input [63:0] v;
        input integer n;
        begin ROR = (v >> n) | (v << (64-n)); end
    endfunction

    wire [63:0] d0 = s0 ^ ROR(s0, 19) ^ ROR(s0, 28);
    wire [63:0] d1 = s1 ^ ROR(s1, 61) ^ ROR(s1, 39);
    wire [63:0] d2 = s2 ^ ROR(s2,  1) ^ ROR(s2,  6);
    wire [63:0] d3 = s3 ^ ROR(s3, 10) ^ ROR(s3, 17);
    wire [63:0] d4 = s4 ^ ROR(s4,  7) ^ ROR(s4, 41);

    assign state_out = {d0, d1, d2, d3, d4};

endmodule
module ascon_PERMUTATION #(
    parameter G_SBOX_PIPELINE = 0,   // 0=comb unroll, 1=pipelined unroll
    parameter G_ROUNDS_MAX    = 12,  // max rounds (pa=12, pb=6 hay 8)
    parameter G_COMB_RND      = 1    // rounds per pipeline stage (khi pipeline=1)
) (
    input  wire         clk,
    input  wire         rst_n,

    // State input
    input  wire [319:0] state_in,
    input  wire [319:0] state_bypass,
    input  wire         use_bypass,

    // Round control
    input  wire [3:0]   rounds,       // number of rounds to run (4 or 6 or 12)
    input  wire [3:0]   start_rc,     // starting round constant index
    input  wire         start_perm,   // pulse: start permutation

    // Mode (reserved)
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire         mode,
    /* verilator lint_on UNUSEDSIGNAL */

    // Outputs
    output reg  [319:0] state_out,
    output reg          valid,
    output reg          done
);

    wire [319:0] start_st = use_bypass ? state_bypass : state_in;

    // =========================================================================
    // MODE 0: G_SBOX_PIPELINE=0 — Fully Combinational Unroll
    //
    // Tất cả 12 round instances mắc nối tiếp, kết quả ra trong CÙNG 1 cycle.
    // FSM chỉ cần: latch start_st → 1 cycle sau → done.
    //
    // Throughput: 1 call/cycle = max throughput
    // Critical path: 6×(CA+SL+LD) ≈ nhiều gates, nhưng với 100MHz thường OK
    // =========================================================================
    generate
    if (G_SBOX_PIPELINE == 0) begin : gen_comb_unroll

        // Unroll 12 rounds combinationally
        // Mux output theo `rounds` và `start_rc`
        wire [319:0] round_wire [0:G_ROUNDS_MAX]; // 0=input, 1..12=after each round

        // Round 0 input = start_st (registered below)
        reg [319:0] st_reg;
        reg [3:0]   rc_reg;
        reg [3:0]   rnd_reg;
        reg         running;

        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                st_reg  <= 320'h0;
                rc_reg  <= 4'h0;
                rnd_reg <= 4'h0;
                running <= 1'b0;
                done    <= 1'b0;
                valid   <= 1'b0;
                state_out <= 320'h0;
            end else begin
                done  <= 1'b0;
                valid <= 1'b0;

                if (start_perm) begin
                    st_reg  <= start_st;
                    rc_reg  <= start_rc;
                    rnd_reg <= rounds;
                    running <= 1'b1;
                end

                // 1 cycle later: unrolled chain is valid
                if (running) begin
                    running   <= 1'b0;
                    done      <= 1'b1;
                    valid     <= 1'b1;
                    // Output muxed below
                end
            end
        end

        // Combinational unroll chain
        assign round_wire[0] = st_reg;

        genvar r;
        for (r = 0; r < G_ROUNDS_MAX; r = r + 1) begin : comb_rounds
            wire [319:0] rout;
            ASCON_ROUND_COMB u_round (
                .state_in   (round_wire[r]),
                .round_const(rc_reg + r[3:0]),
                .state_out  (rout)
            );
            assign round_wire[r+1] = rout;
        end

        // Output mux: select result after `rnd_reg` rounds
        // Since we always unroll all 12 but only use first `rounds` outputs:
        // Use a registered mux in the "running" cycle
        reg [319:0] mux_out;
        always @(rnd_reg, round_wire[1], round_wire[2], round_wire[3], round_wire[4], round_wire[5], round_wire[6], round_wire[7], round_wire[8], round_wire[9], round_wire[10], round_wire[11], round_wire[12]) begin
            case (rnd_reg)
                4'd1:  mux_out = round_wire[1];
                4'd2:  mux_out = round_wire[2];
                4'd3:  mux_out = round_wire[3];
                4'd4:  mux_out = round_wire[4];
                4'd5:  mux_out = round_wire[5];
                4'd6:  mux_out = round_wire[6];
                4'd7:  mux_out = round_wire[7];
                4'd8:  mux_out = round_wire[8];
                4'd9:  mux_out = round_wire[9];
                4'd10: mux_out = round_wire[10];
                4'd11: mux_out = round_wire[11];
                4'd12: mux_out = round_wire[12];
                default: mux_out = round_wire[6];
            endcase
        end

        always @(posedge clk or negedge rst_n) begin
            if (!rst_n)
                state_out <= 320'h0;
            else if (running)
                state_out <= mux_out;
        end

    end // gen_comb_unroll

    // =========================================================================
    // MODE 1: G_SBOX_PIPELINE=1 — Pipelined Unroll (1 round/stage)
    //
    // Mỗi round là 1 pipeline stage với flip-flop register ở đầu ra.
    // Latency = `rounds` cycles, nhưng Fmax tăng đáng kể.
    //
    // Đây là thiết kế "pipelined" hợp lệ cho bài báo:
    //   - Có thanh ghi chèn giữa các stages (rounds)
    //   - Fmax cao hơn → tần số clock cao hơn → throughput cao hơn
    //   - RTL reviewer có thể thấy flip-flop thực sự
    //
    // QUAN TRỌNG: Với thiết kế này, CONTROLLER cần biết latency = rounds cycles.
    //   Controller phải đếm `rounds` cycles sau start_perm trước khi dùng kết quả.
    // =========================================================================
    else begin : gen_pipe_unroll

        // Pipeline: 12 registered stages
        // Stage i: register holds state after round i
        reg [319:0] pipe_st  [0:G_ROUNDS_MAX-1]; // pipe_st[i] = after round i+1
        reg [3:0]   pipe_rc  [0:G_ROUNDS_MAX-1]; // round constant at each stage
        reg         pipe_v   [0:G_ROUNDS_MAX-1]; // valid bit propagates through

        // Registered round counter for done detection
        reg [3:0]   rnd_target;    // how many rounds needed
        reg [3:0]   lat_cnt;       // cycle counter since start_perm
        reg         counting;

        // ---- Stage 0: combinational from start_st ----
        wire [319:0] r0_out;
        ASCON_ROUND_COMB u_r0 (
            .state_in   (start_st),
            .round_const(start_rc),
            .state_out  (r0_out)
        );

        // ---- Stages 0..11: each stage reads its own registered state ----
        // stage_out[s] = Round_{s+1}(pipe_st[s])
        // pipe_st[0]   = R0(start_st), registered on start_perm
        // pipe_st[k+1] = registered stage_out[k]
        // Result after N rounds is in pipe_st[N-1] at edge N.
        wire [319:0] stage_out [0:G_ROUNDS_MAX-1];

        genvar s;
        for (s = 0; s < G_ROUNDS_MAX; s = s + 1) begin : pipe_stages
            ASCON_ROUND_COMB u_rs (
                .state_in   (pipe_st[s]),
                .round_const(s == 0 ? (start_rc + 4'd1) : (pipe_rc[s-1] + 4'd1)),
                .state_out  (stage_out[s])
            );
        end

        // ---- Clock registers for each stage ----
        integer k;
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                for (k = 0; k < G_ROUNDS_MAX; k = k + 1) begin
                    pipe_st[k] <= 320'h0;
                    pipe_rc[k] <= 4'h0;
                    pipe_v [k] <= 1'b0;
                end
                rnd_target <= 4'h0;
                lat_cnt    <= 4'h0;
                counting   <= 1'b0;
                done       <= 1'b0;
                valid      <= 1'b0;
                state_out  <= 320'h0;
            end else begin
                done  <= 1'b0;
                valid <= 1'b0;

                // Stage 0 register: latch r0_out when start_perm
                if (start_perm) begin
                    pipe_st[0] <= r0_out;
                    pipe_rc[0] <= start_rc + 4'd1;
                    pipe_v [0] <= 1'b1;
                    rnd_target <= rounds;
                    lat_cnt    <= 4'd1;
                    counting   <= 1'b1;
                end else begin
                    pipe_v[0] <= 1'b0;
                end

                // Stage 1..11 shift register
                for (k = 1; k < G_ROUNDS_MAX; k = k + 1) begin
                    pipe_st[k] <= stage_out[k-1];
                    pipe_rc[k] <= pipe_rc[k-1] + 4'd1;
                    pipe_v [k] <= pipe_v[k-1];
                end

                // Done counter
                if (counting) begin
                    lat_cnt <= lat_cnt + 4'd1;
                    if (lat_cnt >= rnd_target) begin
                        counting  <= 1'b0;
                        done      <= 1'b1;
                        valid     <= 1'b1;
                        // pipe_st[N-1] holds result after N rounds at edge N
                        case (rnd_target)
                            4'd1:  state_out <= pipe_st[0];
                            4'd2:  state_out <= pipe_st[1];
                            4'd3:  state_out <= pipe_st[2];
                            4'd4:  state_out <= pipe_st[3];
                            4'd5:  state_out <= pipe_st[4];
                            4'd6:  state_out <= pipe_st[5];
                            4'd7:  state_out <= pipe_st[6];
                            4'd8:  state_out <= pipe_st[7];
                            4'd9:  state_out <= pipe_st[8];
                            4'd10: state_out <= pipe_st[9];
                            4'd11: state_out <= pipe_st[10];
                            4'd12: state_out <= pipe_st[11];
                            default: state_out <= pipe_st[5];
                        endcase
                    end
                end
            end
        end

    end // gen_pipe_unroll
    endgenerate

endmodule
// ==============================================================================
// FILE: ascon_TAG_GENERATOR.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module: ascon_TAG_GENERATOR  (OPT v2 — bswap rút gọn)
//
// OPTIMIZATION: bswap(A ^ bswap(B)) = bswap(A) ^ B
//
//   Baseline:
//     tag_out = { bswap(state[127:64] ^ bswap(key[127:64])),
//                 bswap(state[ 63: 0] ^ bswap(key[ 63: 0])) }
//     → 4 lần bswap64
//
//   Optimized:
//     tag_out = { bswap(state[127:64]) ^ key[127:64],
//                 bswap(state[ 63: 0]) ^ key[ 63: 0] }
//     → 2 lần bswap64 (giảm 50% logic bswap)
//
// Correctness:
//   bswap(x3 ^ bswap(key_hi)) = bswap(x3) ^ bswap(bswap(key_hi))
//                              = bswap(x3) ^ key_hi    ✓
// ============================================================================
module ascon_TAG_GENERATOR (
    input  wire         clk,
    input  wire         rst_n,

    input  wire         gen_tag,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [319:0] state_in,  // [319:128] unused; tag uses x3/x4 = [127:0]
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire [127:0] key_in,

    output reg  [127:0] tag_out,
    output reg          tag_valid
);

    function [63:0] bswap64;
        input [63:0] x;
        begin
            bswap64 = { x[ 7: 0], x[15: 8], x[23:16], x[31:24],
                        x[39:32], x[47:40], x[55:48], x[63:56] };
        end
    endfunction

    // bswap(x3) ^ key_hi  và  bswap(x4) ^ key_lo
    // = output tag bytes đúng chuẩn NIST Ascon-AEAD128
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            tag_out   <= 128'b0;
            tag_valid <= 1'b0;
        end else if (gen_tag) begin
            tag_out <= {
                bswap64(state_in[127:64]) ^ key_in[127:64],  // tag[127:64]
                bswap64(state_in[ 63: 0]) ^ key_in[ 63: 0]   // tag[ 63: 0]
            };
            tag_valid <= 1'b1;
        end else begin
            tag_valid <= 1'b0;
        end
    end

endmodule
// ==============================================================================
// FILE: ascon_TAG_COMPARATOR.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================
// Module: ascon_TAG_COMPARATOR
// Description: Constant-time comparison of computed tag vs
//              received tag. Used in decryption for authenticity.
// ============================================================
module ascon_TAG_COMPARATOR (
    input  wire         clk,
    input  wire         rst_n,

    input  wire         compare,        // pulse: trigger comparison
    input  wire [127:0] tag_computed,   // from TAG_GENERATOR
    input  wire [127:0] tag_received,   // from external (cipher input)

    output reg          tag_match,      // 1 = authentic
    output reg          tag_done        // comparison complete
);

    // Constant-time XOR comparison (avoid timing side-channel)
    wire [127:0] diff;
    wire         all_zero;

    assign diff     = tag_computed ^ tag_received;
    assign all_zero = (diff == 128'b0);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            tag_match <= 1'b0;
            tag_done  <= 1'b0;
        end else if (compare) begin
            tag_match <= all_zero;
            tag_done  <= 1'b1;
        end else begin
            tag_done  <= 1'b0;
        end
    end

endmodule
// ==============================================================================
// FILE: ascon_CONTROLLER.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module: ascon_CONTROLLER  (v9 — Pipeline-aware FSM)
//
// THAY ĐỔI CHÍNH so với v8:
//
//   1. PIPELINE LATENCY SUPPORT
//      - Khi G_SBOX_PIPELINE=1, permutation có latency = `rounds` cycles
//      - FSM dùng perm_done (đã tồn tại) để chờ → KHÔNG cần sửa nhiều
//      - Nhưng thêm perm_lat_cnt để debug và future use
//
//   2. THROUGHPUT OPTIMIZATION (G_SBOX_PIPELINE=0):
//      - Khi comb unroll: permutation done = 2 cycles (start + latch)
//      - FSM có thể overlap: bắt đầu load data trong khi perm đang chạy
//      - Thêm S_PERM_OVERLAP state cho optimization này
//
//   3. CALLS_PA / CALLS_PB ENCODING:
//      ASCON-128:  pa_rounds=12, pb_rounds=6  (pa calls = 1 full pa)
//      ASCON-128a: pa_rounds=12, pb_rounds=8  (pa calls = 1 full pa)
//      → CONTROLLER gọi permutation 1 lần với rounds=12 (pa) hoặc rounds=6/8 (pb)
//      → KHÔNG còn multi-call phức tạp như trước
//
// STATE ENCODING:
//   S_IDLE          → chờ start
//   S_INIT_LOAD     → load key + nonce vào INIT module
//   S_INIT_PERM     → chạy pa (12 rounds)
//   S_POST_INIT     → XOR key vào state
//   S_AD_LOAD       → load AD block
//   S_AD_PERM       → chạy pb
//   S_DOM_SEP       → domain separation
//   S_DATA_LOAD     → load plaintext/ciphertext block
//   S_DATA_PERM     → chạy pb
//   S_PRE_FIN       → XOR key
//   S_FIN_PERM      → chạy pa (12 rounds)
//   S_TAG_GEN       → generate/compare tag
//   S_DONE          → output results
// ============================================================================

module ascon_CONTROLLER #(
    parameter G_COMB_RND_128  = 6,
    parameter G_COMB_RND_128A = 4,
    parameter G_SBOX_PIPELINE = 0
) (
    input  wire         clk,
    input  wire         rst_n,

    // Top-level control
    input  wire         start,
    input  wire [1:0]   mode,      // 00=ASCON-128, 01=ASCON-128a
    input  wire         enc_dec,   // 0=enc, 1=dec

    // Data inputs (for internal use/routing)
    input  wire [127:0] key_in,
    input  wire [127:0] nonce_in,
    input  wire [127:0] ad_in,
    input  wire         ad_valid,
    input  wire         ad_last,
    input  wire [127:0] data_in,
    input  wire         data_valid,
    input  wire         data_last,
    input  wire [6:0]   data_len,
    input  wire [127:0] tag_received,

    // Status from datapath/permutation
    input  wire         init_done,
    input  wire         perm_done,
    input  wire         tag_gen_valid,
    input  wire         tag_cmp_done,
    input  wire         extra_pad_block_needed,

    // Control outputs
    output reg          load_key,
    output reg          load_nonce,
    output reg          init_start,
    output reg  [1:0]   state_src_sel,
    output reg          state_load,
    output reg          dp_pad_enable,
    output reg  [1:0]   dp_block_sel,
    output reg          dp_enc_dec,
    output reg  [3:0]   perm_rounds,
    output reg  [3:0]   perm_start_rc,
    output reg          perm_start,
    output reg          gen_tag,
    output reg          compare_tag,
    output reg          do_post_init_key_xor,
    output reg          do_pre_fin_key_xor,
    output reg          do_dom_sep,

    // Status outputs
    output reg          data_ready,
    output reg          data_out_valid,
    output reg          done,
    output reg          busy
);

    // =========================================================================
    // Mode-dependent parameters
    // =========================================================================
    wire        is_128a    = mode[0];

    // pb rounds: 6 for ASCON-128, 8 for ASCON-128a
    wire [3:0]  pb_rounds  = is_128a ? 4'd8 : 4'd6;

    // pa rounds: always 12
    wire [3:0]  pa_rounds  = 4'd12;

    // start_rc for pb: rc = 12 - pb_rounds
    // ASCON-128:  pb=6 → start_rc = 6
    // ASCON-128a: pb=8 → start_rc = 4
    wire [3:0]  pb_start_rc = is_128a ? 4'd4 : 4'd6;

    // pa always starts at rc=0
    wire [3:0]  pa_start_rc = 4'd0;

    // =========================================================================
    // FSM State encoding
    // =========================================================================
    localparam [3:0]
        S_IDLE       = 4'd0,
        S_INIT_LOAD  = 4'd1,
        S_INIT_PERM  = 4'd2,
        S_POST_INIT  = 4'd3,
        S_AD_LOAD    = 4'd4,
        S_AD_PERM    = 4'd5,
        S_DOM_SEP    = 4'd6,
        S_DATA_LOAD  = 4'd7,
        S_DATA_PERM  = 4'd8,
        S_PRE_FIN    = 4'd9,
        S_FIN_PERM   = 4'd10,
        S_TAG_GEN    = 4'd11,
        S_DONE       = 4'd12;

    reg [3:0] state, next_state;

    // (perm_done from PERMUTATION already encodes the correct latency — no extra counter needed)

    // =========================================================================
    // FSM — Sequential
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            state <= S_IDLE;
        else
            state <= next_state;
    end

    // =========================================================================
    // FSM — Combinational next-state + output
    // =========================================================================
    always @(*) begin
        // Default: hold everything
        next_state           = state;
        load_key             = 1'b0;
        load_nonce           = 1'b0;
        init_start           = 1'b0;
        state_src_sel        = 2'b10;   // default: from perm
        state_load           = 1'b0;
        dp_pad_enable        = 1'b0;
        dp_block_sel         = 2'b00;
        dp_enc_dec           = enc_dec;
        perm_rounds          = pb_rounds;
        perm_start_rc        = pb_start_rc;
        perm_start           = 1'b0;
        gen_tag              = 1'b0;
        compare_tag          = 1'b0;
        do_post_init_key_xor = 1'b0;
        do_pre_fin_key_xor   = 1'b0;
        do_dom_sep           = 1'b0;
        data_ready           = (state == S_IDLE) || (state == S_DATA_LOAD);
        data_out_valid       = 1'b0;
        done                 = 1'b0;
        busy                 = 1'b1;

        case (state)
            // ---- IDLE: wait for start ----
            S_IDLE: begin
                busy = 1'b0;
                if (start) begin
                    load_key   = 1'b1;
                    load_nonce = 1'b1;
                    next_state = S_INIT_LOAD;
                end
            end

            // ---- INIT_LOAD: start init calculation with stable keys ----
            S_INIT_LOAD: begin
                init_start = 1'b1;
                next_state = S_INIT_PERM;
            end

            // ---- INIT_PERM: wait for INIT to produce state, then run pa ----
            S_INIT_PERM: begin
                if (init_done) begin
                    // Load init state into state register
                    state_src_sel = 2'b00;  // from init
                    state_load    = 1'b1;
                    // Start pa permutation
                    perm_rounds   = pa_rounds;
                    perm_start_rc = pa_start_rc;
                    perm_start    = 1'b1;
                    next_state    = S_POST_INIT;
                end
            end

            // ---- POST_INIT: wait for pa done, XOR key into state ----
            S_POST_INIT: begin
                if (perm_done) begin
                    // XOR key: handled in CORE via do_post_init_key_xor
                    do_post_init_key_xor = 1'b1;
                    state_src_sel        = 2'b10;   // from perm (with key XOR in CORE)
                    state_load           = 1'b1;
                    next_state           = S_AD_LOAD;
                end
            end

            // ---- AD_LOAD: absorb one AD block ----
            S_AD_LOAD: begin
                if (ad_valid) begin
                    dp_pad_enable = 1'b1;
                    dp_block_sel  = 2'b00;  // AD
                    state_src_sel = 2'b01;  // from datapath XOR
                    state_load    = 1'b1;

                    // Start pb after loading
                    perm_rounds   = pb_rounds;
                    perm_start_rc = pb_start_rc;
                    perm_start    = 1'b1;
                    next_state    = S_AD_PERM;
                end else if (!ad_valid && !ad_last) begin
                    // No AD at all: go to domain separation
                    next_state = S_DOM_SEP;
                end
            end

            // ---- AD_PERM: wait for pb after AD ----
            S_AD_PERM: begin
                if (perm_done) begin
                    state_src_sel = 2'b10;
                    state_load    = 1'b1;
                    if (ad_last || extra_pad_block_needed) begin
                        next_state = S_DOM_SEP;
                    end else begin
                        next_state = S_AD_LOAD;
                    end
                end
            end

            // ---- DOM_SEP: flip MSB of x4 ----
            S_DOM_SEP: begin
                do_dom_sep    = 1'b1;
                state_src_sel = 2'b10;   // will be overridden by dom_sep in CORE
                state_load    = 1'b1;
                next_state    = S_DATA_LOAD;
            end

            // ---- DATA_LOAD: absorb/extract one data block ----
            S_DATA_LOAD: begin
                if (data_valid) begin
                    dp_pad_enable  = 1'b1;
                    dp_block_sel   = 2'b01;    // data
                    dp_enc_dec     = enc_dec;
                    state_src_sel  = 2'b01;    // from datapath XOR
                    state_load     = 1'b1;
                    data_out_valid = 1'b1;

                    perm_rounds    = pb_rounds;
                    perm_start_rc  = pb_start_rc;
                    perm_start     = !data_last;  // don't permute on last block
                    next_state     = data_last ? S_PRE_FIN : S_DATA_PERM;
                end else begin
                    next_state     = S_DATA_LOAD; // wait for valid data
                end
            end

            // ---- DATA_PERM: wait for pb after data ----
            S_DATA_PERM: begin
                if (perm_done) begin
                    state_src_sel = 2'b10;
                    state_load    = 1'b1;
                    next_state    = S_DATA_LOAD;
                end
            end

            // ---- PRE_FIN: XOR key into state ----
            S_PRE_FIN: begin
                do_pre_fin_key_xor = 1'b1;
                state_src_sel      = 2'b10;
                state_load         = 1'b1;
                // Start pa
                perm_rounds        = pa_rounds;
                perm_start_rc      = pa_start_rc;
                perm_start         = 1'b1;
                next_state         = S_FIN_PERM;
            end

            // ---- FIN_PERM: wait for final pa ----
            S_FIN_PERM: begin
                if (perm_done) begin
                    state_src_sel = 2'b10;
                    state_load    = 1'b1;
                    next_state    = S_TAG_GEN;
                end
            end

            // ---- TAG_GEN: generate or compare tag ----
            S_TAG_GEN: begin
                gen_tag = 1'b1;
                if (tag_gen_valid) begin
                    if (enc_dec == 1'b0) begin
                        next_state = S_DONE;
                    end else begin
                        compare_tag = 1'b1;
                        if (tag_cmp_done) begin
                            next_state = S_DONE;
                        end
                    end
                end
            end

            // ---- DONE ----
            S_DONE: begin
                done       = 1'b1;
                busy       = 1'b0;
                next_state = S_IDLE;
            end

            default: next_state = S_IDLE;
        endcase
    end

endmodule

module ascon_CORE #(
    parameter G_COMB_RND_128  = 6,
    parameter G_COMB_RND_128A = 4,
    parameter G_SBOX_PIPELINE = 0,
    parameter G_DUAL_RATE     = 1,
    /* verilator lint_off UNUSEDPARAM */
    parameter G_AXI_DATA_W    = 64  // passed to submodules for future use
    /* verilator lint_on UNUSEDPARAM */
) (
    input  wire         clk,
    input  wire         rst_n,
    input  wire         start,
    input  wire [1:0]   mode,
    input  wire         enc_dec,
    input  wire [127:0] key_in,
    input  wire [127:0] nonce_in,
    input  wire [127:0] ad_in,
    input  wire         ad_valid,
    input  wire         ad_last,
    input  wire [127:0] data_in,
    input  wire         data_valid,
    input  wire         data_last,
    input  wire [6:0]   data_len,
    input  wire [127:0] tag_received,

    output wire [127:0] data_out,
    output wire         data_out_valid,
    output wire         data_ready,
    output wire [127:0] tag_out,
    output wire         tag_valid,
    output wire         tag_match,
    output wire         done,
    output wire         busy
);

    // Convention: mode=2'b00 = ASCON-128, mode=2'b01 = ASCON-128a
    // Tất cả submodule nhận cùng mode, không đảo bit.
    // INIT dùng mode gốc để chọn IV đúng.
    // CONTROLLER/DATAPATH/PERMUTATION dùng mode[0]:
    //   mode[0]=0 → ASCON-128  (G=6, calls_pa=2, calls_pb=1)
    //   mode[0]=1 → ASCON-128a (G=4, calls_pa=3, calls_pb=2)
    wire [1:0] mode_int = mode;

    // ----------------------------------------------------------------
    // Internal control wires
    // ----------------------------------------------------------------
    wire        ctrl_load_key, ctrl_load_nonce, ctrl_init_start;
    wire [1:0]  ctrl_state_src_sel;
    wire        ctrl_state_load;
    wire        ctrl_dp_pad_enable;
    wire [1:0]  ctrl_dp_block_sel;
    wire        ctrl_dp_enc_dec;
    wire [3:0]  ctrl_perm_rounds;
    wire [3:0]  ctrl_perm_start_rc;
    wire        ctrl_perm_start;
    wire        ctrl_gen_tag, ctrl_compare_tag;
    /* verilator lint_off UNUSEDSIGNAL */
    wire        ctrl_data_out_valid; // shadowed by dp_data_out_valid
    /* verilator lint_on UNUSEDSIGNAL */
    wire        ctrl_done_sig;
    wire        ctrl_busy_sig;
    wire        ctrl_post_init_key_xor;
    wire        ctrl_pre_fin_key_xor;
    wire        ctrl_dom_sep;

    wire [319:0] init_state_out;
    wire         init_valid;
    wire [319:0] state_reg_out;
    wire [319:0] dp_state_xored;
    wire [127:0] dp_data_out;
    wire         dp_data_out_valid;
    wire         dp_extra_pad;
    wire [319:0] perm_state_out;
    wire         perm_done;
    /* verilator lint_off UNUSEDSIGNAL */
    wire         perm_valid; // not used in current pipeline
    /* verilator lint_on UNUSEDSIGNAL */
    wire [127:0] tag_gen_out;
    wire         tag_gen_valid;
    wire         tag_cmp_match, tag_cmp_done;

    // ----------------------------------------------------------------
    // [FIX-UNOPTFLAT] Break combinational loop on ctrl_dp_pad_enable.
    //
    // Root cause:
    //   CONTROLLER (comb always@*) drives ctrl_dp_pad_enable
    //   → DATAPATH  (comb always@*) computes:
    //       extra_pad_block_needed = pad_enable && (data_len == rate_bytes)
    //   → dp_extra_pad wire feeds back directly into CONTROLLER comb block
    //     (S_AD_LOAD / S_DATA_LOAD read extra_pad_block_needed to decide
    //      the next value of dp_pad_enable) → pure combinational loop.
    //
    // Fix: register dp_extra_pad through one flip-flop here in CORE.
    //   dp_extra_pad   — raw combinational output from DATAPATH  (wire)
    //   dp_extra_pad_r — registered 1-cycle later               (reg)
    //
    // Timing: CONTROLLER only needs extra_pad_block_needed at the
    //   S_AD_LOAD / S_DATA_LOAD states, which fire *after* the block
    //   has already been presented and data_len is stable.  The 1-cycle
    //   pipeline delay is absorbed by the FSM before it transitions.
    // ----------------------------------------------------------------
    reg dp_extra_pad_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            dp_extra_pad_r <= 1'b0;
        else
            dp_extra_pad_r <= dp_extra_pad;
    end

    // ----------------------------------------------------------------
    // Key byte-swap (BE → LE)
    // ----------------------------------------------------------------
    wire [63:0] key_hi_bswap = {
        key_in[ 71: 64], key_in[ 79: 72], key_in[ 87: 80], key_in[ 95: 88],
        key_in[103: 96], key_in[111:104], key_in[119:112], key_in[127:120]
    };
    wire [63:0] key_lo_bswap = {
        key_in[  7:  0], key_in[ 15:  8], key_in[ 23: 16], key_in[ 31: 24],
        key_in[ 39: 32], key_in[ 47: 40], key_in[ 55: 48], key_in[ 63: 56]
    };

    // POST_INIT: XOR key vào x3 và x4
    wire [319:0] post_init_state = {
        perm_state_out[319:128],
        perm_state_out[127: 64] ^ key_hi_bswap,
        perm_state_out[ 63:  0] ^ key_lo_bswap
    };

    // PRE_FIN: XOR key vào x2 và x3
    wire [319:0] pre_fin_state = {
        state_reg_out[319:192],
        state_reg_out[191:128] ^ key_hi_bswap,
        state_reg_out[127: 64] ^ key_lo_bswap,
        state_reg_out[ 63:  0]
    };

    // DOM_SEP: flip MSB của x4
    wire [319:0] dom_sep_state = {
        state_reg_out[319:64],
        ~state_reg_out[63],
        state_reg_out[ 62:  0]
    };

    wire [319:0] state_next_final =
        ctrl_post_init_key_xor ? post_init_state  :
        ctrl_pre_fin_key_xor   ? pre_fin_state     :
        ctrl_dom_sep           ? dom_sep_state      :
        (ctrl_state_src_sel == 2'b00) ? init_state_out  :
        (ctrl_state_src_sel == 2'b01) ? dp_state_xored  :
                                        perm_state_out;

    wire use_bypass = ctrl_state_load & ctrl_perm_start;

    // ----------------------------------------------------------------
    // Submodule instantiation
    // ----------------------------------------------------------------

    // FIX: INITIALIZATION dùng mode GỐC (không đảo) → chọn đúng IV
    ascon_INITIALIZATION u_init (
        .clk(clk), .rst_n(rst_n),
        .load_key(ctrl_load_key), .load_nonce(ctrl_load_nonce),
        .mode(mode),                 // ← mode gốc, không đảo
        .init_start(ctrl_init_start),
        .key_in(key_in), .nonce_in(nonce_in),
        .init_state_out(init_state_out), .init_valid(init_valid)
    );

    ascon_STATE_REGISTER u_state_reg (
        .clk(clk), .rst_n(rst_n),
        .src_sel(ctrl_state_src_sel), .load(ctrl_state_load),
        .state_in(state_next_final),
        .init_state(init_state_out),
        .dp_state(dp_state_xored),
        .perm_state(perm_state_out),
        .state_out(state_reg_out)
    );

    // FIX: DATAPATH dùng mode_int → 128a rate (128-bit)
    ascon_DATAPATH #(
        .G_DUAL_RATE(G_DUAL_RATE)
    ) u_dp (
        .clk(clk), .rst_n(rst_n),
        .mode(mode_int),             // ← mode_int
        .enc_dec(ctrl_dp_enc_dec),
        .pad_enable(ctrl_dp_pad_enable), .block_sel(ctrl_dp_block_sel),
        .ad_in(ad_in), .data_in(data_in), .data_len(data_len),
        .state_in(state_reg_out),
        .state_xored(dp_state_xored),
        .data_out(dp_data_out), .data_out_valid(dp_data_out_valid),
        .extra_pad_block_needed(dp_extra_pad)
    );

    // FIX: PERMUTATION dùng mode_int (consistent)
    ascon_PERMUTATION #(
        .G_SBOX_PIPELINE(G_SBOX_PIPELINE)
    ) u_perm (
        .clk(clk), .rst_n(rst_n),
        .state_in(state_reg_out),
        .state_bypass(state_next_final),
        .use_bypass(use_bypass),
        .rounds(ctrl_perm_rounds),
        .start_rc(ctrl_perm_start_rc),
        .start_perm(ctrl_perm_start),
        .mode(mode_int[0]),          // ← mode_int
        .state_out(perm_state_out),
        .valid(perm_valid), .done(perm_done)
    );

    ascon_TAG_GENERATOR u_tag_gen (
        .clk(clk), .rst_n(rst_n),
        .gen_tag(ctrl_gen_tag),
        .state_in(state_reg_out), .key_in(key_in),
        .tag_out(tag_gen_out), .tag_valid(tag_gen_valid)
    );

    ascon_TAG_COMPARATOR u_tag_cmp (
        .clk(clk), .rst_n(rst_n),
        .compare(ctrl_compare_tag),
        .tag_computed(tag_gen_out), .tag_received(tag_received),
        .tag_match(tag_cmp_match), .tag_done(tag_cmp_done)
    );

    // FIX: CONTROLLER dùng mode_int → 128a GCD params
    ascon_CONTROLLER #(
        .G_COMB_RND_128 (G_COMB_RND_128),
        .G_COMB_RND_128A(G_COMB_RND_128A),
        .G_SBOX_PIPELINE(G_SBOX_PIPELINE)
    ) u_ctrl (
        .clk(clk), .rst_n(rst_n),
        .start(start), .mode(mode_int), .enc_dec(enc_dec),  // ← mode_int
        .key_in(key_in), .nonce_in(nonce_in),
        .ad_in(ad_in), .ad_valid(ad_valid), .ad_last(ad_last),
        .data_in(data_in), .data_valid(data_valid), .data_last(data_last), .data_len(data_len),
        .tag_received(tag_received),
        .data_ready(data_ready), .data_out_valid(ctrl_data_out_valid),
        .done(ctrl_done_sig), .busy(ctrl_busy_sig),
        .load_key(ctrl_load_key), .load_nonce(ctrl_load_nonce),
        .init_start(ctrl_init_start),
        .state_src_sel(ctrl_state_src_sel), .state_load(ctrl_state_load),
        .dp_pad_enable(ctrl_dp_pad_enable), .dp_block_sel(ctrl_dp_block_sel),
        .dp_enc_dec(ctrl_dp_enc_dec),
        .perm_rounds(ctrl_perm_rounds),
        .perm_start_rc(ctrl_perm_start_rc),
        .perm_start(ctrl_perm_start),
        .gen_tag(ctrl_gen_tag), .compare_tag(ctrl_compare_tag),
        .do_post_init_key_xor(ctrl_post_init_key_xor),
        .do_pre_fin_key_xor(ctrl_pre_fin_key_xor),
        .do_dom_sep(ctrl_dom_sep),
        .extra_pad_block_needed(dp_extra_pad_r),  // [FIX-UNOPTFLAT] registered
        .init_done(init_valid), .perm_done(perm_done),
        .tag_gen_valid(tag_gen_valid), .tag_cmp_done(tag_cmp_done)
    );

    assign data_out       = dp_data_out;
    assign data_out_valid = dp_data_out_valid;
    assign tag_out        = tag_gen_out;
    assign tag_valid      = tag_gen_valid;
    assign tag_match      = tag_cmp_match;
    assign done           = ctrl_done_sig;
    assign busy           = ctrl_busy_sig;

endmodule
// ==============================================================================
// FILE: ascon_dma.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : ascon_dma
// Project : ASCON Crypto Accelerator IP
// Version : 1.2  (fix: remove nonexistent wr_start connection to u_ctrl_fsm)
//
// Description:
//   ASCON-dedicated DMA engine. Orchestrates the full data movement pipeline:
//     DDR → (AXI4 read) → RD FIFO → ascon_CORE → WR FIFO → (AXI4 write) → DDR
//
//   Register map (offset within ascon_axi_slave space, base 0x2000_0000):
//     0x100  DMA_SRC_ADDR   R/W  Source address (plaintext in DDR)
//     0x104  DMA_DST_ADDR   R/W  Destination address (ctext+tag out)
//     0x108  DMA_BYTE_LEN   R/W  Bytes to read (Phase 1: always 8)
//     0x10C  DMA_CTRL       R/W  [0]=START [1]=SOFT_RST [2]=RD_ONLY [3]=WR_ONLY
//     0x110  DMA_STATUS     RO   [0]=BUSY [1]=DONE [2]=RD_DONE [3]=WR_DONE
//                                [4]=RD_ERROR [5]=WR_ERROR [6]=FIFO_OVERFLOW
//     0x114  DMA_BURST_LEN  R/W  [7:0] AXI burst length (0=1 beat)
//     0x118  DMA_ERR_ADDR   RO   Address that caused AXI error (debug)
//
//   Register values are driven from ascon_reg_bank via the control interface.
//   This module has NO internal AXI slave — all registers live in ascon_reg_bank.
//
// Hierarchy:
//   ascon_dma
//   ├── dma_ctrl_fsm         — top control FSM (sequences all phases)
//   ├── dma_read_engine      — AXI4 master read (fetch plaintext)
//   ├── dma_write_engine     — AXI4 master write (store ctext + tag)
//   ├── sync_fifo (rd_fifo)  — 4 × 64-bit RD FIFO
//   └── sync_fifo (wr_fifo)  — 8 × 32-bit WR FIFO
//
// External interfaces:
//   Control   : from ascon_axi_slave (reg_bank) — src_addr, dst_addr, byte_len,
//               dma_start, dma_soft_rst, burst_len, dma_busy, dma_done, dma_error
//   Core      : to/from ascon_CORE
//   AXI4 Full : M_AXI_* master interface (connects to crossbar / memory)
//
// Phase 1 constraints:
//   - Single 64-bit block (8 bytes plaintext)
//   - 1-beat AXI read (ARLEN=0), 3-beat AXI write (AWLEN=2)
//   - No concurrent read/write; strictly sequential
//   - No unaligned access handling (driver must ensure 8-byte alignment)
//
// Firmware driver notes (DO NOT CHANGE without updating firmware):
//   1. Write DMA_SRC_ADDR (0x100), DMA_DST_ADDR (0x104), DMA_BYTE_LEN (0x108)
//      each separated by a STATUS read fence (AXI ordering)
//   2. Write DMA_CTRL (0x10C) bit[0]=1 to START — this is SEPARATE from
//      ASCON core CTRL at offset 0x000. Driver MUST write 0x10C, NOT 0x000.
//   3. Poll DMA_STATUS (0x110) bit[1]=DONE or bit[4:5]=ERROR
//      NOTE: CPU-side STATUS mirror is at 0x004 bits[3:2] (dma_done/dma_busy)
//            in ascon_reg_bank. Firmware polls 0x20000004 bits[3:2].
//   4. Data coherency: CPU must ensure plaintext is in DMEM SRAM (not only
//      in DCache) before DMA start. Use non-cacheable writes (MMIO path) or
//      explicit cache flush. DMA bypasses DCache and reads SRAM directly.
// ============================================================================


// ==============================================================================
// FILE: sync_fifo.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : sync_fifo
// Project : ASCON Crypto Accelerator IP
//
// Description:
//   Generic synchronous FIFO with optional FWFT (First-Word-Fall-Through).
//   - Full/empty flags are registered (no combinational glitch)
//   - Simultaneous push + pop when not empty/full is supported
//   - DATA_OUT is registered (read latency = 1 cycle after pop)
//   - DATA_OUT holds last value when empty
//   - [OPT] fwft_dout/fwft_valid: combinational read of FIFO head,
//           available immediately when !empty. Enables zero-latency consume.
//
// Parameters:
//   WIDTH : data width in bits
//   DEPTH : number of entries (must be power of 2)
//
// [FIX] Split mem[] write from pointer reset into separate always blocks.
//
// Root cause of Yosys "Multiple edge sensitive events" error:
//   The original write block `always @(posedge clk or negedge rst_n)` had
//   BOTH `mem[wr_idx] <= din` AND `wr_ptr` reset inside it.  Yosys tries
//   to infer $adff (async-reset DFF) for every signal in that sensitivity
//   list, including the mem[] array.  RAM/ROM arrays cannot be synthesised
//   as $adff; the tool hits an internal contradiction and aborts.
//
// Fix: mem[] lives in its own `always @(posedge clk)` block with NO reset
//   branch.  This maps cleanly to a standard $dff / BRAM primitive.
//   wr_ptr stays in its own `always @(posedge clk or negedge rst_n)` block
//   so it still resets correctly.  Functional behaviour is unchanged:
//   mem[] contents are undefined after rst_n but can never be consumed
//   until wr_ptr advances, which only happens on a valid push.
// ============================================================================

module sync_fifo #(
    parameter WIDTH = 64,
    parameter DEPTH = 4           // must be power of 2
) (
    input  wire             clk,
    input  wire             rst_n,

    // Write port
    input  wire [WIDTH-1:0] din,
    input  wire             push,
    output wire             full,

    // Read port (registered — 1 cycle latency after pop)
    output reg  [WIDTH-1:0] dout,
    input  wire             pop,
    output wire             empty,

    // FWFT port (combinational — zero latency, valid when fwft_valid=1)
    output wire [WIDTH-1:0] fwft_dout,
    output wire             fwft_valid,

    // Status
    output wire [$clog2(DEPTH):0] count   // number of entries currently stored
);

    localparam PTR_W = $clog2(DEPTH);

    // Assertion: DEPTH must be a power of 2
    initial begin
        if ((DEPTH & (DEPTH - 1)) != 0) begin
            $error("sync_fifo: DEPTH=%0d must be a power of 2", DEPTH);
            $finish;
        end
    end

    reg [WIDTH-1:0] mem [0:DEPTH-1];
    reg [PTR_W:0]   wr_ptr;   // one extra bit for full/empty distinction
    reg [PTR_W:0]   rd_ptr;

    wire [PTR_W-1:0] wr_idx = wr_ptr[PTR_W-1:0];
    wire [PTR_W-1:0] rd_idx = rd_ptr[PTR_W-1:0];

    assign full  = (wr_ptr == {~rd_ptr[PTR_W], rd_ptr[PTR_W-1:0]});
    assign empty = (wr_ptr == rd_ptr);

    // ── FWFT: combinational read of current head ─────────────────────────
    // Available immediately when FIFO is not empty. Consumer can latch
    // fwft_dout in the same cycle as checking fwft_valid, then pop next cycle.
    assign fwft_dout  = mem[rd_idx];
    assign fwft_valid = ~empty;
    assign count = wr_ptr - rd_ptr;

    // ── Write pointer — async reset, infers $adff ─────────────────────────
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            wr_ptr <= {(PTR_W+1){1'b0}};
        else if (push && !full)
            wr_ptr <= wr_ptr + 1'b1;
    end

    // ── Memory array — posedge clk ONLY, infers $dff / BRAM ──────────────
    // [FIX] No negedge rst_n here: mem[] cannot be an $adff.
    // Contents are undefined after reset but safe — wr_ptr == rd_ptr == 0
    // (empty) so no pop can occur until a push writes valid data first.
    always @(posedge clk) begin
        if (push && !full)
            mem[wr_idx] <= din;
    end

    // ── Read pointer and output — async reset, infers $adff ──────────────
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_ptr <= {(PTR_W+1){1'b0}};
            dout   <= {WIDTH{1'b0}};
        end else if (pop && !empty) begin
            dout   <= mem[rd_idx];
            rd_ptr <= rd_ptr + 1'b1;
        end
    end

endmodule
// ==============================================================================
// FILE: dma_read_engine.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : dma_read_engine
// Project : ASCON Crypto Accelerator IP
// Parent  : ascon_dma
//
// Description:
//   AXI4-Full Master read engine. Issues one read transaction to fetch
//   plaintext from memory and pushes the received data into the RD FIFO.
//
// AXI burst behaviour (configurable via burst_len):
//   ARLEN  = burst_len   (0 = 1 beat, N = N+1 beats)
//   ARSIZE = 3'b011      (8 bytes/beat — matches 64-bit bus)
//   ARBURST= 2'b01       (INCR)
//
// FSM states:
//   RD_IDLE → RD_ADDR → RD_DATA → RD_DONE → RD_IDLE
//
// Error handling:
//   [FIX-1] rd_error is now STICKY across beats (was accidentally cleared on
//           subsequent valid beats in the same burst when RRESP was OK).
//   [FIX-2] FIFO-full error now captures the current read-address beat
//           (M_AXI_ARADDR + beat_count*8) instead of the fixed ARADDR.
//   [FIX-3] rd_error is cleared at the START of a new transaction (rd_start),
//           not unconditionally each cycle, so the host can read the sticky
//           error flag after the burst completes.
//   [FIX-4] Beat counter added so multi-beat bursts push every beat into FIFO.
//           Previous code had no counter → only last beat was pushed correctly
//           (fifo_push de-asserted between beats by the default clearing).
//   [FIX-5] M_AXI_RREADY is de-asserted when FIFO is full (back-pressure),
//           preventing data loss on slow FIFOs. Previous code left RREADY high
//           and set rd_error instead — data was silently dropped.
//   [FIX-6] rd_busy is kept high through RD_DONE state so that the upstream
//           FSM cannot issue a new rd_start before rd_done is seen.
//
// ============================================================================

module dma_read_engine #(
    parameter ADDR_WIDTH     = 32,
    parameter AXI_DATA_WIDTH = 64,
    parameter AXI_ID_WIDTH   = 4
) (
    input  wire                       clk,
    input  wire                       rst_n,

    // ── Control (from DMA top FSM) ────────────────────────────────────────────
    input  wire [ADDR_WIDTH-1:0]      src_addr,
    input  wire [7:0]                 burst_len,    // ARLEN value (0 = 1 beat)
    input  wire                       dma_start,    // 1-cycle pulse: reset cur_src_addr to src_addr
    input  wire                       rd_start,     // 1-cycle pulse: begin transaction
    output reg                        rd_busy,
    output reg                        rd_done,      // 1-cycle pulse: all beats received
    output reg                        rd_error,     // sticky: AXI returned error or FIFO full
    output reg  [ADDR_WIDTH-1:0]      rd_err_addr,

    // ── RD FIFO push interface ────────────────────────────────────────────────
    output reg  [AXI_DATA_WIDTH-1:0]  fifo_din,
    output reg                        fifo_push,
    input  wire                       fifo_full,

    // ── AXI4 Read Address Channel ─────────────────────────────────────────────
    output reg  [AXI_ID_WIDTH-1:0]    M_AXI_ARID,
    output reg  [ADDR_WIDTH-1:0]      M_AXI_ARADDR,
    output reg  [7:0]                 M_AXI_ARLEN,
    output wire [2:0]                 M_AXI_ARSIZE,
    output wire [1:0]                 M_AXI_ARBURST,
    output wire [3:0]                 M_AXI_ARCACHE,
    output wire [2:0]                 M_AXI_ARPROT,
    output reg                        M_AXI_ARVALID,
    input  wire                       M_AXI_ARREADY,

    // ── AXI4 Read Data Channel ────────────────────────────────────────────────
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [AXI_ID_WIDTH-1:0]    M_AXI_RID,   // ID not checked (single outstanding)
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire [AXI_DATA_WIDTH-1:0]  M_AXI_RDATA,
    input  wire [1:0]                 M_AXI_RRESP,
    input  wire                       M_AXI_RLAST,
    input  wire                       M_AXI_RVALID,
    output reg                        M_AXI_RREADY
);

    // ─── Fixed AXI parameters ────────────────────────────────────────────────
    assign M_AXI_ARSIZE  = 3'b011;   // 8 bytes/beat (64-bit bus)
    assign M_AXI_ARBURST = 2'b01;    // INCR
    assign M_AXI_ARCACHE = 4'b0010;  // Normal Non-cacheable Bufferable
    assign M_AXI_ARPROT  = 3'b000;

    // ─── FSM state encoding ───────────────────────────────────────────────────
    localparam [1:0]
        RD_IDLE = 2'd0,
        RD_ADDR = 2'd1,
        RD_DATA = 2'd2,
        RD_DONE = 2'd3;

    reg [1:0] state;

    // ─── Current source address (auto-increments per burst for multi-block DMA) ─
    reg [ADDR_WIDTH-1:0] cur_src_addr;

    // ─── Beat counter (tracks which beat of burst we are on) ─────────────────
    // [FIX-4] Needed to correctly push every beat and to compute err_addr per beat
    reg [7:0] beat_cnt;

    // ─── Registered burst_len (latched on rd_start so it cannot change mid-burst)
    /* verilator lint_off UNUSEDSIGNAL */
    reg [7:0] burst_len_r;  // safety latch, not read back in FSM
    /* verilator lint_on UNUSEDSIGNAL */

    // ─── Current beat address (base + beat_cnt * bytes_per_beat) ─────────────
    // Used only for rd_err_addr capture; AXI INCR addressing is done by slave.
    wire [ADDR_WIDTH-1:0] cur_beat_addr =
        M_AXI_ARADDR + {{(ADDR_WIDTH-11){1'b0}}, beat_cnt, 3'b000};
        // beat_cnt * 8  (3-bit left-shift, zero-extended to ADDR_WIDTH)

    // =========================================================================
    // Main FSM
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state          <= RD_IDLE;
            rd_busy        <= 1'b0;
            rd_done        <= 1'b0;
            rd_error       <= 1'b0;
            rd_err_addr    <= {ADDR_WIDTH{1'b0}};
            M_AXI_ARVALID  <= 1'b0;
            M_AXI_ARID     <= {AXI_ID_WIDTH{1'b0}};
            M_AXI_ARADDR   <= {ADDR_WIDTH{1'b0}};
            M_AXI_ARLEN    <= 8'h00;
            M_AXI_RREADY   <= 1'b0;
            fifo_push      <= 1'b0;
            fifo_din       <= {AXI_DATA_WIDTH{1'b0}};
            beat_cnt       <= 8'h00;
            burst_len_r    <= 8'h00;
            cur_src_addr   <= {ADDR_WIDTH{1'b0}};
        end else begin
            // ── Default: clear 1-cycle strobes ───────────────────────────────
            rd_done   <= 1'b0;
            fifo_push <= 1'b0;

            // Capture base address on DMA start (also used for simultaneous rd_start)
            if (dma_start) cur_src_addr <= src_addr;

            case (state)

                // ─────────────────────────────────────────────────────────────
                RD_IDLE: begin
                    rd_busy       <= 1'b0;
                    M_AXI_ARVALID <= 1'b0;
                    M_AXI_RREADY  <= 1'b0;
                    beat_cnt      <= 8'h00;

                    if (rd_start) begin
                        // [FIX-3] Clear error only when a new transaction begins
                        rd_error      <= 1'b0;
                        rd_err_addr   <= {ADDR_WIDTH{1'b0}};

                        rd_busy       <= 1'b1;
                        burst_len_r   <= burst_len;        // latch for safety
                        M_AXI_ARID    <= {AXI_ID_WIDTH{1'b0}};
                        // dma_start and rd_start arrive together for block-0; use src_addr directly.
                        // For blocks 1+, dma_start=0 and cur_src_addr holds the next address.
                        M_AXI_ARADDR  <= dma_start ? src_addr : cur_src_addr;
                        M_AXI_ARLEN   <= burst_len;
                        M_AXI_ARVALID <= 1'b1;
                        state         <= RD_ADDR;
                    end
                end

                // ─────────────────────────────────────────────────────────────
                RD_ADDR: begin
                    if (M_AXI_ARREADY && M_AXI_ARVALID) begin
                        M_AXI_ARVALID <= 1'b0;
                        // [FIX-5] Only assert RREADY when FIFO has space
                        M_AXI_RREADY  <= ~fifo_full;
                        state         <= RD_DATA;
                    end
                end

                // ─────────────────────────────────────────────────────────────
                RD_DATA: begin
                    // [FIX-5] Dynamic back-pressure: follow FIFO availability
                    M_AXI_RREADY <= ~fifo_full;

                    if (M_AXI_RVALID && M_AXI_RREADY) begin
                        // ── AXI response check ────────────────────────────────
                        // [FIX-1] Use |= semantics: once set, rd_error stays set
                        if (M_AXI_RRESP != 2'b00) begin
                            rd_error    <= 1'b1;
                            // Only capture the first error address
                            if (!rd_error)
                                rd_err_addr <= cur_beat_addr;
                        end

                        // ── Push data into FIFO ───────────────────────────────
                        // RREADY was only asserted when !fifo_full, so we should
                        // never arrive here with fifo_full=1.  Guard anyway.
                        if (!fifo_full) begin
                            fifo_din  <= M_AXI_RDATA;
                            fifo_push <= 1'b1;
                        end else begin
                            // [FIX-2] Capture per-beat address, not fixed ARADDR
                            rd_error <= 1'b1;
                            if (!rd_error)
                                rd_err_addr <= cur_beat_addr;
                        end

                        // [FIX-4] Advance beat counter on every accepted beat
                        beat_cnt <= beat_cnt + 8'h01;

                        // ── End-of-burst ──────────────────────────────────────
                        if (M_AXI_RLAST) begin
                            M_AXI_RREADY <= 1'b0;
                            // Advance cur_src_addr by (ARLEN+1)*8 bytes for the next burst
                            cur_src_addr <= M_AXI_ARADDR + {22'b0, burst_len_r, 3'b000} + 32'd8;
                            state        <= RD_DONE;
                        end
                    end
                end

                // ─────────────────────────────────────────────────────────────
                // Wait 1 cycle after the last fifo_push so the FIFO's wr_ptr
                // has incremented and empty=0 before asserting rd_done.
                // [FIX-6] rd_busy stays high here — cleared in IDLE entry.
                RD_DONE: begin
                    rd_done <= 1'b1;
                    // rd_busy will be cleared at the top of RD_IDLE next cycle
                    state   <= RD_IDLE;
                end

                default: state <= RD_IDLE;

            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: dma_write_engine.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : dma_write_engine
// Version : v4.0  (FWFT + Dynamic AXI Burst)
//
// CHANGES from v3.0:
//   [OPT-1] FWFT read: uses fifo_fwft_dout (combinational) instead of
//           fifo_dout (registered). Eliminates WR_WAIT_H + WR_LATCH_H +
//           WR_WAIT_L states → 3 fewer cycles per AXI beat.
//
//   [OPT-2] Dynamic AXI burst: AWLEN = min(remaining_beats-1, MAX_BURST_LEN).
//           With MAX_BURST_LEN=15, CT (16 beats) → AWLEN=15 (1 transaction).
//           TAG (2 beats) → AWLEN=1. Only 2 AXI transactions vs 18 before.
//           Amortises IDLE+ADDR+RESP overhead across 16 beats instead of 1.
//
//   [OPT-3] New input: total_wr_beats [28:0]. Initialises remaining_beats
//           counter on dma_start. Enables per-transaction AWLEN computation
//           without changing ctrl_fsm interface.
//
//   wr_done still pulsed once per AXI W handshake (not per transaction)
//   → fully compatible with dma_ctrl_fsm beat-counting logic.
//
// FSM states (6):
//   WR_IDLE   — wait for fifo_count>=2 && remaining_beats>0; issue AWVALID
//   WR_ADDR   — wait AWREADY; latch H via FWFT (or go WR_LOAD_H if empty)
//   WR_LOAD_H — stall until H word appears in FIFO; latch + pop
//   WR_DATA_L — wait for L word; form 64-bit WDATA; assert WVALID+WLAST
//   WR_BEAT   — wait WREADY; pulse wr_done; loop back or go WR_RESP
//   WR_RESP   — wait BVALID; update address; decrement remaining_beats
//
// Per-beat timing (no stall, assuming AWREADY/WREADY/BVALID immediate):
//   First beat of burst: WR_ADDR(1)+WR_DATA_L(1)+WR_BEAT(1) = 3 cycles
//   Each subsequent   : WR_LOAD_H(1)+WR_DATA_L(1)+WR_BEAT(1) = 3 cycles
//   Plus overhead     : WR_IDLE(1)+WR_RESP(1) amortised over burst_beats
//
// ============================================================================

module dma_write_engine #(
    parameter ADDR_WIDTH     = 32,
    parameter AXI_DATA_WIDTH = 64,
    parameter AXI_ID_WIDTH   = 4,
    parameter MAX_BURST_LEN  = 8'd15   // max AWLEN value (0-based); 15 → 16 beats
) (
    input  wire                        clk,
    input  wire                        rst_n,

    // ── Control ───────────────────────────────────────────────────────────────
    input  wire [ADDR_WIDTH-1:0]       dst_addr,
    input  wire                        dma_start,      // pulse: reset addr + beat counter
    input  wire [28:0]                 total_wr_beats, // total beats = total_blocks + 2
    output reg                         wr_busy,
    output reg                         wr_done,        // pulsed once per W handshake
    output reg                         wr_error,
    output reg  [ADDR_WIDTH-1:0]       wr_err_addr,

    // ── WR FIFO registered path (kept for port compatibility, unused in logic) ─
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [31:0]                 fifo_dout,
    /* verilator lint_on UNUSEDSIGNAL */
    output reg                         fifo_pop,
    input  wire [5:0]                  fifo_count,

    // ── WR FIFO FWFT path (combinational — zero latency) ──────────────────────
    input  wire [31:0]                 fifo_fwft_dout,
    input  wire                        fifo_fwft_valid,

    // ── AXI4 Write Address Channel ────────────────────────────────────────────
    output reg  [AXI_ID_WIDTH-1:0]     M_AXI_AWID,
    output reg  [ADDR_WIDTH-1:0]       M_AXI_AWADDR,
    output wire [7:0]                  M_AXI_AWLEN,    // driven from awlen_reg
    output wire [2:0]                  M_AXI_AWSIZE,
    output wire [1:0]                  M_AXI_AWBURST,
    output wire [3:0]                  M_AXI_AWCACHE,
    output wire [2:0]                  M_AXI_AWPROT,
    output reg                         M_AXI_AWVALID,
    input  wire                        M_AXI_AWREADY,

    // ── AXI4 Write Data Channel ───────────────────────────────────────────────
    output reg  [AXI_DATA_WIDTH-1:0]   M_AXI_WDATA,
    output wire [AXI_DATA_WIDTH/8-1:0] M_AXI_WSTRB,
    output reg                         M_AXI_WLAST,
    output reg                         M_AXI_WVALID,
    input  wire                        M_AXI_WREADY,

    // ── AXI4 Write Response Channel ───────────────────────────────────────────
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [AXI_ID_WIDTH-1:0]     M_AXI_BID,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire [1:0]                  M_AXI_BRESP,
    input  wire                        M_AXI_BVALID,
    output reg                         M_AXI_BREADY
);

    // ── Fixed AXI parameters (combinational assigns) ─────────────────────────
    reg [7:0] awlen_reg;
    assign M_AXI_AWLEN   = awlen_reg;
    assign M_AXI_AWSIZE  = 3'b011;         // 8 bytes/beat
    assign M_AXI_AWBURST = 2'b01;          // INCR
    assign M_AXI_AWCACHE = 4'b0010;        // Normal Non-cacheable Bufferable
    assign M_AXI_AWPROT  = 3'b000;
    assign M_AXI_WSTRB   = {(AXI_DATA_WIDTH/8){1'b1}};

    // ── FSM state encoding ────────────────────────────────────────────────────
    localparam [2:0]
        WR_IDLE   = 3'd0,
        WR_ADDR   = 3'd1,
        WR_LOAD_H = 3'd2,
        WR_DATA_L = 3'd3,
        WR_BEAT   = 3'd4,
        WR_RESP   = 3'd5;

    reg [2:0]            state;
    reg [31:0]           wdata_hi;          // latched high word of current beat
    reg [ADDR_WIDTH-1:0] cur_dst_addr;

    // ── Beat tracking registers ───────────────────────────────────────────────
    reg [28:0] remaining_beats;   // beats still to be written this DMA operation
    reg [7:0]  beats_in_burst;    // beats remaining in current AXI transaction
    reg [7:0]  burst_beats;       // = awlen_reg + 1; used for addr/counter update

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state           <= WR_IDLE;
            wr_busy         <= 1'b0;
            wr_done         <= 1'b0;
            wr_error        <= 1'b0;
            wr_err_addr     <= {ADDR_WIDTH{1'b0}};
            M_AXI_AWVALID   <= 1'b0;
            M_AXI_AWID      <= {AXI_ID_WIDTH{1'b0}};
            M_AXI_AWADDR    <= {ADDR_WIDTH{1'b0}};
            awlen_reg       <= 8'd0;
            M_AXI_WVALID    <= 1'b0;
            M_AXI_WDATA     <= {AXI_DATA_WIDTH{1'b0}};
            M_AXI_WLAST     <= 1'b0;
            M_AXI_BREADY    <= 1'b0;
            fifo_pop        <= 1'b0;
            wdata_hi        <= 32'h0;
            cur_dst_addr    <= {ADDR_WIDTH{1'b0}};
            remaining_beats <= 29'd0;
            beats_in_burst  <= 8'd0;
            burst_beats     <= 8'd0;
        end else begin
            // ── Default: clear 1-cycle strobes ───────────────────────────────
            wr_done  <= 1'b0;
            fifo_pop <= 1'b0;

            // ── dma_start: highest priority — reinitialise for new DMA op ────
            if (dma_start) begin
                state           <= WR_IDLE;
                cur_dst_addr    <= dst_addr;
                remaining_beats <= total_wr_beats;
                wr_error        <= 1'b0;
                wr_busy         <= 1'b0;
                M_AXI_AWVALID   <= 1'b0;
                M_AXI_WVALID    <= 1'b0;
                M_AXI_BREADY    <= 1'b0;
                M_AXI_WLAST     <= 1'b0;
            end else begin

                case (state)

                    // ── WR_IDLE: wait for data; compute burst; issue AWVALID ──────
                    WR_IDLE: begin
                        M_AXI_AWVALID <= 1'b0;
                        M_AXI_WVALID  <= 1'b0;
                        M_AXI_BREADY  <= 1'b0;
                        M_AXI_WLAST   <= 1'b0;

                        if (remaining_beats > 29'd0 && fifo_count >= 6'd2) begin
                            // Compute AWLEN = min(remaining_beats - 1, MAX_BURST_LEN)
                            if (remaining_beats > ({21'd0, MAX_BURST_LEN} + 29'd1)) begin
                                // remaining > MAX_BURST_LEN+1: use maximum burst
                                awlen_reg      <= MAX_BURST_LEN;
                                burst_beats    <= MAX_BURST_LEN + 8'd1;
                                beats_in_burst <= MAX_BURST_LEN + 8'd1;
                            end else begin
                                // remaining <= MAX_BURST_LEN+1: use all remaining beats
                                awlen_reg      <= remaining_beats[7:0] - 8'd1;
                                burst_beats    <= remaining_beats[7:0];
                                beats_in_burst <= remaining_beats[7:0];
                            end
                            wr_busy       <= 1'b1;
                            M_AXI_AWID    <= {AXI_ID_WIDTH{1'b0}};
                            M_AXI_AWADDR  <= cur_dst_addr;
                            M_AXI_AWVALID <= 1'b1;
                            state         <= WR_ADDR;
                        end else begin
                            wr_busy <= 1'b0;
                        end
                    end

                    // ── WR_ADDR: wait AWREADY; inline H-latch from FWFT if ready ─
                    WR_ADDR: begin
                        if (M_AXI_AWREADY && M_AXI_AWVALID) begin
                            M_AXI_AWVALID <= 1'b0;
                            if (fifo_fwft_valid) begin
                                // Fast path: H word available now (pop → L becomes head)
                                wdata_hi <= fifo_fwft_dout;
                                fifo_pop <= 1'b1;
                                state    <= WR_DATA_L;
                            end else begin
                                // Slow path: FIFO temporarily empty, wait for H
                                state <= WR_LOAD_H;
                            end
                        end
                    end

                    // ── WR_LOAD_H: stall until H word arrives; pop it ─────────────
                    WR_LOAD_H: begin
                        if (fifo_fwft_valid) begin
                            wdata_hi <= fifo_fwft_dout;
                            fifo_pop <= 1'b1;   // pop H → L becomes fwft_dout next cycle
                            state    <= WR_DATA_L;
                        end
                    end

                    // ── WR_DATA_L: stall until L word ready; build WDATA; WVALID ──
                    // After pop of H in WR_ADDR/WR_LOAD_H, rd_ptr has advanced so
                    // fwft_dout now points to L word (combinationally).
                    WR_DATA_L: begin
                        if (fifo_fwft_valid) begin
                            M_AXI_WDATA  <= {fifo_fwft_dout, wdata_hi}; // {L[31:0], H[31:0]}
                            M_AXI_WVALID <= 1'b1;
                            M_AXI_WLAST  <= (beats_in_burst == 8'd1);   // last beat of burst
                            fifo_pop     <= 1'b1;   // pop L → next H becomes fwft_dout
                            state        <= WR_BEAT;
                        end
                        // else stall: WVALID stays 0; AXI4 allows de-assertion between beats
                    end

                    // ── WR_BEAT: wait WREADY; pulse wr_done; advance to next beat ──
                    WR_BEAT: begin
                        if (M_AXI_WVALID && M_AXI_WREADY) begin
                            wr_done      <= 1'b1;   // per-beat pulse (ctrl_fsm counts 18)
                            M_AXI_WVALID <= 1'b0;
                            M_AXI_WLAST  <= 1'b0;

                            if (beats_in_burst > 8'd1) begin
                                // More beats remain in this burst
                                beats_in_burst <= beats_in_burst - 8'd1;
                                // fwft_dout now has next H word (L was popped in WR_DATA_L)
                                if (fifo_fwft_valid) begin
                                    wdata_hi <= fifo_fwft_dout;
                                    fifo_pop <= 1'b1;
                                    state    <= WR_DATA_L;
                                end else begin
                                    state <= WR_LOAD_H;
                                end
                            end else begin
                                // Last beat of this burst: wait for B response
                                beats_in_burst <= 8'd0;
                                M_AXI_BREADY   <= 1'b1;
                                state          <= WR_RESP;
                            end
                        end
                    end

                    // ── WR_RESP: wait BVALID; update address + remaining counter ───
                    WR_RESP: begin
                        if (M_AXI_BVALID) begin
                            M_AXI_BREADY <= 1'b0;
                            if (M_AXI_BRESP != 2'b00) begin
                                wr_error <= 1'b1;
                                if (!wr_error) wr_err_addr <= M_AXI_AWADDR;
                            end
                            // Advance by burst_beats * 8 bytes
                            cur_dst_addr    <= cur_dst_addr + ({24'd0, burst_beats} << 3);
                            // Decrement remaining by burst_beats
                            remaining_beats <= remaining_beats - {21'd0, burst_beats};
                            state           <= WR_IDLE;
                        end
                    end

                    default: state <= WR_IDLE;
                endcase
            end
        end
    end

endmodule

// ==============================================================================
// FILE: dma_ctrl_fsm.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : dma_ctrl_fsm  (v3.0 — Optimized Concurrent/Decoupled)
//
// CHANGES from v2.0:
//   [OPT-1] core_pump uses FWFT output from RD FIFO (rd_fifo_fwft_dout/valid).
//           Eliminates PUMP_WAIT state — data is available combinationally
//           when FIFO is not empty. Reduces per-block overhead from 3 to 1 cycle.
//
//   [OPT-2] Simplified pump FSM: 2 states instead of 4.
//           PUMP_IDLE: check fwft_valid → latch + core_start → PUMP_WAIT_CORE
//           PUMP_WAIT_CORE: wait core_data_out_valid → pop FIFO → PUMP_IDLE
//
//   Per-block timing improvement:
//     v2.0: IDLE(1) → WAIT(1) → LATCH(1) → WAIT_CORE(N) = 3+N cycles
//     v3.0: IDLE(1) → WAIT_CORE(N) = 1+N cycles  (saved 2 cycles/block)
// ============================================================================

module dma_ctrl_fsm (
    input  wire         clk,
    input  wire         rst_n,

    // ── From axi_slave ───────────────────────────────────────────────────────
    input  wire         dma_start,
    input  wire         dma_soft_rst,
    input  wire [31:0]  byte_len,
    input  wire [7:0]   burst_len,

    // ── Status outputs ────────────────────────────────────────────────────────
    output reg          dma_busy,
    output reg          dma_done,
    output reg          dma_error,

    // ── Read engine ───────────────────────────────────────────────────────────
    output reg          rd_start,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire         rd_busy,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire         rd_done,
    input  wire         rd_error,

    // ── RD FIFO (registered path — kept for compatibility) ────────────────────
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire [63:0]  rd_fifo_dout,
    /* verilator lint_on UNUSEDSIGNAL */
    output reg          rd_fifo_pop,
    input  wire         rd_fifo_empty,

    // ── RD FIFO (FWFT — combinational, zero-latency) ─────────────────────────
    input  wire [63:0]  rd_fifo_fwft_dout,
    input  wire         rd_fifo_fwft_valid,

    // ── ascon_CORE ────────────────────────────────────────────────────────────
    output reg  [31:0]  core_ptext_0,
    output reg  [31:0]  core_ptext_1,
    output reg          core_data_valid,
    input  wire         core_data_ready,
    output reg          core_start,
    output reg          core_data_last,
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire         core_busy,
    input  wire         core_done,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire         core_data_out_valid,
    input  wire         core_tag_valid,

    input  wire [31:0]  core_ctext_0,
    input  wire [31:0]  core_ctext_1,
    input  wire [31:0]  core_tag_0,
    input  wire [31:0]  core_tag_1,
    input  wire [31:0]  core_tag_2,
    input  wire [31:0]  core_tag_3,

    // ── WR FIFO ───────────────────────────────────────────────────────────────
    output reg  [31:0]  wr_fifo_din,
    output reg          wr_fifo_push,
    input  wire         wr_fifo_full,

    // ── Write engine (Auto-triggering) ────────────────────────────────────────
    /* verilator lint_off UNUSEDSIGNAL */
    input  wire         wr_busy,
    /* verilator lint_on UNUSEDSIGNAL */
    input  wire         wr_done,
    input  wire         wr_error,

    // ── Status bits ───────────────────────────────────────────────────────────
    output reg          status_rd_done,
    output reg          status_wr_done,
    output reg          status_fifo_overflow
);

    wire [28:0] total_blocks    = byte_len[31:3]; // 8 bytes per block
    wire [28:0] blocks_per_read = {21'd0, burst_len} + 29'd1;

    // We write CT for EVERY block (total_blocks beats) + TAG logic (2 beats)
    // tag is 128-bit = 4 words = 2 beats (since we always write beats of AWLEN=0 / 2 words)
    wire [28:0] expected_wr_beats = total_blocks + 29'd2;

    reg [28:0] rd_blocks_sent;
    reg [28:0] core_blocks_fed;
    reg [28:0] wr_beats_done;

    // =========================================================================
    // BLOCK 1: rd_ctrl — Auto-issue rd_start on rd_done
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_start       <= 1'b0;
            rd_blocks_sent <= 29'd0;
            status_rd_done <= 1'b0;
        end else if (dma_soft_rst) begin
            rd_start       <= 1'b0;
            rd_blocks_sent <= 29'd0;
            status_rd_done <= 1'b0;
        end else begin
            rd_start <= 1'b0; // default pulse

            if (dma_start) begin
                rd_blocks_sent <= 29'd0;
                rd_start       <= 1'b1;
                status_rd_done <= 1'b0;
            end else if (rd_done) begin
                if (rd_blocks_sent + blocks_per_read < total_blocks) begin
                    rd_start       <= 1'b1;
                    rd_blocks_sent <= rd_blocks_sent + blocks_per_read;
                end else begin
                    rd_blocks_sent <= rd_blocks_sent + blocks_per_read;
                    status_rd_done <= 1'b1;
                end
            end
        end
    end

    // =========================================================================
    // BLOCK 2: core_pump — Optimized with FWFT (v3.0)
    //
    // [OPT-1] Uses rd_fifo_fwft_dout (combinational) instead of rd_fifo_dout
    //         (registered). This eliminates the PUMP_WAIT state entirely.
    //
    // Old (v2.0): PUMP_IDLE → PUMP_WAIT → PUMP_LATCH → PUMP_WAIT_CORE
    //             = 3 cycles overhead per block before ASCON core starts
    //
    // New (v3.0): PUMP_IDLE → PUMP_WAIT_CORE
    //             = 1 cycle overhead per block
    //
    // How it works:
    //   PUMP_IDLE: FWFT data is already valid on fwft_dout when fwft_valid=1.
    //             We latch it directly into core_ptext, assert core_start,
    //             and pop the FIFO (pop advances rd_ptr for next entry).
    //   PUMP_WAIT_CORE: Wait for core_data_out_valid, then return to IDLE.
    // =========================================================================
    localparam PUMP_IDLE      = 1'b0;
    localparam PUMP_WAIT_CORE = 1'b1;

    reg pump_state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
             pump_state      <= PUMP_IDLE;
             rd_fifo_pop     <= 1'b0;
             core_ptext_0    <= 32'h0;
             core_ptext_1    <= 32'h0;
             core_data_valid <= 1'b0;
             core_start      <= 1'b0;
             core_data_last  <= 1'b0;
             core_blocks_fed <= 29'd0;
        end else if (dma_soft_rst) begin
             pump_state      <= PUMP_IDLE;
             rd_fifo_pop     <= 1'b0;
             core_ptext_0    <= 32'h0;
             core_ptext_1    <= 32'h0;
             core_data_valid <= 1'b0;
             core_start      <= 1'b0;
             core_data_last  <= 1'b0;
             core_blocks_fed <= 29'd0;
        end else begin
             rd_fifo_pop <= 1'b0;
             core_start  <= 1'b0;

             if (dma_start) begin
                 pump_state      <= PUMP_IDLE;
                 core_blocks_fed <= 29'd0;
                 core_data_valid <= 1'b0;
             end

             case (pump_state)
                 PUMP_IDLE: begin
                     // [OPT-1] Use FWFT: data available combinationally
                     if (rd_fifo_fwft_valid && dma_busy && (core_blocks_fed < total_blocks)) begin
                         // Latch FWFT data directly (no wait cycle needed)
                         core_ptext_0    <= rd_fifo_fwft_dout[31:0];
                         core_ptext_1    <= rd_fifo_fwft_dout[63:32];
                         core_data_valid <= 1'b1;
                         core_data_last  <= (core_blocks_fed + 1 >= total_blocks);
                         core_start      <= 1'b1;  // 1-cycle pulse
                         core_blocks_fed <= core_blocks_fed + 1;
                         // Pop FIFO to advance to next entry
                         rd_fifo_pop     <= 1'b1;
                         pump_state      <= PUMP_WAIT_CORE;
                     end
                 end
                 PUMP_WAIT_CORE: begin
                     if (core_data_out_valid) begin
                         core_data_valid <= 1'b0;
                         pump_state      <= PUMP_IDLE;
                     end
                 end
             endcase
        end
    end

    // =========================================================================
    // BLOCK 3: wr_push (combinational to WR FIFO) & Overall DMA Status
    // =========================================================================
    reg [2:0] push_state;
    reg [31:0] latch_ctext_1;
    reg [31:0] latch_tag_1, latch_tag_2, latch_tag_3;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_fifo_push         <= 1'b0;
            wr_fifo_din          <= 32'h0;
            push_state           <= 3'd0;
            wr_beats_done        <= 29'd0;
            status_wr_done       <= 1'b0;
            status_fifo_overflow <= 1'b0;
            dma_busy             <= 1'b0;
            dma_done             <= 1'b0;
            dma_error            <= 1'b0;
            latch_ctext_1        <= 32'h0;
            latch_tag_1          <= 32'h0;
            latch_tag_2          <= 32'h0;
            latch_tag_3          <= 32'h0;
        end else if (dma_soft_rst) begin
            wr_fifo_push         <= 1'b0;
            wr_fifo_din          <= 32'h0;
            push_state           <= 3'd0;
            wr_beats_done        <= 29'd0;
            status_wr_done       <= 1'b0;
            status_fifo_overflow <= 1'b0;
            dma_busy             <= 1'b0;
            dma_done             <= 1'b0;
            dma_error            <= 1'b0;
        end else begin
            wr_fifo_push <= 1'b0;
            dma_done     <= 1'b0;

            if (dma_start) begin
                dma_busy       <= 1'b1;
                dma_error      <= 1'b0;
                status_wr_done <= 1'b0;
                wr_beats_done  <= 29'd0;
                push_state     <= 3'd0;
            end

            // Error monitoring
            if (rd_error || wr_error) begin
                 dma_error <= 1'b1;
            end

            // Push to FIFO based on core combination outputs
            if (wr_fifo_full && (core_data_out_valid || core_tag_valid || push_state != 0)) begin
                 status_fifo_overflow <= 1'b1;
                 dma_error <= 1'b1;
            end else begin
                case (push_state)
                    3'd0: begin
                        // Latch and Push first valid word immediately
                        if (core_data_out_valid) begin
                            wr_fifo_din   <= core_ctext_0;
                            wr_fifo_push  <= 1'b1;
                            latch_ctext_1 <= core_ctext_1;
                            push_state    <= 3'd1;
                        end else if (core_tag_valid) begin
                            wr_fifo_din  <= core_tag_0;
                            wr_fifo_push <= 1'b1;
                            latch_tag_1  <= core_tag_1;
                            latch_tag_2  <= core_tag_2;
                            latch_tag_3  <= core_tag_3;
                            push_state   <= 3'd2;
                        end
                    end
                    3'd1: begin
                        wr_fifo_din  <= latch_ctext_1;
                        wr_fifo_push <= 1'b1;
                        push_state   <= 3'd0;
                    end
                    3'd2: begin
                        wr_fifo_din  <= latch_tag_1;
                        wr_fifo_push <= 1'b1;
                        push_state   <= 3'd3;
                    end
                    3'd3: begin
                        wr_fifo_din  <= latch_tag_2;
                        wr_fifo_push <= 1'b1;
                        push_state   <= 3'd4;
                    end
                    3'd4: begin
                        wr_fifo_din  <= latch_tag_3;
                        wr_fifo_push <= 1'b1;
                        push_state   <= 3'd0;
                    end
                    default: push_state <= 3'd0;
                endcase
            end

            // Monitor Write Engine done pulses
            if (wr_done) begin
                wr_beats_done <= wr_beats_done + 1'b1;
                if (wr_beats_done + 1'b1 == expected_wr_beats) begin
                     status_wr_done <= 1'b1;
                     dma_busy <= 1'b0;
                     dma_done <= 1'b1;
                end
            end

        end
    end

endmodule
module ascon_dma #(
    parameter ADDR_WIDTH     = 32,
    parameter AXI_DATA_WIDTH = 64,   // AXI4 Master data bus width
    parameter AXI_ID_WIDTH   = 4,
    parameter RD_FIFO_DEPTH  = 4,    // entries (64-bit each)
    parameter WR_FIFO_DEPTH  = 32    // entries (32-bit each); 8 blocks × 2 ctext + 4 tag = 20 max
) (
    input  wire  clk,
    input  wire  rst_n,

    // =========================================================================
    // Control interface (from ascon_reg_bank via ascon_axi_slave)
    // Registers: DMA_SRC_ADDR(0x100), DMA_DST_ADDR(0x104), DMA_BYTE_LEN(0x108)
    //            DMA_CTRL(0x10C), DMA_BURST_LEN(0x114)
    // =========================================================================
    input  wire [ADDR_WIDTH-1:0]  src_addr,      // DMA_SRC_ADDR
    input  wire [ADDR_WIDTH-1:0]  dst_addr,      // DMA_DST_ADDR
    input  wire [31:0]            byte_len,      // DMA_BYTE_LEN
    input  wire [7:0]             burst_len,     // DMA_BURST_LEN[7:0]

    input  wire                   dma_start,     // from DMA_CTRL[0] pulse
    input  wire                   dma_soft_rst,  // from DMA_CTRL[1] pulse

    // Status outputs → to ascon_reg_bank for DMA_STATUS register (0x110)
    output wire                   dma_busy,      // DMA_STATUS[0]
    output wire                   dma_done,      // DMA_STATUS[1]  (sticky in reg_bank)
    output wire                   dma_error,     // DMA_STATUS[4|5] aggregate

    // Full status bits for DMA_STATUS register
    output wire                   status_rd_done,       // DMA_STATUS[2]
    output wire                   status_wr_done,       // DMA_STATUS[3]
    output wire                   status_rd_error,      // DMA_STATUS[4]
    output wire                   status_wr_error,      // DMA_STATUS[5]
    output wire                   status_fifo_overflow, // DMA_STATUS[6]

    // DMA_ERR_ADDR (0x118) — address that caused AXI error
    output wire [ADDR_WIDTH-1:0]  dma_err_addr,

    // =========================================================================
    // Interface to ascon_CORE
    // =========================================================================
    output wire [31:0]            core_ptext_0,
    output wire [31:0]            core_ptext_1,
    output wire                   core_data_valid,
    input  wire                   core_data_ready,
    output wire                   core_start,
    output wire                   core_data_last,
    input  wire                   core_busy,
    input  wire                   core_done,
    input  wire                   core_data_out_valid,
    input  wire                   core_tag_valid,

    // Results from core (captured by ctrl_fsm on core_done)
    input  wire [31:0]            core_ctext_0,
    input  wire [31:0]            core_ctext_1,
    input  wire [31:0]            core_tag_0,
    input  wire [31:0]            core_tag_1,
    input  wire [31:0]            core_tag_2,
    input  wire [31:0]            core_tag_3,

    // =========================================================================
    // AXI4-Full Master Interface (to crossbar / DMEM / external memory)
    // =========================================================================

    // Write Address Channel
    output wire [AXI_ID_WIDTH-1:0]       M_AXI_AWID,
    output wire [ADDR_WIDTH-1:0]         M_AXI_AWADDR,
    output wire [7:0]                    M_AXI_AWLEN,
    output wire [2:0]                    M_AXI_AWSIZE,
    output wire [1:0]                    M_AXI_AWBURST,
    output wire [3:0]                    M_AXI_AWCACHE,
    output wire [2:0]                    M_AXI_AWPROT,
    output wire                          M_AXI_AWVALID,
    input  wire                          M_AXI_AWREADY,

    // Write Data Channel
    output wire [AXI_DATA_WIDTH-1:0]     M_AXI_WDATA,
    output wire [AXI_DATA_WIDTH/8-1:0]   M_AXI_WSTRB,
    output wire                          M_AXI_WLAST,
    output wire                          M_AXI_WVALID,
    input  wire                          M_AXI_WREADY,

    // Write Response Channel
    input  wire [AXI_ID_WIDTH-1:0]       M_AXI_BID,
    input  wire [1:0]                    M_AXI_BRESP,
    input  wire                          M_AXI_BVALID,
    output wire                          M_AXI_BREADY,

    // Read Address Channel
    output wire [AXI_ID_WIDTH-1:0]       M_AXI_ARID,
    output wire [ADDR_WIDTH-1:0]         M_AXI_ARADDR,
    output wire [7:0]                    M_AXI_ARLEN,
    output wire [2:0]                    M_AXI_ARSIZE,
    output wire [1:0]                    M_AXI_ARBURST,
    output wire [3:0]                    M_AXI_ARCACHE,
    output wire [2:0]                    M_AXI_ARPROT,
    output wire                          M_AXI_ARVALID,
    input  wire                          M_AXI_ARREADY,

    // Read Data Channel
    input  wire [AXI_ID_WIDTH-1:0]       M_AXI_RID,
    input  wire [AXI_DATA_WIDTH-1:0]     M_AXI_RDATA,
    input  wire [1:0]                    M_AXI_RRESP,
    input  wire                          M_AXI_RLAST,
    input  wire                          M_AXI_RVALID,
    output wire                          M_AXI_RREADY
);

    // =========================================================================
    // Internal wires
    // =========================================================================

    // RD FIFO (64-bit wide, 4 deep)
    wire [63:0] rd_fifo_din;
    wire        rd_fifo_push;
    wire        rd_fifo_full;
    wire [63:0] rd_fifo_dout;
    wire        rd_fifo_pop;
    wire        rd_fifo_empty;

    wire [31:0] wr_fifo_din;
    wire        wr_fifo_push;
    wire        wr_fifo_full;
    wire [31:0] wr_fifo_dout;
    wire        wr_fifo_pop;
    wire        wr_fifo_empty;
    wire [5:0]  wr_fifo_count;

    // FWFT (combinational) outputs for zero-latency reads
    wire [63:0] rd_fifo_fwft_dout;
    wire        rd_fifo_fwft_valid;
    wire [31:0] wr_fifo_fwft_dout;
    wire        wr_fifo_fwft_valid;

    // Total write beats = (byte_len / 8) blocks + 2 TAG beats (128-bit tag = 4 words = 2 beats)
    wire [28:0] total_wr_beats_w = byte_len[31:3] + 29'd2;

    // Read engine ↔ ctrl_fsm
    wire        rd_start_w;
    wire        rd_busy_w;
    wire        rd_done_w;
    wire        rd_error_w;
    wire [ADDR_WIDTH-1:0] rd_err_addr_w;

    // Write engine ↔ ctrl_fsm
    wire        wr_busy_w;
    wire        wr_done_w;
    wire        wr_error_w;
    wire [ADDR_WIDTH-1:0] wr_err_addr_w;

    // [FIX-RTL-1] dma_ctrl_fsm의 dma_error output을 캡처할 wire
    wire        dma_error_fsm_w;   // FSM internal error flag

    // Aggregate error address: whichever engine errored last
    assign dma_err_addr = rd_error_w ? rd_err_addr_w : wr_err_addr_w;

    // Aggregate status flags — [FIX-RTL-1] include FSM error
    assign status_rd_error = rd_error_w;
    assign status_wr_error = wr_error_w;
    assign dma_error       = rd_error_w | wr_error_w | dma_error_fsm_w;

    // =========================================================================
    // [FIX-RTL-2] Soft-reset: combined rst_n for FIFOs includes dma_soft_rst
    // =========================================================================
    wire fifo_rst_n = rst_n & ~dma_soft_rst;

    // =========================================================================
    // RD FIFO — 64-bit × 4 deep
    // =========================================================================
    sync_fifo #(
        .WIDTH (64),
        .DEPTH (RD_FIFO_DEPTH)
    ) u_rd_fifo (
        .clk        (clk),
        .rst_n      (fifo_rst_n),
        .din        (rd_fifo_din),
        .push       (rd_fifo_push),
        .full       (rd_fifo_full),
        .dout       (rd_fifo_dout),
        .pop        (rd_fifo_pop),
        .empty      (rd_fifo_empty),
        .fwft_dout  (rd_fifo_fwft_dout),
        .fwft_valid (rd_fifo_fwft_valid),
        .count      ()
    );

    // =========================================================================
    // WR FIFO — 32-bit × 8 deep
    // =========================================================================
    sync_fifo #(
        .WIDTH (32),
        .DEPTH (WR_FIFO_DEPTH)
    ) u_wr_fifo (
        .clk        (clk),
        .rst_n      (fifo_rst_n),
        .din        (wr_fifo_din),
        .push       (wr_fifo_push),
        .full       (wr_fifo_full),
        .dout       (wr_fifo_dout),
        .pop        (wr_fifo_pop),
        .empty      (wr_fifo_empty),
        .fwft_dout  (wr_fifo_fwft_dout),
        .fwft_valid (wr_fifo_fwft_valid),
        .count      (wr_fifo_count)
    );

    // =========================================================================
    // DMA Control FSM
    // =========================================================================
    dma_ctrl_fsm u_ctrl_fsm (
        .clk                 (clk),
        .rst_n               (rst_n),
        .dma_start           (dma_start),
        .dma_soft_rst        (dma_soft_rst),
        .byte_len            (byte_len),
        .burst_len           (burst_len),
        // Status
        .dma_busy            (dma_busy),
        .dma_done            (dma_done),
        .dma_error           (dma_error_fsm_w),
        // Read engine
        .rd_start            (rd_start_w),
        .rd_busy             (rd_busy_w),
        .rd_done             (rd_done_w),
        .rd_error            (rd_error_w),
        // RD FIFO (registered path — kept for compatibility)
        .rd_fifo_dout        (rd_fifo_dout),
        .rd_fifo_pop         (rd_fifo_pop),
        .rd_fifo_empty       (rd_fifo_empty),
        // RD FIFO (FWFT path — zero-latency)
        .rd_fifo_fwft_dout   (rd_fifo_fwft_dout),
        .rd_fifo_fwft_valid  (rd_fifo_fwft_valid),
        // ascon_CORE
        .core_ptext_0        (core_ptext_0),
        .core_ptext_1        (core_ptext_1),
        .core_data_valid     (core_data_valid),
        .core_data_ready     (core_data_ready),
        .core_start          (core_start),
        .core_data_last      (core_data_last),
        .core_busy           (core_busy),
        .core_done           (core_done),
        .core_data_out_valid (core_data_out_valid),
        .core_tag_valid      (core_tag_valid),
        // Results
        .core_ctext_0        (core_ctext_0),
        .core_ctext_1        (core_ctext_1),
        .core_tag_0          (core_tag_0),
        .core_tag_1          (core_tag_1),
        .core_tag_2          (core_tag_2),
        .core_tag_3          (core_tag_3),
        // WR FIFO
        .wr_fifo_din         (wr_fifo_din),
        .wr_fifo_push        (wr_fifo_push),
        .wr_fifo_full        (wr_fifo_full),
        // Write engine
        .wr_busy             (wr_busy_w),
        .wr_done             (wr_done_w),
        .wr_error            (wr_error_w),
        // Status bits
        .status_rd_done      (status_rd_done),
        .status_wr_done      (status_wr_done),
        .status_fifo_overflow(status_fifo_overflow)
    );

    // =========================================================================
    // DMA Read Engine
    // =========================================================================
    dma_read_engine #(
        .ADDR_WIDTH     (ADDR_WIDTH),
        .AXI_DATA_WIDTH (AXI_DATA_WIDTH),
        .AXI_ID_WIDTH   (AXI_ID_WIDTH)
    ) u_rd_engine (
        .clk            (clk),
        .rst_n          (rst_n),
        // Control
        .src_addr       (src_addr),
        .burst_len      (burst_len),
        .dma_start      (dma_start),
        .rd_start       (rd_start_w),
        .rd_busy        (rd_busy_w),
        .rd_done        (rd_done_w),
        .rd_error       (rd_error_w),
        .rd_err_addr    (rd_err_addr_w),
        // RD FIFO push
        .fifo_din       (rd_fifo_din),
        .fifo_push      (rd_fifo_push),
        .fifo_full      (rd_fifo_full),
        // AXI4 AR channel
        .M_AXI_ARID     (M_AXI_ARID),
        .M_AXI_ARADDR   (M_AXI_ARADDR),
        .M_AXI_ARLEN    (M_AXI_ARLEN),
        .M_AXI_ARSIZE   (M_AXI_ARSIZE),
        .M_AXI_ARBURST  (M_AXI_ARBURST),
        .M_AXI_ARCACHE  (M_AXI_ARCACHE),
        .M_AXI_ARPROT   (M_AXI_ARPROT),
        .M_AXI_ARVALID  (M_AXI_ARVALID),
        .M_AXI_ARREADY  (M_AXI_ARREADY),
        // AXI4 R channel
        .M_AXI_RID      (M_AXI_RID),
        .M_AXI_RDATA    (M_AXI_RDATA),
        .M_AXI_RRESP    (M_AXI_RRESP),
        .M_AXI_RLAST    (M_AXI_RLAST),
        .M_AXI_RVALID   (M_AXI_RVALID),
        .M_AXI_RREADY   (M_AXI_RREADY)
    );

    // =========================================================================
    // DMA Write Engine
    // =========================================================================
    dma_write_engine #(
        .ADDR_WIDTH     (ADDR_WIDTH),
        .AXI_DATA_WIDTH (AXI_DATA_WIDTH),
        .AXI_ID_WIDTH   (AXI_ID_WIDTH)
    ) u_wr_engine (
        .clk            (clk),
        .rst_n          (rst_n),
        .dst_addr       (dst_addr),
        .dma_start      (dma_start),
        .total_wr_beats (total_wr_beats_w),
        .wr_busy        (wr_busy_w),
        .wr_done        (wr_done_w),
        .wr_error       (wr_error_w),
        .wr_err_addr    (wr_err_addr_w),
        // WR FIFO pop (registered path)
        .fifo_dout      (wr_fifo_dout),
        .fifo_pop       (wr_fifo_pop),
        .fifo_count     (wr_fifo_count),
        // WR FIFO FWFT (combinational path)
        .fifo_fwft_dout (wr_fifo_fwft_dout),
        .fifo_fwft_valid(wr_fifo_fwft_valid),
        // AXI4 AW channel
        .M_AXI_AWID     (M_AXI_AWID),
        .M_AXI_AWADDR   (M_AXI_AWADDR),
        .M_AXI_AWLEN    (M_AXI_AWLEN),
        .M_AXI_AWSIZE   (M_AXI_AWSIZE),
        .M_AXI_AWBURST  (M_AXI_AWBURST),
        .M_AXI_AWCACHE  (M_AXI_AWCACHE),
        .M_AXI_AWPROT   (M_AXI_AWPROT),
        .M_AXI_AWVALID  (M_AXI_AWVALID),
        .M_AXI_AWREADY  (M_AXI_AWREADY),
        // AXI4 W channel
        .M_AXI_WDATA    (M_AXI_WDATA),
        .M_AXI_WSTRB    (M_AXI_WSTRB),
        .M_AXI_WLAST    (M_AXI_WLAST),
        .M_AXI_WVALID   (M_AXI_WVALID),
        .M_AXI_WREADY   (M_AXI_WREADY),
        // AXI4 B channel
        .M_AXI_BID      (M_AXI_BID),
        .M_AXI_BRESP    (M_AXI_BRESP),
        .M_AXI_BVALID   (M_AXI_BVALID),
        .M_AXI_BREADY   (M_AXI_BREADY)
    );

endmodule
module ascon_ip_top #(
    // ---- Spec Section 2.2 ----
    parameter G_COMB_RND_128  = 6,
    parameter G_COMB_RND_128A = 4,
    parameter G_SBOX_PIPELINE = 0,  // PERMUTATION v8 chỉ hỗ trợ =0 (combinational)
    parameter G_DUAL_RATE     = 1,
    parameter G_AXI_DATA_W    = 64,
    // ---- AXI4-Full Slave (CPU) ----
    parameter S_ADDR_WIDTH = 32,
    parameter S_DATA_WIDTH = 32,
    parameter S_ID_WIDTH   = 4,
    // ---- AXI4-Full Master (DMA) ----
    parameter M_ADDR_WIDTH  = 32,
    parameter M_DATA_WIDTH  = 64,
    parameter M_ID_WIDTH    = 4,
    // ---- DMA FIFO ----
    parameter RD_FIFO_DEPTH = 4,
    parameter WR_FIFO_DEPTH = 32
) (
    input  wire  clk,
    input  wire  rst_n,

    // =========================================================================
    // AXI4-Full Slave Interface (from CPU)
    // FIX-BUG1: tất cả tín hiệu AXI4-Full được kết nối đầy đủ vào u_slave
    // =========================================================================
    input  wire [S_ID_WIDTH-1:0]     S_AXI_AWID,
    input  wire [S_ADDR_WIDTH-1:0]   S_AXI_AWADDR,
    input  wire [7:0]                S_AXI_AWLEN,
    input  wire [2:0]                S_AXI_AWSIZE,
    input  wire [1:0]                S_AXI_AWBURST,
    input  wire [2:0]                S_AXI_AWPROT,
    input  wire                      S_AXI_AWVALID,
    output wire                      S_AXI_AWREADY,

    input  wire [S_DATA_WIDTH-1:0]   S_AXI_WDATA,
    input  wire [S_DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                      S_AXI_WLAST,
    input  wire                      S_AXI_WVALID,
    output wire                      S_AXI_WREADY,

    output wire [S_ID_WIDTH-1:0]     S_AXI_BID,
    output wire [1:0]                S_AXI_BRESP,
    output wire                      S_AXI_BVALID,
    input  wire                      S_AXI_BREADY,

    input  wire [S_ID_WIDTH-1:0]     S_AXI_ARID,
    input  wire [S_ADDR_WIDTH-1:0]   S_AXI_ARADDR,
    input  wire [7:0]                S_AXI_ARLEN,
    input  wire [2:0]                S_AXI_ARSIZE,
    input  wire [1:0]                S_AXI_ARBURST,
    input  wire [2:0]                S_AXI_ARPROT,
    input  wire                      S_AXI_ARVALID,
    output wire                      S_AXI_ARREADY,

    output wire [S_ID_WIDTH-1:0]     S_AXI_RID,
    output wire [S_DATA_WIDTH-1:0]   S_AXI_RDATA,
    output wire [1:0]                S_AXI_RRESP,
    output wire                      S_AXI_RLAST,
    output wire                      S_AXI_RVALID,
    input  wire                      S_AXI_RREADY,

    // =========================================================================
    // AXI4-Full Master Interface (DMA → DDR)
    // =========================================================================
    output wire [M_ID_WIDTH-1:0]       M_AXI_AWID,
    output wire [M_ADDR_WIDTH-1:0]     M_AXI_AWADDR,
    output wire [7:0]                  M_AXI_AWLEN,
    output wire [2:0]                  M_AXI_AWSIZE,
    output wire [1:0]                  M_AXI_AWBURST,
    output wire [3:0]                  M_AXI_AWCACHE,
    output wire [2:0]                  M_AXI_AWPROT,
    output wire                        M_AXI_AWVALID,
    input  wire                        M_AXI_AWREADY,

    output wire [M_DATA_WIDTH-1:0]     M_AXI_WDATA,
    output wire [M_DATA_WIDTH/8-1:0]   M_AXI_WSTRB,
    output wire                        M_AXI_WLAST,
    output wire                        M_AXI_WVALID,
    input  wire                        M_AXI_WREADY,

    input  wire [M_ID_WIDTH-1:0]       M_AXI_BID,
    input  wire [1:0]                  M_AXI_BRESP,
    input  wire                        M_AXI_BVALID,
    output wire                        M_AXI_BREADY,

    output wire [M_ID_WIDTH-1:0]       M_AXI_ARID,
    output wire [M_ADDR_WIDTH-1:0]     M_AXI_ARADDR,
    output wire [7:0]                  M_AXI_ARLEN,
    output wire [2:0]                  M_AXI_ARSIZE,
    output wire [1:0]                  M_AXI_ARBURST,
    output wire [3:0]                  M_AXI_ARCACHE,
    output wire [2:0]                  M_AXI_ARPROT,
    output wire                        M_AXI_ARVALID,
    input  wire                        M_AXI_ARREADY,

    input  wire [M_ID_WIDTH-1:0]       M_AXI_RID,
    input  wire [M_DATA_WIDTH-1:0]     M_AXI_RDATA,
    input  wire [1:0]                  M_AXI_RRESP,
    input  wire                        M_AXI_RLAST,
    input  wire                        M_AXI_RVALID,
    output wire                        M_AXI_RREADY,

    // Tag output (parallel)
    output wire [127:0]               o_tag,
    output wire                       o_tag_valid,
    output wire                       o_busy,

    // =========================================================================
    // Interrupt
    // =========================================================================
    output wire  irq
);

    // =========================================================================
    // Internal wires: ascon_axi_slave → ascon_CORE (CPU-Direct / DMA mode)
    // =========================================================================
    wire [127:0] slave_core_key;
    wire [127:0] slave_core_nonce;
    wire [127:0] slave_core_data_in;
    wire [6:0]   slave_core_data_len;   // FIX-BUG2: từ register
    wire         slave_core_enc_dec;
    wire [1:0]   slave_core_mode;
    wire         slave_core_start;
    /* verilator lint_off UNUSEDSIGNAL */
    wire         slave_core_soft_rst;  // output of slave, not forwarded
    /* verilator lint_on UNUSEDSIGNAL */  // connected to slave but not forwarded (intentional)

    wire         core_busy_w;
    wire         core_done_w;
    wire         core_data_out_valid_w;
    wire [127:0] core_data_out_w;
    wire [127:0] core_tag_out_w;
    wire         core_tag_valid_w;
    wire         core_data_valid_w; // NEW
    wire         core_data_ready_w; // NEW

    // =========================================================================
    // Internal wires: slave → DMA
    // =========================================================================
    wire [31:0]  slave_dma_src_addr;
    wire [31:0]  slave_dma_dst_addr;
    wire [31:0]  slave_dma_length;
    wire [7:0]   slave_dma_burst_len; // NEW
    wire         slave_dma_en;
    wire         slave_dma_start;
    wire         slave_dma_soft_rst;

    wire         dma_busy_w;
    wire         dma_done_w;
    wire         dma_error_w;

    // =========================================================================
    // Internal wires: DMA → CORE
    // =========================================================================
    wire [31:0]  dma_core_ptext_0;
    wire [31:0]  dma_core_ptext_1;
    wire         dma_core_data_valid;  // DMA→CORE data valid; gated với dma_core_start trong core_start_mux
    wire         dma_core_data_ready;
    wire         dma_core_start;
    wire         dma_core_data_last; // NEW

    wire [31:0]  core_dma_ctext_0;
    wire [31:0]  core_dma_ctext_1;
    wire [31:0]  core_dma_tag_0;
    wire [31:0]  core_dma_tag_1;
    wire [31:0]  core_dma_tag_2;
    wire [31:0]  core_dma_tag_3;

    // =========================================================================
    // [FIX] Bỏ AXI-Stream mode. core_start_mux:
    //   CPU-Direct: slave_core_start_pulse (rising-edge của slave_core_start)
    //               → đảm bảo CORE nhận đúng 1-cycle pulse, không bị restart
    //                 liên tục nếu AXI slave giữ core_start HIGH nhiều cycle
    //   DMA mode:   dma_core_start AND dma_core_data_valid
    //               → tránh race condition (CORE không được start trước khi
    //                 DMA FSM đã nạp dữ liệu vào ptext_0/ptext_1)
    // =========================================================================
    // Edge-detect: tạo 1-cycle pulse từ slave_core_start (có thể là level)
    reg slave_core_start_d;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) slave_core_start_d <= 1'b0;
        else        slave_core_start_d <= slave_core_start;
    end
    wire slave_core_start_pulse = slave_core_start & ~slave_core_start_d;

    wire core_start_mux = slave_dma_en
        ? (dma_core_start & dma_core_data_valid)
        : slave_core_start_pulse;

    // DMA cung cấp 2x32-bit word (ptext_0=upper, ptext_1=lower) → ghép 64-bit
    // Đặt vào upper 64-bit của 128-bit data_in, lower 64-bit zero-pad
    // DATAPATH sẽ dùng data_len để biết chỉ lấy bao nhiêu byte thực tế
    wire [127:0] core_data_in_mux = slave_dma_en
        ? {dma_core_ptext_0, dma_core_ptext_1, 64'h0}
        : slave_core_data_in;

    wire core_data_last = slave_dma_en ? dma_core_data_last : 1'b1;
    wire core_data_valid = slave_dma_en ? dma_core_data_valid : 1'b1;

    wire [127:0] core_ad_in    = 128'h0;
    wire         core_ad_valid = 1'b0;
    wire         core_ad_last  = 1'b0;
    wire [127:0] core_tag_received = 128'h0;

    // Slice core output for DMA
    assign core_dma_ctext_0 = core_data_out_w[127:96];
    assign core_dma_ctext_1 = core_data_out_w[95:64];
    assign core_dma_tag_0   = core_tag_out_w[127:96];
    assign core_dma_tag_1   = core_tag_out_w[95:64];
    assign core_dma_tag_2   = core_tag_out_w[63:32];
    assign core_dma_tag_3   = core_tag_out_w[31:0];

    assign dma_core_data_ready = core_data_ready_w; // properly route ready

    // =========================================================================
    // u_slave : ascon_axi_slave v2.0 (AXI4-Full)
    // FIX-BUG1: tất cả AXI4-Full ports được kết nối
    // =========================================================================
    ascon_axi_slave #(
        .ADDR_WIDTH(S_ADDR_WIDTH),
        .DATA_WIDTH(S_DATA_WIDTH),
        .ID_WIDTH  (S_ID_WIDTH)
    ) u_slave (
        .clk                (clk),
        .rst_n              (rst_n),

        // FIX-BUG1: Write Address Channel — đầy đủ AXI4-Full
        .S_AXI_AWID         (S_AXI_AWID),
        .S_AXI_AWADDR       (S_AXI_AWADDR),
        .S_AXI_AWLEN        (S_AXI_AWLEN),
        .S_AXI_AWSIZE       (S_AXI_AWSIZE),
        .S_AXI_AWBURST      (S_AXI_AWBURST),
        .S_AXI_AWPROT       (S_AXI_AWPROT),
        .S_AXI_AWVALID      (S_AXI_AWVALID),
        .S_AXI_AWREADY      (S_AXI_AWREADY),

        .S_AXI_WDATA        (S_AXI_WDATA),
        .S_AXI_WSTRB        (S_AXI_WSTRB),
        .S_AXI_WLAST        (S_AXI_WLAST),
        .S_AXI_WVALID       (S_AXI_WVALID),
        .S_AXI_WREADY       (S_AXI_WREADY),

        .S_AXI_BID          (S_AXI_BID),
        .S_AXI_BRESP        (S_AXI_BRESP),
        .S_AXI_BVALID       (S_AXI_BVALID),
        .S_AXI_BREADY       (S_AXI_BREADY),

        // FIX-BUG1: Read Address Channel — đầy đủ AXI4-Full
        .S_AXI_ARID         (S_AXI_ARID),
        .S_AXI_ARADDR       (S_AXI_ARADDR),
        .S_AXI_ARLEN        (S_AXI_ARLEN),
        .S_AXI_ARSIZE       (S_AXI_ARSIZE),
        .S_AXI_ARBURST      (S_AXI_ARBURST),
        .S_AXI_ARPROT       (S_AXI_ARPROT),
        .S_AXI_ARVALID      (S_AXI_ARVALID),
        .S_AXI_ARREADY      (S_AXI_ARREADY),

        .S_AXI_RID          (S_AXI_RID),
        .S_AXI_RDATA        (S_AXI_RDATA),
        .S_AXI_RRESP        (S_AXI_RRESP),
        .S_AXI_RLAST        (S_AXI_RLAST),
        .S_AXI_RVALID       (S_AXI_RVALID),
        .S_AXI_RREADY       (S_AXI_RREADY),

        .core_key           (slave_core_key),
        .core_nonce         (slave_core_nonce),
        .core_data_in       (slave_core_data_in),
        .core_data_len      (slave_core_data_len),  // FIX-BUG2: từ register
        .core_enc_dec       (slave_core_enc_dec),
        .core_mode          (slave_core_mode),
        .core_start         (slave_core_start),
        .core_soft_rst      (slave_core_soft_rst),

        .core_busy          (core_busy_w),
        .core_done          (core_done_w),
        .core_data_out_valid(core_data_out_valid_w),
        .core_data_out      (core_data_out_w),
        .core_tag_out       (core_tag_out_w),
        .core_tag_valid     (core_tag_valid_w),

        .dma_src_addr       (slave_dma_src_addr),
        .dma_dst_addr       (slave_dma_dst_addr),
        .dma_length         (slave_dma_length),
        .dma_burst_len      (slave_dma_burst_len), // NEW
        .dma_en             (slave_dma_en),
        .dma_start          (slave_dma_start),
        .dma_soft_rst       (slave_dma_soft_rst),

        .dma_busy           (dma_busy_w),
        .dma_done           (dma_done_w),
        .dma_error          (dma_error_w),

        .irq                (irq)
    );

    // =========================================================================
    // u_core_cpu : ascon_CORE cho CPU-Direct / DMA mode
    // core_start_mux:
    //   CPU-Direct (dma_en=0): slave_core_start (1-cycle pulse từ slave)
    //   DMA mode   (dma_en=1): dma_core_start & dma_core_data_valid
    // mode[0] chọn ASCON-128 (0) vs ASCON-128a (1)
    // =========================================================================
    // tag_match: kết quả so sánh tag trong decrypt mode
    // FIX-PINCONNECTEMPTY: kết nối vào wire thay vì bỏ trống
    /* verilator lint_off UNUSEDSIGNAL */
    wire core_tag_match_w;  // available for future use (decrypt tag check)
    /* verilator lint_on UNUSEDSIGNAL */

    ascon_CORE #(
        .G_COMB_RND_128 (G_COMB_RND_128),
        .G_COMB_RND_128A(G_COMB_RND_128A),
        .G_SBOX_PIPELINE(G_SBOX_PIPELINE),
        .G_DUAL_RATE    (G_DUAL_RATE),
        .G_AXI_DATA_W   (G_AXI_DATA_W)
    ) u_core_cpu (
        .clk          (clk),
        .rst_n        (rst_n),
        .start        (core_start_mux),
        .mode         (slave_core_mode),     // mode[0]: 0=128, 1=128a
        .enc_dec      (slave_core_enc_dec),
        .key_in       (slave_core_key),
        .nonce_in     (slave_core_nonce),
        .ad_in        (core_ad_in),
        .ad_valid     (core_ad_valid),
        .ad_last      (core_ad_last),
        .data_in      (core_data_in_mux),
        .data_valid   (core_data_valid), // NEW
        .data_last    (core_data_last),
        .data_len     (slave_core_data_len),
        .tag_received (core_tag_received),
        .data_out     (core_data_out_w),
        .data_out_valid(core_data_out_valid_w),
        .data_ready   (core_data_ready_w), // NEW
        .tag_out      (core_tag_out_w),
        .tag_valid    (core_tag_valid_w),
        .tag_match    (core_tag_match_w),
        .done         (core_done_w),
        .busy         (core_busy_w)
    );

    // =========================================================================
    // u_dma : ascon_dma (AXI4-Full Master)
    // burst_len=8'd0 → 1-beat 64-bit. Cấu hình linh hoạt qua register DMA_BURST_LEN.
    // =========================================================================
    ascon_dma #(
        .ADDR_WIDTH    (M_ADDR_WIDTH),
        .AXI_DATA_WIDTH(M_DATA_WIDTH),
        .AXI_ID_WIDTH  (M_ID_WIDTH),
        .RD_FIFO_DEPTH (RD_FIFO_DEPTH),
        .WR_FIFO_DEPTH (WR_FIFO_DEPTH)
    ) u_dma (
        .clk                  (clk),
        .rst_n                (rst_n),

        .src_addr             (slave_dma_src_addr),
        .dst_addr             (slave_dma_dst_addr),
        .byte_len             (slave_dma_length),
        .burst_len            (slave_dma_burst_len), // FIX: Use configurable burst length

        .dma_start            (slave_dma_start),
        .dma_soft_rst         (slave_dma_soft_rst),

        .dma_busy             (dma_busy_w),
        .dma_done             (dma_done_w),
        .dma_error            (dma_error_w),

        /* verilator lint_off PINCONNECTEMPTY */
        .status_rd_done       (),
        .status_wr_done       (),
        .status_rd_error      (),
        .status_wr_error      (),
        .status_fifo_overflow (),
        .dma_err_addr         (),
        /* verilator lint_on PINCONNECTEMPTY */

        .core_ptext_0         (dma_core_ptext_0),
        .core_ptext_1         (dma_core_ptext_1),
        .core_data_valid      (dma_core_data_valid),
        .core_data_ready      (dma_core_data_ready), // Now connected correctly
        .core_start           (dma_core_start),
        .core_data_last       (dma_core_data_last), // NEW
        .core_busy            (core_busy_w),
        .core_done            (core_done_w),
        .core_data_out_valid  (core_data_out_valid_w), // NEW
        .core_tag_valid       (core_tag_valid_w),      // NEW

        .core_ctext_0         (core_dma_ctext_0),
        .core_ctext_1         (core_dma_ctext_1),
        .core_tag_0           (core_dma_tag_0),
        .core_tag_1           (core_dma_tag_1),
        .core_tag_2           (core_dma_tag_2),
        .core_tag_3           (core_dma_tag_3),

        .M_AXI_AWID           (M_AXI_AWID),
        .M_AXI_AWADDR         (M_AXI_AWADDR),
        .M_AXI_AWLEN          (M_AXI_AWLEN),
        .M_AXI_AWSIZE         (M_AXI_AWSIZE),
        .M_AXI_AWBURST        (M_AXI_AWBURST),
        .M_AXI_AWCACHE        (M_AXI_AWCACHE),
        .M_AXI_AWPROT         (M_AXI_AWPROT),
        .M_AXI_AWVALID        (M_AXI_AWVALID),
        .M_AXI_AWREADY        (M_AXI_AWREADY),

        .M_AXI_WDATA          (M_AXI_WDATA),
        .M_AXI_WSTRB          (M_AXI_WSTRB),
        .M_AXI_WLAST          (M_AXI_WLAST),
        .M_AXI_WVALID         (M_AXI_WVALID),
        .M_AXI_WREADY         (M_AXI_WREADY),

        .M_AXI_BID            (M_AXI_BID),
        .M_AXI_BRESP          (M_AXI_BRESP),
        .M_AXI_BVALID         (M_AXI_BVALID),
        .M_AXI_BREADY         (M_AXI_BREADY),

        .M_AXI_ARID           (M_AXI_ARID),
        .M_AXI_ARADDR         (M_AXI_ARADDR),
        .M_AXI_ARLEN          (M_AXI_ARLEN),
        .M_AXI_ARSIZE         (M_AXI_ARSIZE),
        .M_AXI_ARBURST        (M_AXI_ARBURST),
        .M_AXI_ARCACHE        (M_AXI_ARCACHE),
        .M_AXI_ARPROT         (M_AXI_ARPROT),
        .M_AXI_ARVALID        (M_AXI_ARVALID),
        .M_AXI_ARREADY        (M_AXI_ARREADY),

        .M_AXI_RID            (M_AXI_RID),
        .M_AXI_RDATA          (M_AXI_RDATA),
        .M_AXI_RRESP          (M_AXI_RRESP),
        .M_AXI_RLAST          (M_AXI_RLAST),
        .M_AXI_RVALID         (M_AXI_RVALID),
        .M_AXI_RREADY         (M_AXI_RREADY)
    );

    // =========================================================================
    // Output assigns
    // =========================================================================
    assign o_tag       = core_tag_out_w;
    assign o_tag_valid = core_tag_valid_w;
    assign o_busy      = core_busy_w | dma_busy_w;  // phản ánh trạng thái cả Core và DMA

endmodule
// ==============================================================================
// FILE: axi_width_converter_64to32.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// axi_width_converter_64to32.v  (fixed)
// AXI4 Data Width Converter: 64-bit Master -> 32-bit Slave
// ============================================================================
module axi_width_converter_64to32 #(
    parameter ADDR_WIDTH   = 32,
    parameter ID_WIDTH     = 4,
    parameter M_DATA_WIDTH = 64,
    parameter S_DATA_WIDTH = 32,
    parameter M_STRB_WIDTH = M_DATA_WIDTH / 8,
    parameter S_STRB_WIDTH = S_DATA_WIDTH / 8
)(
    input wire clk,
    input wire rst_n,

    // Master side (64-bit)
    input  wire [ID_WIDTH-1:0]     M_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]   M_AXI_AWADDR,
    input  wire [7:0]              M_AXI_AWLEN,
    input  wire [2:0]              M_AXI_AWSIZE,
    input  wire [1:0]              M_AXI_AWBURST,
    input  wire [3:0]              M_AXI_AWCACHE,
    input  wire [2:0]              M_AXI_AWPROT,
    input  wire                    M_AXI_AWVALID,
    output wire                    M_AXI_AWREADY,

    input  wire [M_DATA_WIDTH-1:0] M_AXI_WDATA,
    input  wire [M_STRB_WIDTH-1:0] M_AXI_WSTRB,
    input  wire                    M_AXI_WLAST,
    input  wire                    M_AXI_WVALID,
    output wire                    M_AXI_WREADY,

    output wire [ID_WIDTH-1:0]     M_AXI_BID,
    output wire [1:0]              M_AXI_BRESP,
    output wire                    M_AXI_BVALID,
    input  wire                    M_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]     M_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]   M_AXI_ARADDR,
    input  wire [7:0]              M_AXI_ARLEN,
    input  wire [2:0]              M_AXI_ARSIZE,
    input  wire [1:0]              M_AXI_ARBURST,
    input  wire [3:0]              M_AXI_ARCACHE,
    input  wire [2:0]              M_AXI_ARPROT,
    input  wire                    M_AXI_ARVALID,
    output wire                    M_AXI_ARREADY,

    output wire [ID_WIDTH-1:0]     M_AXI_RID,
    output wire [M_DATA_WIDTH-1:0] M_AXI_RDATA,
    output wire [1:0]              M_AXI_RRESP,
    output wire                    M_AXI_RLAST,
    output wire                    M_AXI_RVALID,
    input  wire                    M_AXI_RREADY,

    // Slave side (32-bit)
    output wire [ID_WIDTH-1:0]     S_AXI_AWID,
    output wire [ADDR_WIDTH-1:0]   S_AXI_AWADDR,
    output wire [7:0]              S_AXI_AWLEN,
    output wire [2:0]              S_AXI_AWSIZE,
    output wire [1:0]              S_AXI_AWBURST,
    output wire [2:0]              S_AXI_AWPROT,
    output wire                    S_AXI_AWVALID,
    input  wire                    S_AXI_AWREADY,

    output wire [S_DATA_WIDTH-1:0] S_AXI_WDATA,
    output wire [S_STRB_WIDTH-1:0] S_AXI_WSTRB,
    output wire                    S_AXI_WLAST,
    output wire                    S_AXI_WVALID,
    input  wire                    S_AXI_WREADY,

    input  wire [ID_WIDTH-1:0]     S_AXI_BID,
    input  wire [1:0]              S_AXI_BRESP,
    input  wire                    S_AXI_BVALID,
    output wire                    S_AXI_BREADY,

    output wire [ID_WIDTH-1:0]     S_AXI_ARID,
    output wire [ADDR_WIDTH-1:0]   S_AXI_ARADDR,
    output wire [7:0]              S_AXI_ARLEN,
    output wire [2:0]              S_AXI_ARSIZE,
    output wire [1:0]              S_AXI_ARBURST,
    output wire [2:0]              S_AXI_ARPROT,
    output wire                    S_AXI_ARVALID,
    input  wire                    S_AXI_ARREADY,

    input  wire [ID_WIDTH-1:0]     S_AXI_RID,
    input  wire [S_DATA_WIDTH-1:0] S_AXI_RDATA,
    input  wire [1:0]              S_AXI_RRESP,
    input  wire                    S_AXI_RLAST,
    input  wire                    S_AXI_RVALID,
    output wire                    S_AXI_RREADY
);

// ============================================================================
// WRITE ADDRESS CHANNEL
// ============================================================================
assign S_AXI_AWID    = M_AXI_AWID;
assign S_AXI_AWADDR  = M_AXI_AWADDR;
assign S_AXI_AWLEN   = {M_AXI_AWLEN[6:0], 1'b1};
assign S_AXI_AWSIZE  = 3'b010;
assign S_AXI_AWBURST = M_AXI_AWBURST;
assign S_AXI_AWPROT  = M_AXI_AWPROT;
assign S_AXI_AWVALID = M_AXI_AWVALID;
assign M_AXI_AWREADY = S_AXI_AWREADY;

// ============================================================================
// WRITE DATA CHANNEL
//
// 3-state FSM:
//   WS_IDLE : chờ master WVALID, latch 64-bit, chuyển sang WS_LOW
//   WS_LOW  : gửi low word [31:0] tới slave, chờ WREADY
//   WS_HIGH : gửi high word [63:32] tới slave, chờ WREADY, về IDLE
// ============================================================================
localparam WS_IDLE = 2'd0,
           WS_LOW  = 2'd1,
           WS_HIGH = 2'd2;

reg [1:0]              ws_state;
reg [M_DATA_WIDTH-1:0] ws_data;
reg [M_STRB_WIDTH-1:0] ws_strb;
reg                    ws_last;

reg                    s_wvalid_r;
reg [S_DATA_WIDTH-1:0] s_wdata_r;
reg [S_STRB_WIDTH-1:0] s_wstrb_r;
reg                    s_wlast_r;

assign S_AXI_WVALID = s_wvalid_r;
assign S_AXI_WDATA  = s_wdata_r;
assign S_AXI_WSTRB  = s_wstrb_r;
assign S_AXI_WLAST  = s_wlast_r;
assign M_AXI_WREADY = (ws_state == WS_IDLE);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        ws_state   <= WS_IDLE;
        ws_data    <= 0;
        ws_strb    <= 0;
        ws_last    <= 0;
        s_wvalid_r <= 0;
        s_wdata_r  <= 0;
        s_wstrb_r  <= 0;
        s_wlast_r  <= 0;
    end else begin
        case (ws_state)
            WS_IDLE: begin
                if (M_AXI_WVALID) begin
                    ws_data    <= M_AXI_WDATA;
                    ws_strb    <= M_AXI_WSTRB;
                    ws_last    <= M_AXI_WLAST;
                    s_wdata_r  <= M_AXI_WDATA[31:0];
                    s_wstrb_r  <= M_AXI_WSTRB[3:0];
                    s_wlast_r  <= 1'b0;
                    s_wvalid_r <= 1'b1;
                    ws_state   <= WS_LOW;
                end
            end
            WS_LOW: begin
                if (S_AXI_WREADY) begin
                    s_wdata_r  <= ws_data[63:32];
                    s_wstrb_r  <= ws_strb[7:4];
                    s_wlast_r  <= ws_last;
                    s_wvalid_r <= 1'b1;
                    ws_state   <= WS_HIGH;
                end
            end
            WS_HIGH: begin
                if (S_AXI_WREADY) begin
                    s_wvalid_r <= 1'b0;
                    s_wlast_r  <= 1'b0;
                    ws_state   <= WS_IDLE;
                end
            end
            default: ws_state <= WS_IDLE;
        endcase
    end
end

// ============================================================================
// WRITE RESPONSE CHANNEL — pass-through
// ============================================================================
assign M_AXI_BID    = S_AXI_BID;
assign M_AXI_BRESP  = S_AXI_BRESP;
assign M_AXI_BVALID = S_AXI_BVALID;
assign S_AXI_BREADY = M_AXI_BREADY;

// ============================================================================
// READ ADDRESS CHANNEL
// ============================================================================
assign S_AXI_ARID    = M_AXI_ARID;
assign S_AXI_ARADDR  = M_AXI_ARADDR;
assign S_AXI_ARLEN   = {M_AXI_ARLEN[6:0], 1'b1};
assign S_AXI_ARSIZE  = 3'b010;
assign S_AXI_ARBURST = M_AXI_ARBURST;
assign S_AXI_ARPROT  = M_AXI_ARPROT;
assign S_AXI_ARVALID = M_AXI_ARVALID;
assign M_AXI_ARREADY = S_AXI_ARREADY;

// ============================================================================
// READ DATA CHANNEL
//
// 3-state FSM:
//   RS_LOW  : chờ slave beat 0 (low word), latch vào rs_low_r
//   RS_HIGH : chờ slave beat 1 (high word), assemble 64-bit, drive master
//   RS_WAIT : giữ master RVALID cho đến khi master RREADY
//
// Toàn bộ output master R đi qua register — không dùng S_AXI_RDATA
// combinational để tránh data thay đổi khi master stall.
// ============================================================================
localparam RS_LOW  = 2'd0,
           RS_HIGH = 2'd1,
           RS_WAIT = 2'd2;

reg [1:0]              rs_state;
reg [S_DATA_WIDTH-1:0] rs_low_r;
reg [1:0]              rs_resp_r;
reg [ID_WIDTH-1:0]     rs_id_r;

reg                    m_rvalid_r;
reg [M_DATA_WIDTH-1:0] m_rdata_r;
reg [1:0]              m_rresp_r;
reg                    m_rlast_r;
reg [ID_WIDTH-1:0]     m_rid_r;

assign M_AXI_RVALID = m_rvalid_r;
assign M_AXI_RDATA  = m_rdata_r;
assign M_AXI_RRESP  = m_rresp_r;
assign M_AXI_RLAST  = m_rlast_r;
assign M_AXI_RID    = m_rid_r;

assign S_AXI_RREADY = (rs_state == RS_LOW) || (rs_state == RS_HIGH);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        rs_state   <= RS_LOW;
        rs_low_r   <= 0;
        rs_resp_r  <= 0;
        rs_id_r    <= 0;
        m_rvalid_r <= 0;
        m_rdata_r  <= 0;
        m_rresp_r  <= 0;
        m_rlast_r  <= 0;
        m_rid_r    <= 0;
    end else begin
        case (rs_state)
            RS_LOW: begin
                if (S_AXI_RVALID) begin
                    rs_low_r  <= S_AXI_RDATA;
                    rs_resp_r <= S_AXI_RRESP;
                    rs_id_r   <= S_AXI_RID;
                    rs_state  <= RS_HIGH;
                end
            end
            RS_HIGH: begin
                if (S_AXI_RVALID) begin
                    m_rid_r    <= rs_id_r;
                    m_rdata_r  <= {S_AXI_RDATA, rs_low_r};
                    m_rresp_r  <= rs_resp_r | S_AXI_RRESP;
                    m_rlast_r  <= S_AXI_RLAST;
                    m_rvalid_r <= 1'b1;
                    rs_state   <= RS_WAIT;
                end
            end
            RS_WAIT: begin
                if (M_AXI_RREADY) begin
                    m_rvalid_r <= 1'b0;
                    m_rlast_r  <= 1'b0;
                    rs_state   <= RS_LOW;
                end
            end
            default: rs_state <= RS_LOW;
        endcase
    end
end

endmodule
// ============================================================================
// END
// ============================================================================
// ==============================================================================
// FILE: soc_ctrl_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// =============================================================================
// Module   : soc_ctrl_slave
// Project  : RISC-V + ASCON SoC
// Target   : S3 slave @ 0x3000_0000
//
// Changes vs previous version:
//   [Fix-PLIC] irq_out đã chuyển sang PLIC. irq_out port vẫn giữ để
//              tương thích ngược với soc_top.v — nối vào PLIC irq_sources.
//              Khi PLIC active, CPU external_irq = PLIC.meip (không dùng irq_out trực tiếp nữa).
//
//   [Fix-IRQ]  IRQ_STATUS mở rộng từ 1-bit lên 6-bit:
//              Bit[0]: ASCON_IRQ
//              Bit[1]: UART_IRQ  (từ plic / uart_top.irq_out)
//              Bit[2]: GPIO_IRQ
//              Bit[3]: SPI_IRQ
//              Bit[4]: TIMER_IRQ
//              Bit[5]: WDT_IRQ
//
//   [Fix-IRQ]  IRQ_MASK mở rộng 6-bit tương ứng.
//
//   [Fix-NEW]  Thêm HART_ID register tại 0x028 → read = 0x0.
//
//   [Fix-NEW]  Thêm input port cho uart/gpio/spi/timer/wdt irq.
//              (tie to 0 trong soc_top cho đến khi peripheral được kết nối)
// =============================================================================

// `timescale 1ns/1ps

module soc_ctrl_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire                   clk,
    input  wire                   rst_n,

    // ----------------------------------------------------------------
    // AXI4-Full slave port
    // ----------------------------------------------------------------
    input  wire [ID_WIDTH-1:0]    S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]  S_AXI_AWADDR,
    input  wire [7:0]             S_AXI_AWLEN,
    input  wire [2:0]             S_AXI_AWSIZE,
    input  wire [1:0]             S_AXI_AWBURST,
    input  wire [2:0]             S_AXI_AWPROT,
    input  wire                   S_AXI_AWVALID,
    output wire                   S_AXI_AWREADY,

    input  wire [DATA_WIDTH-1:0]  S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                   S_AXI_WLAST,
    input  wire                   S_AXI_WVALID,
    output wire                   S_AXI_WREADY,

    output wire [ID_WIDTH-1:0]    S_AXI_BID,
    output wire [1:0]             S_AXI_BRESP,
    output wire                   S_AXI_BVALID,
    input  wire                   S_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]    S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]  S_AXI_ARADDR,
    input  wire [7:0]             S_AXI_ARLEN,
    input  wire [2:0]             S_AXI_ARSIZE,
    input  wire [1:0]             S_AXI_ARBURST,
    input  wire [2:0]             S_AXI_ARPROT,
    input  wire                   S_AXI_ARVALID,
    output wire                   S_AXI_ARREADY,

    output wire [ID_WIDTH-1:0]    S_AXI_RID,
    output wire [DATA_WIDTH-1:0]  S_AXI_RDATA,
    output wire [1:0]             S_AXI_RRESP,
    output wire                   S_AXI_RLAST,
    output wire                   S_AXI_RVALID,
    input  wire                   S_AXI_RREADY,

    // ----------------------------------------------------------------
    // SoC status inputs
    // ----------------------------------------------------------------
    input  wire [31:0]            icache_hits,
    input  wire [31:0]            icache_misses,
    input  wire [31:0]            dcache_hits,
    input  wire [31:0]            dcache_misses,
    input  wire [31:0]            dcache_writes,

    // [Fix-IRQ] 6 IRQ sources — tie unused ones to 0 in soc_top
    input  wire                   ascon_irq,
    input  wire                   uart_irq,    // từ uart_top.irq_out
    input  wire                   gpio_irq,    // từ gpio_top.irq_out
    input  wire                   spi_irq,     // từ spi_top.irq_out
    input  wire                   timer_irq,   // từ timer_wdt_top (GPT expire)
    input  wire                   wdt_irq,     // từ timer_wdt_top (WDT warn)

    // [A2] Performance counter inputs — từ CPU core
    input  wire                   perf_stall_in,      // = stall_any
    input  wire                   perf_instr_ret_in,  // = regwrite_wb && !stall_any

    // ----------------------------------------------------------------
    // SoC control outputs
    // ----------------------------------------------------------------
    // [Fix-PLIC] irq_out vẫn giữ để nối vào PLIC irq_sources[8] (ASCON).
    // Khi PLIC active, CPU external_irq = PLIC.meip thay vì irq_out trực tiếp.
    output wire                   irq_out,

    output wire                   soft_rst_pulse
);

// =============================================================================
// Register Address Map
// =============================================================================
localparam ADDR_SYS_ID      = 12'h000;  // RO  0x3000_0000
localparam ADDR_SYS_CTRL    = 12'h004;  // WO  0x3000_0004
localparam ADDR_IRQ_STATUS  = 12'h008;  // RW1C 0x3000_0008  [6-bit]
localparam ADDR_IRQ_MASK    = 12'h00C;  // RW  0x3000_000C  [6-bit]
localparam ADDR_ICACHE_HITS = 12'h010;  // RO
localparam ADDR_ICACHE_MISS = 12'h014;  // RO
localparam ADDR_DCACHE_HITS = 12'h018;  // RO
localparam ADDR_DCACHE_MISS = 12'h01C;  // RO
localparam ADDR_DCACHE_WR   = 12'h020;  // RO
localparam ADDR_CYCLE_CNT   = 12'h024;  // RO  cycle[31:0]
localparam ADDR_HART_ID     = 12'h028;  // RO  = 32'h0
localparam ADDR_PERF_CTRL   = 12'h02C;  // RW  [0]=enable [1]=reset_on_read
localparam ADDR_CYCLE_HI    = 12'h030;  // RO  cycle[63:32]
localparam ADDR_INSTR_LO    = 12'h034;  // RO  instr_ret[31:0]
localparam ADDR_INSTR_HI    = 12'h038;  // RO  instr_ret[63:32]
localparam ADDR_STALL_CNT   = 12'h03C;  // RO  stall_cycles[31:0]

localparam SYS_ID_VALUE     = 32'hA5C0_0001;

// =============================================================================
// Soft-Reset Pulse
// =============================================================================
reg soft_rst_pending;
assign soft_rst_pulse = soft_rst_pending;

// =============================================================================
// [Fix-IRQ] 6-bit IRQ registers
// =============================================================================
reg [5:0] irq_mask_r;    // [5:0] = {wdt, timer, spi, gpio, uart, ascon}
reg [5:0] irq_status_r;  // sticky W1C

// irq_out: OR of all masked IRQ sources → nối vào PLIC source[8] hoặc
// tạm thời nối trực tiếp vào CPU external_irq trước khi có PLIC
assign irq_out = |(irq_status_r & irq_mask_r);

// =============================================================================
// IRQ Edge Detect & Sticky Latch
// =============================================================================
reg [5:0] irq_prev;
wire [5:0] irq_raw   = {wdt_irq, timer_irq, spi_irq, gpio_irq, uart_irq, ascon_irq};
wire [5:0] irq_rising = irq_raw & ~irq_prev;

reg [5:0] irq_w1c_mask;   // bits to clear this cycle (from write path)

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        irq_prev     <= 6'd0;
        irq_status_r <= 6'd0;
    end else begin
        irq_prev <= irq_raw;
        // W1C has priority over set (to avoid re-arming same cycle)
        irq_status_r <= (irq_status_r & ~irq_w1c_mask) | irq_rising;
    end
end

// =============================================================================
// [A2] PERF_CTRL register — [0]=perf_en (gate all counter increments)
// Write handler is below in the AXI write section.
// =============================================================================
reg perf_ctrl_r;
wire perf_en = perf_ctrl_r;

// =============================================================================
// CYCLE_CNT (64-bit), INSTR_CNT (64-bit), STALL_CNT (32-bit)
// perf_ror_trigger defined in Read Channel section — resets on INSTR_HI read
// =============================================================================
reg [63:0] cycle_cnt_r;
reg [63:0] instr_cnt_r;
reg [31:0] stall_cnt_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cycle_cnt_r <= 64'd0;
        instr_cnt_r <= 64'd0;
        stall_cnt_r <= 32'd0;
    end else if (soft_rst_pulse) begin
        cycle_cnt_r <= 64'd0;
        instr_cnt_r <= 64'd0;
        stall_cnt_r <= 32'd0;
    end else begin
        if (perf_en)
            cycle_cnt_r <= cycle_cnt_r + 64'd1;
        if (perf_en && perf_instr_ret_in)
            instr_cnt_r <= instr_cnt_r + 64'd1;
        if (perf_en && perf_stall_in)
            stall_cnt_r <= stall_cnt_r + 32'd1;
    end
end

// =============================================================================
// AXI Write Channel
// =============================================================================
reg [ID_WIDTH-1:0]     aw_id_lat;
reg [ADDR_WIDTH-1:0]   aw_addr_lat;
reg                    aw_done;
reg                    w_done;
reg [DATA_WIDTH-1:0]   w_data_lat;
reg [DATA_WIDTH/8-1:0] w_strb_lat;
reg                    bvalid_r;
reg [1:0]              bresp_r;

wire [11:0] aw_offset = aw_addr_lat[11:0];

wire aw_is_ro = (aw_offset == ADDR_SYS_ID)      ||
                (aw_offset == ADDR_ICACHE_HITS)  ||
                (aw_offset == ADDR_ICACHE_MISS)  ||
                (aw_offset == ADDR_DCACHE_HITS)  ||
                (aw_offset == ADDR_DCACHE_MISS)  ||
                (aw_offset == ADDR_DCACHE_WR)    ||
                (aw_offset == ADDR_CYCLE_CNT)    ||
                (aw_offset == ADDR_HART_ID)      ||
                (aw_offset == ADDR_CYCLE_HI)     ||
                (aw_offset == ADDR_INSTR_LO)     ||
                (aw_offset == ADDR_INSTR_HI)     ||
                (aw_offset == ADDR_STALL_CNT);

wire write_execute = aw_done && w_done && !bvalid_r;

// Soft-reset pulse
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        soft_rst_pending <= 1'b0;
    end else begin
        soft_rst_pending <= 1'b0;
        if (write_execute && (aw_offset == ADDR_SYS_CTRL))
            if (w_data_lat[0] & w_strb_lat[0])
                soft_rst_pending <= 1'b1;
    end
end

// IRQ_MASK write (6-bit)
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        irq_mask_r <= 6'd0;
    end else begin
        if (write_execute && (aw_offset == ADDR_IRQ_MASK)) begin
            if (w_strb_lat[0]) irq_mask_r <= w_data_lat[5:0];
        end
    end
end

// [A2] PERF_CTRL write
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        perf_ctrl_r <= 1'b1;       // default: counters enabled
    end else if (soft_rst_pulse) begin
        perf_ctrl_r <= 1'b1;
    end else begin
        if (write_execute && (aw_offset == ADDR_PERF_CTRL)) begin
            if (w_strb_lat[0]) perf_ctrl_r <= w_data_lat[0];
        end
    end
end

// IRQ_STATUS W1C (6-bit)
always @(*) begin
    irq_w1c_mask = 6'd0;
    if (write_execute && (aw_offset == ADDR_IRQ_STATUS))
        if (w_strb_lat[0])
            irq_w1c_mask = w_data_lat[5:0];  // write 1 to clear
end

// AW latch
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        aw_done <= 1'b0; aw_id_lat <= {ID_WIDTH{1'b0}}; aw_addr_lat <= {ADDR_WIDTH{1'b0}};
    end else begin
        if (S_AXI_AWVALID && S_AXI_AWREADY) begin
            aw_id_lat <= S_AXI_AWID; aw_addr_lat <= S_AXI_AWADDR; aw_done <= 1'b1;
        end
        if (bvalid_r && S_AXI_BREADY) aw_done <= 1'b0;
    end
end

// W latch
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        w_done <= 1'b0; w_data_lat <= {DATA_WIDTH{1'b0}}; w_strb_lat <= {(DATA_WIDTH/8){1'b0}};
    end else begin
        if (S_AXI_WVALID && S_AXI_WREADY) begin
            w_data_lat <= S_AXI_WDATA; w_strb_lat <= S_AXI_WSTRB; w_done <= 1'b1;
        end
        if (bvalid_r && S_AXI_BREADY) w_done <= 1'b0;
    end
end

// B channel
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        bvalid_r <= 1'b0; bresp_r <= 2'b00;
    end else begin
        if (write_execute) begin
            bvalid_r <= 1'b1;
            bresp_r  <= (aw_is_ro) ? 2'b10 : 2'b00; // SLVERR for RO
        end
        if (bvalid_r && S_AXI_BREADY) bvalid_r <= 1'b0;
    end
end

assign S_AXI_AWREADY = !aw_done;
assign S_AXI_WREADY  = !w_done;
assign S_AXI_BVALID  = bvalid_r;
assign S_AXI_BRESP   = bresp_r;
assign S_AXI_BID     = aw_id_lat;

// =============================================================================
// AXI Read Channel
// =============================================================================
reg [ID_WIDTH-1:0]   ar_id_lat;
reg [ADDR_WIDTH-1:0] ar_addr_lat;
reg                  ar_done;
reg                  rvalid_r;
reg [DATA_WIDTH-1:0] rdata_r;

wire [11:0] ar_offset = ar_addr_lat[11:0];

reg [DATA_WIDTH-1:0] rdata_mux;
always @(*) begin
    case (ar_offset)
        ADDR_SYS_ID     : rdata_mux = SYS_ID_VALUE;
        ADDR_SYS_CTRL   : rdata_mux = 32'd0;
        ADDR_IRQ_STATUS : rdata_mux = {26'd0, irq_status_r};
        ADDR_IRQ_MASK   : rdata_mux = {26'd0, irq_mask_r};
        ADDR_ICACHE_HITS: rdata_mux = icache_hits;
        ADDR_ICACHE_MISS: rdata_mux = icache_misses;
        ADDR_DCACHE_HITS: rdata_mux = dcache_hits;
        ADDR_DCACHE_MISS: rdata_mux = dcache_misses;
        ADDR_DCACHE_WR  : rdata_mux = dcache_writes;
        ADDR_CYCLE_CNT  : rdata_mux = cycle_cnt_r[31:0];
        ADDR_HART_ID    : rdata_mux = 32'd0;
        ADDR_PERF_CTRL  : rdata_mux = {31'd0, perf_ctrl_r};
        ADDR_CYCLE_HI   : rdata_mux = cycle_cnt_r[63:32];
        ADDR_INSTR_LO   : rdata_mux = instr_cnt_r[31:0];
        ADDR_INSTR_HI   : rdata_mux = instr_cnt_r[63:32];
        ADDR_STALL_CNT  : rdata_mux = stall_cnt_r;
        default         : rdata_mux = 32'd0;
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        ar_done <= 1'b0; ar_id_lat <= {ID_WIDTH{1'b0}}; ar_addr_lat <= {ADDR_WIDTH{1'b0}};
    end else begin
        if (S_AXI_ARVALID && S_AXI_ARREADY) begin
            ar_id_lat <= S_AXI_ARID; ar_addr_lat <= S_AXI_ARADDR; ar_done <= 1'b1;
        end
        if (rvalid_r && S_AXI_RREADY) ar_done <= 1'b0;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        rvalid_r <= 1'b0; rdata_r <= {DATA_WIDTH{1'b0}};
    end else begin
        if (ar_done && !rvalid_r) begin
            rvalid_r <= 1'b1; rdata_r <= rdata_mux;
        end
        if (rvalid_r && S_AXI_RREADY) rvalid_r <= 1'b0;
    end
end

assign S_AXI_ARREADY = !ar_done;
assign S_AXI_RVALID  = rvalid_r;
assign S_AXI_RDATA   = rdata_r;
assign S_AXI_RRESP   = 2'b00;
assign S_AXI_RLAST   = 1'b1;
assign S_AXI_RID     = ar_id_lat;

endmodule
// =============================================================================
// END: soc_ctrl_slave.v
// =============================================================================
// ==============================================================================
// FILE: clint.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// clint.v  —  RISC-V Core Local Interrupt Controller (CLINT)
// ============================================================================
// Spec:  RISC-V Privileged Architecture v1.12  §3.1.9 / SiFive CLINT spec
// Base address (khi mount vào SoC): 0x4000_0000
//
// Address map (offset từ base):
//   0x0000        msip          [RW]  Machine Software Interrupt Pending (bit[0])
//   0x4000        mtimecmp_lo   [RW]  Timer compare — 32-bit thấp
//   0x4004        mtimecmp_hi   [RW]  Timer compare — 32-bit cao
//   0xBFF8        mtime_lo      [RO]  Current mtime   — 32-bit thấp
//   0xBFFC        mtime_hi      [RO]  Current mtime   — 32-bit cao
//
// Fix log (giữ nguyên từ bản cũ):
//   [D3]          mtime_tick input từ soc_top prescaler
//   [RD-LOCK]     Snapshot mtime khi AR latch — đọc 64-bit nhất quán
//   [WR-ATOMICITY] mtimecmp_shadow_r: ghi lo → shadow, commit khi ghi hi
//   [BURST-DRAIN] Drain burst beats, chỉ ghi beat đầu
//   [B-OVERLAP]   b_id_r latch từ eff_awid, không đọc lại S_AXI_AWID
//   [RST-TIMER]   mtimecmp init = 0xFFFF...FFFF
//
// BUGFIX v2 (file này):
//
//   [BUG1-REG-IN-ALWAYS] Khai báo "reg [31:0] new_hi" bên trong always block
//       là syntax error trong Verilog-2001 (chỉ hợp lệ SystemVerilog).
//       Fix: khai báo new_hi_comb ở module level (reg), dùng trong always @(*).
//       Viết mtimecmp_hi case trực tiếp không cần block begin/end lồng nhau.
//
//   [BUG2-WDATA-LATCH] Khi master gửi W beat trước AW (FSM → WR_WWAIT),
//       WDATA/WSTRB chỉ valid trong cycle đó. Khi AW arrive sau,
//       wr_do_write fires nhưng S_AXI_WDATA đã không còn valid.
//       Fix: latch wd_data_r/wd_strb_r khi w_fire; dùng các reg này
//       thay vì S_AXI_WDATA/WSTRB trực tiếp khi ghi register.
//
//   [BUG3-DRAIN-COUNT] WR_DRAIN thoát khi cnt == wr_burst_len_r - 1,
//       off-by-one: bỏ sót beat cuối.
//       cnt khởi tạo = 1 (sau beat đầu ở AWWAIT), tăng mỗi w_fire.
//       Beat cuối = beat AWLEN → cnt = AWLEN = wr_burst_len_r.
//       Fix: đổi điều kiện thành cnt == wr_burst_len_r.
//
// ============================================================================

// `timescale 1ns/1ps
`default_nettype none

module clint #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire clk,
    input  wire rst_n,          // active-low (fabric_rst_n từ soc_top)

    // [D3] mtime tick từ prescaler trong soc_top (1 MHz)
    input  wire mtime_tick,

    // ── AXI4 Full Slave ──────────────────────────────────────────────────────
    // Write Address Channel
    input  wire [ID_WIDTH-1:0]   S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0] S_AXI_AWADDR,
    input  wire [7:0]            S_AXI_AWLEN,
    input  wire [2:0]            S_AXI_AWSIZE,
    input  wire [1:0]            S_AXI_AWBURST,
    input  wire [2:0]            S_AXI_AWPROT,
    input  wire                  S_AXI_AWVALID,
    output wire                  S_AXI_AWREADY,

    // Write Data Channel
    input  wire [DATA_WIDTH-1:0]   S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0] S_AXI_WSTRB,
    input  wire                    S_AXI_WLAST,
    input  wire                    S_AXI_WVALID,
    output wire                    S_AXI_WREADY,

    // Write Response Channel
    output wire [ID_WIDTH-1:0] S_AXI_BID,
    output wire [1:0]          S_AXI_BRESP,
    output wire                S_AXI_BVALID,
    input  wire                S_AXI_BREADY,

    // Read Address Channel
    input  wire [ID_WIDTH-1:0]   S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0] S_AXI_ARADDR,
    input  wire [7:0]            S_AXI_ARLEN,
    input  wire [2:0]            S_AXI_ARSIZE,
    input  wire [1:0]            S_AXI_ARBURST,
    input  wire [2:0]            S_AXI_ARPROT,
    input  wire                  S_AXI_ARVALID,
    output wire                  S_AXI_ARREADY,

    // Read Data Channel
    output wire [ID_WIDTH-1:0]   S_AXI_RID,
    output wire [DATA_WIDTH-1:0] S_AXI_RDATA,
    output wire [1:0]            S_AXI_RRESP,
    output wire                  S_AXI_RLAST,
    output wire                  S_AXI_RVALID,
    input  wire                  S_AXI_RREADY,

    // ── Interrupt outputs → CPU ───────────────────────────────────────────────
    output wire timer_irq,
    output wire sw_irq
);

    // ========================================================================
    // Local parameters
    // ========================================================================
    localparam STRB_WIDTH = DATA_WIDTH / 8;

    localparam OFFSET_MSIP         = 16'h0000;
    localparam OFFSET_MTIMECMP_LO  = 16'h4000;
    localparam OFFSET_MTIMECMP_HI  = 16'h4004;
    localparam OFFSET_MTIME_LO     = 16'hBFF8;
    localparam OFFSET_MTIME_HI     = 16'hBFFC;

    localparam RESP_OKAY   = 2'b00;
    localparam RESP_SLVERR = 2'b10;

    // ========================================================================
    // CLINT registers
    // ========================================================================
    reg [63:0] mtime_r;
    reg [63:0] mtimecmp_r;
    reg [31:0] mtimecmp_shadow_r;
    reg        msip_r;

    // ========================================================================
    // [D3] mtime counter
    // ========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mtime_r <= 64'd0;
        else if (mtime_tick)
            mtime_r <= mtime_r + 64'd1;
    end

    // ========================================================================
    // Interrupt outputs
    // ========================================================================
    assign timer_irq = (mtime_r >= mtimecmp_r);
    assign sw_irq    = msip_r;

    // ========================================================================
    // AXI4 Write FSM
    // ========================================================================
    reg [2:0] wr_state;
    localparam WR_IDLE   = 3'd0;
    localparam WR_AWWAIT = 3'd1;
    localparam WR_WWAIT  = 3'd2;
    localparam WR_DRAIN  = 3'd3;
    localparam WR_BRESP  = 3'd4;

    reg [ID_WIDTH-1:0] wr_id_r;
    reg [15:0]         wr_offset_r;
    reg [7:0]          wr_burst_len_r;
    reg [7:0]          wr_beat_cnt_r;
    reg                first_beat_r;

    // [BUG2-WDATA-LATCH] Latch WDATA/WSTRB khi w_fire để dùng sau khi AW arrive
    reg [DATA_WIDTH-1:0]   wd_data_r;
    reg [DATA_WIDTH/8-1:0] wd_strb_r;

    // Effective write data: dùng latched data khi ở WWAIT (W đã arrive trước AW)
    wire [DATA_WIDTH-1:0]   eff_wdata = (wr_state == WR_WWAIT) ? wd_data_r : S_AXI_WDATA;
    wire [DATA_WIDTH/8-1:0] eff_wstrb = (wr_state == WR_WWAIT) ? wd_strb_r : S_AXI_WSTRB;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wd_data_r <= {DATA_WIDTH{1'b0}};
            wd_strb_r <= {(DATA_WIDTH/8){1'b0}};
        end else if (w_fire) begin
            wd_data_r <= S_AXI_WDATA;
            wd_strb_r <= S_AXI_WSTRB;
        end
    end

    assign S_AXI_AWREADY = (wr_state == WR_IDLE) || (wr_state == WR_WWAIT);
    assign S_AXI_WREADY  = (wr_state == WR_IDLE)  ||
                           (wr_state == WR_AWWAIT) ||
                           (wr_state == WR_DRAIN);

    wire aw_fire = S_AXI_AWVALID && S_AXI_AWREADY;
    wire w_fire  = S_AXI_WVALID  && S_AXI_WREADY;
    wire b_fire  = S_AXI_BVALID  && S_AXI_BREADY;

    wire wr_do_write = ((wr_state == WR_IDLE)  && aw_fire && w_fire) ||
                       ((wr_state == WR_AWWAIT) && w_fire)            ||
                       ((wr_state == WR_WWAIT)  && aw_fire);

    // Latch AW
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_offset_r    <= 16'd0;
            wr_id_r        <= {ID_WIDTH{1'b0}};
            wr_burst_len_r <= 8'd0;
        end else if (aw_fire) begin
            wr_offset_r    <= S_AXI_AWADDR[15:0];
            wr_id_r        <= S_AXI_AWID;
            wr_burst_len_r <= S_AXI_AWLEN;
        end
    end

    wire [15:0]         eff_offset = (wr_state == WR_IDLE) ? S_AXI_AWADDR[15:0] : wr_offset_r;
    wire [ID_WIDTH-1:0] eff_awid   = (wr_state == WR_IDLE) ? S_AXI_AWID         : wr_id_r;

    // FSM transitions
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state      <= WR_IDLE;
            wr_beat_cnt_r <= 8'd0;
            first_beat_r  <= 1'b1;
        end else begin
            case (wr_state)
                WR_IDLE: begin
                    first_beat_r  <= 1'b1;
                    wr_beat_cnt_r <= 8'd0;
                    if (aw_fire && !w_fire)
                        wr_state <= WR_AWWAIT;
                    else if (!aw_fire && w_fire)
                        wr_state <= WR_WWAIT;
                    else if (aw_fire && w_fire) begin
                        if (S_AXI_AWLEN != 8'd0)
                            wr_state <= WR_DRAIN;
                        else
                            wr_state <= WR_BRESP;
                    end
                end

                WR_AWWAIT: begin
                    if (w_fire) begin
                        first_beat_r <= 1'b0;
                        if (wr_burst_len_r != 8'd0 && !S_AXI_WLAST) begin
                            wr_beat_cnt_r <= 8'd1;
                            wr_state      <= WR_DRAIN;
                        end else
                            wr_state <= WR_BRESP;
                    end
                end

                WR_WWAIT: begin
                    if (aw_fire) begin
                        if (S_AXI_AWLEN != 8'd0)
                            wr_state <= WR_DRAIN;
                        else
                            wr_state <= WR_BRESP;
                    end
                end

                WR_DRAIN: begin
                    if (w_fire) begin
                        wr_beat_cnt_r <= wr_beat_cnt_r + 8'd1;
                        // [BUG3-DRAIN-COUNT] Fix: == wr_burst_len_r (không phải -1)
                        // cnt bắt đầu từ 1 (beat đầu xử lý ở AWWAIT/IDLE)
                        // beat cuối = beat AWLEN → cnt = AWLEN = wr_burst_len_r
                        if (S_AXI_WLAST || (wr_beat_cnt_r == wr_burst_len_r))
                            wr_state <= WR_BRESP;
                    end
                end

                WR_BRESP: begin
                    if (b_fire) begin
                        wr_state      <= WR_IDLE;
                        wr_beat_cnt_r <= 8'd0;
                        first_beat_r  <= 1'b1;
                    end
                end

                default: wr_state <= WR_IDLE;
            endcase
        end
    end

    // B channel
    // [BUG4-BVALID-EARLY] b_valid_r harus set saat FSM masuk WR_BRESP,
    // BUKAN saat wr_do_write (yang fire di awal burst, sebelum drain selesai).
    // Jika bvalid=1 saat masih WR_DRAIN: master terima B response lebih awal,
    // b_fire clear bvalid → saat DRAIN selesai masuk WR_BRESP, bvalid=0 → stall.
    // Fix: set b_valid_r & b_id_r saat transisi ke WR_BRESP dalam FSM.
    // Deteksi: (wr_state akan pindah ke WR_BRESP di posedge ini)
    //   - dari AWWAIT: w_fire && (burst done atau single)
    //   - dari DRAIN:  w_fire && (WLAST || cnt == burst_len)
    //   - dari WWAIT:  aw_fire && AWLEN==0
    //   - dari IDLE:   aw_fire && w_fire && AWLEN==0
    // Sederhana: set b_valid ketika next_state == WR_BRESP
    reg                b_valid_r;
    reg [ID_WIDTH-1:0] b_id_r;

    assign S_AXI_BVALID = b_valid_r;
    assign S_AXI_BID    = b_id_r;
    assign S_AXI_BRESP  = RESP_OKAY;

    // Sinyal "sedang masuk WR_BRESP cycle ini"
    wire going_to_bresp =
        ((wr_state == WR_IDLE)   && aw_fire && w_fire && (S_AXI_AWLEN == 8'd0))           ||
        ((wr_state == WR_AWWAIT) && w_fire  && (wr_burst_len_r == 8'd0 || S_AXI_WLAST))  ||
        ((wr_state == WR_WWAIT)  && aw_fire && (S_AXI_AWLEN == 8'd0))                     ||
        ((wr_state == WR_DRAIN)  && w_fire  && (S_AXI_WLAST || (wr_beat_cnt_r == wr_burst_len_r)));

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            b_valid_r <= 1'b0;
            b_id_r    <= {ID_WIDTH{1'b0}};
        end else begin
            if (going_to_bresp) begin
                b_valid_r <= 1'b1;
                b_id_r    <= eff_awid;
            end else if (b_fire) begin
                b_valid_r <= 1'b0;
            end
        end
    end

    // ========================================================================
    // Register writes
    //
    // [BUG1-REG-IN-ALWAYS] Fix: dùng eff_wdata/eff_wstrb (đã latch),
    //   viết trực tiếp không khai báo reg bên trong always block.
    //   Dùng module-level reg mtimecmp_hi_new (combinational temp) cho
    //   OFFSET_MTIMECMP_HI để giữ logic rõ ràng.
    //
    // [BUG2-WDATA-LATCH] Dùng eff_wdata/eff_wstrb thay vì S_AXI_WDATA/WSTRB.
    // [WR-ATOMICITY]     Ghi lo → shadow; ghi hi → atomic commit 64-bit.
    // ========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            msip_r            <= 1'b0;
            mtimecmp_r        <= 64'hFFFF_FFFF_FFFF_FFFF;
            mtimecmp_shadow_r <= 32'hFFFF_FFFF;
        end else if (wr_do_write) begin
            case (eff_offset)
                OFFSET_MSIP: begin
                    if (eff_wstrb[0]) msip_r <= eff_wdata[0];
                end

                OFFSET_MTIMECMP_LO: begin
                    // [WR-ATOMICITY] Ghi lo vào shadow, chưa commit mtimecmp_r
                    if (eff_wstrb[0]) mtimecmp_shadow_r[ 7: 0] <= eff_wdata[ 7: 0];
                    if (eff_wstrb[1]) mtimecmp_shadow_r[15: 8] <= eff_wdata[15: 8];
                    if (eff_wstrb[2]) mtimecmp_shadow_r[23:16] <= eff_wdata[23:16];
                    if (eff_wstrb[3]) mtimecmp_shadow_r[31:24] <= eff_wdata[31:24];
                end

                OFFSET_MTIMECMP_HI: begin
                    // [WR-ATOMICITY] Ghi hi → atomic commit {new_hi, shadow_lo}
                    // [BUG1-REG-IN-ALWAYS] Viết trực tiếp từng byte, không khai báo
                    // reg bên trong always block (syntax error Verilog-2001).
                    mtimecmp_r[32 +  7 : 32 +  0] <= eff_wstrb[0] ? eff_wdata[ 7: 0]
                                                                    : mtimecmp_r[39:32];
                    mtimecmp_r[32 + 15 : 32 +  8] <= eff_wstrb[1] ? eff_wdata[15: 8]
                                                                    : mtimecmp_r[47:40];
                    mtimecmp_r[32 + 23 : 32 + 16] <= eff_wstrb[2] ? eff_wdata[23:16]
                                                                    : mtimecmp_r[55:48];
                    mtimecmp_r[32 + 31 : 32 + 24] <= eff_wstrb[3] ? eff_wdata[31:24]
                                                                    : mtimecmp_r[63:56];
                    // Commit lo half từ shadow
                    mtimecmp_r[31:0] <= mtimecmp_shadow_r;
                end

                OFFSET_MTIME_LO,
                OFFSET_MTIME_HI: begin
                    /* mtime read-only — ignore write, trả OKAY */
                end

                default: begin
                    /* unmapped — ignore */
                end
            endcase
        end
    end

    // ========================================================================
    // AXI4 Read FSM
    // [RD-LOCK] Snapshot mtime_r khi AR latch
    // ========================================================================
    reg                ar_pending_r;
    reg [ID_WIDTH-1:0] ar_id_r;
    reg [15:0]         ar_offset_r;
    reg [7:0]          ar_len_r;
    reg [7:0]          ar_beat_cnt_r;
    reg [63:0]         mtime_snap_r;

    wire ar_fire = S_AXI_ARVALID && S_AXI_ARREADY;
    wire r_fire  = S_AXI_RVALID  && S_AXI_RREADY;

    assign S_AXI_ARREADY = ~ar_pending_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ar_pending_r  <= 1'b0;
            ar_id_r       <= {ID_WIDTH{1'b0}};
            ar_offset_r   <= 16'd0;
            ar_len_r      <= 8'd0;
            ar_beat_cnt_r <= 8'd0;
            mtime_snap_r  <= 64'd0;
        end else begin
            if (ar_fire) begin
                ar_pending_r  <= 1'b1;
                ar_id_r       <= S_AXI_ARID;
                ar_offset_r   <= S_AXI_ARADDR[15:0];
                ar_len_r      <= S_AXI_ARLEN;
                ar_beat_cnt_r <= 8'd0;
                mtime_snap_r  <= mtime_r;   // [RD-LOCK] snapshot
            end else if (r_fire) begin
                if (ar_beat_cnt_r == ar_len_r)
                    ar_pending_r <= 1'b0;
                else
                    ar_beat_cnt_r <= ar_beat_cnt_r + 8'd1;
            end
        end
    end

    reg [DATA_WIDTH-1:0] r_data_r;
    always @(*) begin
        case (ar_offset_r)
            OFFSET_MSIP:        r_data_r = {{(DATA_WIDTH-1){1'b0}}, msip_r};
            OFFSET_MTIMECMP_LO: r_data_r = mtimecmp_r[31: 0];
            OFFSET_MTIMECMP_HI: r_data_r = mtimecmp_r[63:32];
            OFFSET_MTIME_LO:    r_data_r = mtime_snap_r[31: 0];  // [RD-LOCK]
            OFFSET_MTIME_HI:    r_data_r = mtime_snap_r[63:32];  // [RD-LOCK]
            default:            r_data_r = {DATA_WIDTH{1'b0}};
        endcase
    end

    assign S_AXI_RVALID = ar_pending_r;
    assign S_AXI_RID    = ar_id_r;
    assign S_AXI_RDATA  = r_data_r;
    assign S_AXI_RRESP  = RESP_OKAY;
    assign S_AXI_RLAST  = (ar_beat_cnt_r == ar_len_r);

endmodule

`default_nettype wire
// ============================================================================
// END: clint.v
// ============================================================================
// ==============================================================================
// FILE: clk_reset_ctrl.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : clk_reset_ctrl
// Project : RISC-V SoC
//
// Bộ điều khiển Clock và Reset trung tâm — thay thế dòng nguy hiểm:
//   wire fabric_rst_n = ext_rst_n;   // CŨ: metastability hazard!
//
// [THÊM MỚI so với v1]
//   Input ndmreset từ jtag_debug_top (riscv_dm):
//     ndmreset = 1 → reset CPU + tất cả peripheral, NGOẠI TRỪ fabric (crossbar)
//                    và bản thân JTAG DM (để debugger vẫn connected).
//     WHY không reset fabric: JTAG DM dùng crossbar (M4 SBA) để đọc/ghi
//     DMEM/IMEM trong khi CPU đang bị reset. Nếu reset crossbar, path đó bị
//     cắt và debugger mất kết nối.
//     WHY không reset JTAG DM: DM là người phát ndmreset, nếu reset chính nó
//     sẽ tự giải phóng ndmreset và CPU chưa kịp reset đầy đủ.
//
//   Tín hiệu ndmreset đến từ tck domain (JTAG TAP) nhưng đã được đồng bộ
//   bên trong jtag_dtm (2-FF synchronizer tck→clk). Ở đây clk_reset_ctrl
//   vẫn qua thêm reset_sync để chắc chắn — defense in depth.
//
// [THÊM MỚI v3] AON mini-domain:
//   clk_aon = clk_in (không bao giờ gate) — cấp cho wake-up logic của
//   UART RX detector, GPIO edge detector, Timer compare, PLIC.
//   aon_rst_n chỉ bị POR + ext_rst, KHÔNG bị soft_rst hoặc ndmreset:
//     WHY: wake logic phải giữ state xuyên suốt soft_rst và JTAG session.
//   periph_wake_req (async từ AON) → ungate clk_periph ngay lập tức.
//   wake_ack = periph_clk_dyn_en_r → AON logic biết clock đã ổn, clear wake_pend.
//
// Hierarchy:
//   clk_reset_ctrl
//   ├── por_stretcher            — kéo dài POR ≥10µs sau khi VDD ổn định
//   ├── reset_sync u_sync_fabric — đồng bộ reset vào domain CORE/FABRIC
//   ├── reset_sync u_sync_cpu    — đồng bộ reset vào domain CPU
//   ├── reset_sync u_sync_periph — đồng bộ reset vào domain PERIPH
//   ├── reset_sync u_sync_ndm   — đồng bộ ndmreset trước khi combine
//   ├── reset_sync u_sync_aon   — đồng bộ AON reset (por+ext only) [MỚI]
//   ├── soft_rst_sync            — tái đồng bộ soft_rst_pulse, kéo dài 8 cycle
//   ├── clk_buf u_clk_core       — ICG gate cho domain CORE
//   └── clk_buf u_clk_periph     — ICG gate cho domain PERIPH
//   (clk_aon = clk_in trực tiếp, không qua ICG)
//
// Reset logic (tất cả active-low):
//   combined_rst_n       = por_n_stretched AND ext_rst_n AND soft_rst_n
//   combined_cpu_rst_n   = combined_rst_n AND ndm_rst_n AND boot_done
//   aon_combined_rst_n   = por_n_stretched AND ext_rst_n  (không soft, không ndm)
//   fabric_rst_n         = sync(combined_rst_n)     — KHÔNG bị ndmreset
//   cpu_rst_n            = sync(combined_cpu_rst_n)
//   periph_rst_n         = sync(combined_cpu_rst_n)
//   aon_rst_n            = sync(aon_combined_rst_n) — KHÔNG bị soft/ndm [MỚI]
//
// Kết nối trong soc_top.v:
//   clk_reset_ctrl u_clkrst (
//       .clk_in          (clk),
//       .por_n           (por_n),
//       .ext_rst_n       (ext_rst_n),
//       .soft_rst_pulse  (soft_rst_pulse),
//       .ndmreset        (jtag_ndmreset),
//       .boot_done       (boot_done),
//       .test_en         (1'b0),
//       .core_clk_en     (1'b1),
//       .periph_clk_en   (1'b1),
//       .periph_wake_req (periph_wake_req),   // ← MỚI: async từ AON
//       .clk_core        (clk_core),
//       .clk_periph      (clk_periph),
//       .clk_aon         (clk_aon),           // ← MỚI: always-on
//       .aon_rst_n       (aon_rst_n),         // ← MỚI: AON reset
//       .wake_ack        (wake_ack),           // ← MỚI: periph clock stable
//       .fabric_rst_n    (fabric_rst_n),
//       .cpu_rst_n       (cpu_rst_n),
//       .periph_rst_n    (periph_rst_n)
//   );
//   wire cpu_rst = ~cpu_rst_n;   // CPU core dùng active-high rst
// ============================================================================

// ==============================================================================
// FILE: reset_sync.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : reset_sync
// Project : RISC-V SoC
//
// Đồng bộ hóa tín hiệu reset bất đồng bộ vào domain clock cục bộ.
// Dùng chuỗi 2 flip-flop (tiêu chuẩn công nghiệp để chống metastability).
//
// WHY 2FF: Khi rst_async_n thay đổi không đồng bộ với clk, FF đầu tiên
//   có thể rơi vào metastable. Xác suất FF vẫn metastable sau 1 chu kỳ
//   clock là cực nhỏ (< 10^-20 ở 28nm). FF thứ 2 bắt output đã ổn định.
//
// Lưu ý synthesis: Attribute (* ASYNC_REG = "TRUE" *) báo cho tool biết
//   đây là chuỗi đồng bộ hóa → không optimize / retime các FF này.
// ============================================================================

// PROVIDES: rst_sync_n (async-assert / sync-deassert, 2FF metastability filtered)
// REQUIRES: clk (destination domain clock), rst_async_n (any domain, active-low)
module reset_sync (
    input  wire clk,          // clock của domain nhận
    input  wire rst_async_n,  // reset bất đồng bộ đầu vào (active-low)
    output wire rst_sync_n    // reset đã đồng bộ ra (active-low)
);

    // 2 FF nối tiếp, attribute giữ FF không bị optimize / retimed bởi tool
    (* ASYNC_REG = "TRUE" *) reg ff1, ff2;

    always @(posedge clk or negedge rst_async_n) begin
        if (!rst_async_n) begin
            // Khi reset assert: cả 2 FF về 0 ngay lập tức (async path)
            ff1 <= 1'b0;
            ff2 <= 1'b0;
        end else begin
            // Khi reset deassert: 1 = release, truyền qua chuỗi FF
            // Sau 2 chu kỳ clock, rst_sync_n = 1 (released)
            ff1 <= 1'b1;
            ff2 <= ff1;
        end
    end

    assign rst_sync_n = ff2;

endmodule
// ==============================================================================
// FILE: por_stretcher.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : por_stretcher
// Project : RISC-V SoC
//
// Kéo dài tín hiệu Power-On Reset (POR) tối thiểu POR_CYCLES chu kỳ
// sau khi por_n từ pad assert (low). Đảm bảo toàn bộ rail nguồn đã ổn
// định trước khi reset release.
//
// WHY: Pad POR_N từ foundry có thể bounce hoặc rise rất nhanh. Counter
//   giữ reset thêm N chu kỳ sau khi pad lên 1 → safe margin.
//
// POR_CYCLES = 1000 → tại 100 MHz = 10 µs (đáp ứng yêu cầu spec ≥10 µs).
// ============================================================================

// PROVIDES: por_n_out (POR stretched ≥ POR_CYCLES cycles, glitch-filtered, active-low)
// REQUIRES: clk (any freq), por_n_raw (pad POR, active-low, may bounce)
module por_stretcher #(
    parameter POR_CYCLES = 1000   // WHY 1000: 10µs @ 100MHz. Tăng nếu VDD rise chậm hơn.
) (
    input  wire clk,
    input  wire por_n_raw,    // POR từ pad (có thể glitch)
    output wire por_n_out     // POR đã kéo dài, sạch
);

    // Counter đủ rộng để đếm POR_CYCLES
    localparam CTR_W = $clog2(POR_CYCLES + 1);

    reg [CTR_W-1:0] ctr;
    reg             stretched;

    always @(posedge clk or negedge por_n_raw) begin
        if (!por_n_raw) begin
            // POR assert → reset counter, giữ output ở 0
            ctr       <= {CTR_W{1'b0}};
            stretched <= 1'b0;
        end else begin
            if (ctr < POR_CYCLES[CTR_W-1:0]) begin
                // Đang đếm: giữ reset
                ctr       <= ctr + 1'b1;
                stretched <= 1'b0;
            end else begin
                // Đã đủ chu kỳ: release reset
                stretched <= 1'b1;
            end
        end
    end

    assign por_n_out = stretched;

endmodule
// ==============================================================================
// FILE: soft_rst_sync.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : soft_rst_sync
// Project : RISC-V SoC
//
// Tái đồng bộ hóa soft_rst_pulse từ SOC CTRL vào domain fabric_rst_n.
//
// WHY cần module riêng:
//   soft_rst_pulse được tạo trong domain clock bởi soc_ctrl_slave (AXI write).
//   Tuy nhiên nó phải kết hợp với fabric_rst_n để tạo cpu_rst.
//   Nếu pulse rất ngắn (1 cycle), cần đảm bảo nó không bị miss hoặc gây
//   glitch trên rst_n combined.
//
// Logic:
//   1. Latch soft_rst_pulse vào SR-latch
//   2. Kéo dài thành STRETCH_CYCLES chu kỳ để đảm bảo tất cả FF nhận được
//   3. Kết hợp với por_rst_n thành fabric_rst_n_combined
//
// STRETCH_CYCLES = 8: đủ để truyền qua chuỗi reset_sync và flush pipeline CPU.
// ============================================================================

// PROVIDES: soft_rst_n (1-cycle pulse → stretched STRETCH_CYCLES cycles, active-low)
// REQUIRES: clk, por_rst_n (POR gate — inhibit soft_rst before power stable), soft_rst_pulse (1-cycle same domain)
module soft_rst_sync #(
    parameter STRETCH_CYCLES = 8   // WHY 8: đủ để flush 5-stage pipeline + 2FF sync
) (
    input  wire clk,
    input  wire por_rst_n,        // POR combined reset (đã sync)
    input  wire soft_rst_pulse,   // 1-cycle pulse từ soc_ctrl_slave
    output wire soft_rst_n        // active-low reset output, đã kéo dài
);

    localparam CTR_W = $clog2(STRETCH_CYCLES + 1);

    reg [CTR_W-1:0] ctr;
    reg             rst_active;

    always @(posedge clk or negedge por_rst_n) begin
        if (!por_rst_n) begin
            ctr        <= {CTR_W{1'b0}};
            rst_active <= 1'b0;
        end else begin
            if (soft_rst_pulse && !rst_active) begin
                // Bắt đầu soft reset: bắt pulse, khởi động counter
                ctr        <= {CTR_W{1'b0}};
                rst_active <= 1'b1;
            end else if (rst_active) begin
                if (ctr < STRETCH_CYCLES[CTR_W-1:0] - 1) begin
                    ctr <= ctr + 1'b1;
                end else begin
                    // Hết thời gian: release reset
                    rst_active <= 1'b0;
                    ctr        <= {CTR_W{1'b0}};
                end
            end
        end
    end

    // active-low: 0 khi đang reset, 1 khi bình thường
    assign soft_rst_n = ~rst_active;

endmodule
// ==============================================================================
// FILE: clk_buf.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : clk_buf
// Project : RISC-V SoC
//
// Clock buffer tích hợp ICG (Integrated Clock Gating).
// Khi enable=0: clock out bị gate → domain tắt, tiết kiệm điện.
// Khi enable=1: clock out = clk_in.
//
// WHY ICG vs simple AND gate:
//   AND gate thông thường tạo glitch nếu enable thay đổi trong khi clk=1.
//   ICG dùng latch để "latch" enable khi clk=0 → chuyển đổi sạch.
//
// SYNTHESIS NOTE:
//   Tool tổng hợp sẽ map module này thành cell ICG của foundry
//   (vd: TSMC CLKGATETST_X8, Sky130 sky130_fd_sc_hd__dlclkp_1).
//   `ifdef SIMULATION giữ behavioral model chạy được trong simulation.
//
// FPGA NOTE:
//   Trên FPGA không có ICG cell → dùng enable register thay thế.
//   Pragma KEEP_HIERARCHY ngăn Vivado/Quartus optimize module đi.
// ============================================================================

// PROVIDES: clk_out (ICG glitch-free gated clock), DFT test_en bypass
// REQUIRES: clk_in (any freq), enable (must be stable before posedge for clean gate)
module clk_buf (
    input  wire clk_in,    // clock đầu vào từ PLL hoặc pad
    input  wire enable,    // 1=clock chạy, 0=gate
    input  wire test_en,   // scan test: bypass gate (DFT)
    output wire clk_out    // clock ra đến domain
);

`ifdef SYNTHESIS

    // Trong synthesis: tool sẽ infer ICG cell từ foundry library
    // (tương đương CLKGATETST_X8 của TSMC 28nm)
    // Latch enable khi clock thấp → không glitch
    // WHY (* dont_touch *): không để tool rename/optimize đi
    (* dont_touch = "true" *)
    wire en_latch;

    // Level-sensitive latch: transparent khi clk_in = 0
    // Đây là pattern chuẩn tool nhận ra và map vào ICG cell
    latch_en u_latch (
        .clk   (clk_in),
        .d     (enable | test_en),
        .q     (en_latch)
    );

    assign clk_out = clk_in & en_latch;

`else

    // Behavioral model cho simulation
    // WHY: không cần latch trong sim, AND gate đủ chính xác
    assign clk_out = clk_in & (enable | test_en);

`endif

endmodule

// ============================================================================
// Latch primitive (chỉ dùng trong synthesis path)
// Tool sẽ map thành ICG latch của foundry
// ============================================================================
`ifdef SYNTHESIS
module latch_en (
    input  wire clk,   // enable khi clk=0 (active-low transparent)
    input  wire d,
    output reg  q
);
    always @(*) begin
        if (!clk) q <= d;   // latch transparent khi clock thấp
    end
endmodule
`endif

// PROVIDES: clk_core, clk_periph (ICG-gated); clk_aon (always-on);
//           fabric_rst_n, cpu_rst_n, periph_rst_n, aon_rst_n (synced resets);
//           wake_ack (periph clock stable signal for AON clear)
// REQUIRES: clk_in (main osc), por_n, ext_rst_n, ndmreset, boot_done,
//           periph_wake_req (async from AON domain), gating policy inputs
module clk_reset_ctrl #(
    parameter POR_CYCLES       = 1000,  // 10µs @ 100MHz
    parameter SOFT_RST_STRETCH = 8,     // 8 cycle pulse stretch
    parameter CORE_IDLE_HOLD_CYCLES   = 32,
    parameter PERIPH_IDLE_HOLD_CYCLES = 64
) (
    // =========================================================================
    // Clock inputs
    // =========================================================================
    input  wire clk_in,         // clock chính từ pad (hoặc PLL output)

    // =========================================================================
    // Reset inputs
    // =========================================================================
    input  wire por_n,          // Power-On Reset từ pad (active-low, có thể bounce)
    input  wire ext_rst_n,      // External reset từ GPIO (active-low, không sync)
    input  wire soft_rst_pulse, // Soft reset 1-cycle pulse từ soc_ctrl_slave

    // =========================================================================
    // Boot done — CPU held in reset until boot_ctrl finishes loading IMEM
    //
    // WHY: IMEM is now a blank SRAM loaded by boot_ctrl at startup.
    // If CPU were released before loading completes, it would fetch NOPs or
    // garbage. boot_done=0 keeps cpu_rst_n=0; after all PROG_WORDS written,
    // boot_done=1 and cpu_rst_n follows combined_cpu_rst_n normally.
    // =========================================================================
    input  wire boot_done,      // from boot_ctrl (active-high, sticky)

    // =========================================================================
    // JTAG Non-Debug Module Reset  [THÊM MỚI]
    //
    // ndmreset = 1 (active-high, theo RISC-V debug spec §3.3):
    //   → Reset CPU core và tất cả peripheral
    //   → KHÔNG reset crossbar (fabric) — giữ đường SBA của DM
    //   → KHÔNG reset JTAG DM — DM vẫn phải điều khiển được reset
    //
    // WHY active-high khác với các reset input khác (active-low):
    //   RISC-V Debug Spec định nghĩa ndmreset là active-high để phân biệt
    //   rõ với các reset hệ thống thông thường. Chúng ta convert thành
    //   active-low (ndm_rst_n = ~ndmreset_sync) trước khi AND vào combined.
    //
    // WHY cần thêm reset_sync cho ndmreset:
    //   Dù jtag_dtm đã sync tck→clk, thêm 1 tầng FF nữa là "defense in depth"
    //   an toàn hơn khi clk_reset_ctrl là module boundary cuối cùng trước
    //   khi reset đến từng domain.
    // =========================================================================
    input  wire ndmreset,       // JTAG DM → reset CPU+periph (active-high, đã sync)

    // =========================================================================
    // DFT / Test
    // =========================================================================
    input  wire test_en,        // Scan test enable — bypass ICG khi scan

    // =========================================================================
    // Clock enable cho từng power domain
    // =========================================================================
    input  wire core_clk_en,    // static allow/mask cho CORE gating policy
    input  wire periph_clk_en,  // static allow/mask cho PERIPH gating policy

    // =========================================================================
    // Dynamic clock-gating policy inputs (đã tổng hợp ở soc_top)
    // =========================================================================
    input  wire cpu_wfi,
    input  wire ascon_busy,
    input  wire core_bus_active,
    input  wire core_wake_event,
    input  wire periph_bus_active,
    input  wire periph_busy,
    input  wire periph_wake_event,
    input  wire periph_gate_allow,

    // =========================================================================
    // AON wake request [MỚI]
    //
    // periph_wake_req = 1 (async từ AON domain):
    //   → override gate condition → periph_clk_dyn_en_r set ngay lập tức
    //   → sau FF sampling: periph clock bật, wake_ack assert
    //   WHY async OK: periph_clk_dyn_en_r là FF → giải quyết metastability
    //   trước khi tín hiệu đến ICG latch.
    // =========================================================================
    input  wire periph_wake_req,  // async wake từ AON (GPIO/UART RX/Timer)

    // =========================================================================
    // Clock outputs (gated + always-on)
    // =========================================================================
    output wire clk_core,         // clock đến CPU, Cache, ASCON, Crossbar (ICG)
    output wire clk_periph,       // clock đến UART, SPI, GPIO, Timer, PLIC (ICG)
    output wire clk_aon,          // always-on clock = clk_in, không bao giờ gate

    // =========================================================================
    // Reset outputs (active-low, đã đồng bộ)
    // =========================================================================
    output wire fabric_rst_n,     // reset cho toàn bộ fabric — KHÔNG bị ndmreset
    output wire cpu_rst_n,        // reset riêng cho CPU core — BỊ ndmreset
    output wire periph_rst_n,     // reset cho domain PERIPH — BỊ ndmreset
    output wire aon_rst_n,        // reset cho AON domain — chỉ POR+ext, KHÔNG soft/ndm
    output wire wake_ack          // periph clock đang chạy → AON có thể clear wake_pend
);

    // =========================================================================
    // Stage 1: POR stretcher
    // =========================================================================
    wire por_n_stretched;

    por_stretcher #(
        .POR_CYCLES (POR_CYCLES)
    ) u_por (
        .clk        (clk_in),
        .por_n_raw  (por_n),
        .por_n_out  (por_n_stretched)
    );

    // =========================================================================
    // Stage 2a: Soft reset
    // =========================================================================
    wire soft_rst_n_w;

    soft_rst_sync #(
        .STRETCH_CYCLES (SOFT_RST_STRETCH)
    ) u_soft (
        .clk            (clk_in),
        .por_rst_n      (por_n_stretched),
        .soft_rst_pulse (soft_rst_pulse),
        .soft_rst_n     (soft_rst_n_w)
    );

    // =========================================================================
    // Stage 2b: Kết hợp reset cho FABRIC (không có ndmreset)
    //
    // WHY fabric KHÔNG có ndmreset:
    //   Crossbar cần hoạt động liên tục để JTAG DM (M4) có thể truy cập
    //   DMEM/IMEM qua System Bus Access trong khi CPU đang bị ndmreset.
    //   Nếu fabric bị reset, M4 AXI path bị cắt → debugger mất khả năng
    //   load chương trình hoặc đọc memory sau khi reset CPU.
    // =========================================================================
    wire combined_rst_n = por_n_stretched & ext_rst_n & soft_rst_n_w;

    // =========================================================================
    // Stage 2c: Đồng bộ ndmreset vào clk domain (defense in depth)
    //
    // ndmreset là active-high → convert sang active-low trước khi dùng
    // Dùng reset_sync với rst_async_n = ~ndmreset:
    //   ndmreset=0 (bình thường) → rst_async_n=1 → rst_sync_n=1 → không reset
    //   ndmreset=1 (reset)       → rst_async_n=0 → rst_sync_n=0 → reset assert
    // =========================================================================
    wire ndm_rst_n_sync;    // đã đồng bộ, active-low

    reset_sync u_sync_ndm (
        .clk         (clk_in),
        .rst_async_n (~ndmreset),      // active-high → flip thành active-low
        .rst_sync_n  (ndm_rst_n_sync)
    );

    // combined_cpu_rst_n: thêm ndmreset + boot_done vào chain reset CPU/periph
    // WHY AND: active-low → bất kỳ nguồn nào pull xuống 0 → reset assert
    // boot_done=0 giữ CPU reset cho đến khi boot_ctrl nạp xong IMEM
    wire combined_cpu_rst_n = combined_rst_n & ndm_rst_n_sync & boot_done;

    // =========================================================================
    // Stage 2d: AON reset — chỉ POR + ext_rst, KHÔNG soft_rst, KHÔNG ndmreset
    //
    // WHY tách riêng: wake-up logic trong peripheral (UART RX detector, GPIO
    // edge detector, Timer compare) phải giữ trạng thái xuyên qua soft_rst
    // và JTAG ndmreset. Nếu AON reset bị kéo xuống khi soft_rst → wake_pend
    // bị xóa → CPU không thể tỉnh dậy khi reset xong.
    // ext_rst_n được include vì đây là hard reset vật lý (nút reset trên board).
    // =========================================================================
    wire aon_combined_rst_n = por_n_stretched & ext_rst_n;

    reset_sync u_sync_aon (
        .clk        (clk_in),
        .rst_async_n(aon_combined_rst_n),
        .rst_sync_n (aon_rst_n)
    );

    // clk_aon: không qua ICG — luôn = clk_in bất kể mọi gate condition
    assign clk_aon = clk_in;

    // =========================================================================
    // Stage 3: 2FF synchronizer cho mỗi reset domain
    // =========================================================================

    // Fabric reset: chỉ từ combined_rst_n — KHÔNG có ndmreset
    reset_sync u_sync_fabric (
        .clk        (clk_in),
        .rst_async_n(combined_rst_n),
        .rst_sync_n (fabric_rst_n)
    );

    // CPU reset: combined + ndmreset
    // WHY riêng biệt: debug module cần reset CPU mà không reset crossbar.
    // Khi ndmreset=1, cpu_rst_n=0 nhưng fabric_rst_n vẫn=1.
    reset_sync u_sync_cpu (
        .clk        (clk_in),
        .rst_async_n(combined_cpu_rst_n),
        .rst_sync_n (cpu_rst_n)
    );

    // Peripheral reset: cũng bị ndmreset
    // WHY: UART, SPI, GPIO cần reset khi CPU reset để tránh stale state
    // (ví dụ UART đang TX giữa chừng, GPIO output bị giữ sai level).
    // PLIC cũng reset để xóa pending interrupts từ session debug trước.
    reset_sync u_sync_periph (
        .clk        (clk_in),
        .rst_async_n(combined_cpu_rst_n),
        .rst_sync_n (periph_rst_n)
    );

    // =========================================================================
    // Stage 4: Clock gating (ICG)
    // =========================================================================
    reg [31:0] core_idle_hold_r;
    reg [31:0] periph_idle_hold_r;
    reg        core_clk_dyn_en_r;
    reg        periph_clk_dyn_en_r;

    wire core_clk_req =
        core_clk_en &&
        (core_wake_event || ascon_busy || core_bus_active || !cpu_wfi);

    // periph_wake_req (async từ AON) nằm trong điều kiện OR → FF sampling tại
    // posedge clk_in giải quyết metastability trước khi kết quả đến ICG latch
    wire periph_clk_req =
        periph_clk_en &&
        (periph_wake_req || periph_wake_event || periph_bus_active ||
         periph_busy || !periph_gate_allow);

    always @(posedge clk_in or negedge combined_rst_n) begin
        if (!combined_rst_n) begin
            core_idle_hold_r    <= 32'd0;
            periph_idle_hold_r  <= 32'd0;
            core_clk_dyn_en_r   <= 1'b1;
            periph_clk_dyn_en_r <= 1'b1;
        end else begin
            if (!core_clk_en) begin
                core_idle_hold_r  <= 32'd0;
                core_clk_dyn_en_r <= 1'b0;
            end else if (core_clk_req) begin
                core_idle_hold_r  <= (CORE_IDLE_HOLD_CYCLES > 0) ? (CORE_IDLE_HOLD_CYCLES - 1) : 0;
                core_clk_dyn_en_r <= 1'b1;
            end else if (core_idle_hold_r != 32'd0) begin
                core_idle_hold_r  <= core_idle_hold_r - 32'd1;
                core_clk_dyn_en_r <= 1'b1;
            end else begin
                core_clk_dyn_en_r <= 1'b0;
            end

            if (!periph_clk_en) begin
                periph_idle_hold_r  <= 32'd0;
                periph_clk_dyn_en_r <= 1'b0;
            end else if (periph_clk_req) begin
                periph_idle_hold_r  <= (PERIPH_IDLE_HOLD_CYCLES > 0) ? (PERIPH_IDLE_HOLD_CYCLES - 1) : 0;
                periph_clk_dyn_en_r <= 1'b1;
            end else if (periph_idle_hold_r != 32'd0) begin
                periph_idle_hold_r  <= periph_idle_hold_r - 32'd1;
                periph_clk_dyn_en_r <= 1'b1;
            end else begin
                periph_clk_dyn_en_r <= 1'b0;
            end
        end
    end

    clk_buf u_clk_core (
        .clk_in  (clk_in),
        .enable  (core_clk_dyn_en_r),
        .test_en (test_en),
        .clk_out (clk_core)
    );

    clk_buf u_clk_periph (
        .clk_in  (clk_in),
        .enable  (periph_clk_dyn_en_r),
        .test_en (test_en),
        .clk_out (clk_periph)
    );

    // wake_ack: assert khi periph clock đang chạy ổn định
    // AON logic dùng wake_ack để clear wake_pend SR-latch sau khi biết
    // clk_periph đã bật và peripheral sẵn sàng xử lý interrupt.
    assign wake_ack = periph_clk_dyn_en_r;

endmodule

// ==============================================================================
// FILE: uart_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_top
// Project : RISC-V SoC
//
// UART peripheral 8N1 với AXI4-Full slave interface.
// Địa chỉ: S5 = 0x5000_0000, kích thước 4KB
//
// Hierarchy:
//   uart_top
//   ├── uart_axi_slave   — AXI4-Full register access + thanh ghi CTRL/STATUS
//   ├── uart_baud_gen    — baud rate divider, tạo tick_tx và tick_rx16
//   ├── uart_fifo (tx)   — TX FIFO 8-bit × 16 deep
//   ├── uart_fifo (rx)   — RX FIFO 8-bit × 16 deep
//   ├── uart_tx          — TX shift register FSM (8N1)
//   ├── uart_rx          — RX sampler FSM (x16 oversample)
//   └── uart_irq_gen     — edge-detect IRQ generator
//
// Bản đồ thanh ghi (offset từ base 0x5000_0000):
//   0x00  TX_DATA    WO  [7:0]   ghi byte ra UART TX
//   0x04  RX_DATA    RO  [7:0]   đọc byte từ UART RX
//   0x08  STATUS     RO  [4:0]   {rx_overrun, rx_full, rx_empty, tx_full, tx_empty}
//   0x0C  CTRL       RW  [1:0]   {rx_irq_en, tx_irq_en}
//   0x10  BAUD_DIV   RW  [15:0]  divisor = clk_freq/baud - 1 (default 867 = 115200@100MHz)
//   0x14  IRQ_STATUS RW1C[1:0]   {rx_valid_irq, tx_empty_irq} ghi 1 để xóa
//
// Kết nối vào soc_top.v:
//   uart_top #(
//       .AXI_ADDR_WIDTH(32), .AXI_DATA_WIDTH(32), .AXI_ID_WIDTH(4)
//   ) u_uart (
//       .clk        (clk),
//       .rst_n      (periph_rst_n),    // từ clk_reset_ctrl
//       .s_axi_*    (s5_*),            // Slave port S5 của crossbar
//       .uart_tx    (uart_tx_pad),
//       .uart_rx    (uart_rx_pad),
//       .irq_out    (uart_irq)         // → PLIC source [0]
//   );
// ============================================================================


// ==============================================================================
// FILE: uart_axi_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_axi_slave
// Project : RISC-V SoC — UART peripheral
//
// AXI4-Full slave interface cho UART. Xử lý các thanh ghi:
//   0x00  TX_DATA    WO  [7:0]   ghi byte vào TX FIFO
//   0x04  RX_DATA    RO  [7:0]   đọc byte từ RX FIFO
//   0x08  STATUS     RO  [4:0]   tx_full|tx_empty|rx_full|rx_empty|rx_overrun
//   0x0C  CTRL       RW  [1:0]   rx_irq_en|tx_irq_en
//   0x10  BAUD_DIV   RW  [15:0]  baud divisor
//   0x14  IRQ_STATUS RW1C[1:0]   tx_empty_irq|rx_valid_irq (ghi 1 để xóa)
//
// WHY AXI4-Full (không phải Lite):
//   Crossbar của SoC chỉ hỗ trợ AXI4-Full. Tuy UART chỉ cần register access
//   đơn giản, vẫn phải implement đủ AWLEN/ARLEN/WLAST/BID/RID.
//   Tất cả burst đều xử lý như single-beat (AWLEN/ARLEN bị ignore).
//
// AXI4-Full handshake:
//   Write: AW channel → W channel → B channel (response)
//   Read:  AR channel → R channel (response với RID)
// ============================================================================

module uart_axi_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
) (
    input  wire                   clk,
    input  wire                   rst_n,

    // =========================================================================
    // AXI4-Full Write Address Channel
    // =========================================================================
    input  wire [ID_WIDTH-1:0]    s_axi_awid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_awaddr,
    input  wire [7:0]             s_axi_awlen,
    input  wire [2:0]             s_axi_awsize,
    input  wire [1:0]             s_axi_awburst,
    input  wire                   s_axi_awvalid,
    output wire                   s_axi_awready,

    // AXI4-Full Write Data Channel
    input  wire [DATA_WIDTH-1:0]  s_axi_wdata,
    input  wire [DATA_WIDTH/8-1:0]s_axi_wstrb,
    input  wire                   s_axi_wlast,
    input  wire                   s_axi_wvalid,
    output wire                   s_axi_wready,

    // AXI4-Full Write Response Channel
    output wire [ID_WIDTH-1:0]    s_axi_bid,
    output wire [1:0]             s_axi_bresp,
    output wire                   s_axi_bvalid,
    input  wire                   s_axi_bready,

    // =========================================================================
    // AXI4-Full Read Address Channel
    // =========================================================================
    input  wire [ID_WIDTH-1:0]    s_axi_arid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_araddr,
    input  wire [7:0]             s_axi_arlen,
    input  wire [2:0]             s_axi_arsize,
    input  wire [1:0]             s_axi_arburst,
    input  wire                   s_axi_arvalid,
    output wire                   s_axi_arready,

    // AXI4-Full Read Data Channel
    output wire [ID_WIDTH-1:0]    s_axi_rid,
    output wire [DATA_WIDTH-1:0]  s_axi_rdata,
    output wire [1:0]             s_axi_rresp,
    output wire                   s_axi_rlast,
    output wire                   s_axi_rvalid,
    input  wire                   s_axi_rready,

    // =========================================================================
    // Register interface → UART datapath
    // =========================================================================
    // TX FIFO
    output wire [7:0]  reg_tx_data,
    output wire        reg_tx_push,   // 1-cycle strobe: ghi byte vào TX FIFO
    input  wire        tx_fifo_full,
    input  wire        tx_fifo_empty,

    // RX FIFO
    input  wire [7:0]  reg_rx_data,
    output wire        reg_rx_pop,    // 1-cycle strobe: pop byte từ RX FIFO
    input  wire        rx_fifo_full,
    input  wire        rx_fifo_empty,
    input  wire        rx_overrun,

    // Config
    output wire [15:0] reg_baud_div,
    output wire        reg_rx_irq_en,
    output wire        reg_tx_irq_en,

    // IRQ
    input  wire        tx_empty_irq_in,  // từ datapath
    input  wire        rx_valid_irq_in,
    output wire        irq_out
);

    // =========================================================================
    // Register bank
    // =========================================================================
    reg [15:0] baud_div_r;
    reg        rx_irq_en_r, tx_irq_en_r;
    reg        tx_irq_r, rx_irq_r;   // IRQ status (sticky, RW1C)

    assign reg_baud_div  = baud_div_r;
    assign reg_rx_irq_en = rx_irq_en_r;
    assign reg_tx_irq_en = tx_irq_en_r;
    assign irq_out       = (tx_irq_r & tx_irq_en_r) | (rx_irq_r & rx_irq_en_r);

    // =========================================================================
    // Write FSM
    // WHY FSM: AXI4 tách kênh AW và W → cần latch awid và awaddr riêng,
    //   sau đó chờ W beat, rồi mới xử lý, cuối cùng trả B response.
    // =========================================================================
    localparam WS_IDLE  = 2'd0;
    localparam WS_DATA  = 2'd1;
    localparam WS_RESP  = 2'd2;

    reg [1:0]            wr_state;
    reg [ID_WIDTH-1:0]   wr_id;
    reg [ADDR_WIDTH-1:0] wr_addr;
    reg                  awready_r, wready_r, bvalid_r;
    reg [ID_WIDTH-1:0]   bid_r;
    reg                  tx_push_r;
    reg [7:0]            tx_data_r;

    assign s_axi_awready = awready_r;
    assign s_axi_wready  = wready_r;
    assign s_axi_bvalid  = bvalid_r;
    assign s_axi_bid     = bid_r;
    assign s_axi_bresp   = 2'b00;   // OKAY
    assign reg_tx_push   = tx_push_r;
    assign reg_tx_data   = tx_data_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state    <= WS_IDLE;
            wr_id       <= {ID_WIDTH{1'b0}};
            wr_addr     <= {ADDR_WIDTH{1'b0}};
            awready_r   <= 1'b1;
            wready_r    <= 1'b0;
            bvalid_r    <= 1'b0;
            bid_r       <= {ID_WIDTH{1'b0}};
            tx_push_r   <= 1'b0;
            tx_data_r   <= 8'd0;
            baud_div_r  <= 16'd867;   // default 115200 @ 100MHz
            rx_irq_en_r <= 1'b0;
            tx_irq_en_r <= 1'b0;
            tx_irq_r    <= 1'b0;
            rx_irq_r    <= 1'b0;
        end else begin
            tx_push_r <= 1'b0;

            // Sticky IRQ: set khi event xảy ra
            if (tx_empty_irq_in) tx_irq_r <= 1'b1;
            if (rx_valid_irq_in) rx_irq_r <= 1'b1;

            case (wr_state)
                WS_IDLE: begin
                    awready_r <= 1'b1;
                    if (s_axi_awvalid && awready_r) begin
                        wr_id     <= s_axi_awid;
                        wr_addr   <= s_axi_awaddr;
                        awready_r <= 1'b0;
                        wready_r  <= 1'b1;
                        wr_state  <= WS_DATA;
                    end
                end

                WS_DATA: begin
                    if (s_axi_wvalid && wready_r) begin
                        wready_r <= 1'b0;
                        // Decode địa chỉ (offset = addr[7:0])
                        case (wr_addr[7:2])   // word-aligned → dùng [7:2]
                            6'h00: begin  // 0x00 TX_DATA
                                if (!tx_fifo_full) begin
                                    tx_data_r <= s_axi_wdata[7:0];
                                    tx_push_r <= 1'b1;
                                end
                            end
                            6'h03: begin  // 0x0C CTRL
                                tx_irq_en_r <= s_axi_wdata[0];
                                rx_irq_en_r <= s_axi_wdata[1];
                            end
                            6'h04: begin  // 0x10 BAUD_DIV
                                baud_div_r <= s_axi_wdata[15:0];
                            end
                            6'h05: begin  // 0x14 IRQ_STATUS (RW1C: ghi 1 để xóa)
                                if (s_axi_wdata[0]) tx_irq_r <= 1'b0;
                                if (s_axi_wdata[1]) rx_irq_r <= 1'b0;
                            end
                            default: ;  // read-only regs: ignore write
                        endcase
                        bvalid_r <= 1'b1;
                        bid_r    <= wr_id;
                        wr_state <= WS_RESP;
                    end
                end

                WS_RESP: begin
                    if (s_axi_bready && bvalid_r) begin
                        bvalid_r <= 1'b0;
                        wr_state <= WS_IDLE;
                    end
                end

                default: wr_state <= WS_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Read FSM
    // =========================================================================
    localparam RS_IDLE = 1'b0;
    localparam RS_RESP = 1'b1;

    reg             rd_state;
    reg [ID_WIDTH-1:0]   ar_id;
    reg [ADDR_WIDTH-1:0] ar_addr;
    reg             arready_r, rvalid_r;
    reg [DATA_WIDTH-1:0] rdata_r;
    reg [ID_WIDTH-1:0]   rid_r;
    reg             rx_pop_r;

    assign s_axi_arready = arready_r;
    assign s_axi_rvalid  = rvalid_r;
    assign s_axi_rdata   = rdata_r;
    assign s_axi_rid     = rid_r;
    assign s_axi_rresp   = 2'b00;
    assign s_axi_rlast   = rvalid_r;   // single-beat burst: RLAST = RVALID
    assign reg_rx_pop    = rx_pop_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state  <= RS_IDLE;
            arready_r <= 1'b1;
            rvalid_r  <= 1'b0;
            rdata_r   <= {DATA_WIDTH{1'b0}};
            rid_r     <= {ID_WIDTH{1'b0}};
            rx_pop_r  <= 1'b0;
            ar_id     <= {ID_WIDTH{1'b0}};
            ar_addr   <= {ADDR_WIDTH{1'b0}};
        end else begin
            rx_pop_r <= 1'b0;

            case (rd_state)
                RS_IDLE: begin
                    arready_r <= 1'b1;
                    if (s_axi_arvalid && arready_r) begin
                        ar_id     <= s_axi_arid;
                        ar_addr   <= s_axi_araddr;
                        arready_r <= 1'b0;

                        // Decode và latch read data
                        case (s_axi_araddr[7:2])
                            6'h00: rdata_r <= 32'd0;  // TX_DATA: write-only, return 0
                            6'h01: begin               // 0x04 RX_DATA
                                rdata_r  <= {24'd0, reg_rx_data};
                                rx_pop_r <= !rx_fifo_empty;
                            end
                            6'h02: rdata_r <= {27'd0,  // 0x08 STATUS
                                               rx_overrun,
                                               rx_fifo_full,
                                               rx_fifo_empty,
                                               tx_fifo_full,
                                               tx_fifo_empty};
                            6'h03: rdata_r <= {30'd0, rx_irq_en_r, tx_irq_en_r}; // 0x0C CTRL
                            6'h04: rdata_r <= {16'd0, baud_div_r};                // 0x10 BAUD_DIV
                            6'h05: rdata_r <= {30'd0, rx_irq_r, tx_irq_r};       // 0x14 IRQ_STATUS
                            default: rdata_r <= 32'hDEAD_BEEF;
                        endcase

                        rid_r    <= s_axi_arid;
                        rvalid_r <= 1'b1;
                        rd_state <= RS_RESP;
                    end
                end

                RS_RESP: begin
                    if (s_axi_rready && rvalid_r) begin
                        rvalid_r  <= 1'b0;
                        arready_r <= 1'b1;
                        rd_state  <= RS_IDLE;
                    end
                end

                default: rd_state <= RS_IDLE;
            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: uart_baud_gen.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_baud_gen
// Project : RISC-V SoC — UART peripheral
//
// Tạo xung tick 1-cycle mỗi khi đủ (divisor+1) chu kỳ clock.
// TX dùng tick thẳng (1 tick = 1 bit period).
// RX dùng tick x16 oversample để lấy mẫu giữa bit (sample khi cnt_os==8).
//
// Công thức: divisor = clk_freq / baud_rate - 1
//   115200 baud @ 100 MHz → divisor = 868 - 1 = 867 (0x363)
//   9600   baud @ 100 MHz → divisor = 10416 - 1 = 10415
//
// Divisor = 0 → tick mỗi 1 cycle (chỉ dùng test).
// ============================================================================

module uart_baud_gen (
    input  wire        clk,
    input  wire        rst_n,
    input  wire [15:0] divisor,    // từ thanh ghi BAUD_DIV
    output wire        tick_tx,    // 1 pulse mỗi bit period (TX)
    output wire        tick_rx16   // 1 pulse mỗi 1/16 bit period (RX oversample)
);

    // -------------------------------------------------------------------------
    // Counter chia 16 lần cho oversample RX
    // WHY x16: chia bit period thành 16 khe → lấy mẫu tại khe 8 (giữa bit)
    //          chịu được jitter ±6/16 = 37.5% bit period
    // -------------------------------------------------------------------------
    reg [15:0] cnt_tx;
    reg [3:0]  cnt_os;   // 0..15 oversample counter
    reg        tick_tx_r;
    reg        tick_rx16_r;

    // divisor_os = divisor / 16 (baud tick chia 16 cho oversample)
    // WHY dùng shift: divisor >> 4 = divisor / 16, tổng hợp thành wire
    wire [15:0] divisor_os = (divisor == 16'd0) ? 16'd0 : (divisor >> 4);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt_tx      <= 16'd0;
            cnt_os      <= 4'd0;
            tick_tx_r   <= 1'b0;
            tick_rx16_r <= 1'b0;
        end else begin
            tick_tx_r   <= 1'b0;
            tick_rx16_r <= 1'b0;

            // Oversample tick (÷16 của baud)
            if (cnt_tx >= divisor_os) begin
                cnt_tx      <= 16'd0;
                tick_rx16_r <= 1'b1;

                // TX tick: mỗi 16 oversample ticks = 1 bit period
                if (cnt_os == 4'd15) begin
                    cnt_os    <= 4'd0;
                    tick_tx_r <= 1'b1;
                end else begin
                    cnt_os <= cnt_os + 4'd1;
                end
            end else begin
                cnt_tx <= cnt_tx + 16'd1;
            end
        end
    end

    assign tick_tx   = tick_tx_r;
    assign tick_rx16 = tick_rx16_r;

endmodule
// ==============================================================================
// FILE: uart_fifo.v
// ==============================================================================

// `timescale 1ns/1ps
`ifndef UART_FIFO_V
`define UART_FIFO_V

// ============================================================================
// Module  : uart_fifo
// Project : RISC-V SoC — UART peripheral
//
// Synchronous FIFO 8-bit, depth cấu hình bằng tham số DEPTH.
// TX FIFO: depth=16, push từ AXI write, pop từ TX shift register
// RX FIFO: depth=16, push từ RX shift register, pop từ AXI read
//
// WHY FIFO: tách clock domain AXI (bursty, CPU-driven) khỏi UART baud
//   (constant rate). CPU có thể burst ghi nhiều byte rồi để FIFO drain
//   từ từ mà không cần polling liên tục.
//
// Flags:
//   full   = không thể push thêm (TX: CPU block / RX: overrun nếu vẫn push)
//   empty  = không có data để pop (TX: TX idle / RX: CPU chờ)
//   almost_full = còn 1 slot (dùng cho flow control nếu cần)
// ============================================================================

module uart_fifo #(
    parameter DEPTH = 16   // phải là lũy thừa của 2
) (
    input  wire       clk,
    input  wire       rst_n,
    // Write port
    input  wire [7:0] din,
    input  wire       push,
    output wire       full,
    output wire       almost_full,
    // Read port
    output wire [7:0] dout,
    input  wire       pop,
    output wire       empty,
    // Status
    output wire [$clog2(DEPTH):0] count   // số phần tử hiện có
);

    localparam PTR_W = $clog2(DEPTH);

    reg [7:0]       mem [0:DEPTH-1];
    reg [PTR_W:0]   wr_ptr;   // PTR_W+1 bit: bit cao là wrap bit
    reg [PTR_W:0]   rd_ptr;

    // WHY wrap-bit trick: dùng 1 bit thêm để phân biệt full vs empty
    // empty: wr_ptr == rd_ptr (kể cả wrap bit)
    // full : wr_ptr[PTR_W] != rd_ptr[PTR_W] && wr_ptr[PTR_W-1:0] == rd_ptr[PTR_W-1:0]
    assign empty       = (wr_ptr == rd_ptr);
    assign full        = (wr_ptr[PTR_W] != rd_ptr[PTR_W]) &&
                         (wr_ptr[PTR_W-1:0] == rd_ptr[PTR_W-1:0]);
    assign count       = wr_ptr - rd_ptr;
    assign almost_full = (count == (DEPTH - 1));
    assign dout        = mem[rd_ptr[PTR_W-1:0]];

    integer i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr <= {(PTR_W+1){1'b0}};
            rd_ptr <= {(PTR_W+1){1'b0}};
            for (i = 0; i < DEPTH; i = i + 1)
                mem[i] <= 8'd0;
        end else begin
            if (push && !full) begin
                mem[wr_ptr[PTR_W-1:0]] <= din;
                wr_ptr <= wr_ptr + 1'b1;
            end
            if (pop && !empty) begin
                rd_ptr <= rd_ptr + 1'b1;
            end
        end
    end

endmodule
`endif // UART_FIFO_V

// ==============================================================================
// FILE: uart_tx.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_tx
// Project : RISC-V SoC — UART peripheral
//
// TX shift register 8N1: Start(0) + 8 data bits (LSB first) + Stop(1).
// Hoạt động:
//   IDLE:    tx_out=1, chờ fifo_empty=0
//   START:   shift out bit start (0) khi tick_tx
//   DATA:    shift ra 8 bit data, LSB trước
//   STOP:    shift out bit stop (1), sau đó về IDLE
//
// WHY LSB first: chuẩn UART/RS-232 truyền LSB trước (bit 0 ra trước bit 7).
// ============================================================================

module uart_tx (
    input  wire       clk,
    input  wire       rst_n,
    input  wire       tick_tx,    // 1 pulse mỗi bit period từ baud_gen
    // TX FIFO interface
    input  wire [7:0] fifo_dout,  // data từ TX FIFO
    input  wire       fifo_empty, // TX FIFO rỗng
    output wire       fifo_pop,   // pop 1 byte từ TX FIFO
    // UART line
    output wire       tx_out,     // chân TX ra pad
    // Status
    output wire       tx_busy     // 1 khi đang truyền (dùng cho IRQ tx_empty)
);

    // FSM states
    localparam S_IDLE  = 2'd0;
    localparam S_START = 2'd1;
    localparam S_DATA  = 2'd2;
    localparam S_STOP  = 2'd3;

    reg [1:0]  state;
    reg [7:0]  shift_reg;
    reg [2:0]  bit_cnt;   // đếm 0..7 cho 8 bit data
    reg        tx_reg;    // output register
    reg        pop_reg;

    assign tx_out   = tx_reg;
    assign fifo_pop = pop_reg;
    assign tx_busy  = (state != S_IDLE);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= S_IDLE;
            shift_reg <= 8'd0;
            bit_cnt   <= 3'd0;
            tx_reg    <= 1'b1;   // line idle = high
            pop_reg   <= 1'b0;
        end else begin
            pop_reg <= 1'b0;    // pulse 1 cycle

            case (state)
                S_IDLE: begin
                    tx_reg <= 1'b1;
                    if (!fifo_empty && tick_tx) begin
                        // Load byte từ FIFO, bắt đầu truyền
                        shift_reg <= fifo_dout;
                        pop_reg   <= 1'b1;   // pop byte này
                        state     <= S_START;
                    end
                end

                S_START: begin
                    if (tick_tx) begin
                        tx_reg  <= 1'b0;   // start bit = 0
                        bit_cnt <= 3'd0;
                        state   <= S_DATA;
                    end
                end

                S_DATA: begin
                    if (tick_tx) begin
                        tx_reg    <= shift_reg[0];       // LSB first
                        shift_reg <= {1'b0, shift_reg[7:1]};  // shift right
                        if (bit_cnt == 3'd7) begin
                            state <= S_STOP;
                        end else begin
                            bit_cnt <= bit_cnt + 3'd1;
                        end
                    end
                end

                S_STOP: begin
                    if (tick_tx) begin
                        tx_reg <= 1'b1;   // stop bit = 1
                        state  <= S_IDLE;
                    end
                end

                default: state <= S_IDLE;
            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: uart_rx.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_rx
// Project : RISC-V SoC — UART peripheral
//
// RX sampler với x16 oversample, 8N1.
// Phát hiện start bit bằng cạnh xuống của rx_in.
// Lấy mẫu tại khe 8/16 (giữa bit) để đạt noise margin tốt nhất.
//
// WHY sample tại khe 8: đây là điểm cách cạnh bit xa nhất,
//   chịu được jitter ±7/16 ≈ 44% bit period trước khi lỗi.
//
// Overrun: nếu RX FIFO đầy khi RX hoàn thành 1 byte → set overrun flag,
//   byte mới bị bỏ (FIFO không push). CPU phải clear flag qua CTRL.
// ============================================================================

module uart_rx (
    input  wire       clk,
    input  wire       rst_n,
    input  wire       tick_rx16,  // 1 pulse mỗi 1/16 bit period
    // Input
    input  wire       rx_in,      // chân RX từ pad
    // RX FIFO interface
    input  wire       fifo_full,
    output wire [7:0] fifo_din,
    output wire       fifo_push,
    // Status
    output wire       rx_overrun  // set khi byte đến mà FIFO đầy
);

    // FSM states
    localparam S_IDLE  = 2'd0;
    localparam S_START = 2'd1;
    localparam S_DATA  = 2'd2;
    localparam S_STOP  = 2'd3;

    // 2-FF synchronizer cho rx_in (tránh metastability từ async UART line)
    (* ASYNC_REG = "TRUE" *) reg rx_ff1, rx_ff2, rx_ff3;
    wire rx_sync = rx_ff2;
    wire rx_fall = rx_ff3 & ~rx_ff2;   // cạnh xuống (start bit detect)

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rx_ff1 <= 1'b1;
            rx_ff2 <= 1'b1;
            rx_ff3 <= 1'b1;
        end else begin
            rx_ff1 <= rx_in;
            rx_ff2 <= rx_ff1;
            rx_ff3 <= rx_ff2;
        end
    end

    reg [1:0]  state;
    reg [3:0]  os_cnt;    // oversample counter 0..15
    reg [2:0]  bit_cnt;   // bit counter 0..7
    reg [7:0]  shift_reg;
    reg        push_r;
    reg        overrun_r;

    assign fifo_din  = shift_reg;
    assign fifo_push = push_r;
    assign rx_overrun = overrun_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= S_IDLE;
            os_cnt    <= 4'd0;
            bit_cnt   <= 3'd0;
            shift_reg <= 8'd0;
            push_r    <= 1'b0;
            overrun_r <= 1'b0;
        end else begin
            push_r <= 1'b0;

            case (state)
                S_IDLE: begin
                    overrun_r <= 1'b0;
                    if (rx_fall) begin
                        // Phát hiện start bit: bắt đầu đếm oversample
                        os_cnt <= 4'd0;
                        state  <= S_START;
                    end
                end

                S_START: begin
                    // Chờ đến khe 8 (giữa start bit) để xác nhận start bit thật
                    if (tick_rx16) begin
                        if (os_cnt == 4'd7) begin
                            // Sample giữa start bit: phải = 0
                            if (!rx_sync) begin
                                os_cnt  <= 4'd0;
                                bit_cnt <= 3'd0;
                                state   <= S_DATA;
                            end else begin
                                // Noise / glitch → quay lại IDLE
                                state <= S_IDLE;
                            end
                        end else begin
                            os_cnt <= os_cnt + 4'd1;
                        end
                    end
                end

                S_DATA: begin
                    if (tick_rx16) begin
                        if (os_cnt == 4'd15) begin
                            // Khe 15 = cuối bit hiện tại, cũng là sample point bit kế
                            // WHY sample tại khe 15 của os_cnt:
                            //   os_cnt reset về 0 khi bắt đầu bit mới, khe 7-8 là giữa.
                            //   Nhưng sau start bit align, sample tại 15 = giữa của bit data.
                            os_cnt    <= 4'd0;
                            shift_reg <= {rx_sync, shift_reg[7:1]};  // LSB first: shift right
                            if (bit_cnt == 3'd7) begin
                                state <= S_STOP;
                            end else begin
                                bit_cnt <= bit_cnt + 3'd1;
                            end
                        end else begin
                            os_cnt <= os_cnt + 4'd1;
                        end
                    end
                end

                S_STOP: begin
                    if (tick_rx16) begin
                        if (os_cnt == 4'd7) begin
                            // Sample giữa stop bit
                            if (rx_sync) begin
                                // Stop bit hợp lệ: push vào FIFO
                                if (!fifo_full) begin
                                    push_r <= 1'b1;
                                end else begin
                                    overrun_r <= 1'b1;   // FIFO đầy → overrun
                                end
                            end
                            // Dù stop bit có hợp lệ hay không → về IDLE
                            state  <= S_IDLE;
                            os_cnt <= 4'd0;
                        end else begin
                            os_cnt <= os_cnt + 4'd1;
                        end
                    end
                end

                default: state <= S_IDLE;
            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: uart_irq_gen.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : uart_irq_gen
// Project : RISC-V SoC — UART peripheral
//
// Tạo xung IRQ 1 cycle cho các sự kiện UART:
//   tx_empty_irq : TX FIFO chuyển từ non-empty → empty (CPU nên nạp thêm)
//   rx_valid_irq : RX FIFO chuyển từ empty → non-empty (có byte mới)
//
// WHY phát hiện cạnh (edge detect) thay vì level:
//   Level IRQ sẽ liên tục assert khi FIFO rỗng/đầy → CPU bị ngắt liên tục.
//   Edge detect chỉ báo khi trạng thái THAY ĐỔI → CPU nhận 1 IRQ, xử lý xong.
//   Sau đó IRQ_STATUS sticky latch giữ nguyên cho đến khi CPU RW1C clear.
// ============================================================================

module uart_irq_gen (
    input  wire clk,
    input  wire rst_n,
    // FIFO status inputs
    input  wire tx_fifo_empty,
    input  wire rx_fifo_empty,
    // IRQ pulse outputs (1-cycle)
    output wire tx_empty_irq,   // TX FIFO vừa trở nên rỗng
    output wire rx_valid_irq    // RX FIFO vừa có dữ liệu
);

    reg tx_empty_prev;
    reg rx_empty_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            tx_empty_prev <= 1'b1;
            rx_empty_prev <= 1'b1;
        end else begin
            tx_empty_prev <= tx_fifo_empty;
            rx_empty_prev <= rx_fifo_empty;
        end
    end

    // Cạnh lên của tx_fifo_empty: FIFO vừa drain hết
    assign tx_empty_irq = tx_fifo_empty & ~tx_empty_prev;

    // Cạnh xuống của rx_fifo_empty: FIFO vừa có byte đầu tiên
    assign rx_valid_irq = ~rx_fifo_empty & rx_empty_prev;

endmodule
module uart_top #(
    parameter AXI_ADDR_WIDTH = 32,
    parameter AXI_DATA_WIDTH = 32,
    parameter AXI_ID_WIDTH   = 4,
    parameter TX_FIFO_DEPTH  = 16,
    parameter RX_FIFO_DEPTH  = 16
) (
    input  wire                        clk,
    input  wire                        rst_n,

    // =========================================================================
    // AXI4-Full Slave Interface (từ crossbar S5)
    // =========================================================================
    input  wire [AXI_ID_WIDTH-1:0]    s_axi_awid,
    input  wire [AXI_ADDR_WIDTH-1:0]  s_axi_awaddr,
    input  wire [7:0]                 s_axi_awlen,
    input  wire [2:0]                 s_axi_awsize,
    input  wire [1:0]                 s_axi_awburst,
    input  wire                       s_axi_awvalid,
    output wire                       s_axi_awready,

    input  wire [AXI_DATA_WIDTH-1:0]  s_axi_wdata,
    input  wire [AXI_DATA_WIDTH/8-1:0]s_axi_wstrb,
    input  wire                       s_axi_wlast,
    input  wire                       s_axi_wvalid,
    output wire                       s_axi_wready,

    output wire [AXI_ID_WIDTH-1:0]    s_axi_bid,
    output wire [1:0]                 s_axi_bresp,
    output wire                       s_axi_bvalid,
    input  wire                       s_axi_bready,

    input  wire [AXI_ID_WIDTH-1:0]    s_axi_arid,
    input  wire [AXI_ADDR_WIDTH-1:0]  s_axi_araddr,
    input  wire [7:0]                 s_axi_arlen,
    input  wire [2:0]                 s_axi_arsize,
    input  wire [1:0]                 s_axi_arburst,
    input  wire                       s_axi_arvalid,
    output wire                       s_axi_arready,

    output wire [AXI_ID_WIDTH-1:0]    s_axi_rid,
    output wire [AXI_DATA_WIDTH-1:0]  s_axi_rdata,
    output wire [1:0]                 s_axi_rresp,
    output wire                       s_axi_rlast,
    output wire                       s_axi_rvalid,
    input  wire                       s_axi_rready,

    // =========================================================================
    // UART IO pads
    // =========================================================================
    output wire uart_tx,
    input  wire uart_rx,

    // =========================================================================
    // Interrupt → PLIC source [0]
    // =========================================================================
    output wire irq_out,
    output wire uart_active,

    // =========================================================================
    // DMA handshake — flow control signals for periph mode
    // =========================================================================
    output wire tx_dma_req,   // TX FIFO has space  → DMA can write (mode 10)
    output wire rx_dma_req,   // RX FIFO has data   → DMA can read  (mode 01)

    // =========================================================================
    // AON wake interface (clk_aon domain)
    // =========================================================================
    input  wire clk_aon,
    input  wire aon_rst_n,
    input  wire wake_ack,
    output wire uart_wake_req
);

    // =========================================================================
    // Internal wires
    // =========================================================================

    // Baud gen → TX, RX
    wire tick_tx, tick_rx16;

    // AXI slave → TX FIFO
    wire [7:0] reg_tx_data;
    wire       reg_tx_push;

    // AXI slave → RX FIFO (pop)
    wire       reg_rx_pop;

    // TX FIFO → TX shift
    wire [7:0] tx_fifo_dout;
    wire       tx_fifo_full, tx_fifo_empty;
    wire       tx_fifo_pop;   // từ uart_tx
    wire       tx_busy_w;

    // RX FIFO ← RX sampler
    wire [7:0] rx_fifo_din;
    wire       rx_fifo_push;
    wire       rx_fifo_full, rx_fifo_empty;

    // AXI slave → RX FIFO dout
    wire [7:0] rx_fifo_dout;

    // Status
    wire rx_overrun_w;

    // Config
    wire [15:0] reg_baud_div;
    wire        reg_rx_irq_en, reg_tx_irq_en;

    // IRQ
    wire tx_empty_irq_w, rx_valid_irq_w;

    // =========================================================================
    // uart_axi_slave
    // =========================================================================
    uart_axi_slave #(
        .ADDR_WIDTH (AXI_ADDR_WIDTH),
        .DATA_WIDTH (AXI_DATA_WIDTH),
        .ID_WIDTH   (AXI_ID_WIDTH)
    ) u_axi (
        .clk             (clk),
        .rst_n           (rst_n),
        .s_axi_awid      (s_axi_awid),
        .s_axi_awaddr    (s_axi_awaddr),
        .s_axi_awlen     (s_axi_awlen),
        .s_axi_awsize    (s_axi_awsize),
        .s_axi_awburst   (s_axi_awburst),
        .s_axi_awvalid   (s_axi_awvalid),
        .s_axi_awready   (s_axi_awready),
        .s_axi_wdata     (s_axi_wdata),
        .s_axi_wstrb     (s_axi_wstrb),
        .s_axi_wlast     (s_axi_wlast),
        .s_axi_wvalid    (s_axi_wvalid),
        .s_axi_wready    (s_axi_wready),
        .s_axi_bid       (s_axi_bid),
        .s_axi_bresp     (s_axi_bresp),
        .s_axi_bvalid    (s_axi_bvalid),
        .s_axi_bready    (s_axi_bready),
        .s_axi_arid      (s_axi_arid),
        .s_axi_araddr    (s_axi_araddr),
        .s_axi_arlen     (s_axi_arlen),
        .s_axi_arsize    (s_axi_arsize),
        .s_axi_arburst   (s_axi_arburst),
        .s_axi_arvalid   (s_axi_arvalid),
        .s_axi_arready   (s_axi_arready),
        .s_axi_rid       (s_axi_rid),
        .s_axi_rdata     (s_axi_rdata),
        .s_axi_rresp     (s_axi_rresp),
        .s_axi_rlast     (s_axi_rlast),
        .s_axi_rvalid    (s_axi_rvalid),
        .s_axi_rready    (s_axi_rready),
        .reg_tx_data     (reg_tx_data),
        .reg_tx_push     (reg_tx_push),
        .tx_fifo_full    (tx_fifo_full),
        .tx_fifo_empty   (tx_fifo_empty),
        .reg_rx_data     (rx_fifo_dout),
        .reg_rx_pop      (reg_rx_pop),
        .rx_fifo_full    (rx_fifo_full),
        .rx_fifo_empty   (rx_fifo_empty),
        .rx_overrun      (rx_overrun_w),
        .reg_baud_div    (reg_baud_div),
        .reg_rx_irq_en   (reg_rx_irq_en),
        .reg_tx_irq_en   (reg_tx_irq_en),
        .tx_empty_irq_in (tx_empty_irq_w),
        .rx_valid_irq_in (rx_valid_irq_w),
        .irq_out         (irq_out)
    );

    // =========================================================================
    // uart_baud_gen
    // =========================================================================
    uart_baud_gen u_baud (
        .clk      (clk),
        .rst_n    (rst_n),
        .divisor  (reg_baud_div),
        .tick_tx  (tick_tx),
        .tick_rx16(tick_rx16)
    );

    // =========================================================================
    // TX FIFO
    // =========================================================================
    uart_fifo #(.DEPTH(TX_FIFO_DEPTH)) u_tx_fifo (
        .clk        (clk),
        .rst_n      (rst_n),
        .din        (reg_tx_data),
        .push       (reg_tx_push),
        .full       (tx_fifo_full),
        .almost_full(),
        .dout       (tx_fifo_dout),
        .pop        (tx_fifo_pop),
        .empty      (tx_fifo_empty),
        .count      ()
    );

    // =========================================================================
    // uart_tx
    // =========================================================================
    uart_tx u_tx (
        .clk       (clk),
        .rst_n     (rst_n),
        .tick_tx   (tick_tx),
        .fifo_dout (tx_fifo_dout),
        .fifo_empty(tx_fifo_empty),
        .fifo_pop  (tx_fifo_pop),
        .tx_out    (uart_tx),
        .tx_busy   (tx_busy_w)
    );

    // =========================================================================
    // RX FIFO
    // =========================================================================
    uart_fifo #(.DEPTH(RX_FIFO_DEPTH)) u_rx_fifo (
        .clk        (clk),
        .rst_n      (rst_n),
        .din        (rx_fifo_din),
        .push       (rx_fifo_push),
        .full       (rx_fifo_full),
        .almost_full(),
        .dout       (rx_fifo_dout),
        .pop        (reg_rx_pop),
        .empty      (rx_fifo_empty),
        .count      ()
    );

    // =========================================================================
    // uart_rx
    // =========================================================================
    uart_rx u_rx (
        .clk       (clk),
        .rst_n     (rst_n),
        .tick_rx16 (tick_rx16),
        .rx_in     (uart_rx),
        .fifo_full (rx_fifo_full),
        .fifo_din  (rx_fifo_din),
        .fifo_push (rx_fifo_push),
        .rx_overrun(rx_overrun_w)
    );

    // =========================================================================
    // uart_irq_gen
    // =========================================================================
    uart_irq_gen u_irq (
        .clk          (clk),
        .rst_n        (rst_n),
        .tx_fifo_empty(tx_fifo_empty),
        .rx_fifo_empty(rx_fifo_empty),
        .tx_empty_irq (tx_empty_irq_w),
        .rx_valid_irq (rx_valid_irq_w)
    );

    assign uart_active = tx_busy_w | !tx_fifo_empty | !rx_fifo_empty;
    assign tx_dma_req  = !tx_fifo_full;
    assign rx_dma_req  = !rx_fifo_empty;

    // =========================================================================
    // AON start-bit detector (clk_aon domain — chạy kể cả khi clk_periph gate)
    // =========================================================================
    reg uart_rx_aon_d1;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n) uart_rx_aon_d1 <= 1'b1;
        else            uart_rx_aon_d1 <= uart_rx;
    end
    wire start_bit_det_w = uart_rx_aon_d1 & ~uart_rx;  // falling edge = start bit

    reg uart_wake_pend_r;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n)           uart_wake_pend_r <= 1'b0;
        else if (wake_ack)        uart_wake_pend_r <= 1'b0;
        else if (start_bit_det_w) uart_wake_pend_r <= 1'b1;
    end
    assign uart_wake_req = uart_wake_pend_r | start_bit_det_w;

endmodule

// ==============================================================================
// FILE: plic_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : plic_top
// Project : RISC-V SoC
//
// RISC-V Platform-Level Interrupt Controller (PLIC) v1.0
// 1 context (hart 0, M-mode). 32 sources (source 0 reserved).
// Address: S9 = 0x5004_0000, size 4KB (remapped layout — xem plic_regfile.v)
//
// Hierarchy:
//   plic_top
//   ├── plic_regfile          — AXI4-Full slave + register bank
//   ├── plic_gateway ×31      — per-source gateway (edge-latch + claim/complete)
//   └── plic_priority_encoder — tìm source ưu tiên cao nhất
//
// Source Assignment (từ SoC_Register_Map_Full.docx section 10):
//   Source 0  : reserved (always 0)
//   Source 1  : UART TX IRQ  (uart_top)
//   Source 2  : UART RX IRQ  (uart_top)
//   Source 3  : SPI IRQ      (spi_top)
//   Source 4  : GPIO IRQ     (gpio_top)
//   Source 5  : TIMER0 IRQ   (timer_wdt_top)
//   Source 6  : TIMER1 IRQ   (timer_wdt_top)
//   Source 7  : WDT WARN IRQ (timer_wdt_top)
//   Source 8  : ASCON IRQ    (ascon_ip_top / soc_ctrl_slave.irq_out)
//   Source 9..31: reserved (tie irq_src[9:31] = 0 in soc_top)
//
// Kết nối trong soc_top.v:
//   plic_top u_plic (
//       .clk        (clk),
//       .rst_n      (fabric_rst_n),
//       .s_axi_*    (s9_*),
//       .irq_src    ({23'd0, soc_ctrl_irq_out, wdt_irq, timer1_irq,
//                     timer0_irq, gpio_irq, spi_irq,
//                     uart_rx_irq, uart_tx_irq, 1'b0}),
//       .meip       (external_irq)   // → CPU
//   );
//
// Remapping 4KB:
//   priority[N]  : 0x000 + 4×N  (N=0..11 trong 4KB, đủ cho 12 sources)
//   pending[0]   : 0x080         (remapped từ spec 0x001000)
//   enable[0]    : 0x100         (remapped từ spec 0x002000)
//   threshold    : 0x200         (remapped từ spec 0x200000)
//   claim/complete: 0x204        (remapped từ spec 0x200004)
// ============================================================================


// ==============================================================================
// FILE: plic_regfile.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : plic_regfile  (FIXED)
// BUG FIXES: 1=claim_pulse double-driver  2=NUM_SRC truncation
//            3=rdata latch timing          4=priority decode overlap 0x080
// ============================================================================
// `timescale 1ns/1ps
module plic_regfile #(
    parameter NUM_SRC   = 32,
    parameter PRIO_W    = 3,
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire                   clk,
    input  wire                   rst_n,
    input  wire [ID_WIDTH-1:0]    s_axi_awid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_awaddr,
    input  wire [7:0]             s_axi_awlen,
    input  wire [2:0]             s_axi_awsize,
    input  wire [1:0]             s_axi_awburst,
    input  wire [2:0]             s_axi_awprot,
    input  wire                   s_axi_awvalid,
    output wire                   s_axi_awready,
    input  wire [DATA_WIDTH-1:0]  s_axi_wdata,
    input  wire [DATA_WIDTH/8-1:0]s_axi_wstrb,
    input  wire                   s_axi_wlast,
    input  wire                   s_axi_wvalid,
    output wire                   s_axi_wready,
    output wire [ID_WIDTH-1:0]    s_axi_bid,
    output wire [1:0]             s_axi_bresp,
    output wire                   s_axi_bvalid,
    input  wire                   s_axi_bready,
    input  wire [ID_WIDTH-1:0]    s_axi_arid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_araddr,
    input  wire [7:0]             s_axi_arlen,
    input  wire [2:0]             s_axi_arsize,
    input  wire [1:0]             s_axi_arburst,
    input  wire [2:0]             s_axi_arprot,
    input  wire                   s_axi_arvalid,
    output wire                   s_axi_arready,
    output wire [ID_WIDTH-1:0]    s_axi_rid,
    output wire [DATA_WIDTH-1:0]  s_axi_rdata,
    output wire [1:0]             s_axi_rresp,
    output wire                   s_axi_rlast,
    output wire                   s_axi_rvalid,
    input  wire                   s_axi_rready,
    output wire [PRIO_W*NUM_SRC-1:0] priority_flat,
    output wire [NUM_SRC-1:0]         enable,
    output wire [PRIO_W-1:0]          threshold,
    output wire                        claim_pulse,
    output wire                        complete_pulse,
    output wire [$clog2(NUM_SRC)-1:0]  complete_id,
    input  wire [$clog2(NUM_SRC)-1:0]  claim_id_in,
    input  wire [NUM_SRC-1:0]           pending_in
);
    localparam ID_W = $clog2(NUM_SRC);

    // --- Register storage ---
    reg [PRIO_W-1:0]  prio_r [0:NUM_SRC-1];
    reg [NUM_SRC-1:0] enable_r;
    reg [PRIO_W-1:0]  threshold_r;
    reg [ID_W-1:0]    complete_id_r;
    reg               complete_pulse_r;
    reg               claim_pulse_r;

    assign threshold      = threshold_r;
    assign enable         = enable_r;
    assign complete_id    = complete_id_r;
    assign complete_pulse = complete_pulse_r;
    assign claim_pulse    = claim_pulse_r;

    genvar gi;
    generate
        for (gi = 0; gi < NUM_SRC; gi = gi + 1) begin : pack_prio
            assign priority_flat[PRIO_W*gi +: PRIO_W] = prio_r[gi];
        end
    endgenerate

    // --- AXI Write FSM ---
    reg [ID_WIDTH-1:0]     aw_id_lat;
    reg [ADDR_WIDTH-1:0]   aw_addr_lat;
    reg                    aw_done, w_done, bvalid_r;
    reg [DATA_WIDTH-1:0]   w_data_lat;
    reg [DATA_WIDTH/8-1:0] w_strb_lat;
    reg [1:0]              bresp_r;

    wire [11:0] aw_off = aw_addr_lat[11:0];
    wire write_exec    = aw_done && w_done && !bvalid_r;

    integer k;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (k = 0; k < NUM_SRC; k = k + 1) prio_r[k] <= {PRIO_W{1'b0}};
            enable_r         <= {NUM_SRC{1'b0}};
            threshold_r      <= {PRIO_W{1'b0}};
            complete_id_r    <= {ID_W{1'b0}};
            complete_pulse_r <= 1'b0;
        end else begin
            complete_pulse_r <= 1'b0;
            if (write_exec) begin
                // FIX 4: aw_off[7]==0 guards priority range 0x000..0x07C
                // prevents overlap with 0x080 (pending RO) which has bit[7]=1
                if (aw_off[11:8]==4'h0 && aw_off[7]==1'b0 && aw_off[1:0]==2'b00) begin
                    if (aw_off[6:2] < NUM_SRC) begin  // FIX 2: full-width compare
                        if (w_strb_lat[0]) prio_r[aw_off[6:2]] <= w_data_lat[PRIO_W-1:0];
                    end
                end
                else if (aw_off == 12'h100) begin
                    if (w_strb_lat[0]) enable_r[7:0]   <= w_data_lat[7:0];
                    if (w_strb_lat[1]) enable_r[15:8]  <= w_data_lat[15:8];
                    if (w_strb_lat[2]) enable_r[23:16] <= w_data_lat[23:16];
                    if (w_strb_lat[3]) enable_r[31:24] <= w_data_lat[31:24];
                end
                else if (aw_off == 12'h200) begin
                    if (w_strb_lat[0]) threshold_r <= w_data_lat[PRIO_W-1:0];
                end
                else if (aw_off == 12'h204) begin
                    complete_id_r    <= w_data_lat[ID_W-1:0];
                    complete_pulse_r <= 1'b1;
                end
                // 0x080 = pending RO: write ignored
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin aw_done<=1'b0; aw_id_lat<=0; aw_addr_lat<=0;
        end else begin
            if (s_axi_awvalid && s_axi_awready) begin
                aw_id_lat<=s_axi_awid; aw_addr_lat<=s_axi_awaddr; aw_done<=1'b1;
            end
            if (bvalid_r && s_axi_bready) aw_done<=1'b0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin w_done<=1'b0; w_data_lat<=0; w_strb_lat<=0;
        end else begin
            if (s_axi_wvalid && s_axi_wready) begin
                w_data_lat<=s_axi_wdata; w_strb_lat<=s_axi_wstrb; w_done<=1'b1;
            end
            if (bvalid_r && s_axi_bready) w_done<=1'b0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin bvalid_r<=1'b0; bresp_r<=2'b00;
        end else begin
            if (write_exec) begin bvalid_r<=1'b1; bresp_r<=2'b00; end
            if (bvalid_r && s_axi_bready) bvalid_r<=1'b0;
        end
    end

    assign s_axi_awready = !aw_done;
    assign s_axi_wready  = !w_done;
    assign s_axi_bvalid  = bvalid_r;
    assign s_axi_bresp   = bresp_r;
    assign s_axi_bid     = aw_id_lat;

    // --- AXI Read Channel ---
    reg [ID_WIDTH-1:0]   ar_id_lat;
    reg [ADDR_WIDTH-1:0] ar_addr_lat;
    reg                  ar_done, ar_done_d1, rvalid_r;
    reg [DATA_WIDTH-1:0] rdata_r;
    wire [11:0] ar_off = ar_addr_lat[11:0];

    // FIX 4 read-side: ar_off[7]==0 prevents 0x080 being decoded as priority[32]
    reg [DATA_WIDTH-1:0] rdata_mux;
    wire [PRIO_W-1:0] prio_read_val = prio_r[ar_off[6:2]];
    always @(*) begin
        rdata_mux = 32'd0;
        if (ar_off[11:8]==4'h0 && ar_off[7]==1'b0 && ar_off[1:0]==2'b00)
            rdata_mux[PRIO_W-1:0] = prio_read_val;
        else if (ar_off == 12'h080)
            rdata_mux[NUM_SRC-1:0] = pending_in[NUM_SRC-1:0];
        else if (ar_off == 12'h100)
            rdata_mux[NUM_SRC-1:0] = enable_r;
        else if (ar_off == 12'h200)
            rdata_mux[PRIO_W-1:0] = threshold_r;
        else if (ar_off == 12'h204)
            rdata_mux[ID_W-1:0] = claim_id_in;
    end

    // AR latch — only manages AR state, does NOT drive claim_pulse_r
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin ar_done<=1'b0; ar_id_lat<=0; ar_addr_lat<=0;
        end else begin
            if (s_axi_arvalid && s_axi_arready) begin
                ar_id_lat<=s_axi_arid; ar_addr_lat<=s_axi_araddr; ar_done<=1'b1;
            end
            if (rvalid_r && s_axi_rready) ar_done<=1'b0;
        end
    end

    // FIX 3: ar_done_d1 pipeline — rdata_mux latched 1 cycle after ar_addr_lat stable
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin ar_done_d1<=1'b0; rvalid_r<=1'b0; rdata_r<=0;
        end else begin
            ar_done_d1 <= ar_done && !rvalid_r;
            if (ar_done_d1 && !rvalid_r) begin rvalid_r<=1'b1; rdata_r<=rdata_mux; end
            if (rvalid_r && s_axi_rready) rvalid_r<=1'b0;
        end
    end

    // =========================================================================
    // FIX 1 FINAL: claim_pulse_r — completely independent single-driver block
    //
    // Root cause of all previous attempts failing:
    //   Attempt A (original): 2 always blocks drive same reg → illegal
    //   Attempt B (ar_claim_pending flag): AR latch sets flag at posedge N;
    //     write-FSM reads flag at SAME posedge N but sees OLD value=0 due to
    //     Verilog non-blocking assignment semantics → claim_pulse_r stays 0
    //
    // CORRECT FIX: Detect AR handshake directly from INPUT WIRE signals.
    //   s_axi_arvalid  = input wire → value at posedge is CURRENT (no NBA delay)
    //   s_axi_arready  = !ar_done  = combinational wire → also CURRENT
    //   s_axi_araddr   = input wire → CURRENT
    //
    // This block has NO dependency on any reg in this module, so there is
    // no non-blocking assignment ordering issue whatsoever.
    //
    // Timing: claim_pulse_r=1 fires at posedge of AR handshake cycle.
    //   Same cycle: ar_done_d1=0 (ar_done just became 1 via NBA, not yet seen)
    //   Next cycle: ar_done_d1=1 → rvalid_r=1 (rdata available to CPU)
    //   Same cycle as rvalid: claim_pulse_r has already been 1 for 1 cycle,
    //     and is now 0 again.
    //   Gateway received claim_pulse one cycle before CPU reads data — fine,
    //   the pending clear happens before CPU even acknowledges the read.
    // =========================================================================
    // claim_pulse fires when rvalid is presented to CPU (ar_done_d1 cycle).
    // WHY: claim_id_in is still valid at this cycle (gateway hasn't cleared yet).
    //   Firing at AR handshake was too early: gateway cleared pending before
    //   rdata_mux was latched, so claim_id_in became 0 before CPU read it.
    // ar_done_d1=1 AND !rvalid_r means: rdata is being latched right now,
    //   AND the address was 0x204 (stored in ar_addr_lat).
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            claim_pulse_r <= 1'b0;
        end else begin
            claim_pulse_r <= ar_done_d1 && !rvalid_r &&
                             (ar_addr_lat[11:0] == 12'h204);
        end
    end

    assign s_axi_arready = !ar_done;
    assign s_axi_rvalid  = rvalid_r;
    assign s_axi_rdata   = rdata_r;
    assign s_axi_rresp   = 2'b00;
    assign s_axi_rlast   = 1'b1;
    assign s_axi_rid     = ar_id_lat;

endmodule
// ==============================================================================
// FILE: plic_gateway.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : plic_gateway
// Project : RISC-V SoC — PLIC
//
// Interrupt Gateway cho MỘT source. Theo RISC-V PLIC spec:
//   - Nhận tín hiệu interrupt từ peripheral (level hoặc edge)
//   - Latch thành PENDING bit (sticky until claim)
//   - Khi claim xảy ra: clear pending, cho phép nhận IRQ tiếp theo
//   - Khi complete xảy ra: re-enable gate để nhận IRQ mới từ peripheral
//
// Level-triggered: pending set khi interrupt HIGH, hold cho đến claim.
//
// Trong SoC này: tất cả ngoại vi đều có sticky IRQ_STATUS (lưu trạng thái ngắt).
// Do đó PLIC Gateway ĐƯỢC THIẾT KẾ DẠNG LEVEL-TRIGGERED để bắt đúng các ngắt
// nối tiếp nhau mà không bị rơi rớt trong lúc CPU đang in-service.
// ============================================================================

module plic_gateway (
    input  wire clk,
    input  wire rst_n,

    input  wire irq_in,      // interrupt từ peripheral
    input  wire claim,       // 1-cycle pulse: CPU đang claim source này
    input  wire complete,    // 1-cycle pulse: CPU complete xử lý

    output wire pending      // 1 = source này đang pending
);

    reg  pending_r;
    reg  in_service;   // 1 = đang được claim, chưa complete

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            pending_r  <= 1'b0;
            in_service <= 1'b0;
        end else begin
            if (claim) begin
                pending_r  <= 1'b0;  // clear pending khi CPU claim
                in_service <= 1'b1;  // mark in-service
            end

            if (complete) begin
                in_service <= 1'b0;  // CPU done, có thể nhận IRQ mới
            end

            // Level-triggered: Set pending khi irq_in=1 và đang không được xử lý
            if (irq_in && !in_service && !claim) begin
                pending_r <= 1'b1;
            end
        end
    end

    assign pending = pending_r;

endmodule
// ==============================================================================
// FILE: plic_priority_encoder.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// Module  : plic_priority_encoder
// Project : RISC-V SoC — PLIC
//
// Tìm source ID có priority cao nhất trong số các source pending & enabled.
// Output: ID của source thắng (0 = không có), priority của source đó.
//
// Algorithm: linear scan XUÔI từ source 1..NUM_SRC-1, giữ max priority.
// Ghi đè chỉ khi prio[i] STRICTLY cao hơn winner hiện tại.
// Tie-break: source ID nhỏ hơn thắng — vì loop xuôi, source ID nhỏ
// được ghi trước và không bị ghi đè khi priority bằng nhau.
//
// WHY combinational: PLIC spec yêu cầu claim/complete phải phản ánh
// trạng thái hiện tại ngay lập tức. Latency 1 cycle nếu dùng FF sẽ
// làm CPU đọc stale value ngay sau khi IRQ assert.
// ============================================================================

module plic_priority_encoder #(
    parameter NUM_SRC = 32,   // số nguồn IRQ (source 0 luôn reserved)
    parameter PRIO_W  = 3     // số bit priority (0..7)
)(
    input  wire [NUM_SRC-1:0]          pending,    // pending[i] = source i có IRQ
    input  wire [NUM_SRC-1:0]          enabled,    // enabled[i] = context 0 enable
    input  wire [PRIO_W-1:0]           threshold,  // priority threshold context 0
    input  wire [PRIO_W*NUM_SRC-1:0]   priority_flat, // priority[i] = [PRIO_W*i+:PRIO_W]

    output reg  [$clog2(NUM_SRC)-1:0]  claim_id,   // source ID thắng (0=none)
    output reg  [PRIO_W-1:0]           claim_prio, // priority của winner
    output wire                         irq_pending // =1 nếu có source vượt threshold
);

    localparam ID_W = $clog2(NUM_SRC);

    integer i;
    always @(*) begin
        claim_id   = {ID_W{1'b0}};
        claim_prio = {PRIO_W{1'b0}};

        // Source 0 always reserved — bắt đầu từ i=1
        //
        // BUG FIX: Loop gốc chạy NGƯỢC (NUM_SRC-1 → 1) với điều kiện:
        //   if (prio[i] > claim_prio || claim_id == 0)
        //
        // Lỗi: khi claim_id==0 (chưa có winner), điều kiện || luôn true
        // → mọi source hợp lệ đều ghi đè → source cuối cùng được xét
        // (source ID nhỏ nhất trong loop ngược) thắng.
        // Nhưng vì loop NGƯỢC, source cuối cùng được xét là source 1 (nhỏ nhất)...
        // ... trừ khi có source có priority bằng nhau ở bước giữa.
        //
        // Ví dụ: src2(prio=5), src3(prio=5), loop ngược:
        //   i=31..4: không có pending
        //   i=3: pending, prio=5>0 → ghi claim_id=3, claim_prio=5
        //   i=2: pending, prio=5 > claim_prio(5)? NO. claim_id==0? NO (=3).
        //        → không ghi đè → claim_id=3 THẮNG (sai! ID nhỏ phải thắng)
        //
        // FIX ĐÚNG: Loop XUÔI từ 1 → NUM_SRC-1
        //   Chỉ ghi đè khi prio[i] > claim_prio (strictly higher, không có ||).
        //   - Source đầu tiên hợp lệ (ID nhỏ nhất) ghi vào vì claim_prio=0
        //     và prio[i] > 0 (đã pass threshold check).
        //   - Source sau chỉ ghi đè khi priority CAO HƠN.
        //   - Tie-break: source ID nhỏ không bị ghi đè → thắng. ✓
        //
        // WHY "prio[i] > 0" luôn đúng ở bước đầu:
        //   Điều kiện eligible đã có "prio[i] > threshold".
        //   Nếu threshold=0 thì prio[i] >= 1 → prio[i] > claim_prio(0) ✓
        //   Nếu threshold>0 thì prio[i] > threshold > 0 ✓
        for (i = 1; i < NUM_SRC; i = i + 1) begin
            // Eligible: pending AND enabled AND priority > threshold
            if (pending[i] && enabled[i] && (priority_flat[PRIO_W*i +: PRIO_W] > threshold)) begin
                // Ghi đè chỉ khi STRICTLY higher priority
                // Tie → giữ nguyên claim_id (ID nhỏ hơn đã ghi trước thắng)
                if (priority_flat[PRIO_W*i +: PRIO_W] > claim_prio) begin
                    claim_id   = i[ID_W-1:0];
                    claim_prio = priority_flat[PRIO_W*i +: PRIO_W];
                end
            end
        end
    end

    assign irq_pending = (claim_id != {ID_W{1'b0}});

endmodule
module plic_top #(
    parameter NUM_SRC    = 32,
    parameter PRIO_W     = 3,
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire                   clk,
    input  wire                   rst_n,

    // =========================================================================
    // AXI4-Full Slave Interface (từ crossbar S9)
    // =========================================================================
    input  wire [ID_WIDTH-1:0]    s_axi_awid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_awaddr,
    input  wire [7:0]             s_axi_awlen,
    input  wire [2:0]             s_axi_awsize,
    input  wire [1:0]             s_axi_awburst,
    input  wire [2:0]             s_axi_awprot,
    input  wire                   s_axi_awvalid,
    output wire                   s_axi_awready,

    input  wire [DATA_WIDTH-1:0]  s_axi_wdata,
    input  wire [DATA_WIDTH/8-1:0]s_axi_wstrb,
    input  wire                   s_axi_wlast,
    input  wire                   s_axi_wvalid,
    output wire                   s_axi_wready,

    output wire [ID_WIDTH-1:0]    s_axi_bid,
    output wire [1:0]             s_axi_bresp,
    output wire                   s_axi_bvalid,
    input  wire                   s_axi_bready,

    input  wire [ID_WIDTH-1:0]    s_axi_arid,
    input  wire [ADDR_WIDTH-1:0]  s_axi_araddr,
    input  wire [7:0]             s_axi_arlen,
    input  wire [2:0]             s_axi_arsize,
    input  wire [1:0]             s_axi_arburst,
    input  wire [2:0]             s_axi_arprot,
    input  wire                   s_axi_arvalid,
    output wire                   s_axi_arready,

    output wire [ID_WIDTH-1:0]    s_axi_rid,
    output wire [DATA_WIDTH-1:0]  s_axi_rdata,
    output wire [1:0]             s_axi_rresp,
    output wire                   s_axi_rlast,
    output wire                   s_axi_rvalid,
    input  wire                   s_axi_rready,

    // =========================================================================
    // Interrupt Sources (NUM_SRC bits, source 0 = bit 0 always 0)
    // =========================================================================
    input  wire [NUM_SRC-1:0]     irq_src,   // irq_src[0] ignored (reserved)

    // =========================================================================
    // Output → CPU external interrupt
    // =========================================================================
    output wire                   meip       // Machine External Interrupt Pending
);

    localparam ID_W = $clog2(NUM_SRC);

    // =========================================================================
    // Internal wires
    // =========================================================================
    wire [PRIO_W*NUM_SRC-1:0] priority_flat;
    wire [NUM_SRC-1:0]         enable;
    wire [PRIO_W-1:0]          threshold;
    wire                       claim_pulse;
    wire                       complete_pulse;
    wire [ID_W-1:0]            complete_id;
    wire [ID_W-1:0]            claim_id;
    wire [PRIO_W-1:0]          claim_prio;
    wire [NUM_SRC-1:0]         pending;

    // =========================================================================
    // plic_regfile — AXI4-Full slave + config registers
    // =========================================================================
    plic_regfile #(
        .NUM_SRC    (NUM_SRC),
        .PRIO_W     (PRIO_W),
        .ADDR_WIDTH (ADDR_WIDTH),
        .DATA_WIDTH (DATA_WIDTH),
        .ID_WIDTH   (ID_WIDTH)
    ) u_regfile (
        .clk            (clk),
        .rst_n          (rst_n),
        .s_axi_awid     (s_axi_awid),    .s_axi_awaddr  (s_axi_awaddr),
        .s_axi_awlen    (s_axi_awlen),   .s_axi_awsize  (s_axi_awsize),
        .s_axi_awburst  (s_axi_awburst), .s_axi_awprot  (s_axi_awprot),
        .s_axi_awvalid  (s_axi_awvalid), .s_axi_awready (s_axi_awready),
        .s_axi_wdata    (s_axi_wdata),   .s_axi_wstrb   (s_axi_wstrb),
        .s_axi_wlast    (s_axi_wlast),   .s_axi_wvalid  (s_axi_wvalid),
        .s_axi_wready   (s_axi_wready),
        .s_axi_bid      (s_axi_bid),     .s_axi_bresp   (s_axi_bresp),
        .s_axi_bvalid   (s_axi_bvalid),  .s_axi_bready  (s_axi_bready),
        .s_axi_arid     (s_axi_arid),    .s_axi_araddr  (s_axi_araddr),
        .s_axi_arlen    (s_axi_arlen),   .s_axi_arsize  (s_axi_arsize),
        .s_axi_arburst  (s_axi_arburst), .s_axi_arprot  (s_axi_arprot),
        .s_axi_arvalid  (s_axi_arvalid), .s_axi_arready (s_axi_arready),
        .s_axi_rid      (s_axi_rid),     .s_axi_rdata   (s_axi_rdata),
        .s_axi_rresp    (s_axi_rresp),   .s_axi_rlast   (s_axi_rlast),
        .s_axi_rvalid   (s_axi_rvalid),  .s_axi_rready  (s_axi_rready),
        .priority_flat  (priority_flat),
        .enable         (enable),
        .threshold      (threshold),
        .claim_pulse    (claim_pulse),
        .complete_pulse (complete_pulse),
        .complete_id    (complete_id),
        .claim_id_in    (claim_id),
        .pending_in     (pending)
    );

    // =========================================================================
    // plic_gateway ×NUM_SRC — per-source gateway
    // Source 0: tie-off (reserved per PLIC spec)
    // =========================================================================
    assign pending[0] = 1'b0;

    genvar gi;
    generate
        for (gi = 1; gi < NUM_SRC; gi = gi + 1) begin : gen_gw
            plic_gateway u_gw (
                .clk      (clk),
                .rst_n    (rst_n),
                .irq_in   (irq_src[gi]),
                // claim pulse fires only for this source
                .claim    (claim_pulse    && (claim_id    == gi[ID_W-1:0])),
                .complete (complete_pulse && (complete_id == gi[ID_W-1:0])),
                .pending  (pending[gi])
            );
        end
    endgenerate

    // =========================================================================
    // plic_priority_encoder — find highest-priority pending+enabled source
    // =========================================================================
    plic_priority_encoder #(
        .NUM_SRC (NUM_SRC),
        .PRIO_W  (PRIO_W)
    ) u_enc (
        .pending        (pending),
        .enabled        (enable),
        .threshold      (threshold),
        .priority_flat  (priority_flat),
        .claim_id       (claim_id),
        .claim_prio     (claim_prio),
        .irq_pending    (meip)
    );

endmodule
// ==============================================================================
// FILE: jtag_debug_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// jtag_debug_top.v — JTAG Debug Top
//
// Kết nối:
//   jtag_tap     — TAP state machine (IEEE 1149.1)
//   jtag_dtm     — Debug Transport Module (RISC-V spec)
//   riscv_dm     — Debug Module + System Bus Access
//
// Interface với soc_top:
//   TCK/TMS/TDI/TDO → IO pads (4 dây)
//   M4 AXI4-Full master → Crossbar (System Bus Access)
//   ndmreset → clk_reset_ctrl (non-debug reset)
//   haltreq/resumereq/halted/running ↔ CPU debug port
//
// Lưu ý CDC:
//   TAP chạy ở tck domain (≤ 25 MHz).
//   jtag_dtm có 2-FF synchronizer tck→clk cho DMI request.
//   riscv_dm chạy hoàn toàn trong clk domain (100 MHz).
// ============================================================================


// ==============================================================================
// FILE: jtag_tap.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// jtag_tap.v — JTAG TAP Controller (IEEE 1149.1)
//
// 16-state TAP state machine theo chuẩn JTAG.
// Điều khiển bởi TMS. Dữ liệu vào/ra qua TDI/TDO.
//
// IR length = 5 bits (đủ encode 0x01=IDCODE, 0x10=DTMCS, 0x11=DMI, 0x1F=BYPASS)
// DR length phụ thuộc IR hiện tại: BYPASS=1, IDCODE=32, DTMCS=32, DMI=41
//
// Outputs:
//   capture_dr, shift_dr, update_dr  — kích hoạt DR operations
//   capture_ir, shift_ir, update_ir  — kích hoạt IR operations
//   tdo_en  — enable TDO output (chỉ HIGH khi Shift-DR hoặc Shift-IR)
// ============================================================================

module jtag_tap #(
    parameter IR_LEN    = 5,
    parameter IDCODE    = 32'hDEAD_BEEF   // thay bằng JEDEC ID thực
)(
    // ── JTAG pads ─────────────────────────────────────────────────────────
    input  wire tck,
    input  wire tms,
    input  wire tdi,
    output reg  tdo,
    output wire tdo_en,   // active-high: drive TDO pad

    // ── DR data interface (từ jtag_dtm) ───────────────────────────────────
    input  wire [40:0] dr_data_in,   // data nạp khi Capture-DR
    input  wire [5:0]  dr_len,       // số bit của DR hiện tại (1..41)
    output wire [40:0] dr_data_out,  // data sau Shift-DR (tại Update-DR)
    output wire        dr_update,    // pulse 1 cycle: Update-DR
    output wire        dr_capture,   // pulse 1 cycle: Capture-DR

    // ── IR output (để jtag_dtm biết register nào đang chọn) ───────────────
    output reg  [IR_LEN-1:0] ir_reg,     // IR sau Update-IR
    output wire              ir_update   // pulse 1 cycle: Update-IR
);

    // ── TAP state encoding ─────────────────────────────────────────────────
    localparam [3:0]
        TEST_LOGIC_RESET = 4'h0,
        RUN_TEST_IDLE    = 4'h1,
        SELECT_DR        = 4'h2,
        CAPTURE_DR       = 4'h3,
        SHIFT_DR         = 4'h4,
        EXIT1_DR         = 4'h5,
        PAUSE_DR         = 4'h6,
        EXIT2_DR         = 4'h7,
        UPDATE_DR        = 4'h8,
        SELECT_IR        = 4'h9,
        CAPTURE_IR       = 4'hA,
        SHIFT_IR         = 4'hB,
        EXIT1_IR         = 4'hC,
        PAUSE_IR         = 4'hD,
        EXIT2_IR         = 4'hE,
        UPDATE_IR        = 4'hF;

    reg [3:0] state;
    reg [3:0] next_state;

    // ── Next-state logic (combinational) ──────────────────────────────────
    always @(*) begin
        case (state)
            TEST_LOGIC_RESET: next_state = tms ? TEST_LOGIC_RESET : RUN_TEST_IDLE;
            RUN_TEST_IDLE:    next_state = tms ? SELECT_DR        : RUN_TEST_IDLE;
            SELECT_DR:        next_state = tms ? SELECT_IR        : CAPTURE_DR;
            CAPTURE_DR:       next_state = tms ? EXIT1_DR         : SHIFT_DR;
            SHIFT_DR:         next_state = tms ? EXIT1_DR         : SHIFT_DR;
            EXIT1_DR:         next_state = tms ? UPDATE_DR        : PAUSE_DR;
            PAUSE_DR:         next_state = tms ? EXIT2_DR         : PAUSE_DR;
            EXIT2_DR:         next_state = tms ? UPDATE_DR        : SHIFT_DR;
            UPDATE_DR:        next_state = tms ? SELECT_DR        : RUN_TEST_IDLE;
            SELECT_IR:        next_state = tms ? TEST_LOGIC_RESET : CAPTURE_IR;
            CAPTURE_IR:       next_state = tms ? EXIT1_IR         : SHIFT_IR;
            SHIFT_IR:         next_state = tms ? EXIT1_IR         : SHIFT_IR;
            EXIT1_IR:         next_state = tms ? UPDATE_IR        : PAUSE_IR;
            PAUSE_IR:         next_state = tms ? EXIT2_IR         : PAUSE_IR;
            EXIT2_IR:         next_state = tms ? UPDATE_IR        : SHIFT_IR;
            UPDATE_IR:        next_state = tms ? SELECT_DR        : RUN_TEST_IDLE;
            default:          next_state = TEST_LOGIC_RESET;
        endcase
    end

    // ── State register (clocked on rising TCK) ────────────────────────────
    always @(posedge tck)
        state <= next_state;

    // ── IR shift register ──────────────────────────────────────────────────
    reg [IR_LEN-1:0] ir_shift;

    always @(posedge tck) begin
        case (state)
            CAPTURE_IR: ir_shift <= {{(IR_LEN-2){1'b0}}, 2'b01};  // capture pattern
            SHIFT_IR:   ir_shift <= {tdi, ir_shift[IR_LEN-1:1]};  // shift LSB first
            UPDATE_IR:  ir_reg   <= ir_shift;
            default: ;
        endcase
    end

    // ── DR shift register (max 41 bits for DMI) ────────────────────────────
    reg [40:0] dr_shift;
    reg [40:0] dr_update_reg;

    always @(posedge tck) begin
        case (state)
            CAPTURE_DR: dr_shift <= dr_data_in;
            SHIFT_DR:   dr_shift <= {tdi, dr_shift[40:1]};  // shift LSB first
            UPDATE_DR:  dr_update_reg <= dr_shift;
            default: ;
        endcase
    end

    assign dr_data_out = dr_update_reg;
    assign dr_update   = (state == UPDATE_DR);
    assign dr_capture  = (state == CAPTURE_DR);
    assign ir_update   = (state == UPDATE_IR);

    // ── TDO (clocked on falling TCK per JTAG spec) ────────────────────────
    always @(negedge tck) begin
        if (state == SHIFT_DR)
            tdo <= dr_shift[0];
        else if (state == SHIFT_IR)
            tdo <= ir_shift[0];
        else
            tdo <= 1'b0;
    end

    assign tdo_en = (state == SHIFT_DR) || (state == SHIFT_IR);

endmodule
// ==============================================================================
// FILE: jtag_dtm.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// jtag_dtm.v — JTAG Debug Transport Module
//
// Kết nối jtag_tap (JTAG side) với DMI bus (riscv_dm side).
// Chuẩn: RISC-V External Debug Support v0.13.2
//
// IR registers:
//   0x01 = IDCODE   (32-bit): chip identification
//   0x10 = DTMCS    (32-bit): DTM control/status
//   0x11 = DMI      (41-bit): [40:34]=addr, [33:2]=data, [1:0]=op
//   0x1F = BYPASS   (1-bit):  JTAG bypass
//   other: BYPASS
//
// DMI op encoding:
//   2'b00 = NOP
//   2'b01 = READ   (addr → data return)
//   2'b10 = WRITE  (addr ← data)
//   2'b11 = reserved
//
// DTMCS bits:
//   [3:0]  = version (= 0x1 cho spec v0.13)
//   [9:4]  = abits   (= 7: địa chỉ DMI 7 bit)
//   [11:10]= dmistat (0=OK, 1=reserved, 2=fail, 3=busy)
//   [16]   = dmireset (write 1 to clear sticky error)
// ============================================================================

module jtag_dtm #(
    parameter IDCODE_VAL = 32'hDEAD_0001,  // Thay bằng JEDEC ID thực tế
    parameter ABITS      = 7               // DMI address bits
)(
    // ── JTAG interface (từ/tới pad) ───────────────────────────────────────
    input  wire tck,
    input  wire tms,
    input  wire tdi,
    output wire tdo,
    output wire tdo_en,

    // ── System clock domain ────────────────────────────────────────────────
    // DMI bus: jtag_dtm → riscv_dm
    // (async FIFO / 2FF sync không viết ở đây để giữ module đơn giản;
    //  trong SoC thực tế cần CDC nếu tck và clk khác miền)
    input  wire        clk,
    input  wire        rst_n,

    output reg  [ABITS-1:0]  dmi_addr,
    output reg  [31:0]       dmi_data_wr,
    output reg  [1:0]        dmi_op,
    output reg               dmi_req_valid,
    input  wire              dmi_req_ready,

    input  wire [31:0]       dmi_data_rd,
    input  wire [1:0]        dmi_rsp_op,    // 0=OK, 2=fail, 3=busy
    input  wire              dmi_rsp_valid,
    output wire              dmi_rsp_ready
);

    localparam IR_IDCODE = 5'h01;
    localparam IR_DTMCS  = 5'h10;
    localparam IR_DMI    = 5'h11;
    localparam IR_BYPASS = 5'h1F;

    // ── IR và DR length decoder ────────────────────────────────────────────
    wire [4:0] ir_reg;
    reg  [5:0] dr_len;
    reg  [40:0] dr_cap;  // data nạp vào DR khi Capture-DR

    always @(*) begin
        case (ir_reg)
            IR_BYPASS: begin dr_len = 6'd1;  dr_cap = 41'b0; end
            IR_IDCODE: begin dr_len = 6'd32; dr_cap = {9'b0, IDCODE_VAL}; end
            IR_DTMCS:  begin
                dr_len = 6'd32;
                // version=1, abits=7, dmistat=OK
                dr_cap = {9'b0, 16'b0, 1'b0, 1'b0, 2'b00,
                          ABITS[5:0], 4'h1};
            end
            IR_DMI:    begin dr_len = 6'd41; dr_cap = 41'b0; end
            default:   begin dr_len = 6'd1;  dr_cap = 41'b0; end
        endcase
    end

    // ── Instantiate TAP ────────────────────────────────────────────────────
    wire [40:0] dr_data_out;
    wire        dr_update_pulse;
    wire        dr_capture_pulse;
    wire        ir_update_pulse;

    jtag_tap #(
        .IR_LEN (5),
        .IDCODE (IDCODE_VAL)
    ) u_tap (
        .tck       (tck),
        .tms       (tms),
        .tdi       (tdi),
        .tdo       (tdo),
        .tdo_en    (tdo_en),

        .dr_data_in (dr_cap),
        .dr_len     (dr_len),
        .dr_data_out(dr_data_out),
        .dr_update  (dr_update_pulse),
        .dr_capture (dr_capture_pulse),

        .ir_reg     (ir_reg),
        .ir_update  (ir_update_pulse)
    );

    // ── DMI request: translate Update-DR (DMI) → DMI bus ──────────────────
    // Clock domain crossing: tck → clk
    // Simple approach: pulse stretcher (safe khi tck << clk, là trường hợp
    // thông thường: tck ≤ 25 MHz, clk = 100 MHz)
    reg dmi_update_tck;   // in tck domain
    reg [1:0] dmi_update_sync;  // sync FFs in clk domain

    always @(posedge tck)
        dmi_update_tck <= dr_update_pulse && (ir_reg == IR_DMI);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            dmi_update_sync <= 2'b00;
        else
            dmi_update_sync <= {dmi_update_sync[0], dmi_update_tck};
    end

    wire dmi_update_clk = dmi_update_sync[1];  // synchronized to clk

    // Latch DMI fields (in tck domain at Update-DR)
    reg [ABITS-1:0] dmi_addr_lat;
    reg [31:0]      dmi_data_lat;
    reg [1:0]       dmi_op_lat;

    always @(posedge tck) begin
        if (dr_update_pulse && ir_reg == IR_DMI) begin
            dmi_addr_lat <= dr_data_out[40:40-ABITS+1];
            dmi_data_lat <= dr_data_out[33:2];
            dmi_op_lat   <= dr_data_out[1:0];
        end
    end

    // Drive DMI bus in clk domain
    reg dmi_pending;
    assign dmi_rsp_ready = 1'b1;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dmi_req_valid <= 1'b0;
            dmi_pending   <= 1'b0;
        end else begin
            if (dmi_update_clk && !dmi_pending && dmi_op_lat != 2'b00) begin
                dmi_addr     <= dmi_addr_lat;
                dmi_data_wr  <= dmi_data_lat;
                dmi_op       <= dmi_op_lat;
                dmi_req_valid <= 1'b1;
                dmi_pending   <= 1'b1;
            end else if (dmi_req_valid && dmi_req_ready) begin
                dmi_req_valid <= 1'b0;
            end

            if (dmi_rsp_valid && dmi_pending) begin
                dmi_pending <= 1'b0;
            end
        end
    end

endmodule
// ==============================================================================
// FILE: riscv_dm.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// riscv_dm.v — RISC-V Debug Module
//
// Chuẩn: RISC-V External Debug Support v0.13.2
// Nhận DMI bus từ jtag_dtm, thực hiện debug operations.
// System Bus Access (SBA): AXI4-Full master → Crossbar M4 (đọc/ghi memory
// trực tiếp khi CPU đang halted, không cần CPU làm trung gian).
//
// DMI Address Map (7-bit addr):
//   0x04 = data0     RW  32-bit data buffer (argument/result)
//   0x10 = dmcontrol RW  [0]=dmactive, [1]=ndmreset, [16]=haltreq, [17]=resumereq
//   0x11 = dmstatus  RO  [8]=anyhalted, [9]=allhalted, [10]=anyrunning, [11]=allrunning
//   0x12 = hartinfo  RO  [23:20]=nscratch=1, [16:12]=dataaddr
//   0x16 = abstractcs RW [28:24]=cmderr, [3:0]=datacount=1
//   0x17 = command   WO  [31:24]=cmdtype, [23:0]=control
//   0x38 = sbcs      RW  System Bus Access Control/Status
//   0x39 = sbaddress0 RW  SBA address [31:0]
//   0x3C = sbdata0   RW  SBA data [31:0]
//
// Sub-modules:
//   (không có sub-module thêm — DM đủ nhỏ để viết trong 1 module)
// ============================================================================

module riscv_dm #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter ABITS      = 7
)(
    input  wire clk,
    input  wire rst_n,

    // ── DMI bus (từ jtag_dtm) ─────────────────────────────────────────────
    input  wire [ABITS-1:0] dmi_addr,
    input  wire [31:0]      dmi_data_wr,
    input  wire [1:0]       dmi_op,      // 01=read, 10=write
    input  wire             dmi_req_valid,
    output reg              dmi_req_ready,

    output reg  [31:0]      dmi_data_rd,
    output reg  [1:0]       dmi_rsp_op,  // 00=OK, 10=fail, 11=busy
    output reg              dmi_rsp_valid,
    input  wire             dmi_rsp_ready,

    // ── CPU debug interface ────────────────────────────────────────────────
    output wire             ndmreset,     // non-debug reset → soc_top
    output wire             haltreq,      // halt request → CPU
    output wire             resumereq,    // resume request → CPU
    input  wire             halted,       // CPU halted status
    input  wire             running,      // CPU running status

    // ── AXI4-Full Master (M4 → Crossbar: System Bus Access) ───────────────
    output reg  [ID_WIDTH-1:0]   m_axi_arid,
    output reg  [ADDR_WIDTH-1:0] m_axi_araddr,
    output wire [7:0]            m_axi_arlen,
    output wire [2:0]            m_axi_arsize,
    output wire [1:0]            m_axi_arburst,
    output wire [2:0]            m_axi_arprot,
    output reg                   m_axi_arvalid,
    input  wire                  m_axi_arready,

    input  wire [ID_WIDTH-1:0]   m_axi_rid,
    input  wire [DATA_WIDTH-1:0] m_axi_rdata,
    input  wire [1:0]            m_axi_rresp,
    input  wire                  m_axi_rlast,
    input  wire                  m_axi_rvalid,
    output wire                  m_axi_rready,

    output reg  [ID_WIDTH-1:0]   m_axi_awid,
    output reg  [ADDR_WIDTH-1:0] m_axi_awaddr,
    output wire [7:0]            m_axi_awlen,
    output wire [2:0]            m_axi_awsize,
    output wire [1:0]            m_axi_awburst,
    output wire [2:0]            m_axi_awprot,
    output reg                   m_axi_awvalid,
    input  wire                  m_axi_awready,

    output reg  [DATA_WIDTH-1:0] m_axi_wdata,
    output wire [3:0]            m_axi_wstrb,
    output wire                  m_axi_wlast,
    output reg                   m_axi_wvalid,
    input  wire                  m_axi_wready,

    input  wire [ID_WIDTH-1:0]   m_axi_bid,
    input  wire [1:0]            m_axi_bresp,
    input  wire                  m_axi_bvalid,
    output wire                  m_axi_bready
);

    // Fixed AXI attributes for SBA (single-word transfers only)
    assign m_axi_arlen   = 8'd0;    // 1 beat
    assign m_axi_arsize  = 3'd2;    // 4 bytes
    assign m_axi_arburst = 2'b01;   // INCR
    assign m_axi_arprot  = 3'b000;
    assign m_axi_awlen   = 8'd0;
    assign m_axi_awsize  = 3'd2;
    assign m_axi_awburst = 2'b01;
    assign m_axi_awprot  = 3'b000;
    assign m_axi_wstrb   = 4'hF;
    assign m_axi_wlast   = 1'b1;
    assign m_axi_rready  = 1'b1;
    assign m_axi_bready  = 1'b1;

    // ── Debug Module Registers ────────────────────────────────────────────
    reg         dm_active;
    reg         ndmreset_r;
    reg         haltreq_r;
    reg         resumereq_r;
    reg [31:0]  data0;           // abstract argument/result
    reg [2:0]   cmderr;          // abstract command error
    reg         abstract_busy;

    // System Bus Access registers
    reg [31:0]  sbaddress0;
    reg [31:0]  sbdata0;
    reg         sb_readonaddr;   // auto-read on sbaddress write
    reg         sb_busy;
    reg [2:0]   sberror;

    assign ndmreset  = ndmreset_r;
    assign haltreq   = haltreq_r && dm_active;
    assign resumereq = resumereq_r && dm_active;

    // ── DMI transaction handler ────────────────────────────────────────────
    // Simple single-cycle response for register reads/writes
    // SBA transactions take multiple cycles (AXI)

    localparam DMI_OP_NOP   = 2'b00;
    localparam DMI_OP_READ  = 2'b01;
    localparam DMI_OP_WRITE = 2'b10;

    // DMI register addresses
    localparam [6:0]
        ADDR_DATA0      = 7'h04,
        ADDR_DMCONTROL  = 7'h10,
        ADDR_DMSTATUS   = 7'h11,
        ADDR_HARTINFO   = 7'h12,
        ADDR_ABSTRACTCS = 7'h16,
        ADDR_COMMAND    = 7'h17,
        ADDR_SBCS       = 7'h38,
        ADDR_SBADDRESS0 = 7'h39,
        ADDR_SBDATA0    = 7'h3C;

    // Abstract command FSM
    localparam [1:0] ABS_IDLE = 2'd0, ABS_EXEC = 2'd1, ABS_DONE = 2'd2;
    reg [1:0] abs_state;
    reg [31:0] abs_cmd_r;

    // SBA FSM
    localparam [2:0] SBA_IDLE = 3'd0, SBA_AR = 3'd1, SBA_RD = 3'd2,
                     SBA_AW   = 3'd3, SBA_WD = 3'd4, SBA_WR = 3'd5;
    reg [2:0] sba_state;
    reg       sba_is_write;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dm_active    <= 1'b0;
            ndmreset_r   <= 1'b0;
            haltreq_r    <= 1'b0;
            resumereq_r  <= 1'b0;
            data0        <= 32'h0;
            cmderr       <= 3'h0;
            abstract_busy <= 1'b0;
            sbaddress0   <= 32'h0;
            sbdata0      <= 32'h0;
            sb_readonaddr <= 1'b0;
            sb_busy      <= 1'b0;
            sberror      <= 3'h0;
            abs_state    <= ABS_IDLE;
            sba_state    <= SBA_IDLE;

            dmi_req_ready <= 1'b1;
            dmi_rsp_valid <= 1'b0;
            dmi_rsp_op    <= 2'b00;
            dmi_data_rd   <= 32'h0;

            m_axi_arvalid <= 1'b0;
            m_axi_awvalid <= 1'b0;
            m_axi_wvalid  <= 1'b0;
        end else begin

            // ── Default: de-assert pulses ───────────────────────────────────
            resumereq_r  <= 1'b0;

            // ── SBA state machine ───────────────────────────────────────────
            case (sba_state)
                SBA_IDLE: begin
                    sb_busy <= 1'b0;
                end
                SBA_AR: begin
                    m_axi_arvalid <= 1'b1;
                    m_axi_arid    <= 4'd3;   // JTAG DM master ID
                    m_axi_araddr  <= sbaddress0;
                    if (m_axi_arready) begin
                        m_axi_arvalid <= 1'b0;
                        sba_state     <= SBA_RD;
                    end
                end
                SBA_RD: begin
                    if (m_axi_rvalid) begin
                        sbdata0   <= m_axi_rdata;
                        sberror   <= (m_axi_rresp != 2'b00) ? 3'd4 : 3'd0;
                        sba_state <= SBA_IDLE;
                        sb_busy   <= 1'b0;
                    end
                end
                SBA_AW: begin
                    m_axi_awvalid <= 1'b1;
                    m_axi_awid    <= 4'd3;
                    m_axi_awaddr  <= sbaddress0;
                    if (m_axi_awready) begin
                        m_axi_awvalid <= 1'b0;
                        sba_state     <= SBA_WD;
                    end
                end
                SBA_WD: begin
                    m_axi_wvalid <= 1'b1;
                    m_axi_wdata  <= sbdata0;
                    if (m_axi_wready) begin
                        m_axi_wvalid <= 1'b0;
                        sba_state    <= SBA_WR;
                    end
                end
                SBA_WR: begin
                    if (m_axi_bvalid) begin
                        sberror   <= (m_axi_bresp != 2'b00) ? 3'd4 : 3'd0;
                        sba_state <= SBA_IDLE;
                        sb_busy   <= 1'b0;
                    end
                end
                default: sba_state <= SBA_IDLE;
            endcase

            // ── DMI request handler ─────────────────────────────────────────
            dmi_rsp_valid <= 1'b0;

            if (dmi_req_valid && dmi_req_ready) begin
                dmi_req_ready <= 1'b0;  // busy processing

                if (dmi_op == DMI_OP_READ) begin
                    dmi_rsp_op <= 2'b00;  // OK
                    case (dmi_addr)
                        ADDR_DATA0: dmi_data_rd <= data0;

                        ADDR_DMCONTROL: dmi_data_rd <= {
                            14'b0, resumereq_r, haltreq_r,
                            6'b0, 1'b0, 1'b0,  // hartsello, hartselhi
                            4'b0, ndmreset_r, dm_active
                        };

                        ADDR_DMSTATUS: dmi_data_rd <= {
                            14'b0,
                            ~halted, ~halted,   // anyrunning, allrunning
                            halted,  halted,    // anyhalted, allhalted
                            1'b1,    1'b1,      // authenticated, authbusy=0
                            1'b0,    1'b0,      // anyunavail, allunavail
                            1'b0,    1'b0,      // anynonexistent
                            4'h2                // version = 0.13
                        };

                        ADDR_HARTINFO: dmi_data_rd <= {
                            8'b0, 4'd1,   // nscratch=1
                            3'b0, 1'b0,   // accessreg for data
                            12'h400       // dataaddr (relative)
                        };

                        ADDR_ABSTRACTCS: dmi_data_rd <= {
                            3'b0, cmderr,
                            11'b0, abstract_busy,
                            12'b0, 4'd1   // datacount=1
                        };

                        ADDR_SBCS: dmi_data_rd <= {
                            3'h1,       // sbversion=1
                            6'b0,       // reserved
                            3'b0,       // sbbusyerror, sbbusy, sbreadonaddr
                            2'b01,      // sbaccess=01 (32-bit)
                            1'b0,       // sbautoincrement
                            sb_readonaddr,
                            sberror,
                            1'b0,       // sbreadondata
                            sb_busy,
                            7'd32       // sbasize=32
                        };

                        ADDR_SBADDRESS0: dmi_data_rd <= sbaddress0;
                        ADDR_SBDATA0:    dmi_data_rd <= sbdata0;
                        default:         dmi_data_rd <= 32'h0;
                    endcase

                end else if (dmi_op == DMI_OP_WRITE) begin
                    dmi_data_rd <= 32'h0;
                    dmi_rsp_op  <= 2'b00;
                    case (dmi_addr)
                        ADDR_DATA0:    data0 <= dmi_data_wr;

                        ADDR_DMCONTROL: begin
                            dm_active   <= dmi_data_wr[0];
                            ndmreset_r  <= dmi_data_wr[1];
                            haltreq_r   <= dmi_data_wr[31];
                            if (dmi_data_wr[30]) resumereq_r <= 1'b1;
                        end

                        ADDR_ABSTRACTCS: begin
                            // Write 1 to cmderr bits [10:8] to clear
                            if (dmi_data_wr[10:8] == cmderr)
                                cmderr <= 3'h0;
                        end

                        ADDR_COMMAND: begin
                            // cmdtype=0 (access register)
                            // aarsize=2 (32-bit), transfer=1, postexec=0
                            // regno = dmi_data_wr[15:0]
                            // Simplified: just store, firmware handles
                            abs_cmd_r     <= dmi_data_wr;
                            abstract_busy <= 1'b1;
                            // data0 ← GPR[regno] (hooked via CPU debug port)
                            // For tape-out: connect to CPU halt/resume/regread port
                            cmderr        <= 3'h0;
                            abstract_busy <= 1'b0;
                        end

                        ADDR_SBCS: begin
                            sb_readonaddr <= dmi_data_wr[20];
                            // Clear sberror by writing 1
                            if (dmi_data_wr[14:12] != 3'h0) sberror <= 3'h0;
                        end

                        ADDR_SBADDRESS0: begin
                            sbaddress0 <= dmi_data_wr;
                            // Auto-read if sbreadonaddr=1
                            if (sb_readonaddr && !sb_busy && sberror == 3'h0) begin
                                sb_busy   <= 1'b1;
                                sba_state <= SBA_AR;
                            end
                        end

                        ADDR_SBDATA0: begin
                            sbdata0   <= dmi_data_wr;
                            // Trigger write
                            if (!sb_busy && sberror == 3'h0) begin
                                sb_busy   <= 1'b1;
                                sba_state <= SBA_AW;
                            end
                        end

                        default: ;
                    endcase
                end

                dmi_rsp_valid <= 1'b1;
                dmi_req_ready <= 1'b1;
            end
        end
    end

endmodule
module jtag_debug_top #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter ABITS      = 7,
    parameter IDCODE_VAL = 32'hDEAD_0001   // thay bằng JEDEC ID chip thực
)(
    // ── Clock & Reset ─────────────────────────────────────────────────────
    input  wire clk,
    input  wire rst_n,

    // ── JTAG IO pads ──────────────────────────────────────────────────────
    input  wire tck,
    input  wire tms,
    input  wire tdi,
    output wire tdo,          // tri-state controlled bởi tdo_en
    output wire tdo_en,       // HIGH khi Shift-DR/Shift-IR

    // ── CPU Debug Interface ────────────────────────────────────────────────
    output wire ndmreset,     // → clk_reset_ctrl: reset CPU+peripheral, không reset DM
    output wire haltreq,      // → CPU: yêu cầu dừng
    output wire resumereq,    // → CPU: yêu cầu tiếp tục
    input  wire halted,       // ← CPU: đang dừng
    input  wire running,      // ← CPU: đang chạy

    // ── AXI4-Full Master (M4 → Crossbar: System Bus Access) ───────────────
    output wire [ID_WIDTH-1:0]   M_AXI_ARID,
    output wire [ADDR_WIDTH-1:0] M_AXI_ARADDR,
    output wire [7:0]            M_AXI_ARLEN,
    output wire [2:0]            M_AXI_ARSIZE,
    output wire [1:0]            M_AXI_ARBURST,
    output wire [2:0]            M_AXI_ARPROT,
    output wire                  M_AXI_ARVALID,
    input  wire                  M_AXI_ARREADY,

    input  wire [ID_WIDTH-1:0]   M_AXI_RID,
    input  wire [DATA_WIDTH-1:0] M_AXI_RDATA,
    input  wire [1:0]            M_AXI_RRESP,
    input  wire                  M_AXI_RLAST,
    input  wire                  M_AXI_RVALID,
    output wire                  M_AXI_RREADY,

    output wire [ID_WIDTH-1:0]   M_AXI_AWID,
    output wire [ADDR_WIDTH-1:0] M_AXI_AWADDR,
    output wire [7:0]            M_AXI_AWLEN,
    output wire [2:0]            M_AXI_AWSIZE,
    output wire [1:0]            M_AXI_AWBURST,
    output wire [2:0]            M_AXI_AWPROT,
    output wire                  M_AXI_AWVALID,
    input  wire                  M_AXI_AWREADY,

    output wire [DATA_WIDTH-1:0] M_AXI_WDATA,
    output wire [3:0]            M_AXI_WSTRB,
    output wire                  M_AXI_WLAST,
    output wire                  M_AXI_WVALID,
    input  wire                  M_AXI_WREADY,

    input  wire [ID_WIDTH-1:0]   M_AXI_BID,
    input  wire [1:0]            M_AXI_BRESP,
    input  wire                  M_AXI_BVALID,
    output wire                  M_AXI_BREADY
);

    // ── DMI bus wires ──────────────────────────────────────────────────────
    wire [ABITS-1:0] dmi_addr;
    wire [31:0]      dmi_data_wr;
    wire [1:0]       dmi_op;
    wire             dmi_req_valid;
    wire             dmi_req_ready;

    wire [31:0]      dmi_data_rd;
    wire [1:0]       dmi_rsp_op;
    wire             dmi_rsp_valid;
    wire             dmi_rsp_ready;

    // ── u_dtm: Debug Transport Module ─────────────────────────────────────
    jtag_dtm #(
        .IDCODE_VAL(IDCODE_VAL),
        .ABITS     (ABITS)
    ) u_dtm (
        .tck(tck), .tms(tms), .tdi(tdi),
        .tdo(tdo), .tdo_en(tdo_en),

        .clk(clk), .rst_n(rst_n),

        .dmi_addr      (dmi_addr),
        .dmi_data_wr   (dmi_data_wr),
        .dmi_op        (dmi_op),
        .dmi_req_valid (dmi_req_valid),
        .dmi_req_ready (dmi_req_ready),

        .dmi_data_rd   (dmi_data_rd),
        .dmi_rsp_op    (dmi_rsp_op),
        .dmi_rsp_valid (dmi_rsp_valid),
        .dmi_rsp_ready (dmi_rsp_ready)
    );

    // ── u_dm: Debug Module ─────────────────────────────────────────────────
    riscv_dm #(
        .ADDR_WIDTH(ADDR_WIDTH),
        .DATA_WIDTH(DATA_WIDTH),
        .ID_WIDTH  (ID_WIDTH),
        .ABITS     (ABITS)
    ) u_dm (
        .clk(clk), .rst_n(rst_n),

        .dmi_addr      (dmi_addr),
        .dmi_data_wr   (dmi_data_wr),
        .dmi_op        (dmi_op),
        .dmi_req_valid (dmi_req_valid),
        .dmi_req_ready (dmi_req_ready),

        .dmi_data_rd   (dmi_data_rd),
        .dmi_rsp_op    (dmi_rsp_op),
        .dmi_rsp_valid (dmi_rsp_valid),
        .dmi_rsp_ready (dmi_rsp_ready),

        .ndmreset  (ndmreset),
        .haltreq   (haltreq),
        .resumereq (resumereq),
        .halted    (halted),
        .running   (running),

        .m_axi_arid   (M_AXI_ARID),    .m_axi_araddr  (M_AXI_ARADDR),
        .m_axi_arlen  (M_AXI_ARLEN),   .m_axi_arsize  (M_AXI_ARSIZE),
        .m_axi_arburst(M_AXI_ARBURST), .m_axi_arprot  (M_AXI_ARPROT),
        .m_axi_arvalid(M_AXI_ARVALID), .m_axi_arready (M_AXI_ARREADY),
        .m_axi_rid    (M_AXI_RID),     .m_axi_rdata   (M_AXI_RDATA),
        .m_axi_rresp  (M_AXI_RRESP),   .m_axi_rlast   (M_AXI_RLAST),
        .m_axi_rvalid (M_AXI_RVALID),  .m_axi_rready  (M_AXI_RREADY),
        .m_axi_awid   (M_AXI_AWID),    .m_axi_awaddr  (M_AXI_AWADDR),
        .m_axi_awlen  (M_AXI_AWLEN),   .m_axi_awsize  (M_AXI_AWSIZE),
        .m_axi_awburst(M_AXI_AWBURST), .m_axi_awprot  (M_AXI_AWPROT),
        .m_axi_awvalid(M_AXI_AWVALID), .m_axi_awready (M_AXI_AWREADY),
        .m_axi_wdata  (M_AXI_WDATA),   .m_axi_wstrb   (M_AXI_WSTRB),
        .m_axi_wlast  (M_AXI_WLAST),   .m_axi_wvalid  (M_AXI_WVALID),
        .m_axi_wready (M_AXI_WREADY),
        .m_axi_bid    (M_AXI_BID),     .m_axi_bresp   (M_AXI_BRESP),
        .m_axi_bvalid (M_AXI_BVALID),  .m_axi_bready  (M_AXI_BREADY)
    );

endmodule
// ==============================================================================
// FILE: dma_ctrl.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// dma_ctrl.v — DMA Controller Top (M3 + S11)
//
// Kết nối trong SoC:
//   S11 slave (base 0x6001_0000): CPU config DMA qua AXI4-Full
//   M3  master: DMA thực hiện burst mem-to-mem qua AXI4 crossbar
//   irq_out → PLIC[7]: done/error của bất kỳ channel nào
//
// Sub-modules:
//   dma_reg_slave  — AXI4 slave, register file config
//   dma_channel×4  — 4 kênh DMA độc lập, mỗi kênh có line buffer riêng
//   dma_arbiter    — round-robin cho read bus và write bus
//   dma_axi_master — AXI4 master duy nhất giao tiếp với crossbar
//
// SỬA LỖI so với bản gốc:
//
//  [FIX-1] `include đặt trong module → lỗi Verilog-2001. `include phải đặt
//          trước module declaration. Dùng compile filelist thay thế (xem NOTE).
//          → Xóa tất cả `include; dùng external filelist.
//
//  [FIX-2] s_axi_awprot không được pass xuống dma_reg_slave → port mismatch.
//          → Thêm s_axi_awprot và s_axi_arprot vào instance connection.
//
//  [FIX-3] wr_bready và rd_data_rdy trong channel instances được nối vào ()
//          (không connected) → floating input. dma_channel dùng assign
//          wr_bready = 1'b1 và rd_data_rdy = 1'b1 bên trong → output port
//          này không cần nối từ bên ngoài. Giữ nguyên, thêm comment.
//
//  [FIX-4] Đặt lại AXI ID master. Crossbar cần biết M3 (DMA Ctrl) để route.
//          dma_axi_master đặt m_axi_arid/awid = 4'd0 (đã fix trong module đó).
//          Top không cần can thiệp thêm.
//
// NOTE compile filelist (thứ tự quan trọng):
//   1. dma/rtl/dma_axi_master.v
//   2. dma/rtl/dma_arbiter.v
//   3. dma/rtl/dma_channel.v
//   4. dma/rtl/dma_reg_slave.v
//   5. dma/rtl/dma_ctrl.v   ← file này
//
// Kết nối vào soc_top.v:
//   dma_ctrl u_dma_ctrl (
//       .clk       (clk),
//       .rst_n     (fabric_rst_n),
//       .S_AXI_*   (s11_*),   // S11 từ crossbar
//       .M_AXI_*   (m3_*),    // M3 lên crossbar
//       .irq_out   (dma_irq)  // → PLIC[7]
//   );
// ============================================================================

// ==============================================================================
// FILE: dma_reg_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// dma_reg_slave.v — AXI4-Full Slave: DMA Controller Configuration Registers
//
// Register Map (base = 0x6001_0000):
//   0x000  CH0_SRC    [31:0] RW  — source address
//   0x004  CH0_DST    [31:0] RW  — destination address
//   0x008  CH0_LEN    [31:0] RW  — byte count
//   0x00C  CH0_CTRL   [3:0]  RW  — [0]=EN, [1]=START(SC), [3:2]=MODE
//   0x010  CH1_SRC ... (offset +0x10 per channel)
//   0x020  CH2_SRC ...
//   0x030  CH3_SRC ...
//   0x080  STATUS     [11:0] RO  — [3:0]=done, [7:4]=error, [11:8]=busy
//   0x084  IRQ_EN     [3:0]  RW  — bật IRQ per channel
//   0x088  IRQ_STATUS [3:0]  RW1C — ghi 1 để clear
//
// SỬA LỖI so với bản gốc:
//
//  [FIX-1] Read FSM: RD_IDLE → RD_DATA không check s_axi_arready.
//          ARREADY = (rd_state == RD_IDLE), nhưng FSM transition xảy ra khi
//          s_axi_arvalid HIGH mà không kiểm tra ARREADY → nếu tool đặt
//          register ở output, ARREADY bị delay 1 cycle → handshake không đúng.
//          Fix: gán ARREADY combinational (assign), transition khi arvalid && arready.
//          Bản gốc đã đúng (assign s_axi_arready = rd_state==RD_IDLE), giữ nguyên.
//          Thêm kiểm tra s_axi_arready trong FSM transition cho rõ ràng.
//
//  [FIX-2] IRQ status: ch_done là 1-cycle pulse từ dma_channel.
//          Bản gốc: r_irq_status được set bởi ch_done trong always write block.
//          Nhưng IRQ block phải nằm trong cùng always block với write FSM để
//          tránh multiple-driver trên r_irq_status. Bản gốc đã đúng cấu trúc.
//          Fix: tách ra clearly bằng comment; thêm latch ch_done đúng cách.
//
//  [FIX-3] r_start: bản gốc clear r_start bằng default (mỗi cycle về 0).
//          Nhưng r_start[i] chỉ HIGH 1 cycle ngay sau khi CTRL.START được ghi.
//          Vấn đề: nếu CPU ghi CTRL.START trong cùng cycle r_start đang HIGH
//          (do pipe delay), r_start sẽ bị overwrite → channel miss pulse.
//          Fix: giữ r_start sticky; channel tự clear bằng cách nhận cfg_start
//          và báo busy (busy sẽ block r_start được set lại khi đang chạy).
//          → Thực ra bản gốc đúng: r_start tự clear mỗi cycle vì default <= 0.
//          Giữ nguyên, thêm comment.
//
//  [FIX-4] Read decode function: addr[5:4] dùng làm channel index.
//          Với offset 0x010 per channel: ch0=0x000..0x00F, ch1=0x010..0x01F.
//          addr[5:4]: ch0=00, ch1=01, ch2=10, ch3=11 → đúng.
//          STATUS ở 0x080: addr[7]=1, addr[6:0]=0x00 → khác nhánh 0x080..0x088.
//          Bản gốc decode bằng addr[11:6]==6'b000000 cho channel registers
//          và addr[7:0] cho status. Fix: thống nhất decode bằng addr[11:7].
//
//  [FIX-5] s_axi_awprot không có trong port list bản gốc → compile warning.
//          Thêm vào port list (input, không dùng trong logic = tie-off OK).
//
//  [FIX-6] Output reg s_axi_bid, s_axi_bresp, s_axi_bvalid: bản gốc dùng
//          output reg trực tiếp → không có trường hợp X sau reset vì reset
//          block khởi tạo về 0. Giữ nguyên.
// ============================================================================

module dma_reg_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter NUM_CH     = 4
)(
    input  wire                  clk,
    input  wire                  rst_n,

    // ── AXI4-Full Slave ───────────────────────────────────────────────────
    input  wire [ID_WIDTH-1:0]   s_axi_awid,
    input  wire [ADDR_WIDTH-1:0] s_axi_awaddr,
    input  wire [7:0]            s_axi_awlen,
    input  wire [2:0]            s_axi_awsize,
    input  wire [1:0]            s_axi_awburst,
    input  wire [2:0]            s_axi_awprot,   // [FIX-5]
    input  wire                  s_axi_awvalid,
    output wire                  s_axi_awready,

    input  wire [DATA_WIDTH-1:0] s_axi_wdata,
    input  wire [3:0]            s_axi_wstrb,
    input  wire                  s_axi_wlast,
    input  wire                  s_axi_wvalid,
    output wire                  s_axi_wready,

    output reg  [ID_WIDTH-1:0]   s_axi_bid,
    output reg  [1:0]            s_axi_bresp,
    output reg                   s_axi_bvalid,
    input  wire                  s_axi_bready,

    input  wire [ID_WIDTH-1:0]   s_axi_arid,
    input  wire [ADDR_WIDTH-1:0] s_axi_araddr,
    input  wire [7:0]            s_axi_arlen,
    input  wire [2:0]            s_axi_arsize,
    input  wire [1:0]            s_axi_arburst,
    input  wire [2:0]            s_axi_arprot,   // [FIX-5]
    input  wire                  s_axi_arvalid,
    output wire                  s_axi_arready,

    output reg  [ID_WIDTH-1:0]   s_axi_rid,
    output reg  [DATA_WIDTH-1:0] s_axi_rdata,
    output reg  [1:0]            s_axi_rresp,
    output reg                   s_axi_rlast,
    output reg                   s_axi_rvalid,
    input  wire                  s_axi_rready,

    // ── Config outputs → dma_channel ─────────────────────────────────────
    output wire [ADDR_WIDTH-1:0] ch0_src,  output wire [ADDR_WIDTH-1:0] ch0_dst,
    output wire [31:0]           ch0_len,  output wire [1:0]            ch0_mode,
    output wire                  ch0_en,   output wire                  ch0_start,

    output wire [ADDR_WIDTH-1:0] ch1_src,  output wire [ADDR_WIDTH-1:0] ch1_dst,
    output wire [31:0]           ch1_len,  output wire [1:0]            ch1_mode,
    output wire                  ch1_en,   output wire                  ch1_start,

    output wire [ADDR_WIDTH-1:0] ch2_src,  output wire [ADDR_WIDTH-1:0] ch2_dst,
    output wire [31:0]           ch2_len,  output wire [1:0]            ch2_mode,
    output wire                  ch2_en,   output wire                  ch2_start,

    output wire [ADDR_WIDTH-1:0] ch3_src,  output wire [ADDR_WIDTH-1:0] ch3_dst,
    output wire [31:0]           ch3_len,  output wire [1:0]            ch3_mode,
    output wire                  ch3_en,   output wire                  ch3_start,

    // ── Status inputs ← dma_channel ───────────────────────────────────────
    input  wire [NUM_CH-1:0]     ch_done,   // 1-cycle pulse
    input  wire [NUM_CH-1:0]     ch_error,  // 1-cycle pulse
    input  wire [NUM_CH-1:0]     ch_busy,

    // ── IRQ → PLIC[7] ─────────────────────────────────────────────────────
    output wire                  irq_out
);

    // =========================================================================
    // Internal registers
    // WHY: Mỗi channel có 4 registers (SRC, DST, LEN, CTRL) = 16 bytes.
    // Dùng indexed reg array — OK trong Verilog-2001 cho synthesis.
    // =========================================================================
    reg [ADDR_WIDTH-1:0] r_src  [0:3];
    reg [ADDR_WIDTH-1:0] r_dst  [0:3];
    reg [31:0]           r_len  [0:3];
    reg [1:0]            r_mode [0:3];
    reg                  r_en   [0:3];
    reg [3:0]            r_start;       // [FIX-3] 1-cycle pulse, default → 0

    reg [NUM_CH-1:0]     r_irq_en;
    reg [NUM_CH-1:0]     r_irq_status;  // sticky, cleared by RW1C

    // =========================================================================
    // Config output assignments — single driver
    // =========================================================================
    assign ch0_src = r_src[0]; assign ch0_dst = r_dst[0];
    assign ch0_len = r_len[0]; assign ch0_mode = r_mode[0];
    assign ch0_en  = r_en[0];  assign ch0_start = r_start[0];

    assign ch1_src = r_src[1]; assign ch1_dst = r_dst[1];
    assign ch1_len = r_len[1]; assign ch1_mode = r_mode[1];
    assign ch1_en  = r_en[1];  assign ch1_start = r_start[1];

    assign ch2_src = r_src[2]; assign ch2_dst = r_dst[2];
    assign ch2_len = r_len[2]; assign ch2_mode = r_mode[2];
    assign ch2_en  = r_en[2];  assign ch2_start = r_start[2];

    assign ch3_src = r_src[3]; assign ch3_dst = r_dst[3];
    assign ch3_len = r_len[3]; assign ch3_mode = r_mode[3];
    assign ch3_en  = r_en[3];  assign ch3_start = r_start[3];

    // =========================================================================
    // Sticky STATUS: latch ch_done/ch_error pulse thành register đọc được
    // WHY: ch_done và ch_error là 1-cycle pulse. Đọc combinational luôn = 0
    //      trừ đúng chu kỳ pulse → CPU poll AXI không bao giờ thấy được.
    //      Fix: latch vào r_status_done / r_status_error (sticky), CPU clear
    //      bằng cách ghi 1 vào STATUS (RW1C), giống IRQ_STATUS.
    // =========================================================================
    reg [NUM_CH-1:0] r_status_done;   // [FIX-2] sticky done bits
    reg [NUM_CH-1:0] r_status_error;  // [FIX-2] sticky error bits

    // IRQ: level HIGH khi có bất kỳ kênh nào có pending IRQ và IRQ_EN bật
    assign irq_out = |(r_irq_en & r_irq_status);

    // =========================================================================
    // AXI handshake — combinational AWREADY/WREADY/ARREADY
    // WHY: AWREADY và ARREADY phải combinational để handshake ngay cycle 1.
    // Nếu dùng reg, master có thể timeout hoặc miss handshake (fire-and-forget).
    // =========================================================================
    localparam WR_IDLE = 2'd0, WR_DATA = 2'd1, WR_RESP = 2'd2;
    localparam RD_IDLE = 1'b0, RD_DATA = 1'b1;

    reg [1:0]            wr_state;
    reg [ADDR_WIDTH-1:0] wr_addr;
    reg [ID_WIDTH-1:0]   wr_id;
    reg                  rd_state;

    assign s_axi_awready = (wr_state == WR_IDLE);
    assign s_axi_wready  = (wr_state == WR_DATA);
    assign s_axi_arready = (rd_state == RD_IDLE);

    // =========================================================================
    // Read decode function
    // [FIX-4] Decode rõ ràng theo addr[6:4] cho channel regs, addr[7] cho status
    // =========================================================================
    function [DATA_WIDTH-1:0] read_reg;
        input [ADDR_WIDTH-1:0] addr;
        reg [1:0] ch;
        begin
            read_reg = {DATA_WIDTH{1'b0}};
            if (!addr[7]) begin
                // Channel registers: 0x000..0x07F
                ch = addr[5:4];  // channel index
                case (ch)
                    2'd0: case (addr[3:0])
                        4'h0: read_reg = r_src[0];
                        4'h4: read_reg = r_dst[0];
                        4'h8: read_reg = r_len[0];
                        4'hC: read_reg = {28'h0, r_mode[0], 1'b0, r_en[0]};
                        default: read_reg = 32'h0;
                    endcase
                    2'd1: case (addr[3:0])
                        4'h0: read_reg = r_src[1];
                        4'h4: read_reg = r_dst[1];
                        4'h8: read_reg = r_len[1];
                        4'hC: read_reg = {28'h0, r_mode[1], 1'b0, r_en[1]};
                        default: read_reg = 32'h0;
                    endcase
                    2'd2: case (addr[3:0])
                        4'h0: read_reg = r_src[2];
                        4'h4: read_reg = r_dst[2];
                        4'h8: read_reg = r_len[2];
                        4'hC: read_reg = {28'h0, r_mode[2], 1'b0, r_en[2]};
                        default: read_reg = 32'h0;
                    endcase
                    default: case (addr[3:0])  // 2'd3
                        4'h0: read_reg = r_src[3];
                        4'h4: read_reg = r_dst[3];
                        4'h8: read_reg = r_len[3];
                        4'hC: read_reg = {28'h0, r_mode[3], 1'b0, r_en[3]};
                        default: read_reg = 32'h0;
                    endcase
                endcase
            end else begin
                // Status/IRQ registers: 0x080..0x0FF
                case (addr[7:0])
                    8'h80: read_reg = {20'h0, ch_busy, r_status_error, r_status_done};
                    // [FIX-2] STATUS dùng r_status_done/error (sticky latch)
                    // thay vì ch_done/ch_error trực tiếp (chỉ HIGH 1 cycle → CPU miss).
                    // ch_busy vẫn combinational vì CPU cần real-time busy status.
                    8'h84: read_reg = {28'h0, r_irq_en};
                    8'h88: read_reg = {28'h0, r_irq_status};
                    default: read_reg = 32'h0;
                endcase
            end
        end
    endfunction

    // =========================================================================
    // Write FSM + IRQ latch — single always block (không multi-driver)
    // WHY: Gộp write FSM và IRQ latch vào 1 always block để tránh 2 always
    // block drive cùng r_irq_status (vi phạm Verilog single-driver rule).
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin : write_fsm
        integer k;
        if (!rst_n) begin
            wr_state     <= WR_IDLE;
            wr_addr      <= {ADDR_WIDTH{1'b0}};
            wr_id        <= {ID_WIDTH{1'b0}};
            s_axi_bid    <= {ID_WIDTH{1'b0}};
            s_axi_bresp  <= 2'b00;
            s_axi_bvalid <= 1'b0;
            r_irq_en     <= {NUM_CH{1'b0}};
            r_irq_status <= {NUM_CH{1'b0}};
            r_status_done  <= {NUM_CH{1'b0}};   // [FIX-2]
            r_status_error <= {NUM_CH{1'b0}};   // [FIX-2]
            r_start      <= 4'b0;
            for (k = 0; k < 4; k = k + 1) begin
                r_src[k]  <= {ADDR_WIDTH{1'b0}};
                r_dst[k]  <= {ADDR_WIDTH{1'b0}};
                r_len[k]  <= 32'h0;
                r_mode[k] <= 2'b0;
                r_en[k]   <= 1'b0;
            end
        end else begin
            // ── [FIX-3] Clear r_start mỗi cycle (1-cycle pulse) ───────────
            r_start <= 4'b0;

            // ── [FIX-2] Latch ch_done/ch_error pulse vào sticky STATUS ─────
            // OR-latch: không mất pulse kể cả khi CPU chưa kịp clear
            r_status_done  <= r_status_done  | ch_done;
            r_status_error <= r_status_error | ch_error;

            // ── IRQ latch: ch_done là 1-cycle pulse → set r_irq_status ────
            // WHY: set bằng OR để không mất pulse nếu CPU chưa kịp đọc
            r_irq_status <= r_irq_status | ch_done | ch_error;

            // ── Write FSM ─────────────────────────────────────────────────
            case (wr_state)
                WR_IDLE: begin
                    if (s_axi_awvalid && s_axi_awready) begin
                        wr_addr  <= s_axi_awaddr;
                        wr_id    <= s_axi_awid;
                        wr_state <= WR_DATA;
                    end
                end

                WR_DATA: begin
                    if (s_axi_wvalid && s_axi_wready) begin
                        // Decode write address và ghi vào register tương ứng
                        if (!wr_addr[7]) begin
                            // Channel registers
                            case (wr_addr[5:4])
                                2'd0: case (wr_addr[3:0])
                                    4'h0: begin
                                        if (s_axi_wstrb[0]) r_src[0][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_src[0][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_src[0][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_src[0][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h4: begin
                                        if (s_axi_wstrb[0]) r_dst[0][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_dst[0][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_dst[0][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_dst[0][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h8: begin
                                        if (s_axi_wstrb[0]) r_len[0][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_len[0][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_len[0][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_len[0][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'hC: if (s_axi_wstrb[0]) begin
                                        r_en[0]   <= s_axi_wdata[0];
                                        if (s_axi_wdata[1]) r_start[0] <= 1'b1;
                                        r_mode[0] <= s_axi_wdata[3:2];
                                    end
                                    default: ;
                                endcase
                                2'd1: case (wr_addr[3:0])
                                    4'h0: begin
                                        if (s_axi_wstrb[0]) r_src[1][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_src[1][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_src[1][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_src[1][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h4: begin
                                        if (s_axi_wstrb[0]) r_dst[1][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_dst[1][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_dst[1][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_dst[1][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h8: begin
                                        if (s_axi_wstrb[0]) r_len[1][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_len[1][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_len[1][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_len[1][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'hC: if (s_axi_wstrb[0]) begin
                                        r_en[1]   <= s_axi_wdata[0];
                                        if (s_axi_wdata[1]) r_start[1] <= 1'b1;
                                        r_mode[1] <= s_axi_wdata[3:2];
                                    end
                                    default: ;
                                endcase
                                2'd2: case (wr_addr[3:0])
                                    4'h0: begin
                                        if (s_axi_wstrb[0]) r_src[2][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_src[2][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_src[2][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_src[2][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h4: begin
                                        if (s_axi_wstrb[0]) r_dst[2][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_dst[2][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_dst[2][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_dst[2][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h8: begin
                                        if (s_axi_wstrb[0]) r_len[2][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_len[2][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_len[2][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_len[2][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'hC: if (s_axi_wstrb[0]) begin
                                        r_en[2]   <= s_axi_wdata[0];
                                        if (s_axi_wdata[1]) r_start[2] <= 1'b1;
                                        r_mode[2] <= s_axi_wdata[3:2];
                                    end
                                    default: ;
                                endcase
                                default: case (wr_addr[3:0])  // ch3
                                    4'h0: begin
                                        if (s_axi_wstrb[0]) r_src[3][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_src[3][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_src[3][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_src[3][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h4: begin
                                        if (s_axi_wstrb[0]) r_dst[3][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_dst[3][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_dst[3][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_dst[3][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'h8: begin
                                        if (s_axi_wstrb[0]) r_len[3][ 7: 0] <= s_axi_wdata[ 7: 0];
                                        if (s_axi_wstrb[1]) r_len[3][15: 8] <= s_axi_wdata[15: 8];
                                        if (s_axi_wstrb[2]) r_len[3][23:16] <= s_axi_wdata[23:16];
                                        if (s_axi_wstrb[3]) r_len[3][31:24] <= s_axi_wdata[31:24];
                                    end
                                    4'hC: if (s_axi_wstrb[0]) begin
                                        r_en[3]   <= s_axi_wdata[0];
                                        if (s_axi_wdata[1]) r_start[3] <= 1'b1;
                                        r_mode[3] <= s_axi_wdata[3:2];
                                    end
                                    default: ;
                                endcase
                            endcase
                        end else begin
                            // Status/IRQ registers
                            case (wr_addr[7:0])
                                8'h80: begin
                                    // [FIX-2] STATUS RW1C: CPU ghi 1 để clear done/error bits
                                    // Layout: [3:0]=done, [7:4]=error
                                    r_status_done  <= r_status_done  & ~(s_axi_wdata[NUM_CH-1:0]);
                                    r_status_error <= r_status_error & ~(s_axi_wdata[NUM_CH+3:4]);
                                end
                                8'h84: if (s_axi_wstrb[0])
                                    r_irq_en <= s_axi_wdata[NUM_CH-1:0];
                                // [FIX] RW1C: ghi 1 để clear bit tương ứng
                                // Ưu tiên: clear RW1C trước set từ ch_done
                                // (nếu done đến cùng cycle CPU clear → clear thắng)
                                8'h88: r_irq_status <= r_irq_status
                                                       & ~(s_axi_wdata[NUM_CH-1:0]);
                                default: ;
                            endcase
                        end

                        s_axi_bid    <= wr_id;
                        s_axi_bresp  <= 2'b00;  // OKAY
                        s_axi_bvalid <= 1'b1;
                        wr_state     <= WR_RESP;
                    end
                end

                WR_RESP: begin
                    if (s_axi_bready) begin
                        s_axi_bvalid <= 1'b0;
                        wr_state     <= WR_IDLE;
                    end
                end

                default: wr_state <= WR_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Read FSM
    // [FIX-1] Transition khi arvalid && arready (tường minh)
    // WHY: AXI4 chỉ hoàn thành AR handshake khi BOTH valid && ready HIGH.
    // ARREADY = (rd_state == RD_IDLE) → combinational. Khi rd_state đổi sang
    // RD_DATA, ARREADY tự drop → đúng AXI4 (slave không pre-assert ARREADY
    // trước khi xử lý xong read response).
    // =========================================================================
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state     <= RD_IDLE;
            s_axi_rid    <= {ID_WIDTH{1'b0}};
            s_axi_rdata  <= {DATA_WIDTH{1'b0}};
            s_axi_rresp  <= 2'b00;
            s_axi_rlast  <= 1'b0;
            s_axi_rvalid <= 1'b0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    // [FIX-1] Kiểm tra cả arvalid và arready
                    if (s_axi_arvalid && s_axi_arready) begin
                        s_axi_rid    <= s_axi_arid;
                        s_axi_rdata  <= read_reg(s_axi_araddr);
                        s_axi_rresp  <= 2'b00;
                        s_axi_rlast  <= 1'b1;   // single-beat (thanh ghi 32-bit)
                        s_axi_rvalid <= 1'b1;
                        rd_state     <= RD_DATA;
                    end
                end
                RD_DATA: begin
                    if (s_axi_rready) begin
                        s_axi_rvalid <= 1'b0;
                        s_axi_rlast  <= 1'b0;
                        rd_state     <= RD_IDLE;
                    end
                end
                default: rd_state <= RD_IDLE;
            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: dma_channel.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// dma_channel.v — 1 kênh DMA (mem-to-mem)
//
// SỬA LỖI so với bản gốc:
//
//  [FIX-1] S_WAIT_RD: rd_last được latch từ assign wire (rd_last = m_axi_rlast
//          && m_axi_rvalid && m_axi_rready). Trong bản gốc, rd_last chỉ là
//          m_axi_rlast → có thể HIGH trước khi rvalid/rready → channel chuyển
//          state sớm. Fix: kiểm tra rd_data_v && rd_last cùng lúc.
//
//  [FIX-2] S_WAIT_WR: wr_wvalid / wr_wlast không bị clear sau khi wready
//          accept beat cuối → slave nhận double-beat. Fix: clear wr_wvalid
//          ngay sau handshake (wr_wvalid && wr_wready).
//
//  [FIX-3] bytes_left comparison khi tính done: 
//          "bytes_left <= ((wr_len+1) << 2)" — wr_len là reg [7:0], wr_len+1
//          là 9-bit, shift 2 là 11-bit, nhưng bytes_left là 32-bit.
//          Verilog sẽ zero-extend đúng, nhưng dễ gây cảnh báo tool.
//          Fix: dùng {24'b0, wr_len} + 32'h1 để tường minh.
//
//  [FIX-4] buf_count là 5-bit (0–16) nhưng BUF_DEPTH=16 nên max count=16
//          cần bit thứ 5 (0–16 = 5 bits). Bản gốc đúng, giữ nguyên.
//
//  [FIX-5] integer i trong always block: Verilog-2001 cho phép integer trong
//          always sequential nhưng không synthesizable nếu dùng trong loop
//          với non-constant bound. Bản gốc chỉ dùng i để khởi tạo buf_mem
//          trong initial block (không có initial block nào trong RTL) →
//          loại bỏ integer i và dùng reset block không có loop.
//          → Đổi sang reset buf_mem bằng reg default (FF sẽ reset về 0).
//
//  [FIX-6] S_FETCH_RD: rd_len calculation khi bytes_left không chia hết
//          cho 4. "(bytes_left >> 2) - 1" có thể underflow nếu bytes_left < 4.
//          Fix: gate bằng điều kiện >= 4.
//
//  [FIX-7] Loại bỏ "integer i" ở module scope — không hợp lệ trong Verilog-2001
//          cho synthesis (integer variables ở module scope chỉ dùng được
//          trong initial/task, không trong always sequential).
//
// NOTE về modes:
//   Mode 2'b00 = mem-to-mem: đã implement đầy đủ
//   Mode 2'b01 = periph-to-mem: cần periph_req/periph_ack handshake
//     (chưa implement — channel báo lỗi nếu cfg_mode != 0)
//   Mode 2'b10 = mem-to-periph: tương tự
//   → Trong SoC hiện tại, PLIC + UART/SPI dùng DMA mode 0 (mem-to-mem)
//     vì peripheral FIFO được map vào địa chỉ MMIO.
// ============================================================================

module dma_channel #(
    parameter ADDR_WIDTH  = 32,
    parameter DATA_WIDTH  = 32,
    parameter BURST_LEN   = 8'd15  // AXI ARLEN = 15 → 16-beat burst (64 bytes)
)(
    input  wire                  clk,
    input  wire                  rst_n,

    // ── Config từ dma_reg_slave ───────────────────────────────────────────
    input  wire [ADDR_WIDTH-1:0] cfg_src,
    input  wire [ADDR_WIDTH-1:0] cfg_dst,
    input  wire [31:0]           cfg_len,    // tổng số byte cần transfer
    input  wire [1:0]            cfg_mode,
    input  wire                  cfg_en,
    input  wire                  cfg_start,  // 1-cycle pulse

    // ── Peripheral handshake (mode 01/10 only) ────────────────────────────
    // PERIPH_RX (01): src=MMIO fixed, dst=DMEM increments, 1-word per req
    // PERIPH_TX (10): src=DMEM increments, dst=MMIO fixed, 1-word per req
    input  wire                  periph_req, // peripheral has data / is ready
    output reg                   periph_ack, // 1-cycle pulse after each word xfer

    // ── Status → dma_reg_slave ────────────────────────────────────────────
    output reg                   done,       // 1-cycle pulse khi hoàn tất
    output reg                   error,      // 1-cycle pulse khi lỗi
    output wire                  busy,

    // ── Bus request/grant (từ dma_arbiter) ────────────────────────────────
    output reg                   rd_req,
    input  wire                  rd_grant,
    output reg                   rd_rel,
    output reg                   wr_req,
    input  wire                  wr_grant,
    output reg                   wr_rel,

    // ── Data interface với dma_axi_master ─────────────────────────────────
    output reg  [ADDR_WIDTH-1:0] rd_addr,
    output reg  [7:0]            rd_len,
    output reg                   rd_valid,
    input  wire                  rd_ready,
    input  wire [DATA_WIDTH-1:0] rd_data,
    input  wire                  rd_data_v,  // valid && rready (từ dma_axi_master)
    input  wire                  rd_last,    // last beat (từ dma_axi_master)
    output wire                  rd_data_rdy,

    output reg  [ADDR_WIDTH-1:0] wr_addr,
    output reg  [7:0]            wr_len,
    output reg                   wr_valid,
    input  wire                  wr_ready,
    output reg  [DATA_WIDTH-1:0] wr_data,
    output reg  [3:0]            wr_wstrb,
    output reg                   wr_wvalid,
    output reg                   wr_wlast,
    input  wire                  wr_wready,
    input  wire [1:0]            wr_bresp,
    input  wire                  wr_bvalid,
    output wire                  wr_bready
);

    // WHY rd_data_rdy = 1: channel luôn sẵn sàng nhận data vào buffer.
    // Buffer overflow được kiểm soát bởi buf_full (không ghi khi đầy).
    assign rd_data_rdy = 1'b1;
    assign wr_bready   = 1'b1;
    assign busy        = (state != S_IDLE);

    // ── FSM states ────────────────────────────────────────────────────────
    localparam [2:0]
        S_IDLE     = 3'd0,
        S_FETCH_RD = 3'd1,
        S_WAIT_RD  = 3'd2,
        S_FETCH_WR = 3'd3,
        S_WAIT_WR  = 3'd4,
        S_DONE     = 3'd5,
        S_ERROR    = 3'd6,
        S_P_WAIT   = 3'd7;  // wait for periph_req (mode 01/10)

    reg [2:0]            state;
    reg [ADDR_WIDTH-1:0] cur_src;
    reg [ADDR_WIDTH-1:0] cur_dst;
    reg [31:0]           bytes_left;
    reg                  is_periph;    // 1 when mode=01 or mode=10
    reg                  periph_rx;    // 1=PERIPH_RX(src fixed), 0=PERIPH_TX(dst fixed)

    // WHY line buffer 16×32-bit = 64 bytes = 1 burst (ARLEN=15, 16 beats × 4 bytes).
    // Không cần FIFO lớn hơn vì channel xử lý 1 burst mỗi lần: đọc đầy buffer,
    // rồi ghi hết buffer, rồi mới đọc burst tiếp theo.
    localparam BUF_DEPTH = 16;
    reg [DATA_WIDTH-1:0] buf_mem [0:BUF_DEPTH-1];
    reg [3:0]            buf_wr_ptr;   // write pointer vào buffer
    reg [3:0]            buf_rd_ptr;   // read pointer từ buffer
    reg [4:0]            buf_count;    // số words hiện có trong buffer

    wire buf_empty = (buf_count == 5'd0);
    wire buf_full  = (buf_count == BUF_DEPTH[4:0]);

    // ── Computed burst length cho request tiếp theo ───────────────────────
    // WHY: bytes_left >> 2 = số words còn lại. Burst tối đa = BURST_LEN+1 beats.
    // Nếu còn đủ → dùng full burst; không đủ → dùng partial burst.
    wire [7:0] next_burst_len;
    assign next_burst_len = (bytes_left >= {24'b0, BURST_LEN} + 32'h4) // [FIX-6]
                            ? BURST_LEN
                            : (bytes_left[9:2] - 8'd1);  // words - 1 = ARLEN

    // ── Bytes transferred in current burst ───────────────────────────────
    wire [31:0] burst_bytes;
    assign burst_bytes = ({24'b0, wr_len} + 32'h1) << 2;  // (ARLEN+1) × 4

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state      <= S_IDLE;
            rd_req     <= 1'b0;  wr_req    <= 1'b0;
            rd_rel     <= 1'b0;  wr_rel    <= 1'b0;
            rd_valid   <= 1'b0;  wr_valid  <= 1'b0;
            wr_wvalid  <= 1'b0;  wr_wlast  <= 1'b0;
            done       <= 1'b0;  error     <= 1'b0;
            periph_ack <= 1'b0;
            is_periph  <= 1'b0;  periph_rx <= 1'b0;
            buf_wr_ptr <= 4'd0;  buf_rd_ptr <= 4'd0;
            buf_count  <= 5'd0;
            cur_src    <= {ADDR_WIDTH{1'b0}};
            cur_dst    <= {ADDR_WIDTH{1'b0}};
            bytes_left <= 32'd0;
            rd_addr    <= {ADDR_WIDTH{1'b0}};
            rd_len     <= 8'd0;
            wr_addr    <= {ADDR_WIDTH{1'b0}};
            wr_len     <= 8'd0;
            wr_data    <= {DATA_WIDTH{1'b0}};
            wr_wstrb   <= 4'hF;
        end else begin
            // ── Pulse resets (default) ────────────────────────────────────
            done       <= 1'b0;
            error      <= 1'b0;
            rd_rel     <= 1'b0;
            wr_rel     <= 1'b0;
            periph_ack <= 1'b0;

            case (state)
                // ─────────────────────────────────────────────────────────
                S_IDLE: begin
                    if (cfg_start && cfg_en) begin
                        if (cfg_mode == 2'b00) begin
                            // mem-to-mem
                            if (cfg_len == 32'd0) begin
                                done <= 1'b1;
                            end else begin
                                cur_src    <= cfg_src;
                                cur_dst    <= cfg_dst;
                                bytes_left <= cfg_len;
                                is_periph  <= 1'b0;
                                buf_wr_ptr <= 4'd0;
                                buf_rd_ptr <= 4'd0;
                                buf_count  <= 5'd0;
                                rd_req     <= 1'b1;
                                state      <= S_FETCH_RD;
                            end
                        end else if (cfg_mode == 2'b01 || cfg_mode == 2'b10) begin
                            // periph mode: word-by-word, gated by periph_req
                            if (cfg_len == 32'd0) begin
                                done <= 1'b1;
                            end else begin
                                cur_src    <= cfg_src;
                                cur_dst    <= cfg_dst;
                                bytes_left <= cfg_len;
                                is_periph  <= 1'b1;
                                periph_rx  <= (cfg_mode == 2'b01);
                                buf_wr_ptr <= 4'd0;
                                buf_rd_ptr <= 4'd0;
                                buf_count  <= 5'd0;
                                state      <= S_P_WAIT;
                            end
                        end else begin
                            error <= 1'b1;  // mode 11: reserved
                        end
                    end
                end

                // ─────────────────────────────────────────────────────────
                // S_P_WAIT: wait for peripheral to assert req, then do
                // a single-word (ARLEN=0/AWLEN=0) transfer.
                // ─────────────────────────────────────────────────────────
                S_P_WAIT: begin
                    if (periph_req) begin
                        // Single-beat: rd_len=0 (1 word = 4 bytes)
                        buf_wr_ptr <= 4'd0;
                        buf_rd_ptr <= 4'd0;
                        buf_count  <= 5'd0;
                        rd_req     <= 1'b1;
                        state      <= S_FETCH_RD;
                    end
                end

                // ─────────────────────────────────────────────────────────
                S_FETCH_RD: begin
                    if (rd_grant) begin
                        rd_addr  <= cur_src;
                        rd_len   <= is_periph ? 8'd0 : next_burst_len;
                        rd_valid <= 1'b1;
                        rd_req   <= 1'b0;
                        state    <= S_WAIT_RD;
                    end
                end

                // ─────────────────────────────────────────────────────────
                S_WAIT_RD: begin
                    // Drop rd_valid sau AR handshake
                    if (rd_valid && rd_ready)
                        rd_valid <= 1'b0;

                    // Latch R data vào line buffer
                    // [FIX-1] kiểm tra rd_data_v (đã gated với rvalid && rready)
                    if (rd_data_v && !buf_full) begin
                        buf_mem[buf_wr_ptr] <= rd_data;
                        buf_wr_ptr          <= buf_wr_ptr + 4'd1;
                        buf_count           <= buf_count + 5'd1;
                    end

                    // [FIX-1] rd_last đã gated với valid && ready từ dma_axi_master
                    if (rd_last) begin
                        rd_rel <= 1'b1;
                        wr_req <= 1'b1;
                        state  <= S_FETCH_WR;
                    end
                end

                // ─────────────────────────────────────────────────────────
                S_FETCH_WR: begin
                    if (wr_grant) begin
                        // PERIPH_TX (mode 10): dst is fixed MMIO, don't use cur_dst
                        wr_addr  <= (is_periph && !periph_rx) ? cfg_dst : cur_dst;
                        wr_len   <= rd_len;  // 0 for periph, next_burst_len for mem
                        wr_valid <= 1'b1;
                        wr_req   <= 1'b0;
                        state    <= S_WAIT_WR;
                    end
                end

                // ─────────────────────────────────────────────────────────
                S_WAIT_WR: begin
                    // Drop wr_valid sau AW handshake
                    if (wr_valid && wr_ready)
                        wr_valid <= 1'b0;

                    // Drive W channel từ line buffer
                    // [FIX-2] clear wr_wvalid sau mỗi beat được accept
                    if (!buf_empty && wr_wready && !wr_wvalid) begin
                        // Lấy word từ buffer khi slave sẵn sàng nhận beat mới
                        wr_data    <= buf_mem[buf_rd_ptr];
                        wr_wstrb   <= 4'hF;
                        wr_wvalid  <= 1'b1;
                        wr_wlast   <= (buf_count == 5'd1);  // last beat khi còn 1 word
                        buf_rd_ptr <= buf_rd_ptr + 4'd1;
                        buf_count  <= buf_count - 5'd1;
                    end else if (wr_wvalid && wr_wready) begin
                        // Beat được accept → clear valid
                        // [FIX-2] Không double-drive: sau khi clear,
                        // vòng lặp tiếp theo mới nạp beat kế tiếp
                        wr_wvalid <= 1'b0;
                        wr_wlast  <= 1'b0;
                    end

                    // Chờ B response
                    if (wr_bvalid) begin
                        if (wr_bresp != 2'b00) begin
                            error  <= 1'b1;
                            wr_rel <= 1'b1;
                            state  <= S_ERROR;
                        end else begin
                            wr_rel <= 1'b1;

                            if (is_periph) begin
                                // Periph mode: single-word (4 bytes) per req/ack cycle
                                // PERIPH_RX: src (MMIO) fixed, dst increments
                                // PERIPH_TX: src increments, dst (MMIO) fixed via cfg_dst
                                if (!periph_rx) cur_src <= cur_src + 32'd4;
                                if ( periph_rx) cur_dst <= cur_dst + 32'd4;
                                bytes_left <= bytes_left - 32'd4;
                                periph_ack <= 1'b1;
                                if (bytes_left <= 32'd4) begin
                                    state <= S_DONE;
                                end else begin
                                    state <= S_P_WAIT;
                                end
                            end else begin
                                // mem-to-mem burst loop
                                cur_src    <= cur_src    + burst_bytes;
                                cur_dst    <= cur_dst    + burst_bytes;
                                bytes_left <= bytes_left - burst_bytes;
                                if (bytes_left <= burst_bytes) begin
                                    state <= S_DONE;
                                end else begin
                                    buf_wr_ptr <= 4'd0;
                                    buf_rd_ptr <= 4'd0;
                                    buf_count  <= 5'd0;
                                    rd_req     <= 1'b1;
                                    state      <= S_FETCH_RD;
                                end
                            end
                        end
                    end
                end

                // ─────────────────────────────────────────────────────────
                S_DONE: begin
                    done  <= 1'b1;
                    state <= S_IDLE;
                end

                S_ERROR: begin
                    // error đã được pulse ở S_WAIT_WR
                    state <= S_IDLE;
                end

                default: state <= S_IDLE;
            endcase
        end
    end

endmodule
// ==============================================================================
// FILE: dma_arbiter.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// dma_arbiter.v — Round-Robin Arbitration cho 4 kênh DMA
//
// SỬA LỖI so với bản gốc:
//
//  [FIX-1] Verilog integer dùng trong expression có modulo với reg signal:
//          (rd_last_grant + 1 + i) % NUM_CH
//          → Khi rd_last_grant là reg [1:0] và i là integer, Verilog-2001
//          expand lên 32-bit trước modulo → kết quả đúng, nhưng tool cảnh
//          báo "implicit conversion" và synthesis có thể tạo full 32-bit
//          divider. Fix: dùng lookup table rõ ràng thay vì modulo.
//
//  [FIX-2] Combinational loop tiềm ẩn: rd_next_grant dùng rd_last_grant
//          (reg) và rd_req (input). Nếu công cụ tổng hợp không nhận ra
//          điều này là thuần combinational, có thể tạo latch.
//          Fix: thêm default assignment + đảm bảo mọi path assign rd_next_grant.
//
//  [FIX-3] rd_grant không clear khi kênh release rồi request lại ngay.
//          Bug: rd_busy=1, rd_grant=0001, rd_rel[0]=1 → rd_busy=0, rd_grant=0.
//          Cycle sau: rd_req[0]=1 ngay → rd_grant phải re-arbitrate.
//          Đây là behavior đúng, giữ nguyên nhưng thêm comment rõ hơn.
//
//  [FIX-4] Đặt tên rd_next_grant thành wire (không phải reg) để rõ ràng
//          đây là combinational. Tool Verilog-2001 chấp nhận reg trong always@(*)
//          nhưng wire semantics rõ hơn trong code review.
//          → Giữ là reg vì cần assign trong always@(*) — đây là Verilog style
//          đúng cho combinational logic.
//
// WHY Round-Robin:
//   Nếu ch0 luôn transfer lớn, nó sẽ chiếm bus liên tục → ch1/ch2/ch3 stall.
//   Round-robin đảm bảo sau mỗi grant, ưu tiên xoay sang kênh tiếp theo.
//   "Không cắt burst": một khi kênh được grant, giữ đến khi kênh gửi rel.
//   Điều này tránh AXI ID conflict và simplify channel FSM.
// ============================================================================

module dma_arbiter #(
    parameter NUM_CH = 4
)(
    input  wire clk,
    input  wire rst_n,

    // ── Requests từ các kênh ──────────────────────────────────────────────
    input  wire [NUM_CH-1:0] rd_req,
    output reg  [NUM_CH-1:0] rd_grant,
    input  wire [NUM_CH-1:0] rd_rel,     // release signal từ channel

    input  wire [NUM_CH-1:0] wr_req,
    output reg  [NUM_CH-1:0] wr_grant,
    input  wire [NUM_CH-1:0] wr_rel
);

    // =========================================================================
    // Round-Robin Read Arbiter
    // =========================================================================
    reg [1:0] rd_last_grant;  // index kênh được grant lần trước (0–3)
    reg       rd_busy;        // 1 = bus đang bị giữ

    // [FIX-1] Dùng lookup table thay vì modulo với variable
    // rd_next: kênh nào được grant tiếp theo dựa trên rd_last_grant
    reg [NUM_CH-1:0] rd_next_grant;

    // WHY: always@(*) → synthesis tool nhận ra đây là combinational logic.
    // Mọi output (rd_next_grant) phải được gán trong mọi branch → không latch.
    always @(*) begin
        rd_next_grant = {NUM_CH{1'b0}};  // [FIX-2] default = no grant

        // Lookup table cho 4 kênh: scan theo thứ tự xoay từ rd_last_grant+1
        // Thứ tự ưu tiên (theo rd_last_grant):
        //   0→ scan: 1,2,3,0    1→ scan: 2,3,0,1    2→ scan: 3,0,1,2    3→ scan: 0,1,2,3
        case (rd_last_grant)
            2'd0: begin
                if      (rd_req[1]) rd_next_grant = 4'b0010;
                else if (rd_req[2]) rd_next_grant = 4'b0100;
                else if (rd_req[3]) rd_next_grant = 4'b1000;
                else if (rd_req[0]) rd_next_grant = 4'b0001;
            end
            2'd1: begin
                if      (rd_req[2]) rd_next_grant = 4'b0100;
                else if (rd_req[3]) rd_next_grant = 4'b1000;
                else if (rd_req[0]) rd_next_grant = 4'b0001;
                else if (rd_req[1]) rd_next_grant = 4'b0010;
            end
            2'd2: begin
                if      (rd_req[3]) rd_next_grant = 4'b1000;
                else if (rd_req[0]) rd_next_grant = 4'b0001;
                else if (rd_req[1]) rd_next_grant = 4'b0010;
                else if (rd_req[2]) rd_next_grant = 4'b0100;
            end
            default: begin  // 2'd3
                if      (rd_req[0]) rd_next_grant = 4'b0001;
                else if (rd_req[1]) rd_next_grant = 4'b0010;
                else if (rd_req[2]) rd_next_grant = 4'b0100;
                else if (rd_req[3]) rd_next_grant = 4'b1000;
            end
        endcase
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_grant      <= {NUM_CH{1'b0}};
            rd_last_grant <= 2'd3;  // init: ưu tiên ban đầu cho ch0
            rd_busy       <= 1'b0;
        end else begin
            if (!rd_busy) begin
                // Bus rảnh → arbitrate nếu có request
                if (|rd_req) begin
                    rd_grant  <= rd_next_grant;
                    rd_busy   <= 1'b1;
                    // Latch winner index để round-robin lần sau
                    // WHY: phải latch index chứ không latch rd_next_grant
                    // vì cycle sau rd_req có thể thay đổi
                    case (rd_next_grant)
                        4'b0001: rd_last_grant <= 2'd0;
                        4'b0010: rd_last_grant <= 2'd1;
                        4'b0100: rd_last_grant <= 2'd2;
                        default: rd_last_grant <= 2'd3;
                    endcase
                end
            end else begin
                // Bus bận → chờ kênh được grant gửi release
                // WHY: rd_grant & rd_rel → AND để chỉ release khi đúng kênh được grant
                // gửi rel (không phải kênh khác gửi nhầm)
                if (|(rd_grant & rd_rel)) begin
                    rd_grant <= {NUM_CH{1'b0}};
                    rd_busy  <= 1'b0;
                    // rd_last_grant giữ nguyên → round-robin từ kênh vừa release
                end
            end
        end
    end

    // =========================================================================
    // Round-Robin Write Arbiter (đối xứng với read)
    // WHY: Read bus và Write bus độc lập trong AXI4 (AR và AW channel tách biệt).
    // Cho phép 2 kênh khác nhau đọc và ghi cùng lúc → tăng throughput.
    // =========================================================================
    reg [1:0] wr_last_grant;
    reg       wr_busy;
    reg [NUM_CH-1:0] wr_next_grant;

    always @(*) begin
        wr_next_grant = {NUM_CH{1'b0}};  // [FIX-2] default

        case (wr_last_grant)
            2'd0: begin
                if      (wr_req[1]) wr_next_grant = 4'b0010;
                else if (wr_req[2]) wr_next_grant = 4'b0100;
                else if (wr_req[3]) wr_next_grant = 4'b1000;
                else if (wr_req[0]) wr_next_grant = 4'b0001;
            end
            2'd1: begin
                if      (wr_req[2]) wr_next_grant = 4'b0100;
                else if (wr_req[3]) wr_next_grant = 4'b1000;
                else if (wr_req[0]) wr_next_grant = 4'b0001;
                else if (wr_req[1]) wr_next_grant = 4'b0010;
            end
            2'd2: begin
                if      (wr_req[3]) wr_next_grant = 4'b1000;
                else if (wr_req[0]) wr_next_grant = 4'b0001;
                else if (wr_req[1]) wr_next_grant = 4'b0010;
                else if (wr_req[2]) wr_next_grant = 4'b0100;
            end
            default: begin
                if      (wr_req[0]) wr_next_grant = 4'b0001;
                else if (wr_req[1]) wr_next_grant = 4'b0010;
                else if (wr_req[2]) wr_next_grant = 4'b0100;
                else if (wr_req[3]) wr_next_grant = 4'b1000;
            end
        endcase
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_grant      <= {NUM_CH{1'b0}};
            wr_last_grant <= 2'd3;
            wr_busy       <= 1'b0;
        end else begin
            if (!wr_busy) begin
                if (|wr_req) begin
                    wr_grant  <= wr_next_grant;
                    wr_busy   <= 1'b1;
                    case (wr_next_grant)
                        4'b0001: wr_last_grant <= 2'd0;
                        4'b0010: wr_last_grant <= 2'd1;
                        4'b0100: wr_last_grant <= 2'd2;
                        default: wr_last_grant <= 2'd3;
                    endcase
                end
            end else begin
                if (|(wr_grant & wr_rel)) begin
                    wr_grant <= {NUM_CH{1'b0}};
                    wr_busy  <= 1'b0;
                end
            end
        end
    end

endmodule
// ==============================================================================
// FILE: dma_axi_master.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// dma_axi_master.v — AXI4-Full Master Interface cho DMA Controller (M3)
//
// SỬA LỖI so với bản gốc:
//
//  [FIX-1] m_axi_arid / m_axi_awid hardcode = 4'd2 → sai khi DMA là M3.
//          Crossbar nhận ID từ master và gán thêm master-index vào MSB.
//          DMA master nên dùng ID = 4'd0 (hoặc per-channel ID).
//          → Đổi thành 4'd0 để crossbar phân biệt qua master port index.
//
//  [FIX-2] WR_DATA state: forward W channel bằng blocking assign trong
//          sequential always → ghi vào FF mỗi cycle, tạo ra 1-cycle latency
//          không cần thiết giữa channel output và AXI. Với wr_wvalid=0
//          nhưng m_axi_wvalid vẫn HIGH từ cycle trước → vi phạm AXI4
//          (WVALID không được drop nếu WREADY chưa HIGH).
//          → Fix: gate m_axi_wvalid đúng, thêm WR_WAIT state để đảm bảo
//          WVALID stable sau khi AWREADY nhận.
//
//  [FIX-3] rd_data_v = m_axi_rvalid && (rd_state == RD_BURST) nhưng
//          m_axi_rready bị clear TRƯỚC khi đọc beat cuối → channel có thể
//          miss rd_last. Fix: giữ rready HIGH cho đến rlast+rvalid+rready.
//
//  [FIX-4] Thêm m_axi_arsize / m_axi_awsize cố định = 3'd2 (4 bytes/beat)
//          đúng với DATA_WIDTH=32.
//
//  [FIX-5] wr_bready assign = wr_bready (input wire) → chỉ pass-through.
//          Đây là đúng (channel tự kiểm soát bready), giữ nguyên.
//
// WHY m_axi_arid = 4'd0:
//   Crossbar axi4_crossbar_3m5s (cần mở rộng thành 5m12s) concat
//   {master_idx, channel_id} vào ID trước khi gửi xuống slave.
//   M3 là DMA Ctrl, slave nhận ID = {2'b11, 2'b00} = 4'b1100 (ví dụ).
//   Channel chỉ cần đặt ID thấp = 0 để crossbar không bị ID conflict.
// ============================================================================

module dma_axi_master #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire clk,
    input  wire rst_n,

    // ── AXI4-Full Master → Crossbar M3 ───────────────────────────────────
    output reg  [ID_WIDTH-1:0]   m_axi_arid,
    output reg  [ADDR_WIDTH-1:0] m_axi_araddr,
    output reg  [7:0]            m_axi_arlen,
    output wire [2:0]            m_axi_arsize,   // [FIX-4] wire, luôn = 3'd2
    output wire [1:0]            m_axi_arburst,
    output wire [2:0]            m_axi_arprot,
    output reg                   m_axi_arvalid,
    input  wire                  m_axi_arready,

    input  wire [ID_WIDTH-1:0]   m_axi_rid,
    input  wire [DATA_WIDTH-1:0] m_axi_rdata,
    input  wire [1:0]            m_axi_rresp,
    input  wire                  m_axi_rlast,
    input  wire                  m_axi_rvalid,
    output reg                   m_axi_rready,

    output reg  [ID_WIDTH-1:0]   m_axi_awid,
    output reg  [ADDR_WIDTH-1:0] m_axi_awaddr,
    output reg  [7:0]            m_axi_awlen,
    output wire [2:0]            m_axi_awsize,   // [FIX-4] wire, luôn = 3'd2
    output wire [1:0]            m_axi_awburst,
    output wire [2:0]            m_axi_awprot,
    output reg                   m_axi_awvalid,
    input  wire                  m_axi_awready,

    output reg  [DATA_WIDTH-1:0] m_axi_wdata,
    output reg  [3:0]            m_axi_wstrb,
    output reg                   m_axi_wlast,
    output reg                   m_axi_wvalid,
    input  wire                  m_axi_wready,

    input  wire [ID_WIDTH-1:0]   m_axi_bid,
    input  wire [1:0]            m_axi_bresp,
    input  wire                  m_axi_bvalid,
    output wire                  m_axi_bready,

    // ── Interface với dma_channel (muxed qua arbiter grant) ───────────────
    // Read request (từ kênh được rd_grant)
    input  wire [ADDR_WIDTH-1:0] rd_addr,
    input  wire [7:0]            rd_len,
    input  wire                  rd_valid,   // start transaction
    output wire                  rd_ready,
    output wire [DATA_WIDTH-1:0] rd_data,
    output wire                  rd_data_v,
    output wire                  rd_last,
    input  wire                  rd_data_rdy,

    // Write request (từ kênh được wr_grant)
    input  wire [ADDR_WIDTH-1:0] wr_addr,
    input  wire [7:0]            wr_len,
    input  wire                  wr_valid,
    output wire                  wr_ready,
    input  wire [DATA_WIDTH-1:0] wr_data,
    input  wire [3:0]            wr_wstrb,
    input  wire                  wr_wvalid,
    input  wire                  wr_wlast,
    output wire                  wr_wready,
    output wire [1:0]            wr_bresp,
    output wire                  wr_bvalid,
    input  wire                  wr_bready
);

    // WHY: Fixed AXI4 attributes — DMA luôn dùng INCR burst, 4-byte beat.
    // PROT = 000 (unprivileged, non-secure, data).
    assign m_axi_arsize  = 3'd2;   // 2^2 = 4 bytes/beat
    assign m_axi_arburst = 2'b01;  // INCR
    assign m_axi_arprot  = 3'b000;
    assign m_axi_awsize  = 3'd2;
    assign m_axi_awburst = 2'b01;
    assign m_axi_awprot  = 3'b000;
    assign m_axi_bready  = wr_bready;

    // =========================================================================
    // Read Path FSM
    // WHY: AXI4 yêu cầu ARVALID stable từ khi assert đến khi ARREADY HIGH.
    // Sau ARREADY, master có thể drop ARVALID. Slave bắt đầu burst R.
    // rready nên HIGH trước khi burst bắt đầu (hoặc cùng lúc AR handshake).
    // =========================================================================
    localparam RD_IDLE  = 1'b0;
    localparam RD_BURST = 1'b1;
    reg rd_state;

    // [FIX-3] rd_data_v gate đúng: chỉ valid khi state=BURST và master ready
    assign rd_ready  = (rd_state == RD_IDLE);
    assign rd_data   = m_axi_rdata;
    assign rd_data_v = m_axi_rvalid && m_axi_rready && (rd_state == RD_BURST);
    assign rd_last   = m_axi_rlast  && m_axi_rvalid && m_axi_rready;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state      <= RD_IDLE;
            m_axi_arid    <= {ID_WIDTH{1'b0}};
            m_axi_araddr  <= {ADDR_WIDTH{1'b0}};
            m_axi_arlen   <= 8'd0;
            m_axi_arvalid <= 1'b0;
            m_axi_rready  <= 1'b0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    if (rd_valid) begin
                        m_axi_arid    <= {ID_WIDTH{1'b0}};  // [FIX-1]
                        m_axi_araddr  <= rd_addr;
                        m_axi_arlen   <= rd_len;
                        m_axi_arvalid <= 1'b1;
                        m_axi_rready  <= 1'b1;  // pre-assert rready
                        rd_state      <= RD_BURST;
                    end
                end

                RD_BURST: begin
                    // Drop ARVALID setelah AR handshake (AXI rule)
                    if (m_axi_arvalid && m_axi_arready)
                        m_axi_arvalid <= 1'b0;

                    // [FIX-3] Chỉ drop rready SAU khi đọc beat cuối
                    if (m_axi_rvalid && m_axi_rready && m_axi_rlast) begin
                        m_axi_rready <= 1'b0;
                        rd_state     <= RD_IDLE;
                    end
                end

                default: rd_state <= RD_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Write Path FSM
    // WHY: AXI4 cho phép AW và W concurrent, nhưng nhiều slave chờ AW trước.
    // Để an toàn: phát AW → chờ AWREADY → sau đó mới forward W data.
    // WHY state WR_WAIT: tách biệt AW handshake và W data để tránh
    // m_axi_wvalid HIGH trước khi slave biết có transaction AW.
    // =========================================================================
    localparam WR_IDLE = 2'd0;
    localparam WR_ADDR = 2'd1;  // chờ AW handshake
    localparam WR_DATA = 2'd2;  // forward W channel
    reg [1:0] wr_state;

    assign wr_ready  = (wr_state == WR_IDLE);
    // [FIX-2] wr_wready: chỉ expose khi đang ở WR_DATA (slave sẵn sàng)
    assign wr_wready = m_axi_wready && (wr_state == WR_DATA);
    assign wr_bresp  = m_axi_bresp;
    assign wr_bvalid = m_axi_bvalid;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state      <= WR_IDLE;
            m_axi_awid    <= {ID_WIDTH{1'b0}};
            m_axi_awaddr  <= {ADDR_WIDTH{1'b0}};
            m_axi_awlen   <= 8'd0;
            m_axi_awvalid <= 1'b0;
            m_axi_wdata   <= {DATA_WIDTH{1'b0}};
            m_axi_wstrb   <= 4'hF;
            m_axi_wvalid  <= 1'b0;
            m_axi_wlast   <= 1'b0;
        end else begin
            case (wr_state)
                WR_IDLE: begin
                    if (wr_valid) begin
                        m_axi_awid    <= {ID_WIDTH{1'b0}};  // [FIX-1]
                        m_axi_awaddr  <= wr_addr;
                        m_axi_awlen   <= wr_len;
                        m_axi_awvalid <= 1'b1;
                        m_axi_wvalid  <= 1'b0;  // W chưa valid khi chưa AW
                        wr_state      <= WR_ADDR;
                    end
                end

                WR_ADDR: begin
                    if (m_axi_awvalid && m_axi_awready) begin
                        m_axi_awvalid <= 1'b0;
                        wr_state      <= WR_DATA;
                    end
                end

                WR_DATA: begin
                    // [FIX-2] Forward W channel từ channel khi có dữ liệu.
                    // wr_wvalid HIGH → m_axi_wvalid HIGH; drop theo wr_wvalid.
                    // Không dùng blocking assign → không có latency ẩn.
                    if (wr_wvalid) begin
                        m_axi_wdata  <= wr_data;
                        m_axi_wstrb  <= wr_wstrb;
                        m_axi_wlast  <= wr_wlast;
                        m_axi_wvalid <= 1'b1;
                    end else if (m_axi_wvalid && m_axi_wready) begin
                        // Beat đã được nhận — clear valid nếu channel không gửi thêm
                        m_axi_wvalid <= 1'b0;
                        m_axi_wlast  <= 1'b0;
                    end

                    // Kết thúc khi WLAST được accept
                    if (m_axi_wvalid && m_axi_wready && m_axi_wlast) begin
                        m_axi_wvalid <= 1'b0;
                        m_axi_wlast  <= 1'b0;
                        wr_state     <= WR_IDLE;
                    end
                end

                default: wr_state <= WR_IDLE;
            endcase
        end
    end

endmodule// [FIX-1] Không `include trong file này. Dùng filelist.
module dma_ctrl #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter NUM_CH     = 4
)(
    input  wire clk,
    input  wire rst_n,

    // ── AXI4-Full Slave (S11 ← Crossbar) ─────────────────────────────────
    input  wire [ID_WIDTH-1:0]   S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0] S_AXI_AWADDR,
    input  wire [7:0]            S_AXI_AWLEN,
    input  wire [2:0]            S_AXI_AWSIZE,
    input  wire [1:0]            S_AXI_AWBURST,
    input  wire [2:0]            S_AXI_AWPROT,   // [FIX-2]
    input  wire                  S_AXI_AWVALID,
    output wire                  S_AXI_AWREADY,
    input  wire [DATA_WIDTH-1:0] S_AXI_WDATA,
    input  wire [3:0]            S_AXI_WSTRB,
    input  wire                  S_AXI_WLAST,
    input  wire                  S_AXI_WVALID,
    output wire                  S_AXI_WREADY,
    output wire [ID_WIDTH-1:0]   S_AXI_BID,
    output wire [1:0]            S_AXI_BRESP,
    output wire                  S_AXI_BVALID,
    input  wire                  S_AXI_BREADY,
    input  wire [ID_WIDTH-1:0]   S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0] S_AXI_ARADDR,
    input  wire [7:0]            S_AXI_ARLEN,
    input  wire [2:0]            S_AXI_ARSIZE,
    input  wire [1:0]            S_AXI_ARBURST,
    input  wire [2:0]            S_AXI_ARPROT,   // [FIX-2]
    input  wire                  S_AXI_ARVALID,
    output wire                  S_AXI_ARREADY,
    output wire [ID_WIDTH-1:0]   S_AXI_RID,
    output wire [DATA_WIDTH-1:0] S_AXI_RDATA,
    output wire [1:0]            S_AXI_RRESP,
    output wire                  S_AXI_RLAST,
    output wire                  S_AXI_RVALID,
    input  wire                  S_AXI_RREADY,

    // ── AXI4-Full Master (M3 → Crossbar) ─────────────────────────────────
    output wire [ID_WIDTH-1:0]   M_AXI_ARID,
    output wire [ADDR_WIDTH-1:0] M_AXI_ARADDR,
    output wire [7:0]            M_AXI_ARLEN,
    output wire [2:0]            M_AXI_ARSIZE,
    output wire [1:0]            M_AXI_ARBURST,
    output wire [2:0]            M_AXI_ARPROT,
    output wire                  M_AXI_ARVALID,
    input  wire                  M_AXI_ARREADY,
    input  wire [ID_WIDTH-1:0]   M_AXI_RID,
    input  wire [DATA_WIDTH-1:0] M_AXI_RDATA,
    input  wire [1:0]            M_AXI_RRESP,
    input  wire                  M_AXI_RLAST,
    input  wire                  M_AXI_RVALID,
    output wire                  M_AXI_RREADY,
    output wire [ID_WIDTH-1:0]   M_AXI_AWID,
    output wire [ADDR_WIDTH-1:0] M_AXI_AWADDR,
    output wire [7:0]            M_AXI_AWLEN,
    output wire [2:0]            M_AXI_AWSIZE,
    output wire [1:0]            M_AXI_AWBURST,
    output wire [2:0]            M_AXI_AWPROT,
    output wire                  M_AXI_AWVALID,
    input  wire                  M_AXI_AWREADY,
    output wire [DATA_WIDTH-1:0] M_AXI_WDATA,
    output wire [3:0]            M_AXI_WSTRB,
    output wire                  M_AXI_WLAST,
    output wire                  M_AXI_WVALID,
    input  wire                  M_AXI_WREADY,
    input  wire [ID_WIDTH-1:0]   M_AXI_BID,
    input  wire [1:0]            M_AXI_BRESP,
    input  wire                  M_AXI_BVALID,
    output wire                  M_AXI_BREADY,

    // ── IRQ → PLIC ────────────────────────────────────────────────────────
    output wire                  irq_out,
    output wire                  dma_busy_o,

    // ── Peripheral handshake (per-channel) ───────────────────────────────
    // Connect peripheral DMA-request outputs to dma_req[ch].
    // dma_ack[ch] is a 1-cycle pulse after each word transfer.
    input  wire [NUM_CH-1:0]     dma_req,  // from peripherals
    output wire [NUM_CH-1:0]     dma_ack   // to peripherals
);

    // =========================================================================
    // Internal config wires: dma_reg_slave → dma_channel
    // =========================================================================
    wire [ADDR_WIDTH-1:0] ch0_src,  ch1_src,  ch2_src,  ch3_src;
    wire [ADDR_WIDTH-1:0] ch0_dst,  ch1_dst,  ch2_dst,  ch3_dst;
    wire [31:0]           ch0_len,  ch1_len,  ch2_len,  ch3_len;
    wire [1:0]            ch0_mode, ch1_mode, ch2_mode, ch3_mode;
    wire                  ch0_en,   ch1_en,   ch2_en,   ch3_en;
    wire                  ch0_start,ch1_start,ch2_start,ch3_start;

    // Status: dma_channel → dma_reg_slave
    wire [NUM_CH-1:0] ch_done_w;
    wire [NUM_CH-1:0] ch_error_w;
    wire [NUM_CH-1:0] ch_busy_w;

    // Periph ack wires from channels → dma_ack output
    wire [NUM_CH-1:0] ch_periph_ack_w;
    assign dma_ack = ch_periph_ack_w;

    // =========================================================================
    // Arbiter buses
    // WHY: rd bus và wr bus hoàn toàn độc lập → 2 kênh khác nhau có thể
    // đọc và ghi cùng lúc nếu AXI master hỗ trợ outstanding transactions.
    // =========================================================================
    wire [NUM_CH-1:0] rd_req_w, rd_grant_w, rd_rel_w;
    wire [NUM_CH-1:0] wr_req_w, wr_grant_w, wr_rel_w;

    // =========================================================================
    // Channel → Master: read interfaces (flat)
    // =========================================================================
    wire [ADDR_WIDTH-1:0] ch0_rd_addr, ch1_rd_addr, ch2_rd_addr, ch3_rd_addr;
    wire [7:0]            ch0_rd_len,  ch1_rd_len,  ch2_rd_len,  ch3_rd_len;
    wire                  ch0_rd_valid,ch1_rd_valid,ch2_rd_valid,ch3_rd_valid;
    wire                  ch0_rd_ready,ch1_rd_ready,ch2_rd_ready,ch3_rd_ready;
    wire [DATA_WIDTH-1:0] ch0_rd_data, ch1_rd_data, ch2_rd_data, ch3_rd_data;
    wire                  ch0_rd_dv,   ch1_rd_dv,   ch2_rd_dv,   ch3_rd_dv;
    wire                  ch0_rd_last, ch1_rd_last, ch2_rd_last, ch3_rd_last;

    // =========================================================================
    // Channel → Master: write interfaces (flat)
    // =========================================================================
    wire [ADDR_WIDTH-1:0] ch0_wr_addr,   ch1_wr_addr,   ch2_wr_addr,   ch3_wr_addr;
    wire [7:0]            ch0_wr_len,    ch1_wr_len,    ch2_wr_len,    ch3_wr_len;
    wire                  ch0_wr_valid,  ch1_wr_valid,  ch2_wr_valid,  ch3_wr_valid;
    wire                  ch0_wr_ready,  ch1_wr_ready,  ch2_wr_ready,  ch3_wr_ready;
    wire [DATA_WIDTH-1:0] ch0_wr_data,   ch1_wr_data,   ch2_wr_data,   ch3_wr_data;
    wire [3:0]            ch0_wr_wstrb,  ch1_wr_wstrb,  ch2_wr_wstrb,  ch3_wr_wstrb;
    wire                  ch0_wr_wvalid, ch1_wr_wvalid, ch2_wr_wvalid, ch3_wr_wvalid;
    wire                  ch0_wr_wlast,  ch1_wr_wlast,  ch2_wr_wlast,  ch3_wr_wlast;
    wire                  ch0_wr_wready, ch1_wr_wready, ch2_wr_wready, ch3_wr_wready;
    wire [1:0]            ch0_wr_bresp,  ch1_wr_bresp,  ch2_wr_bresp,  ch3_wr_bresp;
    wire                  ch0_wr_bvalid, ch1_wr_bvalid, ch2_wr_bvalid, ch3_wr_bvalid;

    // =========================================================================
    // Muxed master interface (granted channel → axi_master)
    // =========================================================================
    wire [ADDR_WIDTH-1:0] mx_rd_addr;  wire [7:0] mx_rd_len;
    wire                  mx_rd_valid; wire       mx_rd_ready;
    wire [DATA_WIDTH-1:0] mx_rd_data;  wire       mx_rd_dv;
    wire                  mx_rd_last;

    wire [ADDR_WIDTH-1:0] mx_wr_addr;   wire [7:0] mx_wr_len;
    wire                  mx_wr_valid;  wire       mx_wr_ready;
    wire [DATA_WIDTH-1:0] mx_wr_data;   wire [3:0] mx_wr_wstrb;
    wire                  mx_wr_wvalid; wire       mx_wr_wlast;
    wire                  mx_wr_wready; wire [1:0] mx_wr_bresp;
    wire                  mx_wr_bvalid;

    // =========================================================================
    // u_reg_slave — AXI4 slave config
    // =========================================================================
    dma_reg_slave #(
        .ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH),
        .ID_WIDTH(ID_WIDTH),     .NUM_CH(NUM_CH)
    ) u_reg_slave (
        .clk   (clk),
        .rst_n (rst_n),
        .s_axi_awid    (S_AXI_AWID),    .s_axi_awaddr  (S_AXI_AWADDR),
        .s_axi_awlen   (S_AXI_AWLEN),   .s_axi_awsize  (S_AXI_AWSIZE),
        .s_axi_awburst (S_AXI_AWBURST), .s_axi_awprot  (S_AXI_AWPROT),  // [FIX-2]
        .s_axi_awvalid (S_AXI_AWVALID), .s_axi_awready (S_AXI_AWREADY),
        .s_axi_wdata   (S_AXI_WDATA),   .s_axi_wstrb   (S_AXI_WSTRB),
        .s_axi_wlast   (S_AXI_WLAST),   .s_axi_wvalid  (S_AXI_WVALID),
        .s_axi_wready  (S_AXI_WREADY),
        .s_axi_bid     (S_AXI_BID),     .s_axi_bresp   (S_AXI_BRESP),
        .s_axi_bvalid  (S_AXI_BVALID),  .s_axi_bready  (S_AXI_BREADY),
        .s_axi_arid    (S_AXI_ARID),    .s_axi_araddr  (S_AXI_ARADDR),
        .s_axi_arlen   (S_AXI_ARLEN),   .s_axi_arsize  (S_AXI_ARSIZE),
        .s_axi_arburst (S_AXI_ARBURST), .s_axi_arprot  (S_AXI_ARPROT),  // [FIX-2]
        .s_axi_arvalid (S_AXI_ARVALID), .s_axi_arready (S_AXI_ARREADY),
        .s_axi_rid     (S_AXI_RID),     .s_axi_rdata   (S_AXI_RDATA),
        .s_axi_rresp   (S_AXI_RRESP),   .s_axi_rlast   (S_AXI_RLAST),
        .s_axi_rvalid  (S_AXI_RVALID),  .s_axi_rready  (S_AXI_RREADY),
        .ch0_src(ch0_src), .ch0_dst(ch0_dst), .ch0_len(ch0_len),
        .ch0_mode(ch0_mode), .ch0_en(ch0_en), .ch0_start(ch0_start),
        .ch1_src(ch1_src), .ch1_dst(ch1_dst), .ch1_len(ch1_len),
        .ch1_mode(ch1_mode), .ch1_en(ch1_en), .ch1_start(ch1_start),
        .ch2_src(ch2_src), .ch2_dst(ch2_dst), .ch2_len(ch2_len),
        .ch2_mode(ch2_mode), .ch2_en(ch2_en), .ch2_start(ch2_start),
        .ch3_src(ch3_src), .ch3_dst(ch3_dst), .ch3_len(ch3_len),
        .ch3_mode(ch3_mode), .ch3_en(ch3_en), .ch3_start(ch3_start),
        .ch_done (ch_done_w),
        .ch_error(ch_error_w),
        .ch_busy (ch_busy_w),
        .irq_out (irq_out)
    );

    // =========================================================================
    // u_ch0..u_ch3 — DMA Channels
    // WHY: 4 channels độc lập, mỗi cái có line buffer riêng (64 bytes).
    // Một channel hoạt động một lúc trên mỗi bus (read bus / write bus).
    // [FIX-3] wr_bready và rd_data_rdy là outputs từ dma_channel (assign bên trong).
    //         Để () là OK: Verilog cho phép output port không nối.
    // =========================================================================
    dma_channel #(.ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)) u_ch0 (
        .clk(clk), .rst_n(rst_n),
        .cfg_src(ch0_src), .cfg_dst(ch0_dst), .cfg_len(ch0_len),
        .cfg_mode(ch0_mode), .cfg_en(ch0_en), .cfg_start(ch0_start),
        .periph_req(dma_req[0]), .periph_ack(ch_periph_ack_w[0]),
        .done(ch_done_w[0]), .error(ch_error_w[0]), .busy(ch_busy_w[0]),
        .rd_req(rd_req_w[0]), .rd_grant(rd_grant_w[0]), .rd_rel(rd_rel_w[0]),
        .wr_req(wr_req_w[0]), .wr_grant(wr_grant_w[0]), .wr_rel(wr_rel_w[0]),
        .rd_addr(ch0_rd_addr), .rd_len(ch0_rd_len),
        .rd_valid(ch0_rd_valid), .rd_ready(ch0_rd_ready),
        .rd_data(ch0_rd_data), .rd_data_v(ch0_rd_dv), .rd_last(ch0_rd_last),
        .rd_data_rdy(),
        .wr_addr(ch0_wr_addr), .wr_len(ch0_wr_len),
        .wr_valid(ch0_wr_valid), .wr_ready(ch0_wr_ready),
        .wr_data(ch0_wr_data), .wr_wstrb(ch0_wr_wstrb),
        .wr_wvalid(ch0_wr_wvalid), .wr_wlast(ch0_wr_wlast),
        .wr_wready(ch0_wr_wready), .wr_bresp(ch0_wr_bresp),
        .wr_bvalid(ch0_wr_bvalid), .wr_bready()
    );

    dma_channel #(.ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)) u_ch1 (
        .clk(clk), .rst_n(rst_n),
        .cfg_src(ch1_src), .cfg_dst(ch1_dst), .cfg_len(ch1_len),
        .cfg_mode(ch1_mode), .cfg_en(ch1_en), .cfg_start(ch1_start),
        .periph_req(dma_req[1]), .periph_ack(ch_periph_ack_w[1]),
        .done(ch_done_w[1]), .error(ch_error_w[1]), .busy(ch_busy_w[1]),
        .rd_req(rd_req_w[1]), .rd_grant(rd_grant_w[1]), .rd_rel(rd_rel_w[1]),
        .wr_req(wr_req_w[1]), .wr_grant(wr_grant_w[1]), .wr_rel(wr_rel_w[1]),
        .rd_addr(ch1_rd_addr), .rd_len(ch1_rd_len),
        .rd_valid(ch1_rd_valid), .rd_ready(ch1_rd_ready),
        .rd_data(ch1_rd_data), .rd_data_v(ch1_rd_dv), .rd_last(ch1_rd_last),
        .rd_data_rdy(),
        .wr_addr(ch1_wr_addr), .wr_len(ch1_wr_len),
        .wr_valid(ch1_wr_valid), .wr_ready(ch1_wr_ready),
        .wr_data(ch1_wr_data), .wr_wstrb(ch1_wr_wstrb),
        .wr_wvalid(ch1_wr_wvalid), .wr_wlast(ch1_wr_wlast),
        .wr_wready(ch1_wr_wready), .wr_bresp(ch1_wr_bresp),
        .wr_bvalid(ch1_wr_bvalid), .wr_bready()
    );

    dma_channel #(.ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)) u_ch2 (
        .clk(clk), .rst_n(rst_n),
        .cfg_src(ch2_src), .cfg_dst(ch2_dst), .cfg_len(ch2_len),
        .cfg_mode(ch2_mode), .cfg_en(ch2_en), .cfg_start(ch2_start),
        .periph_req(dma_req[2]), .periph_ack(ch_periph_ack_w[2]),
        .done(ch_done_w[2]), .error(ch_error_w[2]), .busy(ch_busy_w[2]),
        .rd_req(rd_req_w[2]), .rd_grant(rd_grant_w[2]), .rd_rel(rd_rel_w[2]),
        .wr_req(wr_req_w[2]), .wr_grant(wr_grant_w[2]), .wr_rel(wr_rel_w[2]),
        .rd_addr(ch2_rd_addr), .rd_len(ch2_rd_len),
        .rd_valid(ch2_rd_valid), .rd_ready(ch2_rd_ready),
        .rd_data(ch2_rd_data), .rd_data_v(ch2_rd_dv), .rd_last(ch2_rd_last),
        .rd_data_rdy(),
        .wr_addr(ch2_wr_addr), .wr_len(ch2_wr_len),
        .wr_valid(ch2_wr_valid), .wr_ready(ch2_wr_ready),
        .wr_data(ch2_wr_data), .wr_wstrb(ch2_wr_wstrb),
        .wr_wvalid(ch2_wr_wvalid), .wr_wlast(ch2_wr_wlast),
        .wr_wready(ch2_wr_wready), .wr_bresp(ch2_wr_bresp),
        .wr_bvalid(ch2_wr_bvalid), .wr_bready()
    );

    dma_channel #(.ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)) u_ch3 (
        .clk(clk), .rst_n(rst_n),
        .cfg_src(ch3_src), .cfg_dst(ch3_dst), .cfg_len(ch3_len),
        .cfg_mode(ch3_mode), .cfg_en(ch3_en), .cfg_start(ch3_start),
        .periph_req(dma_req[3]), .periph_ack(ch_periph_ack_w[3]),
        .done(ch_done_w[3]), .error(ch_error_w[3]), .busy(ch_busy_w[3]),
        .rd_req(rd_req_w[3]), .rd_grant(rd_grant_w[3]), .rd_rel(rd_rel_w[3]),
        .wr_req(wr_req_w[3]), .wr_grant(wr_grant_w[3]), .wr_rel(wr_rel_w[3]),
        .rd_addr(ch3_rd_addr), .rd_len(ch3_rd_len),
        .rd_valid(ch3_rd_valid), .rd_ready(ch3_rd_ready),
        .rd_data(ch3_rd_data), .rd_data_v(ch3_rd_dv), .rd_last(ch3_rd_last),
        .rd_data_rdy(),
        .wr_addr(ch3_wr_addr), .wr_len(ch3_wr_len),
        .wr_valid(ch3_wr_valid), .wr_ready(ch3_wr_ready),
        .wr_data(ch3_wr_data), .wr_wstrb(ch3_wr_wstrb),
        .wr_wvalid(ch3_wr_wvalid), .wr_wlast(ch3_wr_wlast),
        .wr_wready(ch3_wr_wready), .wr_bresp(ch3_wr_bresp),
        .wr_bvalid(ch3_wr_bvalid), .wr_bready()
    );

    assign dma_busy_o = |ch_busy_w;

    // =========================================================================
    // u_arbiter — Round-robin
    // =========================================================================
    dma_arbiter #(.NUM_CH(NUM_CH)) u_arbiter (
        .clk     (clk),     .rst_n   (rst_n),
        .rd_req  (rd_req_w), .rd_grant(rd_grant_w), .rd_rel(rd_rel_w),
        .wr_req  (wr_req_w), .wr_grant(wr_grant_w), .wr_rel(wr_rel_w)
    );

    // =========================================================================
    // Read MUX: channel được rd_grant → axi_master
    // WHY: Chỉ 1 channel được grant tại một thời điểm →
    // priority mux đơn giản là đủ (không xảy ra 2 grant cùng lúc).
    // =========================================================================
    assign mx_rd_addr  = rd_grant_w[0] ? ch0_rd_addr  :
                         rd_grant_w[1] ? ch1_rd_addr  :
                         rd_grant_w[2] ? ch2_rd_addr  : ch3_rd_addr;
    assign mx_rd_len   = rd_grant_w[0] ? ch0_rd_len   :
                         rd_grant_w[1] ? ch1_rd_len   :
                         rd_grant_w[2] ? ch2_rd_len   : ch3_rd_len;
    assign mx_rd_valid = rd_grant_w[0] ? ch0_rd_valid :
                         rd_grant_w[1] ? ch1_rd_valid :
                         rd_grant_w[2] ? ch2_rd_valid :
                         rd_grant_w[3] ? ch3_rd_valid : 1'b0;

    // Read DEMUX: rd_ready / data / dv / last → channel được grant
    assign ch0_rd_ready = rd_grant_w[0] & mx_rd_ready;
    assign ch1_rd_ready = rd_grant_w[1] & mx_rd_ready;
    assign ch2_rd_ready = rd_grant_w[2] & mx_rd_ready;
    assign ch3_rd_ready = rd_grant_w[3] & mx_rd_ready;

    // Data broadcast: channel lọc bằng dv gated
    assign ch0_rd_data = mx_rd_data; assign ch1_rd_data = mx_rd_data;
    assign ch2_rd_data = mx_rd_data; assign ch3_rd_data = mx_rd_data;

    assign ch0_rd_dv   = rd_grant_w[0] & mx_rd_dv;
    assign ch1_rd_dv   = rd_grant_w[1] & mx_rd_dv;
    assign ch2_rd_dv   = rd_grant_w[2] & mx_rd_dv;
    assign ch3_rd_dv   = rd_grant_w[3] & mx_rd_dv;

    assign ch0_rd_last = rd_grant_w[0] & mx_rd_last;
    assign ch1_rd_last = rd_grant_w[1] & mx_rd_last;
    assign ch2_rd_last = rd_grant_w[2] & mx_rd_last;
    assign ch3_rd_last = rd_grant_w[3] & mx_rd_last;

    // =========================================================================
    // Write MUX: channel được wr_grant → axi_master
    // =========================================================================
    assign mx_wr_addr   = wr_grant_w[0] ? ch0_wr_addr   :
                          wr_grant_w[1] ? ch1_wr_addr   :
                          wr_grant_w[2] ? ch2_wr_addr   : ch3_wr_addr;
    assign mx_wr_len    = wr_grant_w[0] ? ch0_wr_len    :
                          wr_grant_w[1] ? ch1_wr_len    :
                          wr_grant_w[2] ? ch2_wr_len    : ch3_wr_len;
    assign mx_wr_valid  = wr_grant_w[0] ? ch0_wr_valid  :
                          wr_grant_w[1] ? ch1_wr_valid  :
                          wr_grant_w[2] ? ch2_wr_valid  :
                          wr_grant_w[3] ? ch3_wr_valid  : 1'b0;
    assign mx_wr_data   = wr_grant_w[0] ? ch0_wr_data   :
                          wr_grant_w[1] ? ch1_wr_data   :
                          wr_grant_w[2] ? ch2_wr_data   : ch3_wr_data;
    assign mx_wr_wstrb  = wr_grant_w[0] ? ch0_wr_wstrb  :
                          wr_grant_w[1] ? ch1_wr_wstrb  :
                          wr_grant_w[2] ? ch2_wr_wstrb  : ch3_wr_wstrb;
    assign mx_wr_wvalid = wr_grant_w[0] ? ch0_wr_wvalid :
                          wr_grant_w[1] ? ch1_wr_wvalid :
                          wr_grant_w[2] ? ch2_wr_wvalid :
                          wr_grant_w[3] ? ch3_wr_wvalid : 1'b0;
    assign mx_wr_wlast  = wr_grant_w[0] ? ch0_wr_wlast  :
                          wr_grant_w[1] ? ch1_wr_wlast  :
                          wr_grant_w[2] ? ch2_wr_wlast  : ch3_wr_wlast;

    // Write DEMUX
    assign ch0_wr_ready  = wr_grant_w[0] & mx_wr_ready;
    assign ch1_wr_ready  = wr_grant_w[1] & mx_wr_ready;
    assign ch2_wr_ready  = wr_grant_w[2] & mx_wr_ready;
    assign ch3_wr_ready  = wr_grant_w[3] & mx_wr_ready;

    assign ch0_wr_wready = wr_grant_w[0] & mx_wr_wready;
    assign ch1_wr_wready = wr_grant_w[1] & mx_wr_wready;
    assign ch2_wr_wready = wr_grant_w[2] & mx_wr_wready;
    assign ch3_wr_wready = wr_grant_w[3] & mx_wr_wready;

    assign ch0_wr_bresp  = mx_wr_bresp; assign ch1_wr_bresp  = mx_wr_bresp;
    assign ch2_wr_bresp  = mx_wr_bresp; assign ch3_wr_bresp  = mx_wr_bresp;

    assign ch0_wr_bvalid = wr_grant_w[0] & mx_wr_bvalid;
    assign ch1_wr_bvalid = wr_grant_w[1] & mx_wr_bvalid;
    assign ch2_wr_bvalid = wr_grant_w[2] & mx_wr_bvalid;
    assign ch3_wr_bvalid = wr_grant_w[3] & mx_wr_bvalid;

    // =========================================================================
    // u_axi_master — AXI4 Master (M3)
    // =========================================================================
    dma_axi_master #(
        .ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH), .ID_WIDTH(ID_WIDTH)
    ) u_axi_master (
        .clk   (clk),
        .rst_n (rst_n),

        .m_axi_arid    (M_AXI_ARID),    .m_axi_araddr  (M_AXI_ARADDR),
        .m_axi_arlen   (M_AXI_ARLEN),   .m_axi_arsize  (M_AXI_ARSIZE),
        .m_axi_arburst (M_AXI_ARBURST), .m_axi_arprot  (M_AXI_ARPROT),
        .m_axi_arvalid (M_AXI_ARVALID), .m_axi_arready (M_AXI_ARREADY),
        .m_axi_rid     (M_AXI_RID),     .m_axi_rdata   (M_AXI_RDATA),
        .m_axi_rresp   (M_AXI_RRESP),   .m_axi_rlast   (M_AXI_RLAST),
        .m_axi_rvalid  (M_AXI_RVALID),  .m_axi_rready  (M_AXI_RREADY),
        .m_axi_awid    (M_AXI_AWID),    .m_axi_awaddr  (M_AXI_AWADDR),
        .m_axi_awlen   (M_AXI_AWLEN),   .m_axi_awsize  (M_AXI_AWSIZE),
        .m_axi_awburst (M_AXI_AWBURST), .m_axi_awprot  (M_AXI_AWPROT),
        .m_axi_awvalid (M_AXI_AWVALID), .m_axi_awready (M_AXI_AWREADY),
        .m_axi_wdata   (M_AXI_WDATA),   .m_axi_wstrb   (M_AXI_WSTRB),
        .m_axi_wlast   (M_AXI_WLAST),   .m_axi_wvalid  (M_AXI_WVALID),
        .m_axi_wready  (M_AXI_WREADY),
        .m_axi_bid     (M_AXI_BID),     .m_axi_bresp   (M_AXI_BRESP),
        .m_axi_bvalid  (M_AXI_BVALID),  .m_axi_bready  (M_AXI_BREADY),

        .rd_addr    (mx_rd_addr),  .rd_len     (mx_rd_len),
        .rd_valid   (mx_rd_valid), .rd_ready   (mx_rd_ready),
        .rd_data    (mx_rd_data),  .rd_data_v  (mx_rd_dv),
        .rd_last    (mx_rd_last),  .rd_data_rdy(1'b1),

        .wr_addr    (mx_wr_addr),   .wr_len    (mx_wr_len),
        .wr_valid   (mx_wr_valid),  .wr_ready  (mx_wr_ready),
        .wr_data    (mx_wr_data),   .wr_wstrb  (mx_wr_wstrb),
        .wr_wvalid  (mx_wr_wvalid), .wr_wlast  (mx_wr_wlast),
        .wr_wready  (mx_wr_wready), .wr_bresp  (mx_wr_bresp),
        .wr_bvalid  (mx_wr_bvalid), .wr_bready (1'b1)
    );

endmodule

// ==============================================================================
// FILE: uart_boot_ctrl.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// uart_boot_ctrl.v — UART-based Boot Controller
//
// Thay thế boot_ctrl (ROM-based). Hai chế độ hoạt động:
//
//   SIM_MODE=1  : Dùng $readmemh nội bộ, copy 1 word/cycle (giống boot_ctrl cũ).
//                 Dùng cho simulation — không tốn 71M cycles chờ UART.
//
//   SIM_MODE=0  : Nhận chương trình qua UART RX (8N1, BAUD_RATE bps).
//                 Protocol: host gửi đúng PROG_WORDS × 4 bytes, little-endian,
//                 không header, không ACK. boot_done sau khi nhận đủ.
//
// UART RX timing (SIM_MODE=0):
//   - Detect start bit: uart_rx falls to 0
//   - Sample center of start bit sau BAUD_HALF cycles
//   - Sample mỗi data bit sau BAUD_FULL cycles
//   - Byte assembly: 4 bytes → 1 word, little-endian (byte đầu = LSB)
//   - Mỗi 4 bytes: write 1 word vào IMEM qua sideband port
//
// Interface giống boot_ctrl + thêm uart_rx.
// ============================================================================

module uart_boot_ctrl #(
    parameter CLK_FREQ   = 100_000_000,   // Hz
    parameter BAUD_RATE  = 115200,
    parameter PROG_WORDS = 2048,          // = IMEM_SIZE / 4
    parameter SIM_MODE   = 0,             // 0=UART RX, 1=fast $readmemh
    parameter BOOT_FILE  = "memory/program.hex"
)(
    input  wire        clk,
    input  wire        rst_n,      // fabric_rst_n (async active-low)
    input  wire        uart_rx,    // từ pad; idle = 1'b1 (SIM_MODE=1 không dùng)

    // IMEM sideband write port
    output reg         boot_we,
    output reg  [31:0] boot_addr,  // byte address vào IMEM
    output reg  [31:0] boot_wdata,

    output reg         boot_done   // sticky, gates cpu_rst_n release
);

localparam ADDR_W   = $clog2(PROG_WORDS);

// ============================================================================
// SIM_MODE=1: Fast ROM load — $readmemh + copy 1 word/cycle
// ============================================================================
generate
if (SIM_MODE == 1) begin : g_sim

    localparam [1:0] SS_IDLE  = 2'd0,
                     SS_WRITE = 2'd1,
                     SS_DONE  = 2'd2;

    reg [31:0]           mem [0:PROG_WORDS-1];
    reg [1:0]            state;
    reg [ADDR_W-1:0]     widx;

    initial $readmemh(BOOT_FILE, mem);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state      <= SS_IDLE;
            widx       <= {ADDR_W{1'b0}};
            boot_we    <= 1'b0;
            boot_addr  <= 32'h0;
            boot_wdata <= 32'h0;
            boot_done  <= 1'b0;
        end else begin
            case (state)
                SS_IDLE: begin
                    state <= SS_WRITE;
                    widx  <= {ADDR_W{1'b0}};
                    boot_we <= 1'b0;
                end

                SS_WRITE: begin
                    boot_we    <= 1'b1;
                    boot_addr  <= {{(32-ADDR_W-2){1'b0}}, widx, 2'b00};
                    boot_wdata <= mem[widx];
                    if (widx == PROG_WORDS - 1) begin
                        state <= SS_DONE;
                    end else begin
                        widx <= widx + 1'b1;
                    end
                end

                SS_DONE: begin
                    boot_we   <= 1'b0;
                    boot_done <= 1'b1;
                end

                default: state <= SS_IDLE;
            endcase
        end
    end

end else begin : g_uart

// ============================================================================
// SIM_MODE=0: UART RX boot — 8N1, PROG_WORDS × 4 bytes, little-endian
// ============================================================================

// Baud rate constants
localparam [19:0] BAUD_FULL = CLK_FREQ / BAUD_RATE - 1;      // full bit period - 1
localparam [19:0] BAUD_HALF = CLK_FREQ / BAUD_RATE / 2 - 1;  // half-period - 1 (center sample)

localparam [2:0]
    ST_IDLE   = 3'd0,   // uart_rx=1, wait start bit
    ST_CENTER = 3'd1,   // count half-period, verify start bit
    ST_DATA   = 3'd2,   // receive 8 data bits (LSB first)
    ST_STOP   = 3'd3,   // wait stop bit, then process byte
    ST_DONE   = 3'd4;   // boot_done=1, sticky

reg [2:0]         state;
reg [19:0]        tick_cnt;   // baud counter
reg [2:0]         bit_cnt;    // bit index [0..7]
reg [1:0]         byte_cnt;   // byte index in current word [0..3]
reg [7:0]         byte_reg;   // received byte (shifts in LSB first)
reg [23:0]        word_buf;   // lower 3 bytes of assembled word
reg [ADDR_W-1:0]  word_idx;   // next word address

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state      <= ST_IDLE;
        tick_cnt   <= 20'h0;
        bit_cnt    <= 3'd0;
        byte_cnt   <= 2'd0;
        byte_reg   <= 8'h0;
        word_buf   <= 24'h0;
        word_idx   <= {ADDR_W{1'b0}};
        boot_we    <= 1'b0;
        boot_addr  <= 32'h0;
        boot_wdata <= 32'h0;
        boot_done  <= 1'b0;
    end else begin
        // Default: boot_we bị clear mỗi cycle; override trong ST_STOP khi word done
        boot_we <= 1'b0;

        case (state)

            // ── IDLE: đợi start bit (uart_rx falls to 0) ──────────────────────
            ST_IDLE: begin
                if (!uart_rx) begin
                    tick_cnt <= 20'h0;
                    state    <= ST_CENTER;
                end
            end

            // ── CENTER: đợi nửa baud period, xác nhận start bit ───────────────
            ST_CENTER: begin
                if (tick_cnt == BAUD_HALF) begin
                    tick_cnt <= 20'h0;
                    if (!uart_rx) begin
                        // Start bit hợp lệ → bắt đầu nhận data
                        bit_cnt <= 3'd0;
                        state   <= ST_DATA;
                    end else begin
                        // Noise glitch — bỏ qua
                        state   <= ST_IDLE;
                    end
                end else begin
                    tick_cnt <= tick_cnt + 20'h1;
                end
            end

            // ── DATA: sample 8 bits (LSB first, mỗi bit cách nhau BAUD_FULL) ──
            ST_DATA: begin
                if (tick_cnt == BAUD_FULL) begin
                    tick_cnt <= 20'h0;
                    // Shift in bit (LSB first)
                    byte_reg <= {uart_rx, byte_reg[7:1]};
                    if (bit_cnt == 3'd7) begin
                        bit_cnt <= 3'd0;
                        state   <= ST_STOP;
                    end else begin
                        bit_cnt <= bit_cnt + 3'd1;
                    end
                end else begin
                    tick_cnt <= tick_cnt + 20'h1;
                end
            end

            // ── STOP: đợi stop bit period, sau đó xử lý byte ──────────────────
            ST_STOP: begin
                if (tick_cnt == BAUD_FULL) begin
                    tick_cnt <= 20'h0;
                    // Không kiểm tra stop bit (uart_rx nên = 1)
                    if (byte_cnt == 2'd3) begin
                        // Byte thứ 4 → word hoàn chỉnh
                        // word = {byte3(MSB), byte2, byte1, byte0(LSB)} = little-endian
                        boot_we    <= 1'b1;
                        boot_addr  <= {{(32-ADDR_W-2){1'b0}}, word_idx, 2'b00};
                        boot_wdata <= {byte_reg, word_buf};  // {byte3, byte2, byte1, byte0}
                        byte_cnt   <= 2'd0;
                        if (word_idx == PROG_WORDS - 1) begin
                            // Từ cuối cùng → boot done
                            state <= ST_DONE;
                        end else begin
                            word_idx <= word_idx + 1;
                            state    <= ST_IDLE;
                        end
                    end else begin
                        // Byte 0,1,2 → tích lũy vào word_buf
                        case (byte_cnt)
                            2'd0: word_buf[7:0]   <= byte_reg;
                            2'd1: word_buf[15:8]  <= byte_reg;
                            2'd2: word_buf[23:16] <= byte_reg;
                            default: ;
                        endcase
                        byte_cnt <= byte_cnt + 2'd1;
                        state    <= ST_IDLE;
                    end
                end else begin
                    tick_cnt <= tick_cnt + 20'h1;
                end
            end

            // ── DONE: boot_done sticky, CPU released bởi clk_reset_ctrl ───────
            ST_DONE: begin
                boot_done <= 1'b1;
            end

            default: state <= ST_IDLE;

        endcase
    end
end

end // g_uart
endgenerate

endmodule

// ==============================================================================
// FILE: gpio_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// gpio_top.v — GPIO Peripheral Top-Level (AXI4-Full Slave S6)
//
// Address: 0x5001_0000 (S6 in crossbar), 4 KB
// Clock: clk_periph domain
//
// Hierarchy:
//   gpio_top
//   ├── gpio_regfile  — AXI4-Full slave + register file
//   └── gpio_iocell   — 2-FF synchronizer + edge/level IRQ detector
//
// IO interface (split in/out/oe for simulation; use wrapper for inout pads):
//   gpio_out[31:0]  — driven to output pads when gpio_oe=1
//   gpio_oe[31:0]   — output enable (1=drive, 0=high-Z)
//   gpio_in[31:0]   — sampled from input pads
// ============================================================================


// ==============================================================================
// FILE: gpio_regfile.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// gpio_regfile.v — GPIO Register File with AXI4-Lite Slave Interface
//
// Address: 0x5001_0000 (S6 in crossbar)
// Register Map (all 32-bit, word-aligned):
//   0x00  DIR       direction (1=output, 0=input per bit)
//   0x04  DOUT      data output register
//   0x08  DIN       data input (read-only, from gpio_iocell din_sync)
//   0x0C  IRQ_EN    interrupt enable per bit
//   0x10  IRQ_STAT  interrupt status (W1C — write 1 to clear)
//   0x14  IRQ_MODE  0=level, 1=edge per bit
//   0x18  IRQ_POL   0=falling/low, 1=rising/high per bit
// ============================================================================

module gpio_regfile #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter GPIO_WIDTH = 32
)(
    input  wire clk,
    input  wire rst_n,

    // AXI4-Lite slave (simplified: no burst, single beat only)
    input  wire [ID_WIDTH-1:0]      S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_AWADDR,
    input  wire [7:0]               S_AXI_AWLEN,
    input  wire [2:0]               S_AXI_AWSIZE,
    input  wire [1:0]               S_AXI_AWBURST,
    input  wire [2:0]               S_AXI_AWPROT,
    input  wire                     S_AXI_AWVALID,
    output wire                     S_AXI_AWREADY,

    input  wire [DATA_WIDTH-1:0]    S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0]  S_AXI_WSTRB,
    input  wire                     S_AXI_WLAST,
    input  wire                     S_AXI_WVALID,
    output wire                     S_AXI_WREADY,

    output reg  [ID_WIDTH-1:0]      S_AXI_BID,
    output reg  [1:0]               S_AXI_BRESP,
    output reg                      S_AXI_BVALID,
    input  wire                     S_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]      S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_ARADDR,
    input  wire [7:0]               S_AXI_ARLEN,
    input  wire [2:0]               S_AXI_ARSIZE,
    input  wire [1:0]               S_AXI_ARBURST,
    input  wire [2:0]               S_AXI_ARPROT,
    input  wire                     S_AXI_ARVALID,
    output wire                     S_AXI_ARREADY,

    output reg  [ID_WIDTH-1:0]      S_AXI_RID,
    output reg  [DATA_WIDTH-1:0]    S_AXI_RDATA,
    output reg  [1:0]               S_AXI_RRESP,
    output reg                      S_AXI_RLAST,
    output reg                      S_AXI_RVALID,
    input  wire                     S_AXI_RREADY,

    // GPIO register outputs to iocell
    output reg  [GPIO_WIDTH-1:0]    dir_reg,
    output reg  [GPIO_WIDTH-1:0]    dout_reg,
    output reg  [GPIO_WIDTH-1:0]    irq_en,
    output reg  [GPIO_WIDTH-1:0]    irq_mode,
    output reg  [GPIO_WIDTH-1:0]    irq_pol,

    // GPIO register inputs from iocell
    input  wire [GPIO_WIDTH-1:0]    din_sync,
    input  wire [GPIO_WIDTH-1:0]    irq_raw       // edge/level detect from iocell
);

    localparam RESP_OKAY   = 2'b00;
    localparam RESP_SLVERR = 2'b10;

    // Register addresses (byte, relative to S6_BASE)
    localparam REG_DIR      = 7'h00;
    localparam REG_DOUT     = 7'h04;
    localparam REG_DIN      = 7'h08;
    localparam REG_IRQ_EN   = 7'h0C;
    localparam REG_IRQ_STAT = 7'h10;
    localparam REG_IRQ_MODE = 7'h14;
    localparam REG_IRQ_POL  = 7'h18;

    // IRQ status register (W1C)
    reg [GPIO_WIDTH-1:0] irq_stat;

    // Latch IRQ raw into irq_stat (set on edge/level, cleared by W1C write)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            irq_stat <= {GPIO_WIDTH{1'b0}};
        else
            irq_stat <= (irq_stat | (irq_raw & irq_en)) & ~irq_stat_clr;
    end

    reg [GPIO_WIDTH-1:0] irq_stat_clr;

    // =========================================================================
    // Write FSM
    // =========================================================================
    localparam WR_IDLE = 2'b00, WR_DATA = 2'b01, WR_RESP = 2'b10;
    reg [1:0]            wr_state;
    reg [ADDR_WIDTH-1:0] wr_addr_r;
    reg [ID_WIDTH-1:0]   bid_r;

    assign S_AXI_AWREADY = (wr_state == WR_IDLE);
    assign S_AXI_WREADY  = (wr_state == WR_DATA);

    function [DATA_WIDTH-1:0] apply_strb;
        input [DATA_WIDTH-1:0]   old_val;
        input [DATA_WIDTH-1:0]   new_val;
        input [DATA_WIDTH/8-1:0] strb;
        integer k;
        begin
            apply_strb = old_val;
            for (k = 0; k < DATA_WIDTH/8; k = k + 1)
                if (strb[k]) apply_strb[k*8 +: 8] = new_val[k*8 +: 8];
        end
    endfunction

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state     <= WR_IDLE;
            wr_addr_r    <= {ADDR_WIDTH{1'b0}};
            bid_r        <= {ID_WIDTH{1'b0}};
            S_AXI_BID    <= {ID_WIDTH{1'b0}};
            S_AXI_BRESP  <= RESP_OKAY;
            S_AXI_BVALID <= 1'b0;
            dir_reg      <= {GPIO_WIDTH{1'b0}};
            dout_reg     <= {GPIO_WIDTH{1'b0}};
            irq_en       <= {GPIO_WIDTH{1'b0}};
            irq_mode     <= {GPIO_WIDTH{1'b0}};
            irq_pol      <= {GPIO_WIDTH{1'b0}};
            irq_stat_clr <= {GPIO_WIDTH{1'b0}};
        end else begin
            irq_stat_clr <= {GPIO_WIDTH{1'b0}};

            case (wr_state)
                WR_IDLE: begin
                    if (S_AXI_AWVALID) begin
                        wr_addr_r <= S_AXI_AWADDR;
                        bid_r     <= S_AXI_AWID;
                        wr_state  <= WR_DATA;
                    end
                end
                WR_DATA: begin
                    if (S_AXI_WVALID) begin
                        case (wr_addr_r[6:0])
                            REG_DIR:      dir_reg  <= apply_strb(dir_reg,  S_AXI_WDATA, S_AXI_WSTRB);
                            REG_DOUT:     dout_reg <= apply_strb(dout_reg, S_AXI_WDATA, S_AXI_WSTRB);
                            REG_IRQ_EN:   irq_en   <= apply_strb(irq_en,   S_AXI_WDATA, S_AXI_WSTRB);
                            REG_IRQ_STAT: irq_stat_clr <= S_AXI_WDATA & S_AXI_WSTRB;  // W1C
                            REG_IRQ_MODE: irq_mode <= apply_strb(irq_mode, S_AXI_WDATA, S_AXI_WSTRB);
                            REG_IRQ_POL:  irq_pol  <= apply_strb(irq_pol,  S_AXI_WDATA, S_AXI_WSTRB);
                            default: ;    // DIN is read-only, writes ignored
                        endcase

                        if (S_AXI_WLAST) begin
                            S_AXI_BID    <= bid_r;
                            S_AXI_BRESP  <= RESP_OKAY;
                            S_AXI_BVALID <= 1'b1;
                            wr_state     <= WR_RESP;
                        end else begin
                            wr_addr_r <= wr_addr_r + 4;
                        end
                    end
                end
                WR_RESP: begin
                    if (S_AXI_BREADY) begin
                        S_AXI_BVALID <= 1'b0;
                        wr_state     <= WR_IDLE;
                    end
                end
                default: wr_state <= WR_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Read FSM
    // =========================================================================
    localparam RD_IDLE = 1'b0, RD_DATA = 1'b1;
    reg rd_state;

    assign S_AXI_ARREADY = (rd_state == RD_IDLE);

    reg [ADDR_WIDTH-1:0] rd_addr_r;
    reg [ID_WIDTH-1:0]   rid_r;
    reg [7:0]            rd_len_r;

    function [DATA_WIDTH-1:0] reg_read;
        input [6:0] addr;
        begin
            case (addr)
                REG_DIR:      reg_read = dir_reg;
                REG_DOUT:     reg_read = dout_reg;
                REG_DIN:      reg_read = din_sync;
                REG_IRQ_EN:   reg_read = irq_en;
                REG_IRQ_STAT: reg_read = irq_stat;
                REG_IRQ_MODE: reg_read = irq_mode;
                REG_IRQ_POL:  reg_read = irq_pol;
                default:      reg_read = {DATA_WIDTH{1'b0}};
            endcase
        end
    endfunction

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state    <= RD_IDLE;
            S_AXI_RID   <= {ID_WIDTH{1'b0}};
            S_AXI_RDATA <= {DATA_WIDTH{1'b0}};
            S_AXI_RRESP <= RESP_OKAY;
            S_AXI_RLAST <= 1'b0;
            S_AXI_RVALID<= 1'b0;
            rd_addr_r   <= {ADDR_WIDTH{1'b0}};
            rid_r       <= {ID_WIDTH{1'b0}};
            rd_len_r    <= 8'd0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    if (S_AXI_ARVALID) begin
                        rid_r     <= S_AXI_ARID;
                        rd_addr_r <= S_AXI_ARADDR;
                        rd_len_r  <= S_AXI_ARLEN;
                        S_AXI_RID    <= S_AXI_ARID;
                        S_AXI_RDATA  <= reg_read(S_AXI_ARADDR[6:0]);
                        S_AXI_RRESP  <= RESP_OKAY;
                        S_AXI_RLAST  <= (S_AXI_ARLEN == 8'd0);
                        S_AXI_RVALID <= 1'b1;
                        rd_state     <= RD_DATA;
                    end
                end
                RD_DATA: begin
                    if (S_AXI_RREADY) begin
                        if (S_AXI_RLAST) begin
                            S_AXI_RVALID <= 1'b0;
                            rd_state     <= RD_IDLE;
                        end else begin
                            rd_len_r    <= rd_len_r - 8'd1;
                            rd_addr_r   <= rd_addr_r + 4;
                            S_AXI_RDATA <= reg_read(rd_addr_r[6:0] + 7'd4);
                            S_AXI_RLAST <= (rd_len_r == 8'd1);
                        end
                    end
                end
                default: rd_state <= RD_IDLE;
            endcase
        end
    end

endmodule

// ==============================================================================
// FILE: gpio_iocell.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// gpio_iocell.v — GPIO IO Cell (Input synchronizer + interrupt detector)
//
// Per-pin responsibilities:
//   - 2-FF synchronizer on input path to avoid metastability
//   - Edge detector (rising / falling) for edge-triggered IRQ
//   - Level comparator for level-triggered IRQ
//   - OR-reduce all active IRQ bits → single gpio_irq output
// ============================================================================

module gpio_iocell #(
    parameter GPIO_WIDTH = 32
)(
    input  wire                    clk,
    input  wire                    rst_n,

    // Raw IO signals (from pads, split to separate in/out/oe for simulation)
    input  wire [GPIO_WIDTH-1:0]   gpio_in_pad,   // sampled from pads
    input  wire [GPIO_WIDTH-1:0]   dir_reg,        // 1=output, 0=input
    input  wire [GPIO_WIDTH-1:0]   dout_reg,       // output data
    output wire [GPIO_WIDTH-1:0]   gpio_out_pad,   // drive to pads
    output wire [GPIO_WIDTH-1:0]   gpio_oe_pad,    // output enable

    // Synchronized input (for register read)
    output wire [GPIO_WIDTH-1:0]   din_sync,

    // IRQ configuration
    input  wire [GPIO_WIDTH-1:0]   irq_en,
    input  wire [GPIO_WIDTH-1:0]   irq_mode,   // 1=edge, 0=level
    input  wire [GPIO_WIDTH-1:0]   irq_pol,    // 1=rising/high, 0=falling/low

    // IRQ status (raw, before enable mask — captured in regfile as W1C)
    output wire [GPIO_WIDTH-1:0]   irq_raw,

    // Aggregated IRQ to PLIC
    output wire                    gpio_irq
);

    // ── Output drive ─────────────────────────────────────────────────────────
    assign gpio_out_pad = dout_reg;
    assign gpio_oe_pad  = dir_reg;   // 1=output enable

    // ── 2-FF synchronizer on input path ──────────────────────────────────────
    reg [GPIO_WIDTH-1:0] sync_ff1, sync_ff2;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sync_ff1 <= {GPIO_WIDTH{1'b0}};
            sync_ff2 <= {GPIO_WIDTH{1'b0}};
        end else begin
            sync_ff1 <= gpio_in_pad;
            sync_ff2 <= sync_ff1;
        end
    end

    assign din_sync = sync_ff2;

    // ── Edge detector ────────────────────────────────────────────────────────
    reg [GPIO_WIDTH-1:0] sync_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sync_prev <= {GPIO_WIDTH{1'b0}};
        else
            sync_prev <= sync_ff2;
    end

    // Rising edge: 0→1 when irq_pol=1; Falling edge: 1→0 when irq_pol=0
    wire [GPIO_WIDTH-1:0] rising  = ~sync_prev &  sync_ff2;
    wire [GPIO_WIDTH-1:0] falling =  sync_prev & ~sync_ff2;
    wire [GPIO_WIDTH-1:0] edge_det = (irq_pol & rising) | (~irq_pol & falling);

    // Level: high when irq_pol=1; low when irq_pol=0
    wire [GPIO_WIDTH-1:0] level_det = irq_pol ? sync_ff2 : ~sync_ff2;

    // Raw IRQ per bit: edge or level depending on irq_mode
    assign irq_raw = irq_mode ? edge_det : level_det;

    // Aggregated: OR of all (irq_raw & irq_en)
    assign gpio_irq = |(irq_raw & irq_en);

endmodule

module gpio_top #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4,
    parameter GPIO_WIDTH = 32
)(
    input  wire clk,
    input  wire rst_n,

    // ── AXI4-Full Slave (S6) ─────────────────────────────────────────────────
    input  wire [ID_WIDTH-1:0]      S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_AWADDR,
    input  wire [7:0]               S_AXI_AWLEN,
    input  wire [2:0]               S_AXI_AWSIZE,
    input  wire [1:0]               S_AXI_AWBURST,
    input  wire [2:0]               S_AXI_AWPROT,
    input  wire                     S_AXI_AWVALID,
    output wire                     S_AXI_AWREADY,

    input  wire [DATA_WIDTH-1:0]    S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0]  S_AXI_WSTRB,
    input  wire                     S_AXI_WLAST,
    input  wire                     S_AXI_WVALID,
    output wire                     S_AXI_WREADY,

    output wire [ID_WIDTH-1:0]      S_AXI_BID,
    output wire [1:0]               S_AXI_BRESP,
    output wire                     S_AXI_BVALID,
    input  wire                     S_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]      S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_ARADDR,
    input  wire [7:0]               S_AXI_ARLEN,
    input  wire [2:0]               S_AXI_ARSIZE,
    input  wire [1:0]               S_AXI_ARBURST,
    input  wire [2:0]               S_AXI_ARPROT,
    input  wire                     S_AXI_ARVALID,
    output wire                     S_AXI_ARREADY,

    output wire [ID_WIDTH-1:0]      S_AXI_RID,
    output wire [DATA_WIDTH-1:0]    S_AXI_RDATA,
    output wire [1:0]               S_AXI_RRESP,
    output wire                     S_AXI_RLAST,
    output wire                     S_AXI_RVALID,
    input  wire                     S_AXI_RREADY,

    // ── GPIO IO pads (split for simulation) ──────────────────────────────────
    output wire [GPIO_WIDTH-1:0]    gpio_out,   // pad output data
    output wire [GPIO_WIDTH-1:0]    gpio_oe,    // pad output enable
    input  wire [GPIO_WIDTH-1:0]    gpio_in,    // pad input data

    // ── IRQ to PLIC ───────────────────────────────────────────────────────────
    output wire                     gpio_irq,
    output wire                     gpio_wake_armed_o,

    // ── AON wake interface (clk_aon domain) ──────────────────────────────────
    input  wire                     clk_aon,
    input  wire                     aon_rst_n,
    input  wire                     wake_ack,
    output wire                     gpio_wake_req
);

    // Internal wires between regfile and iocell
    wire [GPIO_WIDTH-1:0] dir_reg_w;
    wire [GPIO_WIDTH-1:0] dout_reg_w;
    wire [GPIO_WIDTH-1:0] irq_en_w;
    wire [GPIO_WIDTH-1:0] irq_mode_w;
    wire [GPIO_WIDTH-1:0] irq_pol_w;
    wire [GPIO_WIDTH-1:0] din_sync_w;
    wire [GPIO_WIDTH-1:0] irq_raw_w;

    gpio_regfile #(
        .ADDR_WIDTH (ADDR_WIDTH),
        .DATA_WIDTH (DATA_WIDTH),
        .ID_WIDTH   (ID_WIDTH),
        .GPIO_WIDTH (GPIO_WIDTH)
    ) u_regfile (
        .clk           (clk),
        .rst_n         (rst_n),

        .S_AXI_AWID    (S_AXI_AWID),   .S_AXI_AWADDR  (S_AXI_AWADDR),
        .S_AXI_AWLEN   (S_AXI_AWLEN),  .S_AXI_AWSIZE  (S_AXI_AWSIZE),
        .S_AXI_AWBURST (S_AXI_AWBURST),.S_AXI_AWPROT  (S_AXI_AWPROT),
        .S_AXI_AWVALID (S_AXI_AWVALID),.S_AXI_AWREADY (S_AXI_AWREADY),
        .S_AXI_WDATA   (S_AXI_WDATA),  .S_AXI_WSTRB   (S_AXI_WSTRB),
        .S_AXI_WLAST   (S_AXI_WLAST),  .S_AXI_WVALID  (S_AXI_WVALID),
        .S_AXI_WREADY  (S_AXI_WREADY),
        .S_AXI_BID     (S_AXI_BID),    .S_AXI_BRESP   (S_AXI_BRESP),
        .S_AXI_BVALID  (S_AXI_BVALID), .S_AXI_BREADY  (S_AXI_BREADY),
        .S_AXI_ARID    (S_AXI_ARID),   .S_AXI_ARADDR  (S_AXI_ARADDR),
        .S_AXI_ARLEN   (S_AXI_ARLEN),  .S_AXI_ARSIZE  (S_AXI_ARSIZE),
        .S_AXI_ARBURST (S_AXI_ARBURST),.S_AXI_ARPROT  (S_AXI_ARPROT),
        .S_AXI_ARVALID (S_AXI_ARVALID),.S_AXI_ARREADY (S_AXI_ARREADY),
        .S_AXI_RID     (S_AXI_RID),    .S_AXI_RDATA   (S_AXI_RDATA),
        .S_AXI_RRESP   (S_AXI_RRESP),  .S_AXI_RLAST   (S_AXI_RLAST),
        .S_AXI_RVALID  (S_AXI_RVALID), .S_AXI_RREADY  (S_AXI_RREADY),

        .dir_reg   (dir_reg_w),
        .dout_reg  (dout_reg_w),
        .irq_en    (irq_en_w),
        .irq_mode  (irq_mode_w),
        .irq_pol   (irq_pol_w),
        .din_sync  (din_sync_w),
        .irq_raw   (irq_raw_w)
    );

    gpio_iocell #(
        .GPIO_WIDTH (GPIO_WIDTH)
    ) u_iocell (
        .clk          (clk),
        .rst_n        (rst_n),
        .gpio_in_pad  (gpio_in),
        .dir_reg      (dir_reg_w),
        .dout_reg     (dout_reg_w),
        .gpio_out_pad (gpio_out),
        .gpio_oe_pad  (gpio_oe),
        .din_sync     (din_sync_w),
        .irq_en       (irq_en_w),
        .irq_mode     (irq_mode_w),
        .irq_pol      (irq_pol_w),
        .irq_raw      (irq_raw_w),
        .gpio_irq     (gpio_irq)
    );

    assign gpio_wake_armed_o = |irq_en_w;

    // ── AON edge-detect wake (clk_aon domain — chạy kể cả khi clk_periph gate)
    // 2-FF sync gpio_in pads vào clk_aon domain, rồi detect any edge trên
    // pin có irq_en_w=1. irq_en_w stable khi periph_clk off (write-before-sleep).
    reg [GPIO_WIDTH-1:0] gpio_in_aon_d1, gpio_in_aon_d2;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n) begin
            gpio_in_aon_d1 <= {GPIO_WIDTH{1'b0}};
            gpio_in_aon_d2 <= {GPIO_WIDTH{1'b0}};
        end else begin
            gpio_in_aon_d1 <= gpio_in;
            gpio_in_aon_d2 <= gpio_in_aon_d1;
        end
    end
    wire any_wake_edge_w = |((gpio_in_aon_d2 ^ gpio_in_aon_d1) & irq_en_w);

    reg gpio_wake_pend_r;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n)          gpio_wake_pend_r <= 1'b0;
        else if (wake_ack)       gpio_wake_pend_r <= 1'b0;
        else if (any_wake_edge_w) gpio_wake_pend_r <= 1'b1;
    end
    assign gpio_wake_req = gpio_wake_pend_r;

endmodule

// ==============================================================================
// FILE: timer_top.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// timer_top.v — Timer/WDT Peripheral Top-Level (AXI4-Full Slave S8)
//
// Address: 0x5003_0000 (S8 in crossbar), 4 KB
// Clock: clk_periph domain
//
// Hierarchy:
//   timer_top
//   ├── timer_regfile  — AXI4-Full slave + register decode
//   ├── timer_channel  u_t0 — Timer 0 (32-bit)
//   ├── timer_channel  u_t1 — Timer 1 (32-bit)
//   └── wdt_core            — Watchdog timer
//
// IRQ sources to PLIC:
//   timer0_irq → plic irq_src[5]
//   timer1_irq → plic irq_src[6]
//   wdt_irq    → plic irq_src[7]
//
// wdt_rst_req (active-high) can be fed to soc_top as additional reset source.
// ============================================================================


// ==============================================================================
// FILE: timer_regfile.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// timer_regfile.v — Timer Register File with AXI4-Full Slave Interface
//
// Address: 0x5003_0000 (S8 in crossbar), 4 KB
// Register Map (all 32-bit, word-aligned):
//   0x00  T0_CTRL    [0]=en [1]=auto_reload [2]=irq_en [3]=count_dir
//   0x04  T0_LOAD    reload value for Timer 0
//   0x08  T0_COUNT   current count (read-only)
//   0x0C  T0_STATUS  [0]=timeout_flag (W1C)
//   0x10  T1_CTRL    [0]=en [1]=auto_reload [2]=irq_en [3]=count_dir
//   0x14  T1_LOAD    reload value for Timer 1
//   0x18  T1_COUNT   current count (read-only)
//   0x1C  T1_STATUS  [0]=timeout_flag (W1C)
//   0x20  WDT_CTRL   [0]=en [1]=irq_en
//   0x24  WDT_LOAD   watchdog timeout period
//   0x28  WDT_FEED   write 0xDEAD_FEED to kick watchdog
//   0x2C  WDT_STATUS [0]=expired_flag (W1C)
// ============================================================================

module timer_regfile #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire clk,
    input  wire rst_n,

    // AXI4-Full Slave
    input  wire [ID_WIDTH-1:0]      S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_AWADDR,
    input  wire [7:0]               S_AXI_AWLEN,
    input  wire [2:0]               S_AXI_AWSIZE,
    input  wire [1:0]               S_AXI_AWBURST,
    input  wire [2:0]               S_AXI_AWPROT,
    input  wire                     S_AXI_AWVALID,
    output wire                     S_AXI_AWREADY,

    input  wire [DATA_WIDTH-1:0]    S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0]  S_AXI_WSTRB,
    input  wire                     S_AXI_WLAST,
    input  wire                     S_AXI_WVALID,
    output wire                     S_AXI_WREADY,

    output reg  [ID_WIDTH-1:0]      S_AXI_BID,
    output reg  [1:0]               S_AXI_BRESP,
    output reg                      S_AXI_BVALID,
    input  wire                     S_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]      S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_ARADDR,
    input  wire [7:0]               S_AXI_ARLEN,
    input  wire [2:0]               S_AXI_ARSIZE,
    input  wire [1:0]               S_AXI_ARBURST,
    input  wire [2:0]               S_AXI_ARPROT,
    input  wire                     S_AXI_ARVALID,
    output wire                     S_AXI_ARREADY,

    output reg  [ID_WIDTH-1:0]      S_AXI_RID,
    output reg  [DATA_WIDTH-1:0]    S_AXI_RDATA,
    output reg  [1:0]               S_AXI_RRESP,
    output reg                      S_AXI_RLAST,
    output reg                      S_AXI_RVALID,
    input  wire                     S_AXI_RREADY,

    // ── Timer 0 control/status ────────────────────────────────────────────────
    output reg         t0_en,
    output reg         t0_auto_reload,
    output reg         t0_irq_en,
    output reg         t0_count_dir,
    output reg  [31:0] t0_load,
    input  wire [31:0] t0_count,
    input  wire        t0_timeout_flag,
    output reg         t0_timeout_clr,

    // ── Timer 1 control/status ────────────────────────────────────────────────
    output reg         t1_en,
    output reg         t1_auto_reload,
    output reg         t1_irq_en,
    output reg         t1_count_dir,
    output reg  [31:0] t1_load,
    input  wire [31:0] t1_count,
    input  wire        t1_timeout_flag,
    output reg         t1_timeout_clr,

    // ── WDT control/status ───────────────────────────────────────────────────
    output reg         wdt_en,
    output reg         wdt_irq_en,
    output reg  [31:0] wdt_load,
    output reg         wdt_feed_pulse,  // 1-cycle pulse when DEAD_FEED written
    input  wire [31:0] wdt_count,
    input  wire        wdt_expired_flag,
    output reg         wdt_expired_clr
);

    localparam RESP_OKAY = 2'b00;

    localparam REG_T0_CTRL   = 6'h00;
    localparam REG_T0_LOAD   = 6'h04;
    localparam REG_T0_COUNT  = 6'h08;
    localparam REG_T0_STATUS = 6'h0C;
    localparam REG_T1_CTRL   = 6'h10;
    localparam REG_T1_LOAD   = 6'h14;
    localparam REG_T1_COUNT  = 6'h18;
    localparam REG_T1_STATUS = 6'h1C;
    localparam REG_WDT_CTRL  = 6'h20;
    localparam REG_WDT_LOAD  = 6'h24;
    localparam REG_WDT_FEED  = 6'h28;
    localparam REG_WDT_STAT  = 6'h2C;

    localparam WDT_FEED_MAGIC = 32'hDEAD_FEED;

    // =========================================================================
    // Write FSM
    // =========================================================================
    localparam WR_IDLE = 2'b00, WR_DATA = 2'b01, WR_RESP = 2'b10;
    reg [1:0]            wr_state;
    reg [ADDR_WIDTH-1:0] wr_addr_r;
    reg [ID_WIDTH-1:0]   bid_r;

    assign S_AXI_AWREADY = (wr_state == WR_IDLE);
    assign S_AXI_WREADY  = (wr_state == WR_DATA);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_state       <= WR_IDLE;
            wr_addr_r      <= {ADDR_WIDTH{1'b0}};
            bid_r          <= {ID_WIDTH{1'b0}};
            S_AXI_BID      <= {ID_WIDTH{1'b0}};
            S_AXI_BRESP    <= RESP_OKAY;
            S_AXI_BVALID   <= 1'b0;
            // Timers default off
            t0_en          <= 1'b0; t0_auto_reload <= 1'b0;
            t0_irq_en      <= 1'b0; t0_count_dir   <= 1'b0;
            t0_load        <= 32'hFFFF_FFFF;
            t0_timeout_clr <= 1'b0;
            t1_en          <= 1'b0; t1_auto_reload <= 1'b0;
            t1_irq_en      <= 1'b0; t1_count_dir   <= 1'b0;
            t1_load        <= 32'hFFFF_FFFF;
            t1_timeout_clr <= 1'b0;
            wdt_en         <= 1'b0; wdt_irq_en     <= 1'b0;
            wdt_load       <= 32'hFFFF_FFFF;
            wdt_feed_pulse <= 1'b0;
            wdt_expired_clr<= 1'b0;
        end else begin
            // Default: clear single-cycle pulses
            t0_timeout_clr  <= 1'b0;
            t1_timeout_clr  <= 1'b0;
            wdt_feed_pulse  <= 1'b0;
            wdt_expired_clr <= 1'b0;

            case (wr_state)
                WR_IDLE: begin
                    if (S_AXI_AWVALID) begin
                        wr_addr_r <= S_AXI_AWADDR;
                        bid_r     <= S_AXI_AWID;
                        wr_state  <= WR_DATA;
                    end
                end
                WR_DATA: begin
                    if (S_AXI_WVALID) begin
                        case (wr_addr_r[5:0])
                            REG_T0_CTRL: begin
                                t0_en          <= S_AXI_WDATA[0];
                                t0_auto_reload <= S_AXI_WDATA[1];
                                t0_irq_en      <= S_AXI_WDATA[2];
                                t0_count_dir   <= S_AXI_WDATA[3];
                            end
                            REG_T0_LOAD:   t0_load <= S_AXI_WDATA;
                            REG_T0_STATUS: if (S_AXI_WDATA[0]) t0_timeout_clr <= 1'b1;  // W1C
                            REG_T1_CTRL: begin
                                t1_en          <= S_AXI_WDATA[0];
                                t1_auto_reload <= S_AXI_WDATA[1];
                                t1_irq_en      <= S_AXI_WDATA[2];
                                t1_count_dir   <= S_AXI_WDATA[3];
                            end
                            REG_T1_LOAD:   t1_load <= S_AXI_WDATA;
                            REG_T1_STATUS: if (S_AXI_WDATA[0]) t1_timeout_clr <= 1'b1;
                            REG_WDT_CTRL: begin
                                wdt_en     <= S_AXI_WDATA[0];
                                wdt_irq_en <= S_AXI_WDATA[1];
                            end
                            REG_WDT_LOAD: wdt_load <= S_AXI_WDATA;
                            REG_WDT_FEED: begin
                                if (S_AXI_WDATA == WDT_FEED_MAGIC)
                                    wdt_feed_pulse <= 1'b1;
                            end
                            REG_WDT_STAT: if (S_AXI_WDATA[0]) wdt_expired_clr <= 1'b1;
                            default: ;
                        endcase

                        if (S_AXI_WLAST) begin
                            S_AXI_BID    <= bid_r;
                            S_AXI_BRESP  <= RESP_OKAY;
                            S_AXI_BVALID <= 1'b1;
                            wr_state     <= WR_RESP;
                        end else begin
                            wr_addr_r <= wr_addr_r + 4;
                        end
                    end
                end
                WR_RESP: begin
                    if (S_AXI_BREADY) begin
                        S_AXI_BVALID <= 1'b0;
                        wr_state     <= WR_IDLE;
                    end
                end
                default: wr_state <= WR_IDLE;
            endcase
        end
    end

    // =========================================================================
    // Read FSM
    // =========================================================================
    localparam RD_IDLE = 1'b0, RD_DATA = 1'b1;
    reg rd_state;
    reg [ADDR_WIDTH-1:0] rd_addr_r;
    reg [7:0]            rd_len_r;

    assign S_AXI_ARREADY = (rd_state == RD_IDLE);

    function [DATA_WIDTH-1:0] reg_read;
        input [5:0] addr;
        begin
            case (addr)
                REG_T0_CTRL:  reg_read = {28'd0, t0_count_dir, t0_irq_en, t0_auto_reload, t0_en};
                REG_T0_LOAD:  reg_read = t0_load;
                REG_T0_COUNT: reg_read = t0_count;
                REG_T0_STATUS:reg_read = {31'd0, t0_timeout_flag};
                REG_T1_CTRL:  reg_read = {28'd0, t1_count_dir, t1_irq_en, t1_auto_reload, t1_en};
                REG_T1_LOAD:  reg_read = t1_load;
                REG_T1_COUNT: reg_read = t1_count;
                REG_T1_STATUS:reg_read = {31'd0, t1_timeout_flag};
                REG_WDT_CTRL: reg_read = {30'd0, wdt_irq_en, wdt_en};
                REG_WDT_LOAD: reg_read = wdt_load;
                REG_WDT_FEED: reg_read = 32'd0;  // write-only, read returns 0
                REG_WDT_STAT: reg_read = {31'd0, wdt_expired_flag};
                default:      reg_read = 32'd0;
            endcase
        end
    endfunction

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rd_state     <= RD_IDLE;
            S_AXI_RID    <= {ID_WIDTH{1'b0}};
            S_AXI_RDATA  <= 32'd0;
            S_AXI_RRESP  <= RESP_OKAY;
            S_AXI_RLAST  <= 1'b0;
            S_AXI_RVALID <= 1'b0;
            rd_addr_r    <= {ADDR_WIDTH{1'b0}};
            rd_len_r     <= 8'd0;
        end else begin
            case (rd_state)
                RD_IDLE: begin
                    if (S_AXI_ARVALID) begin
                        rd_addr_r    <= S_AXI_ARADDR;
                        rd_len_r     <= S_AXI_ARLEN;
                        S_AXI_RID    <= S_AXI_ARID;
                        S_AXI_RDATA  <= reg_read(S_AXI_ARADDR[5:0]);
                        S_AXI_RRESP  <= RESP_OKAY;
                        S_AXI_RLAST  <= (S_AXI_ARLEN == 8'd0);
                        S_AXI_RVALID <= 1'b1;
                        rd_state     <= RD_DATA;
                    end
                end
                RD_DATA: begin
                    if (S_AXI_RREADY) begin
                        if (S_AXI_RLAST) begin
                            S_AXI_RVALID <= 1'b0;
                            rd_state     <= RD_IDLE;
                        end else begin
                            rd_len_r    <= rd_len_r - 8'd1;
                            rd_addr_r   <= rd_addr_r + 4;
                            S_AXI_RDATA <= reg_read(rd_addr_r[5:0] + 6'd4);
                            S_AXI_RLAST <= (rd_len_r == 8'd1);
                        end
                    end
                end
                default: rd_state <= RD_IDLE;
            endcase
        end
    end

endmodule

// ==============================================================================
// FILE: timer_channel.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// timer_channel.v — Single 32-bit Timer Channel
//
// Instantiated ×2 in timer_top for Timer0 and Timer1.
// Supports:
//   - Up-counting (count_dir=1) or down-counting (count_dir=0)
//   - Auto-reload: reload from load_val on timeout if auto_reload=1
//   - One-shot: stop on timeout if auto_reload=0
//   - IRQ output: pulses 1 cycle on timeout when irq_en=1
// ============================================================================

module timer_channel (
    input  wire        clk,
    input  wire        rst_n,

    // Control (from timer_regfile)
    input  wire        en,            // enable counting
    input  wire        auto_reload,   // 1=reload on timeout, 0=one-shot
    input  wire        irq_en,        // enable IRQ output
    input  wire        count_dir,     // 1=up, 0=down

    // Load value (also reload value)
    input  wire [31:0] load_val,

    // Status outputs (to timer_regfile)
    output reg  [31:0] count,         // current count value (read-only)
    output reg         timeout_flag,  // set on timeout, cleared by W1C write
    input  wire        timeout_clr,   // W1C clear pulse from regfile

    // IRQ
    output wire        irq
);

    // Timeout condition
    wire timeout_up   = (count_dir == 1'b1) && (count == 32'hFFFF_FFFF);
    wire timeout_down = (count_dir == 1'b0) && (count == 32'h0000_0000);
    wire timeout      = en && (timeout_up || timeout_down);

    // IRQ is a 1-cycle pulse on timeout (not the sticky flag)
    assign irq = timeout && irq_en;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count        <= 32'h0;
            timeout_flag <= 1'b0;
        end else begin
            // Clear sticky flag on W1C write
            if (timeout_clr)
                timeout_flag <= 1'b0;

            if (!en) begin
                // Disabled: hold count (do not reset — allows inspection)
            end else if (timeout) begin
                // Timeout this cycle
                timeout_flag <= 1'b1;
                if (auto_reload)
                    count <= load_val;
                // one-shot: count stays at boundary, en expected to be cleared by SW
            end else begin
                count <= count_dir ? count + 32'd1 : count - 32'd1;
            end
        end
    end

endmodule

// ==============================================================================
// FILE: wdt_core.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// wdt_core.v — Watchdog Timer Core
//
// Down-counter watchdog. Software must periodically write 0xDEAD_FEED to
// WDT_FEED register to kick (reload) the counter. If the counter reaches 0:
//   - wdt_irq is asserted (sticky, cleared by W1C write to WDT_STATUS)
//   - After WDT_RST_DELAY cycles, wdt_rst_req is asserted (active-high)
//     → This can be fed back to soc_top as an additional reset source.
//
// Magic feed value: 0xDEAD_FEED (any other value is ignored).
// ============================================================================

module wdt_core (
    input  wire        clk,
    input  wire        rst_n,

    // Control (from timer_regfile)
    input  wire        en,            // enable watchdog
    input  wire        irq_en,        // enable IRQ on expiry

    // Load value
    input  wire [31:0] load_val,

    // Feed pulse (from regfile: write 0xDEAD_FEED → feed_pulse=1 for 1 cycle)
    input  wire        feed_pulse,

    // Status outputs
    output reg  [31:0] count,
    output reg         expired_flag,  // sticky, W1C
    input  wire        expired_clr,   // W1C clear pulse from regfile

    // Outputs
    output wire        wdt_irq,
    output reg         wdt_rst_req    // active-high reset request (holds for 4 cycles)
);

    localparam WDT_RST_CYCLES = 4;

    reg [2:0] rst_cnt;    // counts down after expiry to generate reset pulse

    wire expired = en && (count == 32'h0);

    assign wdt_irq = expired_flag && irq_en;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count        <= 32'hFFFF_FFFF;
            expired_flag <= 1'b0;
            wdt_rst_req  <= 1'b0;
            rst_cnt      <= 3'd0;
        end else begin
            // W1C clear
            if (expired_clr)
                expired_flag <= 1'b0;

            // Feed watchdog
            if (feed_pulse && en) begin
                count <= load_val;
            end else if (en && !expired) begin
                count <= count - 32'd1;
            end

            // Expiry handling
            if (expired && !expired_flag) begin
                expired_flag <= 1'b1;
                rst_cnt      <= WDT_RST_CYCLES[2:0];
            end

            // Reset pulse generation
            if (rst_cnt != 3'd0) begin
                wdt_rst_req <= 1'b1;
                rst_cnt     <= rst_cnt - 3'd1;
            end else begin
                wdt_rst_req <= 1'b0;
            end
        end
    end

endmodule

module timer_top #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire clk,
    input  wire rst_n,

    // ── AXI4-Full Slave (S8) ─────────────────────────────────────────────────
    input  wire [ID_WIDTH-1:0]      S_AXI_AWID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_AWADDR,
    input  wire [7:0]               S_AXI_AWLEN,
    input  wire [2:0]               S_AXI_AWSIZE,
    input  wire [1:0]               S_AXI_AWBURST,
    input  wire [2:0]               S_AXI_AWPROT,
    input  wire                     S_AXI_AWVALID,
    output wire                     S_AXI_AWREADY,

    input  wire [DATA_WIDTH-1:0]    S_AXI_WDATA,
    input  wire [DATA_WIDTH/8-1:0]  S_AXI_WSTRB,
    input  wire                     S_AXI_WLAST,
    input  wire                     S_AXI_WVALID,
    output wire                     S_AXI_WREADY,

    output wire [ID_WIDTH-1:0]      S_AXI_BID,
    output wire [1:0]               S_AXI_BRESP,
    output wire                     S_AXI_BVALID,
    input  wire                     S_AXI_BREADY,

    input  wire [ID_WIDTH-1:0]      S_AXI_ARID,
    input  wire [ADDR_WIDTH-1:0]    S_AXI_ARADDR,
    input  wire [7:0]               S_AXI_ARLEN,
    input  wire [2:0]               S_AXI_ARSIZE,
    input  wire [1:0]               S_AXI_ARBURST,
    input  wire [2:0]               S_AXI_ARPROT,
    input  wire                     S_AXI_ARVALID,
    output wire                     S_AXI_ARREADY,

    output wire [ID_WIDTH-1:0]      S_AXI_RID,
    output wire [DATA_WIDTH-1:0]    S_AXI_RDATA,
    output wire [1:0]               S_AXI_RRESP,
    output wire                     S_AXI_RLAST,
    output wire                     S_AXI_RVALID,
    input  wire                     S_AXI_RREADY,

    // ── IRQ outputs to PLIC ──────────────────────────────────────────────────
    output wire timer0_irq,
    output wire timer1_irq,
    output wire wdt_irq,

    // ── WDT reset request (active-high) ──────────────────────────────────────
    output wire wdt_rst_req,
    output wire timer_active_o,

    // ── AON wake interface (clk_aon domain) ──────────────────────────────────
    input  wire clk_aon,
    input  wire aon_rst_n,
    input  wire wake_ack,
    output wire timer_wake_req
);

    // ── Timer 0 wires ────────────────────────────────────────────────────────
    wire        t0_en, t0_auto_reload, t0_irq_en, t0_count_dir;
    wire [31:0] t0_load;
    wire [31:0] t0_count;
    wire        t0_timeout_flag;
    wire        t0_timeout_clr;

    // ── Timer 1 wires ────────────────────────────────────────────────────────
    wire        t1_en, t1_auto_reload, t1_irq_en, t1_count_dir;
    wire [31:0] t1_load;
    wire [31:0] t1_count;
    wire        t1_timeout_flag;
    wire        t1_timeout_clr;

    // ── WDT wires ────────────────────────────────────────────────────────────
    wire        wdt_en, wdt_irq_en_w;
    wire [31:0] wdt_load;
    wire        wdt_feed_pulse;
    wire [31:0] wdt_count;
    wire        wdt_expired_flag;
    wire        wdt_expired_clr;

    timer_regfile #(
        .ADDR_WIDTH (ADDR_WIDTH),
        .DATA_WIDTH (DATA_WIDTH),
        .ID_WIDTH   (ID_WIDTH)
    ) u_regfile (
        .clk           (clk),
        .rst_n         (rst_n),

        .S_AXI_AWID    (S_AXI_AWID),   .S_AXI_AWADDR  (S_AXI_AWADDR),
        .S_AXI_AWLEN   (S_AXI_AWLEN),  .S_AXI_AWSIZE  (S_AXI_AWSIZE),
        .S_AXI_AWBURST (S_AXI_AWBURST),.S_AXI_AWPROT  (S_AXI_AWPROT),
        .S_AXI_AWVALID (S_AXI_AWVALID),.S_AXI_AWREADY (S_AXI_AWREADY),
        .S_AXI_WDATA   (S_AXI_WDATA),  .S_AXI_WSTRB   (S_AXI_WSTRB),
        .S_AXI_WLAST   (S_AXI_WLAST),  .S_AXI_WVALID  (S_AXI_WVALID),
        .S_AXI_WREADY  (S_AXI_WREADY),
        .S_AXI_BID     (S_AXI_BID),    .S_AXI_BRESP   (S_AXI_BRESP),
        .S_AXI_BVALID  (S_AXI_BVALID), .S_AXI_BREADY  (S_AXI_BREADY),
        .S_AXI_ARID    (S_AXI_ARID),   .S_AXI_ARADDR  (S_AXI_ARADDR),
        .S_AXI_ARLEN   (S_AXI_ARLEN),  .S_AXI_ARSIZE  (S_AXI_ARSIZE),
        .S_AXI_ARBURST (S_AXI_ARBURST),.S_AXI_ARPROT  (S_AXI_ARPROT),
        .S_AXI_ARVALID (S_AXI_ARVALID),.S_AXI_ARREADY (S_AXI_ARREADY),
        .S_AXI_RID     (S_AXI_RID),    .S_AXI_RDATA   (S_AXI_RDATA),
        .S_AXI_RRESP   (S_AXI_RRESP),  .S_AXI_RLAST   (S_AXI_RLAST),
        .S_AXI_RVALID  (S_AXI_RVALID), .S_AXI_RREADY  (S_AXI_RREADY),

        .t0_en          (t0_en),        .t0_auto_reload  (t0_auto_reload),
        .t0_irq_en      (t0_irq_en),    .t0_count_dir    (t0_count_dir),
        .t0_load        (t0_load),
        .t0_count       (t0_count),     .t0_timeout_flag (t0_timeout_flag),
        .t0_timeout_clr (t0_timeout_clr),

        .t1_en          (t1_en),        .t1_auto_reload  (t1_auto_reload),
        .t1_irq_en      (t1_irq_en),    .t1_count_dir    (t1_count_dir),
        .t1_load        (t1_load),
        .t1_count       (t1_count),     .t1_timeout_flag (t1_timeout_flag),
        .t1_timeout_clr (t1_timeout_clr),

        .wdt_en         (wdt_en),       .wdt_irq_en      (wdt_irq_en_w),
        .wdt_load       (wdt_load),     .wdt_feed_pulse  (wdt_feed_pulse),
        .wdt_count      (wdt_count),    .wdt_expired_flag(wdt_expired_flag),
        .wdt_expired_clr(wdt_expired_clr)
    );

    timer_channel u_t0 (
        .clk          (clk),       .rst_n        (rst_n),
        .en           (t0_en),     .auto_reload  (t0_auto_reload),
        .irq_en       (t0_irq_en), .count_dir    (t0_count_dir),
        .load_val     (t0_load),
        .count        (t0_count),  .timeout_flag (t0_timeout_flag),
        .timeout_clr  (t0_timeout_clr),
        .irq          (timer0_irq)
    );

    timer_channel u_t1 (
        .clk          (clk),       .rst_n        (rst_n),
        .en           (t1_en),     .auto_reload  (t1_auto_reload),
        .irq_en       (t1_irq_en), .count_dir    (t1_count_dir),
        .load_val     (t1_load),
        .count        (t1_count),  .timeout_flag (t1_timeout_flag),
        .timeout_clr  (t1_timeout_clr),
        .irq          (timer1_irq)
    );

    wdt_core u_wdt (
        .clk           (clk),           .rst_n        (rst_n),
        .en            (wdt_en),        .irq_en       (wdt_irq_en_w),
        .load_val      (wdt_load),      .feed_pulse   (wdt_feed_pulse),
        .count         (wdt_count),     .expired_flag (wdt_expired_flag),
        .expired_clr   (wdt_expired_clr),
        .wdt_irq       (wdt_irq),
        .wdt_rst_req   (wdt_rst_req)
    );

    assign timer_active_o = t0_en | t1_en | wdt_en;

    // ── AON timeout wake (clk_aon domain — chạy kể cả khi clk_periph gate)
    // 2-FF CDC: bring clk_periph timeout flags vào clk_aon domain.
    // periph_gate_allow=0 khi timer_active=1, nên flags chỉ assert khi
    // periph_clk đang chạy → 2-FF đủ để capture sạch.
    wire any_timeout_w = t0_timeout_flag | t1_timeout_flag | wdt_expired_flag;
    reg timeout_aon_d1, timeout_aon_d2;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n) begin
            timeout_aon_d1 <= 1'b0;
            timeout_aon_d2 <= 1'b0;
        end else begin
            timeout_aon_d1 <= any_timeout_w;
            timeout_aon_d2 <= timeout_aon_d1;
        end
    end

    reg timer_wake_pend_r;
    always @(posedge clk_aon or negedge aon_rst_n) begin
        if (!aon_rst_n)          timer_wake_pend_r <= 1'b0;
        else if (wake_ack)       timer_wake_pend_r <= 1'b0;
        else if (timeout_aon_d2) timer_wake_pend_r <= 1'b1;
    end
    assign timer_wake_req = timer_wake_pend_r;

endmodule

// ==============================================================================
// FILE: otp_stub_slave.v
// ==============================================================================

// `timescale 1ns/1ps

// ============================================================================
// otp_stub_slave.v — Minimal OTP stub (S10 @ 0x6000_0000)
//
// Trả về fixed read-only data thay vì DECERR:
//   0x000  DEVICE_ID  = 32'hA5C0_CAFE  (chip identity)
//   0x004  OTP_VER    = 32'h0000_0001  (OTP layout version)
//   other  = 32'hDEAD_BEEF             (unprogrammed / reserved)
//
// Writes: always OKAY (ignored) — OTP is physically write-once;
// stub accepts writes silently to avoid spurious SLVERR.
// ============================================================================

module otp_stub_slave #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter ID_WIDTH   = 4
)(
    input  wire                   clk,
    input  wire                   rst_n,

    // AXI4-Full slave (same port naming as other slaves in this SoC)
    input  wire [ID_WIDTH-1:0]    s_arid,
    input  wire [ADDR_WIDTH-1:0]  s_araddr,
    input  wire [7:0]             s_arlen,
    input  wire [2:0]             s_arsize,
    input  wire [1:0]             s_arburst,
    input  wire                   s_arvalid,
    output wire                   s_arready,

    output wire [ID_WIDTH-1:0]    s_rid,
    output wire [DATA_WIDTH-1:0]  s_rdata,
    output wire [1:0]             s_rresp,
    output wire                   s_rlast,
    output wire                   s_rvalid,
    input  wire                   s_rready,

    input  wire [ID_WIDTH-1:0]    s_awid,
    input  wire [ADDR_WIDTH-1:0]  s_awaddr,
    input  wire [7:0]             s_awlen,
    input  wire                   s_awvalid,
    output wire                   s_awready,

    input  wire [DATA_WIDTH-1:0]  s_wdata,
    input  wire [3:0]             s_wstrb,
    input  wire                   s_wlast,
    input  wire                   s_wvalid,
    output wire                   s_wready,

    output wire [ID_WIDTH-1:0]    s_bid,
    output wire [1:0]             s_bresp,
    output wire                   s_bvalid,
    input  wire                   s_bready
);

// ── Read channel ─────────────────────────────────────────────────────────────
reg [ID_WIDTH-1:0]   ar_id_r;
reg [ADDR_WIDTH-1:0] ar_addr_r;
reg [7:0]            ar_len_r;
reg [7:0]            ar_beat_r;   // beats remaining in burst
reg                  ar_active;

reg                  rvalid_r;
reg [DATA_WIDTH-1:0] rdata_r;
reg                  rlast_r;

wire [11:0] rd_offset = ar_addr_r[11:0] + {ar_beat_r, 2'b00}; // word-addressed

// OTP read data mux
wire [DATA_WIDTH-1:0] otp_rdata =
    (rd_offset == 12'h000) ? 32'hA5C0_CAFE :   // DEVICE_ID
    (rd_offset == 12'h004) ? 32'h0000_0001 :   // OTP_VER
                              32'hDEAD_BEEF;    // unprogrammed

assign s_arready = !ar_active;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        ar_active  <= 1'b0;
        ar_id_r    <= {ID_WIDTH{1'b0}};
        ar_addr_r  <= {ADDR_WIDTH{1'b0}};
        ar_len_r   <= 8'd0;
        ar_beat_r  <= 8'd0;
        rvalid_r   <= 1'b0;
        rdata_r    <= {DATA_WIDTH{1'b0}};
        rlast_r    <= 1'b0;
    end else begin
        if (s_arvalid && s_arready) begin
            ar_id_r   <= s_arid;
            ar_addr_r <= s_araddr;
            ar_len_r  <= s_arlen;
            ar_beat_r <= 8'd0;
            ar_active <= 1'b1;
        end

        if (ar_active && !rvalid_r) begin
            rvalid_r <= 1'b1;
            rdata_r  <= otp_rdata;
            rlast_r  <= (ar_beat_r == ar_len_r);
        end

        if (rvalid_r && s_rready) begin
            rvalid_r <= 1'b0;
            if (!rlast_r) begin
                ar_beat_r <= ar_beat_r + 8'd1;
            end else begin
                ar_active <= 1'b0;
            end
        end
    end
end

assign s_rid    = ar_id_r;
assign s_rdata  = rdata_r;
assign s_rresp  = 2'b00;   // OKAY
assign s_rlast  = rlast_r;
assign s_rvalid = rvalid_r;

// ── Write channel (accept & ignore) ─────────────────────────────────────────
reg aw_active;
reg w_active;
reg bvalid_r;
reg [ID_WIDTH-1:0] aw_id_r;

assign s_awready = !aw_active;
assign s_wready  = aw_active && !bvalid_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        aw_active <= 1'b0;
        w_active  <= 1'b0;
        bvalid_r  <= 1'b0;
        aw_id_r   <= {ID_WIDTH{1'b0}};
    end else begin
        if (s_awvalid && s_awready) begin
            aw_id_r   <= s_awid;
            aw_active <= 1'b1;
        end
        if (s_wvalid && s_wready && s_wlast) begin
            bvalid_r <= 1'b1;
        end
        if (bvalid_r && s_bready) begin
            bvalid_r  <= 1'b0;
            aw_active <= 1'b0;
        end
    end
end

assign s_bid    = aw_id_r;
assign s_bresp  = 2'b00;   // OKAY (silent accept)
assign s_bvalid = bvalid_r;

endmodule
// ============================================================================
// END: otp_stub_slave.v
// ============================================================================

// ==============================================================================
// FILE: spi_top.v
// ==============================================================================

// `timescale 1ns/1ps
// ============================================================================
// spi_top.v — SPI Master Peripheral (S7, base 0x5002_0000)
//
// Hierarchy:
//   spi_top
//   ├── spi_axi_slave  — AXI4-Full register file
//   ├── spi_core       — SPI master FSM (8-bit, MSB-first, 4 modes)
//   ├── uart_fifo (tx) — TX FIFO 8-bit × 16 deep (reuse từ UART)
//   └── uart_fifo (rx) — RX FIFO 8-bit × 16 deep
//
// Register map (offset từ 0x5002_0000):
//   0x00  TX_DATA    WO [7:0]   ghi byte vào TX FIFO
//   0x04  RX_DATA    RO [7:0]   đọc byte từ RX FIFO (auto-pop)
//   0x08  STATUS     RO [5:0]   {rx_overrun,rx_full,rx_empty,tx_full,tx_empty,busy}
//   0x0C  CTRL       RW [7:0]   {spi_en,cs_auto,cpol,cpha,--,--,rx_irq_en,tx_irq_en}
//   0x10  DIVIDER    RW [15:0]  SCK = clk/(2*(DIVIDER+1)), default=4→10MHz@100MHz
//   0x14  IRQ_STATUS RW1C [1:0] {rx_valid_irq, tx_empty_irq}
//   0x18  CS_CTRL    RW [3:0]   manual CS (khi CTRL[cs_auto]=0), active-low
//
// IO pads:
//   sck   — SPI clock output
//   mosi  — Master Out Slave In
//   miso  — Master In Slave Out
//   cs_n  — Chip Select[3:0], active-low
//
// Kết nối vào soc_top.v:
//   spi_top u_spi (
//       .clk      (clk),
//       .rst_n    (periph_rst_n),
//       .s_axi_*  (s7_*),
//       .sck      (spi_sck), .mosi (spi_mosi),
//       .miso     (spi_miso), .cs_n (spi_cs_n),
//       .irq_out  (spi_irq),
//       .tx_dma_req(spi_tx_dma_req),
//       .rx_dma_req(spi_rx_dma_req)
//   );
// ============================================================================


// ==============================================================================
// FILE: spi_axi_slave.v
// ==============================================================================

// `timescale 1ns/1ps
// spi_axi_slave.v — AXI4-Full register slave cho SPI peripheral
//
// Register map (offset từ 0x5002_0000):
//   0x00  TX_DATA    WO [7:0]   ghi byte vào TX FIFO
//   0x04  RX_DATA    RO [7:0]   đọc byte từ RX FIFO
//   0x08  STATUS     RO [5:0]   {rx_overrun,rx_full,rx_empty,tx_full,tx_empty,busy}
//   0x0C  CTRL       RW [7:0]   {spi_en,cs_auto,cpol,cpha,--,--,rx_irq_en,tx_irq_en}
//   0x10  DIVIDER    RW [15:0]  SCK = clk/(2*(DIVIDER+1))
//   0x14  IRQ_STATUS RW1C [1:0] {rx_valid_irq, tx_empty_irq}
//   0x18  CS_CTRL    RW [3:0]   CS manual control (khi cs_auto=0)

module spi_axi_slave #(
    parameter AXI_ADDR_WIDTH = 32,
    parameter AXI_DATA_WIDTH = 32,
    parameter AXI_ID_WIDTH   = 4
)(
    input  wire clk,
    input  wire rst_n,

    // AXI4-Full Slave
    input  wire [AXI_ID_WIDTH-1:0]   s_axi_awid,
    input  wire [AXI_ADDR_WIDTH-1:0] s_axi_awaddr,
    input  wire [7:0]                s_axi_awlen,
    input  wire [2:0]                s_axi_awsize,
    input  wire [1:0]                s_axi_awburst,
    input  wire                      s_axi_awvalid,
    output reg                       s_axi_awready,
    input  wire [AXI_DATA_WIDTH-1:0] s_axi_wdata,
    input  wire [AXI_DATA_WIDTH/8-1:0] s_axi_wstrb,
    input  wire                      s_axi_wlast,
    input  wire                      s_axi_wvalid,
    output reg                       s_axi_wready,
    output reg  [AXI_ID_WIDTH-1:0]   s_axi_bid,
    output reg  [1:0]                s_axi_bresp,
    output reg                       s_axi_bvalid,
    input  wire                      s_axi_bready,
    input  wire [AXI_ID_WIDTH-1:0]   s_axi_arid,
    input  wire [AXI_ADDR_WIDTH-1:0] s_axi_araddr,
    input  wire [7:0]                s_axi_arlen,
    input  wire [2:0]                s_axi_arsize,
    input  wire [1:0]                s_axi_arburst,
    input  wire                      s_axi_arvalid,
    output reg                       s_axi_arready,
    output reg  [AXI_ID_WIDTH-1:0]   s_axi_rid,
    output reg  [AXI_DATA_WIDTH-1:0] s_axi_rdata,
    output reg  [1:0]                s_axi_rresp,
    output reg                       s_axi_rlast,
    output reg                       s_axi_rvalid,
    input  wire                      s_axi_rready,

    // → spi_core & spi_top
    output reg  [7:0]  reg_tx_data,
    output reg         reg_tx_push,    // 1-cycle pulse
    input  wire        tx_fifo_full,
    input  wire        tx_fifo_empty,

    input  wire [7:0]  reg_rx_data,
    output reg         reg_rx_pop,     // 1-cycle pulse
    input  wire        rx_fifo_full,
    input  wire        rx_fifo_empty,
    input  wire        rx_overrun,
    input  wire        spi_busy,

    output reg  [15:0] reg_divider,
    output reg         reg_spi_en,
    output reg         reg_cs_auto,
    output reg         reg_cpol,
    output reg         reg_cpha,
    output reg         reg_rx_irq_en,
    output reg         reg_tx_irq_en,
    output reg  [3:0]  reg_cs_ctrl,

    input  wire        tx_empty_irq_in,
    input  wire        rx_valid_irq_in,
    output wire        irq_out
);

    // ── Write FSM ─────────────────────────────────────────────────────────────
    localparam WS_IDLE = 2'd0, WS_DATA = 2'd1, WS_RESP = 2'd2;
    reg [1:0]               ws;
    reg [AXI_ID_WIDTH-1:0]  wr_id;
    reg [4:0]               wr_addr_lat;  // [4:2] = register select

    // ── Read FSM ──────────────────────────────────────────────────────────────
    localparam RS_IDLE = 1'd0, RS_RESP = 1'd1;
    reg                     rs;
    reg [AXI_ID_WIDTH-1:0]  rd_id;

    // ── IRQ sticky flags ──────────────────────────────────────────────────────
    reg tx_irq_r, rx_irq_r;
    assign irq_out = (reg_tx_irq_en & tx_irq_r) | (reg_rx_irq_en & rx_irq_r);

    // ── Default register values ───────────────────────────────────────────────
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_divider   <= 16'd4;    // SCK = clk/10 = 10 MHz @ 100 MHz
            reg_spi_en    <= 1'b0;
            reg_cs_auto   <= 1'b1;
            reg_cpol      <= 1'b0;
            reg_cpha      <= 1'b0;
            reg_rx_irq_en <= 1'b0;
            reg_tx_irq_en <= 1'b0;
            reg_cs_ctrl   <= 4'hF;     // CS deasserted (active-low)
            tx_irq_r      <= 1'b0;
            rx_irq_r      <= 1'b0;
        end else begin
            // Edge-detect IRQ set
            if (tx_empty_irq_in) tx_irq_r <= 1'b1;
            if (rx_valid_irq_in) rx_irq_r <= 1'b1;
        end
    end

    // ── Write FSM ─────────────────────────────────────────────────────────────
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ws           <= WS_IDLE;
            s_axi_awready<= 1'b0;
            s_axi_wready <= 1'b0;
            s_axi_bvalid <= 1'b0;
            s_axi_bresp  <= 2'b00;
            s_axi_bid    <= {AXI_ID_WIDTH{1'b0}};
            wr_id        <= {AXI_ID_WIDTH{1'b0}};
            wr_addr_lat  <= 5'd0;
            reg_tx_data  <= 8'd0;
            reg_tx_push  <= 1'b0;
        end else begin
            reg_tx_push <= 1'b0;  // default pulse-clear

            case (ws)
                WS_IDLE: begin
                    s_axi_awready <= 1'b1;
                    if (s_axi_awvalid && s_axi_awready) begin
                        wr_id       <= s_axi_awid;
                        wr_addr_lat <= s_axi_awaddr[4:0];
                        s_axi_awready <= 1'b0;
                        s_axi_wready  <= 1'b1;
                        ws <= WS_DATA;
                    end
                end
                WS_DATA: begin
                    if (s_axi_wvalid && s_axi_wready) begin
                        s_axi_wready <= 1'b0;
                        case (wr_addr_lat[4:2])
                            3'd0: begin  // 0x00 TX_DATA
                                if (!tx_fifo_full) begin
                                    reg_tx_data <= s_axi_wdata[7:0];
                                    reg_tx_push <= 1'b1;
                                end
                            end
                            3'd3: begin  // 0x0C CTRL
                                reg_spi_en    <= s_axi_wdata[7];
                                reg_cs_auto   <= s_axi_wdata[6];
                                reg_cpol      <= s_axi_wdata[5];
                                reg_cpha      <= s_axi_wdata[4];
                                reg_rx_irq_en <= s_axi_wdata[1];
                                reg_tx_irq_en <= s_axi_wdata[0];
                            end
                            3'd4: begin  // 0x10 DIVIDER
                                reg_divider <= s_axi_wdata[15:0];
                            end
                            3'd5: begin  // 0x14 IRQ_STATUS RW1C
                                if (s_axi_wdata[0]) tx_irq_r <= 1'b0;
                                if (s_axi_wdata[1]) rx_irq_r <= 1'b0;
                            end
                            3'd6: begin  // 0x18 CS_CTRL
                                reg_cs_ctrl <= s_axi_wdata[3:0];
                            end
                            default: ;
                        endcase
                        s_axi_bid    <= wr_id;
                        s_axi_bresp  <= 2'b00;
                        s_axi_bvalid <= 1'b1;
                        ws <= WS_RESP;
                    end
                end
                WS_RESP: begin
                    if (s_axi_bvalid && s_axi_bready) begin
                        s_axi_bvalid <= 1'b0;
                        ws <= WS_IDLE;
                    end
                end
                default: ws <= WS_IDLE;
            endcase
        end
    end

    // ── Read FSM ──────────────────────────────────────────────────────────────
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rs            <= RS_IDLE;
            s_axi_arready <= 1'b0;
            s_axi_rvalid  <= 1'b0;
            s_axi_rlast   <= 1'b0;
            s_axi_rresp   <= 2'b00;
            s_axi_rid     <= {AXI_ID_WIDTH{1'b0}};
            s_axi_rdata   <= {AXI_DATA_WIDTH{1'b0}};
            rd_id         <= {AXI_ID_WIDTH{1'b0}};
            reg_rx_pop    <= 1'b0;
        end else begin
            reg_rx_pop <= 1'b0;

            case (rs)
                RS_IDLE: begin
                    s_axi_arready <= 1'b1;
                    if (s_axi_arvalid && s_axi_arready) begin
                        rd_id         <= s_axi_arid;
                        s_axi_arready <= 1'b0;
                        s_axi_rid     <= s_axi_arid;
                        s_axi_rresp   <= 2'b00;
                        s_axi_rlast   <= 1'b1;
                        case (s_axi_araddr[4:2])
                            3'd0: s_axi_rdata <= {24'd0, reg_tx_data};  // TX_DATA (last written)
                            3'd1: begin  // 0x04 RX_DATA
                                s_axi_rdata <= {24'd0, reg_rx_data};
                                if (!rx_fifo_empty) reg_rx_pop <= 1'b1;
                            end
                            3'd2: s_axi_rdata <= {26'd0, rx_overrun, rx_fifo_full,
                                                  rx_fifo_empty, tx_fifo_full,
                                                  tx_fifo_empty, spi_busy};
                            3'd3: s_axi_rdata <= {24'd0, reg_spi_en, reg_cs_auto,
                                                  reg_cpol, reg_cpha, 2'b00,
                                                  reg_rx_irq_en, reg_tx_irq_en};
                            3'd4: s_axi_rdata <= {16'd0, reg_divider};
                            3'd5: s_axi_rdata <= {30'd0, rx_irq_r, tx_irq_r};
                            3'd6: s_axi_rdata <= {28'd0, reg_cs_ctrl};
                            default: s_axi_rdata <= 32'hDEAD_BEEF;
                        endcase
                        s_axi_rvalid <= 1'b1;
                        rs <= RS_RESP;
                    end
                end
                RS_RESP: begin
                    if (s_axi_rvalid && s_axi_rready) begin
                        s_axi_rvalid <= 1'b0;
                        s_axi_rlast  <= 1'b0;
                        rs <= RS_IDLE;
                    end
                end
                default: rs <= RS_IDLE;
            endcase
        end
    end

endmodule

// ==============================================================================
// FILE: spi_core.v
// ==============================================================================

// `timescale 1ns/1ps
// spi_core.v — SPI Master shift-register FSM
//
// Hỗ trợ 4 SPI modes (CPOL×CPHA).
// Transfer: 8-bit, MSB first.
// SCK = clk / (2*(divider+1)) → divider=4 → SCK=10 MHz @ 100 MHz clk.
//
// CPOL=0: SCK idle LOW.  CPOL=1: SCK idle HIGH.
// CPHA=0: sample 1st edge, shift 2nd.
// CPHA=1: shift  1st edge, sample 2nd.

module spi_core #(
    parameter CS_WIDTH = 4
)(
    input  wire        clk,
    input  wire        rst_n,

    // Config
    input  wire [15:0] divider,
    input  wire        spi_en,
    input  wire        cpol,
    input  wire        cpha,
    input  wire        cs_auto,
    input  wire [CS_WIDTH-1:0] cs_ctrl_manual,  // manual CS (cs_auto=0)

    // TX FIFO interface
    input  wire [7:0]  tx_fifo_dout,
    input  wire        tx_fifo_empty,
    output reg         tx_fifo_pop,

    // RX FIFO interface
    output reg  [7:0]  rx_fifo_din,
    input  wire        rx_fifo_full,
    output reg         rx_fifo_push,

    // SPI pads
    output reg                 sck,
    output wire                mosi,
    input  wire                miso,
    output reg  [CS_WIDTH-1:0] cs_n,   // active-low

    // Status
    output wire        busy,

    // IRQ triggers → spi_top
    output reg         tx_empty_irq,  // 1-cycle pulse khi TX FIFO vừa empty
    output reg         rx_valid_irq   // 1-cycle pulse khi byte mới vào RX FIFO
);

    // ── FSM ───────────────────────────────────────────────────────────────────
    localparam [1:0]
        S_IDLE    = 2'd0,
        S_LOAD    = 2'd1,  // latch TX byte, assert CS
        S_XFER    = 2'd2,  // clock 8 bits
        S_DONE    = 2'd3;  // deassert CS (if cs_auto), push RX

    reg [1:0]  state;
    reg [15:0] clk_cnt;    // baud divider counter
    reg        clk_phase;  // 0=first half, 1=second half of SCK period
    reg [2:0]  bit_cnt;    // 0-7
    reg [7:0]  shift_reg;  // shift register (TX side)
    reg [7:0]  rx_shift;   // shift register (RX side)
    reg        sck_idle;   // SCK level at idle (= cpol)

    assign busy = (state != S_IDLE);
    assign mosi = shift_reg[7];  // MSB first

    // ── Clock edge generation ─────────────────────────────────────────────────
    wire clk_tick = (clk_cnt == 16'd0);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state        <= S_IDLE;
            clk_cnt      <= 16'd0;
            clk_phase    <= 1'b0;
            bit_cnt      <= 3'd0;
            shift_reg    <= 8'd0;
            rx_shift     <= 8'd0;
            sck          <= 1'b0;
            cs_n         <= {CS_WIDTH{1'b1}};
            tx_fifo_pop  <= 1'b0;
            rx_fifo_din  <= 8'd0;
            rx_fifo_push <= 1'b0;
            tx_empty_irq <= 1'b0;
            rx_valid_irq <= 1'b0;
        end else begin
            tx_fifo_pop  <= 1'b0;
            rx_fifo_push <= 1'b0;
            tx_empty_irq <= 1'b0;
            rx_valid_irq <= 1'b0;

            // Manual CS override
            if (!cs_auto) cs_n <= cs_ctrl_manual;

            case (state)
                // ── S_IDLE: wait for byte in TX FIFO ─────────────────────────
                S_IDLE: begin
                    sck     <= cpol;   // SCK idles per CPOL
                    clk_cnt <= divider;
                    clk_phase <= 1'b0;
                    if (spi_en && !tx_fifo_empty) begin
                        state <= S_LOAD;
                    end
                end

                // ── S_LOAD: pop byte, assert CS ───────────────────────────────
                S_LOAD: begin
                    shift_reg   <= tx_fifo_dout;
                    tx_fifo_pop <= 1'b1;
                    bit_cnt     <= 3'd0;
                    clk_cnt     <= divider;
                    clk_phase   <= 1'b0;
                    if (cs_auto) cs_n <= {CS_WIDTH{1'b0}};  // assert all CS (simplest)
                    state <= S_XFER;
                end

                // ── S_XFER: shift 8 bits ──────────────────────────────────────
                S_XFER: begin
                    if (clk_cnt != 16'd0) begin
                        clk_cnt <= clk_cnt - 16'd1;
                    end else begin
                        clk_cnt   <= divider;
                        clk_phase <= ~clk_phase;

                        if (!clk_phase) begin
                            // First half → SCK transition (idle→active)
                            sck <= cpol ^ 1'b1;  // toggle from idle
                            if (!cpha) begin
                                // CPHA=0: sample on first edge
                                rx_shift <= {rx_shift[6:0], miso};
                            end else begin
                                // CPHA=1: shift out on first edge
                                shift_reg <= {shift_reg[6:0], 1'b0};
                            end
                        end else begin
                            // Second half → SCK back to idle level
                            sck <= cpol;
                            if (!cpha) begin
                                // CPHA=0: shift out on second edge
                                shift_reg <= {shift_reg[6:0], 1'b0};
                            end else begin
                                // CPHA=1: sample on second edge
                                rx_shift <= {rx_shift[6:0], miso};
                            end
                            bit_cnt <= bit_cnt + 3'd1;
                            if (bit_cnt == 3'd7) begin
                                state <= S_DONE;
                            end
                        end
                    end
                end

                // ── S_DONE: push RX, deassert CS if cs_auto ──────────────────
                S_DONE: begin
                    if (!rx_fifo_full) begin
                        rx_fifo_din  <= rx_shift;
                        rx_fifo_push <= 1'b1;
                        rx_valid_irq <= 1'b1;
                    end
                    // Deassert CS if auto-mode and no more data
                    if (cs_auto && tx_fifo_empty) begin
                        cs_n <= {CS_WIDTH{1'b1}};
                    end
                    if (tx_fifo_empty) begin
                        tx_empty_irq <= 1'b1;
                    end
                    state <= S_IDLE;
                end

                default: state <= S_IDLE;
            endcase
        end
    end

endmodule

module spi_top #(
    parameter AXI_ADDR_WIDTH = 32,
    parameter AXI_DATA_WIDTH = 32,
    parameter AXI_ID_WIDTH   = 4,
    parameter TX_FIFO_DEPTH  = 16,
    parameter RX_FIFO_DEPTH  = 16,
    parameter CS_WIDTH       = 4
)(
    input  wire clk,
    input  wire rst_n,

    // =========================================================================
    // AXI4-Full Slave (S7 từ crossbar)
    // =========================================================================
    input  wire [AXI_ID_WIDTH-1:0]    s_axi_awid,
    input  wire [AXI_ADDR_WIDTH-1:0]  s_axi_awaddr,
    input  wire [7:0]                 s_axi_awlen,
    input  wire [2:0]                 s_axi_awsize,
    input  wire [1:0]                 s_axi_awburst,
    input  wire                       s_axi_awvalid,
    output wire                       s_axi_awready,
    input  wire [AXI_DATA_WIDTH-1:0]  s_axi_wdata,
    input  wire [AXI_DATA_WIDTH/8-1:0]s_axi_wstrb,
    input  wire                       s_axi_wlast,
    input  wire                       s_axi_wvalid,
    output wire                       s_axi_wready,
    output wire [AXI_ID_WIDTH-1:0]    s_axi_bid,
    output wire [1:0]                 s_axi_bresp,
    output wire                       s_axi_bvalid,
    input  wire                       s_axi_bready,
    input  wire [AXI_ID_WIDTH-1:0]    s_axi_arid,
    input  wire [AXI_ADDR_WIDTH-1:0]  s_axi_araddr,
    input  wire [7:0]                 s_axi_arlen,
    input  wire [2:0]                 s_axi_arsize,
    input  wire [1:0]                 s_axi_arburst,
    input  wire                       s_axi_arvalid,
    output wire                       s_axi_arready,
    output wire [AXI_ID_WIDTH-1:0]    s_axi_rid,
    output wire [AXI_DATA_WIDTH-1:0]  s_axi_rdata,
    output wire [1:0]                 s_axi_rresp,
    output wire                       s_axi_rlast,
    output wire                       s_axi_rvalid,
    input  wire                       s_axi_rready,

    // =========================================================================
    // SPI IO pads
    // =========================================================================
    output wire                  sck,
    output wire                  mosi,
    input  wire                  miso,
    output wire [CS_WIDTH-1:0]   cs_n,

    // =========================================================================
    // IRQ → PLIC
    // =========================================================================
    output wire irq_out,

    // =========================================================================
    // DMA handshake — flow control cho periph mode
    // =========================================================================
    output wire tx_dma_req,   // TX FIFO có chỗ trống → DMA có thể ghi (mode 10)
    output wire rx_dma_req    // RX FIFO có data      → DMA có thể đọc (mode 01)
);

    // ── Internal wires ────────────────────────────────────────────────────────
    wire [7:0] reg_tx_data;
    wire       reg_tx_push;
    wire       tx_fifo_full, tx_fifo_empty;
    wire [7:0] tx_fifo_dout;
    wire       tx_fifo_pop;

    wire [7:0] reg_rx_data;
    wire       reg_rx_pop;
    wire       rx_fifo_full, rx_fifo_empty;
    wire [7:0] rx_fifo_din;
    wire       rx_fifo_push;
    wire       rx_overrun_w;

    wire [15:0] reg_divider;
    wire        reg_spi_en, reg_cs_auto, reg_cpol, reg_cpha;
    wire        reg_rx_irq_en, reg_tx_irq_en;
    wire [CS_WIDTH-1:0] reg_cs_ctrl;

    wire tx_empty_irq_w, rx_valid_irq_w;
    wire spi_busy_w;

    // DMA req: TX FIFO có chỗ / RX FIFO có data
    assign tx_dma_req = !tx_fifo_full;
    assign rx_dma_req = !rx_fifo_empty;

    // RX overrun: RX FIFO full nhưng core vẫn muốn push
    assign rx_overrun_w = rx_fifo_full & rx_fifo_push;

    // ── u_axi_slave ───────────────────────────────────────────────────────────
    spi_axi_slave #(
        .AXI_ADDR_WIDTH(AXI_ADDR_WIDTH),
        .AXI_DATA_WIDTH(AXI_DATA_WIDTH),
        .AXI_ID_WIDTH  (AXI_ID_WIDTH)
    ) u_axi_slave (
        .clk           (clk),
        .rst_n         (rst_n),
        .s_axi_awid    (s_axi_awid),    .s_axi_awaddr  (s_axi_awaddr),
        .s_axi_awlen   (s_axi_awlen),   .s_axi_awsize  (s_axi_awsize),
        .s_axi_awburst (s_axi_awburst), .s_axi_awvalid (s_axi_awvalid),
        .s_axi_awready (s_axi_awready),
        .s_axi_wdata   (s_axi_wdata),   .s_axi_wstrb   (s_axi_wstrb),
        .s_axi_wlast   (s_axi_wlast),   .s_axi_wvalid  (s_axi_wvalid),
        .s_axi_wready  (s_axi_wready),
        .s_axi_bid     (s_axi_bid),     .s_axi_bresp   (s_axi_bresp),
        .s_axi_bvalid  (s_axi_bvalid),  .s_axi_bready  (s_axi_bready),
        .s_axi_arid    (s_axi_arid),    .s_axi_araddr  (s_axi_araddr),
        .s_axi_arlen   (s_axi_arlen),   .s_axi_arsize  (s_axi_arsize),
        .s_axi_arburst (s_axi_arburst), .s_axi_arvalid (s_axi_arvalid),
        .s_axi_arready (s_axi_arready),
        .s_axi_rid     (s_axi_rid),     .s_axi_rdata   (s_axi_rdata),
        .s_axi_rresp   (s_axi_rresp),   .s_axi_rlast   (s_axi_rlast),
        .s_axi_rvalid  (s_axi_rvalid),  .s_axi_rready  (s_axi_rready),
        .reg_tx_data   (reg_tx_data),   .reg_tx_push   (reg_tx_push),
        .tx_fifo_full  (tx_fifo_full),  .tx_fifo_empty (tx_fifo_empty),
        .reg_rx_data   (reg_rx_data),   .reg_rx_pop    (reg_rx_pop),
        .rx_fifo_full  (rx_fifo_full),  .rx_fifo_empty (rx_fifo_empty),
        .rx_overrun    (rx_overrun_w),  .spi_busy      (spi_busy_w),
        .reg_divider   (reg_divider),
        .reg_spi_en    (reg_spi_en),    .reg_cs_auto   (reg_cs_auto),
        .reg_cpol      (reg_cpol),      .reg_cpha      (reg_cpha),
        .reg_rx_irq_en (reg_rx_irq_en), .reg_tx_irq_en (reg_tx_irq_en),
        .reg_cs_ctrl   (reg_cs_ctrl),
        .tx_empty_irq_in(tx_empty_irq_w),
        .rx_valid_irq_in(rx_valid_irq_w),
        .irq_out       (irq_out)
    );

    // ── TX FIFO ───────────────────────────────────────────────────────────────
    uart_fifo #(.DEPTH(TX_FIFO_DEPTH)) u_tx_fifo (
        .clk        (clk),
        .rst_n      (rst_n),
        .din        (reg_tx_data),
        .push       (reg_tx_push),
        .full       (tx_fifo_full),
        .almost_full(),
        .dout       (tx_fifo_dout),
        .pop        (tx_fifo_pop),
        .empty      (tx_fifo_empty),
        .count      ()
    );

    // ── RX FIFO ───────────────────────────────────────────────────────────────
    uart_fifo #(.DEPTH(RX_FIFO_DEPTH)) u_rx_fifo (
        .clk        (clk),
        .rst_n      (rst_n),
        .din        (rx_fifo_din),
        .push       (rx_fifo_push),
        .full       (rx_fifo_full),
        .almost_full(),
        .dout       (reg_rx_data),
        .pop        (reg_rx_pop),
        .empty      (rx_fifo_empty),
        .count      ()
    );

    // ── SPI Core ──────────────────────────────────────────────────────────────
    spi_core #(.CS_WIDTH(CS_WIDTH)) u_core (
        .clk             (clk),
        .rst_n           (rst_n),
        .divider         (reg_divider),
        .spi_en          (reg_spi_en),
        .cpol            (reg_cpol),
        .cpha            (reg_cpha),
        .cs_auto         (reg_cs_auto),
        .cs_ctrl_manual  (reg_cs_ctrl),
        .tx_fifo_dout    (tx_fifo_dout),
        .tx_fifo_empty   (tx_fifo_empty),
        .tx_fifo_pop     (tx_fifo_pop),
        .rx_fifo_din     (rx_fifo_din),
        .rx_fifo_full    (rx_fifo_full),
        .rx_fifo_push    (rx_fifo_push),
        .sck             (sck),
        .mosi            (mosi),
        .miso            (miso),
        .cs_n            (cs_n),
        .busy            (spi_busy_w),
        .tx_empty_irq    (tx_empty_irq_w),
        .rx_valid_irq    (rx_valid_irq_w)
    );

endmodule

module soc_top #(
    // ── AXI parameters ────────────────────────────────────────────────────
    parameter DATA_WIDTH    = 32,
    parameter ADDR_WIDTH    = 32,
    parameter ID_WIDTH      = 4,

    // ── Memory sizes ──────────────────────────────────────────────────────
    parameter IMEM_SIZE      = 8192,   // 8 KB
    parameter DMEM_SIZE      = 8192,   // 8 KB

    parameter IMEM_INIT_FILE = "memory/program.hex",

    // ── Clock/Reset ───────────────────────────────────────────────────────
    parameter POR_CYCLES       = 1000,  // 10µs @ 100 MHz
    parameter SOFT_RST_STRETCH = 8,

    // ── JTAG IDCODE ───────────────────────────────────────────────────────
    parameter [31:0] JTAG_IDCODE = 32'hDEAD_0001,

    // ── Boot mode ─────────────────────────────────────────────────────────
    parameter        SIM_MODE    = 0,     // 0=UART boot (HW), 1=fast $readmemh (sim)

    // ── Crossbar slave address map (S0–S11) ───────────────────────────────
    parameter [31:0] S0_BASE  = 32'h0000_0000,  // IMEM      8 KB
    parameter [31:0] S0_MASK  = 32'hFFFF_E000,
    parameter [31:0] S1_BASE  = 32'h1000_0000,  // DMEM      8 KB (→64KB mở rộng)
    parameter [31:0] S1_MASK  = 32'hFFFF_E000,
    parameter [31:0] S2_BASE  = 32'h2000_0000,  // ASCON     4 KB
    parameter [31:0] S2_MASK  = 32'hFFFF_F000,
    parameter [31:0] S3_BASE  = 32'h3000_0000,  // SoC Ctrl  4 KB
    parameter [31:0] S3_MASK  = 32'hFFFF_F000,
    parameter [31:0] S4_BASE  = 32'h4000_0000,  // CLINT     64 KB
    parameter [31:0] S4_MASK  = 32'hFFFF_0000,
    parameter [31:0] S5_BASE  = 32'h5000_0000,  // UART      4 KB
    parameter [31:0] S5_MASK  = 32'hFFFF_F000,
    parameter [31:0] S6_BASE  = 32'h5001_0000,  // GPIO      4 KB (stub)
    parameter [31:0] S6_MASK  = 32'hFFFF_F000,
    parameter [31:0] S7_BASE  = 32'h5002_0000,  // SPI       4 KB (stub)
    parameter [31:0] S7_MASK  = 32'hFFFF_F000,
    parameter [31:0] S8_BASE  = 32'h5003_0000,  // Timer/WDT 4 KB (stub)
    parameter [31:0] S8_MASK  = 32'hFFFF_F000,
    parameter [31:0] S9_BASE  = 32'h5004_0000,  // PLIC      4 KB
    parameter [31:0] S9_MASK  = 32'hFFFF_F000,
    parameter [31:0] S10_BASE = 32'h6000_0000,  // OTP       4 KB (stub)
    parameter [31:0] S10_MASK = 32'hFFFF_F000,
    parameter [31:0] S11_BASE = 32'h6001_0000,  // DMA Ctrl  4 KB
    parameter [31:0] S11_MASK = 32'hFFFF_F000
)(
    // ── Clock & Reset IO pads ─────────────────────────────────────────────
    input  wire clk,
    input  wire por_n,         // Power-On Reset từ pad (active-low)
    input  wire ext_rst_n,     // External reset button (active-low)

    // ── UART IO pads ──────────────────────────────────────────────────────
    output wire uart_tx,
    input  wire uart_rx,

    // ── JTAG IO pads ──────────────────────────────────────────────────────
    input  wire tck,
    input  wire tms,
    input  wire tdi,
    output wire tdo,
    output wire tdo_en,        // HIGH khi Shift-DR/IR (để điều khiển tri-state pad)

    // ── GPIO IO pads (split in/out/oe cho simulation) ─────────────────────────
    output wire [31:0] gpio_out,   // pad output data
    output wire [31:0] gpio_oe,    // output enable (1=drive, 0=hi-Z)
    input  wire [31:0] gpio_in,    // pad input data

    // ── SPI IO pads ───────────────────────────────────────────────────────────
    output wire        spi_sck,
    output wire        spi_mosi,
    input  wire        spi_miso,
    output wire [3:0]  spi_cs_n,

    // ── WDT reset request ─────────────────────────────────────────────────────
    output wire wdt_rst_req        // active-high, từ watchdog
);

// ============================================================================
// SECTION 1: Clock & Reset (từ clk_reset_ctrl)
//
// WHY: Code cũ dùng "wire fabric_rst_n = ext_rst_n" rất nguy hiểm trên silicon:
//   - ext_rst_n từ pad bên ngoài không đồng bộ với clk → metastability
//   - Không có POR stretching → reset có thể release khi VDD chưa ổn định
// clk_reset_ctrl giải quyết bằng 2-FF synchronizer cho mỗi reset domain.
//
// ndmreset: JTAG DM có thể reset CPU (ndmreset=1) mà KHÔNG reset crossbar,
// vì DM cần giữ kết nối AXI (M4) để load chương trình khi CPU đang reset.
// ============================================================================
wire fabric_rst_n;   // reset cho crossbar, cache, SRAM, CLINT, SoC-Ctrl
wire cpu_rst_n;      // reset cho CPU core (bị ảnh hưởng bởi ndmreset)
wire periph_rst_n;   // reset cho UART, PLIC, DMA (bị ảnh hưởng bởi ndmreset)
wire aon_rst_n;      // reset cho AON domain (chỉ POR+ext, không soft/ndm)
wire clk_core;       // gated clock cho CORE domain (CPU + cache + ASCON)
wire clk_periph;     // gated clock cho PERIPH domain (UART, SPI, GPIO, ...)
wire clk_aon;        // always-on clock = clk_in, không bao giờ gate
wire wake_ack;       // periph clock đang chạy → AON có thể clear wake_pend
wire periph_wake_req;// async wake request từ AON domain
wire uart_wake_req;  // AON start-bit FF từ uart_top
wire gpio_wake_req;  // AON edge-detect FF từ gpio_top
wire timer_wake_req; // AON timeout FF từ timer_top
wire soft_rst_pulse; // từ soc_ctrl_slave → clk_reset_ctrl (1-cycle pulse)
wire jtag_ndmreset;  // từ jtag_debug_top → clk_reset_ctrl
wire cpu_wfi;
wire cpu_perf_stall;      // [A2] = stall_any from CPU
wire cpu_perf_instr_ret;  // [A2] = regwrite_wb && !stall_any from CPU
wire uart_active;
wire timer_active;
wire gpio_wake_armed;
wire dma_busy;
// DMA peripheral handshake
// CH0: UART RX (periph-to-mem),  CH1: UART TX (mem-to-periph)
// CH2: SPI  RX (periph-to-mem),  CH3: SPI  TX (mem-to-periph)
wire uart_tx_dma_req, uart_rx_dma_req;
wire spi_tx_dma_req,  spi_rx_dma_req;
wire [3:0] dma_periph_req;
wire [3:0] dma_periph_ack;
assign dma_periph_req = {spi_tx_dma_req, spi_rx_dma_req,
                         uart_tx_dma_req, uart_rx_dma_req};
wire spi_irq;
wire core_bus_active;
wire core_wake_event;
wire periph_bus_active;
wire periph_busy;
wire periph_wake_event;
wire periph_gate_allow;

// Declare missing implicit wires
wire boot_done;
wire ascon_o_busy;
wire imem_boot_we;
wire [31:0] imem_boot_addr;
wire [31:0] imem_boot_wdata;

// WHY cpu_rst active-high: riscv_cpu_core dùng "rst" active-high convention
wire cpu_rst = ~cpu_rst_n;

clk_reset_ctrl #(
    .POR_CYCLES       (POR_CYCLES),
    .SOFT_RST_STRETCH (SOFT_RST_STRETCH)
) u_clkrst (
    .clk_in        (clk),
    .por_n         (por_n),
    .ext_rst_n     (ext_rst_n),
    .soft_rst_pulse(soft_rst_pulse),
    .ndmreset      (jtag_ndmreset), // JTAG DM → reset CPU+periph không reset fabric
    .boot_done     (boot_done),     // boot_ctrl → giữ cpu_rst_n cho đến khi IMEM loaded
    .test_en       (1'b0),
    .core_clk_en   (1'b1),
    .periph_clk_en (1'b1),
    .cpu_wfi       (cpu_wfi),
    .ascon_busy    (ascon_o_busy),
    .core_bus_active(core_bus_active),
    .core_wake_event(core_wake_event),
    .periph_bus_active(periph_bus_active),
    .periph_busy      (periph_busy),
    .periph_wake_event(periph_wake_event),
    .periph_gate_allow(periph_gate_allow),
    .periph_wake_req  (periph_wake_req),
    .clk_core         (clk_core),
    .clk_periph       (clk_periph),
    .clk_aon          (clk_aon),
    .fabric_rst_n     (fabric_rst_n),
    .cpu_rst_n        (cpu_rst_n),
    .periph_rst_n     (periph_rst_n),
    .aon_rst_n        (aon_rst_n),
    .wake_ack         (wake_ack)
);

// ============================================================================
// SECTION 1b: Boot Controller
//
// Chạy trên fabric_rst_n (giống crossbar). Copies boot ROM → IMEM via sideband
// port. Sau khi xong, asserts boot_done → clk_reset_ctrl releases cpu_rst_n.
// CPU chỉ bắt đầu fetch khi IMEM đã có nội dung hợp lệ.
// ============================================================================
uart_boot_ctrl #(
    .SIM_MODE   (SIM_MODE),
    .BOOT_FILE  (IMEM_INIT_FILE),
    .PROG_WORDS (IMEM_SIZE / 4)
) u_boot (
    .clk        (clk),
    .rst_n      (fabric_rst_n),
    .uart_rx    (uart_rx),        // shared với u_uart (S5 ở periph_rst=0 trong boot)
    .boot_we    (imem_boot_we),
    .boot_addr  (imem_boot_addr),
    .boot_wdata (imem_boot_wdata),
    .boot_done  (boot_done)
);

// ============================================================================
// SECTION 2: mtime_tick prescaler — 100 MHz → 1 MHz (chu kỳ 1µs)
//
// WHY: CLINT.mtime đếm theo µs (RISC-V spec yêu cầu). Prescaler chia 100
// cho clock 100 MHz để tạo tick 1 MHz đưa vào CLINT.
// ============================================================================
reg [6:0] prescaler_cnt;
reg       mtime_tick;

always @(posedge clk or negedge fabric_rst_n) begin
    if (!fabric_rst_n) begin
        prescaler_cnt <= 7'd0;
        mtime_tick    <= 1'b0;
    end else begin
        if (prescaler_cnt == 7'd99) begin
            prescaler_cnt <= 7'd0;
            mtime_tick    <= 1'b1;
        end else begin
            prescaler_cnt <= prescaler_cnt + 7'd1;
            mtime_tick    <= 1'b0;
        end
    end
end

// ============================================================================
// SECTION 3: CPU ↔ ICache / DCache wires
// ============================================================================
wire [31:0] cpu_imem_addr;
wire        cpu_imem_valid;
wire [31:0] icache_imem_rdata;
wire        icache_imem_ready;

wire [31:0] cpu_dcache_addr;
wire [31:0] cpu_dcache_wdata;
wire [3:0]  cpu_dcache_wstrb;
wire        cpu_dcache_req;
wire        cpu_dcache_we;
wire [31:0] dcache_cpu_rdata;
wire        dcache_cpu_ready;
wire [1:0]  cpu_dcache_fence_type;

assign core_bus_active =
    m0_arvalid | m0_awvalid | m0_wvalid | m0_rvalid | m0_bvalid |
    m1_arvalid | m1_awvalid | m1_wvalid | m1_rvalid | m1_bvalid |
    m2_arvalid | m2_awvalid | m2_wvalid | m2_rvalid | m2_bvalid;

// ============================================================================
// SECTION 4: Interrupt wires
//
// WHY cấu trúc IRQ:
//   Tất cả peripheral IRQ → PLIC → meip → CPU.external_irq
//   SOC CTRL giữ irq_out wire nhưng không kết nối vào CPU nữa (PLIC thay thế).
//   CLINT timer_irq / sw_irq đi thẳng vào CPU (theo spec RISC-V, CLINT bypass PLIC).
// ============================================================================
wire external_irq;   // PLIC.meip → CPU (machine external interrupt)
wire timer_irq;      // CLINT → CPU (machine timer interrupt)
wire sw_irq;         // CLINT → CPU (machine software interrupt)
wire ascon_irq;      // ASCON → PLIC source[8]
wire uart_irq;       // UART  → PLIC source[1] (tx) & [2] (rx) — hợp nhất 1 wire
wire dma_irq;        // DMA   → PLIC source[9]
wire gpio_irq;       // GPIO  → PLIC source[4]
wire timer0_irq;     // Timer0 → PLIC source[5]
wire timer1_irq;     // Timer1 → PLIC source[6]
wire wdt_irq;        // WDT   → PLIC source[7]
wire soc_ctrl_irq_out; // soc_ctrl_slave.irq_out — giữ lại để tương thích,
                       // nhưng không dùng làm external_irq (PLIC đảm nhiệm)

assign core_wake_event = external_irq | timer_irq | sw_irq |
                         jtag_haltreq | jtag_resumereq | jtag_ndmreset |
                         !boot_done;

assign periph_bus_active =
    s5_awvalid | s5_wvalid | s5_arvalid | s5_bvalid | s5_rvalid |
    s6_awvalid | s6_wvalid | s6_arvalid | s6_bvalid | s6_rvalid |
    s8_awvalid | s8_wvalid | s8_arvalid | s8_bvalid | s8_rvalid |
    s9_awvalid | s9_wvalid | s9_arvalid | s9_bvalid | s9_rvalid |
    s11_awvalid | s11_wvalid | s11_arvalid | s11_bvalid | s11_rvalid |
    m3_arvalid | m3_awvalid | m3_wvalid | m3_rvalid | m3_bvalid;

assign periph_busy = uart_active | timer_active | dma_busy |
                     uart_irq | gpio_irq | timer0_irq | timer1_irq | wdt_irq |
                     external_irq;

assign periph_wake_event = uart_irq | gpio_irq | timer0_irq | timer1_irq |
                           wdt_irq | dma_irq | external_irq |
                           !uart_rx | jtag_haltreq | jtag_resumereq | jtag_ndmreset;

assign periph_gate_allow = !timer_active && !gpio_wake_armed && !dma_busy;

// periph_wake_req: chỉ dùng AON-domain FF outputs — valid kể cả khi clk_periph gate.
assign periph_wake_req = uart_wake_req | gpio_wake_req | timer_wake_req | external_irq;

// ── Boot controller signal ────────────────────────────────────────────────────
// (Wires declared at the top of the file to fix implicit definition warning)

// ============================================================================
// SECTION 5: JTAG Debug wires
// ============================================================================
wire jtag_haltreq;
wire jtag_resumereq;
wire jtag_halted;
wire jtag_running;

// ============================================================================
// SECTION 6: ASCON AXI-Stream wires (tied off — SoC không dùng stream mode)
// // ============================================================================
// wire [63:0] ascon_s_axis_tdata  = 64'h0;
// wire        ascon_s_axis_tvalid = 1'b0;
// wire        ascon_s_axis_tlast  = 1'b0;
// wire        ascon_s_axis_tready;   // output — không kết nối upstream

// wire [63:0] ascon_m_axis_tdata;
// wire        ascon_m_axis_tvalid;
// wire        ascon_m_axis_tlast;
// wire        ascon_m_axis_tready = 1'b1;  // luôn consume

wire [127:0] ascon_o_tag;
wire         ascon_o_tag_valid;
// ascon_o_busy declared at the top

// ============================================================================
// SECTION 7: Cache statistics wires
// ============================================================================
wire [31:0] icache_stat_hits;
wire [31:0] icache_stat_misses;
wire [31:0] dcache_stat_hits;
wire [31:0] dcache_stat_misses;
wire [31:0] dcache_stat_writes;

// ============================================================================
// SECTION 8: AXI4 Master wires (M0–M4)
//
// Naming convention: m{N}_{signal}
//   M0 = ICache, M1 = DCache, M2 = ASCON-DMA (32b), M3 = DMA-Ctrl, M4 = JTAG-DM
// ============================================================================

// ── M0: ICache ──────────────────────────────────────────────────────────────
wire [ID_WIDTH-1:0]   m0_arid,  m0_awid,  m0_bid,  m0_rid;
wire [ADDR_WIDTH-1:0] m0_araddr, m0_awaddr;
wire [7:0]            m0_arlen,  m0_awlen;
wire [2:0]            m0_arsize, m0_awsize;
wire [1:0]            m0_arburst, m0_awburst;
wire [2:0]            m0_arprot, m0_awprot;
wire                  m0_arvalid, m0_arready;
wire                  m0_awvalid, m0_awready;
wire [DATA_WIDTH-1:0] m0_rdata,   m0_wdata;
wire [DATA_WIDTH/8-1:0] m0_wstrb;
wire [1:0]            m0_rresp,  m0_bresp;
wire                  m0_rlast,  m0_wlast;
wire                  m0_rvalid, m0_rready;
wire                  m0_wvalid, m0_wready;
wire                  m0_bvalid, m0_bready;

// ── M1: DCache ──────────────────────────────────────────────────────────────
wire [ID_WIDTH-1:0]   m1_arid,  m1_awid,  m1_bid,  m1_rid;
wire [ADDR_WIDTH-1:0] m1_araddr, m1_awaddr;
wire [7:0]            m1_arlen,  m1_awlen;
wire [2:0]            m1_arsize, m1_awsize;
wire [1:0]            m1_arburst, m1_awburst;
wire [2:0]            m1_arprot, m1_awprot;
wire                  m1_arvalid, m1_arready;
wire                  m1_awvalid, m1_awready;
wire [DATA_WIDTH-1:0] m1_rdata,   m1_wdata;
wire [DATA_WIDTH/8-1:0] m1_wstrb;
wire [1:0]            m1_rresp,  m1_bresp;
wire                  m1_rlast,  m1_wlast;
wire                  m1_rvalid, m1_rready;
wire                  m1_wvalid, m1_wready;
wire                  m1_bvalid, m1_bready;

// ── M2: ASCON DMA (32-bit, saụ width converter) ──────────────────────────────
wire [ID_WIDTH-1:0]   m2_arid,  m2_awid,  m2_bid,  m2_rid;
wire [ADDR_WIDTH-1:0] m2_araddr, m2_awaddr;
wire [7:0]            m2_arlen,  m2_awlen;
wire [2:0]            m2_arsize, m2_awsize;
wire [1:0]            m2_arburst, m2_awburst;
wire [2:0]            m2_arprot, m2_awprot;
wire                  m2_arvalid, m2_arready;
wire                  m2_awvalid, m2_awready;
wire [DATA_WIDTH-1:0] m2_rdata,   m2_wdata;
wire [DATA_WIDTH/8-1:0] m2_wstrb;
wire [1:0]            m2_rresp,  m2_bresp;
wire                  m2_rlast,  m2_wlast;
wire                  m2_rvalid, m2_rready;
wire                  m2_wvalid, m2_wready;
wire                  m2_bvalid, m2_bready;

// ── M3: DMA Controller ───────────────────────────────────────────────────────
wire [ID_WIDTH-1:0]   m3_arid,  m3_awid,  m3_bid,  m3_rid;
wire [ADDR_WIDTH-1:0] m3_araddr, m3_awaddr;
wire [7:0]            m3_arlen,  m3_awlen;
wire [2:0]            m3_arsize, m3_awsize;
wire [1:0]            m3_arburst, m3_awburst;
wire [2:0]            m3_arprot, m3_awprot;
wire                  m3_arvalid, m3_arready;
wire                  m3_awvalid, m3_awready;
wire [DATA_WIDTH-1:0] m3_rdata,   m3_wdata;
wire [DATA_WIDTH/8-1:0] m3_wstrb;
wire [1:0]            m3_rresp,  m3_bresp;
wire                  m3_rlast,  m3_wlast;
wire                  m3_rvalid, m3_rready;
wire                  m3_wvalid, m3_wready;
wire                  m3_bvalid, m3_bready;

// ── M4: JTAG Debug Module ────────────────────────────────────────────────────
wire [ID_WIDTH-1:0]   m4_arid,  m4_awid,  m4_bid,  m4_rid;
wire [ADDR_WIDTH-1:0] m4_araddr, m4_awaddr;
wire [7:0]            m4_arlen,  m4_awlen;
wire [2:0]            m4_arsize, m4_awsize;
wire [1:0]            m4_arburst, m4_awburst;
wire [2:0]            m4_arprot, m4_awprot;
wire                  m4_arvalid, m4_arready;
wire                  m4_awvalid, m4_awready;
wire [DATA_WIDTH-1:0] m4_rdata,   m4_wdata;
wire [DATA_WIDTH/8-1:0] m4_wstrb;
wire [1:0]            m4_rresp,  m4_bresp;
wire                  m4_rlast,  m4_wlast;
wire                  m4_rvalid, m4_rready;
wire                  m4_wvalid, m4_wready;
wire                  m4_bvalid, m4_bready;

// ============================================================================
// SECTION 9: ASCON DMA 64-bit master wires (trước width converter)
// ============================================================================
wire [ID_WIDTH-1:0]   dma_awid,  dma_arid,  dma_bid,  dma_rid;
wire [ADDR_WIDTH-1:0] dma_awaddr, dma_araddr;
wire [7:0]            dma_awlen,  dma_arlen;
wire [2:0]            dma_awsize, dma_arsize;
wire [1:0]            dma_awburst, dma_arburst;
wire [3:0]            dma_awcache, dma_arcache;
wire [2:0]            dma_awprot, dma_arprot;
wire                  dma_awvalid, dma_awready;
wire                  dma_arvalid, dma_arready;
wire [63:0]           dma_wdata;
wire [7:0]            dma_wstrb;
wire                  dma_wlast,  dma_wvalid, dma_wready;
wire [1:0]            dma_bresp,  dma_rresp;
wire                  dma_bvalid, dma_bready;
wire [63:0]           dma_rdata;
